            <p className="text-muted-foreground">
              Seleziona un'opzione qui sotto o usa il menu rapido in alto per iniziare.
            </p>
          </header>

          {isDeclared === false && (
            <Alert className="bg-amber-50 border-amber-200 text-amber-800 shadow-sm animate-pulse">
              <ShieldAlert className="h-5 w-5 text-amber-600" />
              <div className="flex-1 ml-3">
                <AlertTitle className="font-bold text-amber-900">Dichiarazione Presenze Mancante</AlertTitle>
                <AlertDescription className="text-amber-800">
                  Le presenze per oggi non sono ancora state confermate. Dichiarale ora per aggiornare la capacità del Gantt.
                </AlertDescription>
              </div>
              <div className="flex gap-2 ml-4">
                <Button variant="outline" size="sm" asChild className="border-amber-300 hover:bg-amber-100">
                  <Link href="/admin/attendance-calendar">Apri Calendario</Link>
                </Button>
                <Button size="sm" onClick={() => setIsModalOpen(true)} className="bg-amber-600 hover:bg-amber-700 text-white border-0">
                   Compila Foglio Presenze
                </Button>
              </div>
            </Alert>
          )}

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {navItems.map((item) => (
               <DashboardItem
                key={item.href}
                href={item.href}
                title={item.label}
                description={item.description}
                icon={item.icon}
              />
            ))}
          </div>
        </div>
        {user && (
          <DailyAttendanceModal 
            isOpen={isModalOpen} 
            onOpenChange={setIsModalOpen} 
            uid={user.uid} 
            onDeclared={onDeclared} 
          />
        )}
      </AppShell>
    </AdminAuthGuard>
  );
}

'use client';

import { useState } from 'react';
import { 
    auditCorruptedInventoryData, 
    applyInventoryDataHealing, 
    AuditAnomaly, 
    auditZombieSessions, 
    healZombieSessions, 
    ZombieAnomaly,
    auditBrokenBatches,
    healBrokenBatches,
    AuditBrokenLot,
    auditGroupBlockers,
    forceUnlockAndDissolveGroup,
    GroupBlocker,
    previewStockSync,
    resyncAllMaterialStock,
    StockSyncAnomaly,
    fixCorruptedBatchLoads,
    syncAllJobOrderCommitments
} from './actions';
import { Button } from '@/components/ui/button';
import { Card, CardHeader, CardTitle, CardContent, CardDescription } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Alert, AlertTitle, AlertDescription } from '@/components/ui/alert';
import { Loader2, AlertCircle, CheckCircle2, ShieldCheck, Database, History, TrendingDown, Hammer, Info, Ghost, Skull, UserX, Zap, RotateCcw, Clock, Search, Layers, Unlink, TriangleAlert } from 'lucide-react';
import { useAuth } from '@/components/auth/AuthProvider';
import { useToast } from '@/hooks/use-toast';
import AdminAuthGuard from '@/components/AdminAuthGuard';
import AppShell from '@/components/layout/AppShell';
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Badge } from "@/components/ui/badge";
import { Checkbox } from "@/components/ui/checkbox";
import { 
  ArrowRight, 
  Lock, 
  Calendar, 
  FileText, 
  Check, 
  X, 
  Activity,
  AlertTriangle,
  Scale
} from 'lucide-react';
import { format } from 'date-fns';
import { it } from 'date-fns/locale';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";

export default function AdministrationDataHealingPage() {
    const { operator } = useAuth();
    const { toast } = useToast();
    
    // Status State
    const [loading, setLoading] = useState(false);
    const [executing, setExecuting] = useState(false);
    const [error, setError] = useState<string | null>(null);

    // Inventory Tab State
    const [anomalies, setAnomalies] = useState<AuditAnomaly[]>([]);
    const [summary, setSummary] = useState<any>(null);
    const [isHealModalOpen, setIsHealModalOpen] = useState(false);
    const [confirmText, setConfirmText] = useState("");

    // Zombie Hunter Tab State
    const [zombieAnomalies, setZombieAnomalies] = useState<ZombieAnomaly[]>([]);
    const [selectedZombieIds, setSelectedZombieIds] = useState<string[]>([]);
    const [zombieLoading, setZombieLoading] = useState(false);
    const [zombieExecuting, setZombieExecuting] = useState(false);
    const [isZombieModalOpen, setIsZombieModalOpen] = useState(false);
    const [zombieConfirmText, setZombieConfirmText] = useState("");
    
    // Broken Lot Recovery State
    const [brokenLots, setBrokenLots] = useState<AuditBrokenLot[]>([]);
    const [brokenLoading, setBrokenLoading] = useState(false);
    const [brokenExecuting, setBrokenExecuting] = useState(false);
    const [isBrokenModalOpen, setIsBrokenModalOpen] = useState(false);
    const [brokenConfirmText, setBrokenConfirmText] = useState("");

    // Workgroup Unblock State
    const [groupBlockers, setGroupBlockers] = useState<GroupBlocker[]>([]);
    const [groupLoading, setGroupLoading] = useState(false);
    const [groupExecuting, setGroupExecuting] = useState(false);
    const [isGroupModalOpen, setIsGroupModalOpen] = useState(false);
    const [selectedGroupId, setSelectedGroupId] = useState<string | null>(null);
    const [groupConfirmText, setGroupConfirmText] = useState("");

    // Global Stock Resync Wizard State
    const [resyncLoading, setResyncLoading] = useState(false);
    const [resyncExecuting, setResyncExecuting] = useState(false);
    const [syncAnomalies, setSyncAnomalies] = useState<StockSyncAnomaly[]>([]);
    const [selectedMaterialIds, setSelectedMaterialIds] = useState<string[]>([]);
    const [isResyncModalOpen, setIsResyncModalOpen] = useState(false);
    const [resyncConfirmText, setResyncConfirmText] = useState("");
    
    // Read-Only Erosion Fix State
    const [erosionExecuting, setErosionExecuting] = useState(false);
    const [isErosionModalOpen, setIsErosionModalOpen] = useState(false);
    const [erosionConfirmText, setErosionConfirmText] = useState("");

    // Job Sync State
    const [syncExecuting, setSyncExecuting] = useState(false);
    const [isSyncModalOpen, setIsSyncModalOpen] = useState(false);
    const [syncConfirmText, setSyncConfirmText] = useState("");
    const [syncResults, setSyncResults] = useState<{ processed: number, failed: number, errors: string[] } | null>(null);

    // --- INVENTORY LOGIC ---
    async function handleAudit() {
        setLoading(true);
        setError(null);
        try {
            const res = await auditCorruptedInventoryData();
            if (res.success) {
                setAnomalies(res.anomalies);
                setSummary(res.summary);
            } else {
                setError("Errore durante l'analisi del database inventory.");
            }
        } catch (e) {
            setError("Errore di connessione al server.");
        } finally {
            setLoading(false);
        }
    }

    async function handleExecuteHealing() {
        if (!operator?.id) return;
        setExecuting(true);
        setIsHealModalOpen(false);
        try {
            const res = await applyInventoryDataHealing(operator.id);
            if (res.success) {
                toast({ title: "Sanatoria Completata", description: res.message });
                await handleAudit();
            } else {
                toast({ title: "Errore Sanatoria", description: res.message, variant: "destructive" });
            }
        } catch (e) {
            toast({ title: "Errore di Sistema", description: "Impossibile completare la sanatoria.", variant: "destructive" });
        } finally {
            setExecuting(false);
            setConfirmText("");
        }
    }

    async function handleStockAudit() {
        setResyncLoading(true);
        setError(null);
        try {
            const res = await previewStockSync(operator?.id || "");
            if (res.success) {
                setSyncAnomalies(res.anomalies);
                // Auto-select those that REALLY need sync (diff > 0.001)
                const toSelect = res.anomalies
                    .filter(a => a.needsSync)
                    .map(a => a.materialId);
                setSelectedMaterialIds(toSelect);
                toast({ title: "Audit Completata", description: `Trovate ${res.anomalies.filter(a => a.needsSync).length} anomalie di stock.` });
            } else {
                setError("Errore durante l'audit del magazzino.");
            }
        } catch (e) {
            setError("Impossibile contattare il server per l'audit.");
        } finally {
            setResyncLoading(false);
        }
    }

    async function handleExecuteSelectiveResync() {
        if (!operator?.id || selectedMaterialIds.length === 0) return;
        setResyncExecuting(true);
        setIsResyncModalOpen(false);
        try {
            const res = await resyncAllMaterialStock(selectedMaterialIds, operator.id);
            if (res.success) {
                toast({ title: "Ricalcolo Completato", description: res.message });
                // Reset state after success
                setSyncAnomalies([]);
                setSelectedMaterialIds([]);
            } else {
                toast({ title: "Errore Ricalcolo", description: res.message, variant: "destructive" });
            }
        } catch (e) {
            toast({ title: "Errore di Sistema", description: "Impossibile completare il ricalcolo selettivo.", variant: "destructive" });
        } finally {
            setResyncExecuting(false);
            setResyncConfirmText("");
        }
    }

    const toggleSelection = (id: string) => {
        setSelectedMaterialIds(prev => 
            prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
        );
    };

    const toggleAllDiscrepancies = () => {
        const discrepancyIds = syncAnomalies.filter(a => a.needsSync).map(a => a.materialId);
        if (discrepancyIds.every(id => selectedMaterialIds.includes(id))) {
            setSelectedMaterialIds(prev => prev.filter(id => !discrepancyIds.includes(id)));
        } else {
            setSelectedMaterialIds(prev => Array.from(new Set([...prev, ...discrepancyIds])));
        }
    };

    // --- ZOMBIE LOGIC ---
    async function handleZombieAudit() {
        setZombieLoading(true);
        setError(null);
        try {
            const res = await auditZombieSessions();
            if (res.success) {
                setZombieAnomalies(res.anomalies);
                setSelectedZombieIds(res.anomalies.map(a => a.id));
            } else {
                setError("Errore durante l'analisi delle sessioni zombie.");
            }
        } catch (e) {
            setError("Errore di connessione durante l'audit zombie.");
        } finally {
            setZombieLoading(false);
        }
    }

    async function handleExecuteZombieHealing() {
        if (!operator?.id || selectedZombieIds.length === 0) return;
        setZombieExecuting(true);
        setIsZombieModalOpen(false);
        try {
            const res = await healZombieSessions(selectedZombieIds, operator.id);
            if (res.success) {
                toast({ title: "Caccia Completata", description: res.message });
                await handleZombieAudit();
            } else {
                toast({ title: "Errore Healing", description: res.message, variant: "destructive" });
            }
        } catch (e) {
            toast({ title: "Errore di Sistema", description: "Impossibile completare l'operazione zombie.", variant: "destructive" });
        } finally {
            setZombieExecuting(false);
            setZombieConfirmText("");
        }
    }

    const toggleZombieSelection = (id: string) => {
        setSelectedZombieIds(prev => 
            prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
        );
    };

    const toggleAllZombies = () => {
        if (selectedZombieIds.length === zombieAnomalies.length) {
            setSelectedZombieIds([]);
        } else {
            setSelectedZombieIds(zombieAnomalies.map(a => a.id));
        }
    };

    // --- BROKEN LOT RECOVERY LOGIC ---
    async function handleBrokenAudit() {
        setBrokenLoading(true);
        setError(null);
        try {
            const res = await auditBrokenBatches();
            if (res.success) {
                setBrokenLots(res.anomalies);
            } else {
                setError("Errore durante l'analisi dei lotti corrotti.");
            }
        } catch (e) {
            setError("Errore di connessione durante l'audit dei lotti.");
        } finally {
            setBrokenLoading(false);
        }
    }

    async function handleExecuteBrokenHealing() {
        if (!operator?.id) return;
        setBrokenExecuting(true);
        setIsBrokenModalOpen(false);
        try {
            const res = await healBrokenBatches(operator.id);
            if (res.success) {
                toast({ title: "Ripristino Completato", description: res.message });
                await handleBrokenAudit();
            } else {
                toast({ title: "Errore Ripristino", description: res.message, variant: "destructive" });
            }
        } catch (e) {
            toast({ title: "Errore di Sistema", description: "Impossibile completare il ripristino.", variant: "destructive" });
        } finally {
            setBrokenExecuting(false);
            setBrokenConfirmText("");
        }
    }
    async function handleExecuteErosionHealing() {
        if (!operator?.id) return;
        setErosionExecuting(true);
        setIsErosionModalOpen(false);
        try {
            const res = await fixCorruptedBatchLoads(operator.id);
            if (res.success) {
                toast({ title: "Sanatoria Erosione Completata", description: res.message });
                // We might want to refresh something here, maybe the broken lots audit if open
            } else {
                toast({ title: "Errore Sanatoria", description: res.message, variant: "destructive" });
            }
        } catch (e) {
            toast({ title: "Errore di Sistema", description: "Impossibile completare la sanatoria erosione.", variant: "destructive" });
        } finally {
            setErosionExecuting(false);
            setErosionConfirmText("");
        }
    }

    // --- GROUP UNBLOCK LOGIC ---
    async function handleGroupAudit() {
        setGroupLoading(true);
        setError(null);
        try {
            const res = await auditGroupBlockers();
            if (res.success) {
                setGroupBlockers(res.blockers);
            } else {
                setError("Errore durante l'audit dei gruppi.");
            }
        } catch (e) {
            setError("Errore di connessione durante l'audit gruppi.");
        } finally {
            setGroupLoading(false);
        }
    }

    async function handleExecuteGroupUnlock() {
        if (!operator?.id || !selectedGroupId) return;
        setGroupExecuting(true);
        setIsGroupModalOpen(false);
        try {
            const res = await forceUnlockAndDissolveGroup(selectedGroupId, operator.id);
            if (res.success) {
                toast({ title: "Sblocco Completato", description: res.message });
                await handleGroupAudit();
            } else {
                toast({ title: "Errore Sblocco", description: res.message, variant: "destructive" });
            }
        } catch (e) {
            toast({ title: "Errore di Sistema", description: "Impossibile completare lo sblocco.", variant: "destructive" });
        } finally {
            setGroupExecuting(false);
            setGroupConfirmText("");
            setSelectedGroupId(null);
        }
    }

    // --- JOB SYNC LOGIC ---
    async function handleExecuteJobSync() {
        if (!operator?.id) return;
        setSyncExecuting(true);
        setIsSyncModalOpen(false);
        setSyncResults(null);
        try {
            const res = await syncAllJobOrderCommitments(operator.id);
            setSyncResults({
                processed: res.processed,
                failed: res.failed,
                errors: res.errors
            });
            if (res.success) {
                toast({ title: "Sincronizzazione Completata", description: res.message });
            } else {
                toast({ 
                    title: res.failed > 0 ? "Sincronizzazione Parziale" : "Errore Critico", 
                    description: res.message, 
                    variant: res.failed > 0 ? "default" : "destructive" 
                });
            }
        } catch (e: any) {
            toast({ title: "Errore di Sistema", description: "Impossibile completare la sincronizzazione.", variant: "destructive" });
        } finally {
            setSyncExecuting(false);
            setSyncConfirmText("");
        }
    }

    return (
        <AdminAuthGuard>
            <AppShell>
                <div className="p-6 max-w-7xl mx-auto space-y-8">
                    {/* Header */}
                    <div className="flex items-center justify-between">
                        <div className="space-y-1">
                            <h1 className="text-3xl font-bold tracking-tight">Centro Manutenzione e Integrità Dati</h1>
                            <p className="text-muted-foreground text-lg italic">Strumenti di Audit & Healing per il database di produzione.</p>
                        </div>
                    </div>

                    <Tabs defaultValue="inventory" className="w-full">
                        <TabsList className="grid w-full grid-cols-4 max-w-4xl mb-8">
                            <TabsTrigger value="inventory" className="flex items-center gap-2">
                                <Database className="h-4 w-4" /> Integrità Magazzino
                            </TabsTrigger>
                            <TabsTrigger value="zombie" className="flex items-center gap-2">
                                <Ghost className="h-4 w-4" /> Cacciatore di Zombie
                            </TabsTrigger>
                            <TabsTrigger value="recovery" className="flex items-center gap-2">
                                <RotateCcw className="h-4 w-4 text-orange-500" /> Ripristino Lotti
                            </TabsTrigger>
                            <TabsTrigger value="groups" className="flex items-center gap-2">
                                <Layers className="h-4 w-4 text-blue-500" /> Sblocco Gruppi
                            </TabsTrigger>
                            <TabsTrigger value="jobs" className="flex items-center gap-2">
                                <Zap className="h-4 w-4 text-yellow-500" /> Sync Impegni
                            </TabsTrigger>
                        </TabsList>

                        {/* --- TAB 1: INVENTORY --- */}
                        <TabsContent value="inventory" className="space-y-6">
                            <div className="flex justify-between items-center mb-4">
                                <h2 className="text-2xl font-bold flex items-center gap-2">
                                    <Database className="text-primary h-6 w-6" /> Correzione Anomalie UOM
                                </h2>
                                <div className="flex gap-4">
                                    <Button variant="outline" onClick={handleAudit} disabled={loading || executing || resyncExecuting || resyncLoading}>
                                        {loading ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <ShieldCheck className="mr-2 h-4 w-4" />}
                                        Analizza Pesi
                                    </Button>
                                    
                                    <Button variant="secondary" className="bg-blue-600 hover:bg-blue-700 text-white" onClick={handleStockAudit} disabled={loading || executing || resyncExecuting || resyncLoading}>
                                        {resyncLoading ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Search className="mr-2 h-4 w-4" />}
                                        Analizza Discrepanze Stock (Audit)
                                    </Button>

                                    {syncAnomalies.length > 0 && (
                                        <Button 
                                            variant="default" 
                                            className="bg-green-600 hover:bg-green-700" 
                                            onClick={() => setIsResyncModalOpen(true)} 
                                            disabled={selectedMaterialIds.length === 0 || resyncExecuting}
                                        >
                                            <CheckCircle2 className="mr-2 h-4 w-4" />
                                            Applica Correzioni ({selectedMaterialIds.length})
                                        </Button>
                                    )}

                                    {anomalies.length > 0 && (
                                        <Button variant="destructive" onClick={() => setIsHealModalOpen(true)} disabled={loading || executing || resyncExecuting || resyncLoading}>
                                            {executing ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Hammer className="mr-2 h-4 w-4" />}
                                            Esegui Correzione Pesi
                                        </Button>
                                    )}
                                </div>
                            </div>

                            <Dialog open={isHealModalOpen} onOpenChange={setIsHealModalOpen}>
                                <DialogContent className="sm:max-w-[425px]">
                                    <DialogHeader>
                                        <DialogTitle className="flex items-center text-red-600">
                                            <AlertCircle className="mr-2 h-5 w-5" /> Conferma Correzione Massiva
                                        </DialogTitle>
                                        <DialogDescription className="py-4">
                                            Questa operazione sovrascriverà i pesi di <strong>{anomalies.length}</strong> record storici.
                                            L'azione è irreversibile.
                                        </DialogDescription>
                                    </DialogHeader>
                                    <div className="space-y-4 py-4">
                                        <p className="text-sm text-muted-foreground">Digitare <span className="font-mono font-bold">CONFERMO</span> per procedere:</p>
                                        <Input placeholder="Digita qui..." value={confirmText} onChange={(e) => setConfirmText(e.target.value)} className="uppercase font-bold" />
                                    </div>
                                    <DialogFooter>
                                        <Button variant="ghost" onClick={() => setIsHealModalOpen(false)}>Annulla</Button>
                                        <Button variant="destructive" disabled={confirmText !== "CONFERMO"} onClick={handleExecuteHealing}>CORREGGI ORA</Button>
                                    </DialogFooter>
                                </DialogContent>
                            </Dialog>

                            {/* Modal for Global Resync Wizard */}
                            <Dialog open={isResyncModalOpen} onOpenChange={setIsResyncModalOpen}>
                                <DialogContent className="sm:max-w-[425px]">
                                    <DialogHeader>
                                        <DialogTitle className="flex items-center text-blue-600">
                                            <Database className="mr-2 h-5 w-5" /> Conferma Ricalcolo Selettivo
                                        </DialogTitle>
                                        <DialogDescription className="py-4">
                                            Stai per ricalcolare lo stock di <strong>{selectedMaterialIds.length}</strong> materiali selezionati. 
                                            Verrà applicata la somma reale delle giacenze dei lotti.
                                        </DialogDescription>
                                    </DialogHeader>
                                    <Alert variant="default" className="bg-blue-50 border-blue-200 text-blue-900">
                                        <Info className="h-4 w-4" />
                                        <AlertTitle>Dettaglio Operazione</AlertTitle>
                                        <AlertDescription className="text-sm opacity-90">
                                            Il database verrà aggiornato con i valori calcolati in anteprima. 
                                            I log di sistema registreranno questa operazione come <strong>RICALCOLO SELETTIVO</strong>.
                                        </AlertDescription>
                                    </Alert>
                                    <div className="space-y-4 py-4">
                                        <p className="text-sm text-muted-foreground">Digitare <span className="font-mono font-bold">CONFERMO RICALCOLO</span>:</p>
                                        <Input placeholder="CONFERMO RICALCOLO" value={resyncConfirmText} onChange={(e) => setResyncConfirmText(e.target.value)} className="uppercase font-bold border-blue-300" />
                                    </div>
                                    <DialogFooter>
                                        <Button variant="ghost" onClick={() => setIsResyncModalOpen(false)}>Annulla</Button>
                                        <Button variant="default" className="bg-blue-600 hover:bg-blue-700" disabled={resyncConfirmText !== "CONFERMO RICALCOLO"} onClick={handleExecuteSelectiveResync}>ESEGUI RICALCOLO</Button>
                                    </DialogFooter>
                                </DialogContent>
                            </Dialog>

                            {/* --- PLAN PREVIEW TABLE --- */}
                            {syncAnomalies.length > 0 && (
                                <Card className="shadow-lg animate-in slide-in-from-top duration-500 overflow-hidden border-blue-100">
                                    <div className="bg-blue-600 text-white p-4 flex items-center justify-between">
                                        <div className="flex items-center gap-2">
                                            <Activity className="h-5 w-5" />
                                            <h3 className="font-bold">Piano di Ricalcolo Suggerito</h3>
                                        </div>
                                        <div className="flex items-center gap-4 text-xs">
                                            <div className="flex items-center gap-1">
                                                <Badge className="bg-white/20 text-white border-0">Audit: {syncAnomalies.length}</Badge>
                                            </div>
                                            <div className="flex items-center gap-1">
                                                <Badge className="bg-green-400 text-green-950 border-0">Da Correggere: {syncAnomalies.filter(a => a.needsSync).length}</Badge>
                                            </div>
                                        </div>
                                    </div>
                                    
                                    <div className="overflow-x-auto max-h-[500px]">
                                        <Table>
                                            <TableHeader className="bg-slate-50 sticky top-0 z-10">
                                                <TableRow>
                                                    <TableHead className="w-12">
                                                        <Checkbox 
                                                            checked={syncAnomalies.filter(a => a.needsSync).every(a => selectedMaterialIds.includes(a.materialId))}
                                                            onCheckedChange={toggleAllDiscrepancies}
                                                            className="border-slate-400"
                                                        />
                                                    </TableHead>
                                                    <TableHead className="font-bold">Codice Materia Prima</TableHead>
                                                    <TableHead className="text-center font-bold">UOM</TableHead>
                                                    <TableHead className="text-right font-bold">Stock Attuale (DB)</TableHead>
                                                    <TableHead className="text-right font-bold text-blue-700">Stock Calcolato (Lotti)</TableHead>
                                                    <TableHead className="text-right font-bold">Differenza (Δ)</TableHead>
                                                    <TableHead className="text-center font-bold">Stato</TableHead>
                                                </TableRow>
                                            </TableHeader>
                                            <TableBody>
                                                {syncAnomalies.map((a) => (
                                                    <TableRow key={a.materialId} className={a.needsSync ? "bg-amber-50/30" : ""}>
                                                        <TableCell>
                                                            <Checkbox 
                                                                checked={selectedMaterialIds.includes(a.materialId)}
                                                                onCheckedChange={() => toggleSelection(a.materialId)}
                                                                className="border-slate-400"
                                                            />
                                                        </TableCell>
                                                        <TableCell className="font-semibold">{a.code}</TableCell>
                                                        <TableCell className="text-center"><Badge variant="outline" className="font-mono">{a.unitOfMeasure}</Badge></TableCell>
                                                        <TableCell className="text-right font-mono">{a.currentStock.toFixed(3)}</TableCell>
                                                        <TableCell className="text-right font-mono text-blue-700 font-bold">{a.calculatedStock.toFixed(3)}</TableCell>
                                                        <TableCell className={`text-right font-mono font-bold ${a.difference > 0 ? 'text-green-600' : a.difference < 0 ? 'text-red-600' : 'text-slate-400'}`}>
                                                            {a.difference > 0 ? `+${a.difference.toFixed(3)}` : a.difference.toFixed(3)}
                                                        </TableCell>
                                                        <TableCell className="text-center">
                                                            {a.needsSync ? (
                                                                <Badge variant="destructive" className="bg-amber-500 hover:bg-amber-600 text-amber-950 flex items-center gap-1 w-fit mx-auto">
                                                                    <AlertTriangle className="h-3 w-3" /> Disallineato
                                                                </Badge>
                                                            ) : (
                                                                <Badge variant="outline" className="text-green-600 border-green-200 flex items-center gap-1 w-fit mx-auto">
                                                                    <Check className="h-3 w-3" /> Allineato
                                                                </Badge>
                                                            )}
                                                        </TableCell>
                                                    </TableRow>
                                                ))}
                                            </TableBody>
                                        </Table>
                                    </div>
                                    
                                    <div className="bg-slate-50 p-4 border-t flex items-center justify-between">
                                        <div className="flex gap-6">
                                            <div className="flex items-center gap-2 text-sm">
                                                <Scale className="h-4 w-4 text-slate-500" />
                                                <span className="text-muted-foreground whitespace-nowrap">Peso Totale Correzione:</span>
                                                <span className={`font-bold ${
                                                    syncAnomalies.filter(a => selectedMaterialIds.includes(a.materialId))
                                                        .reduce((sum, a) => sum + a.difference, 0) >= 0 ? 'text-green-600' : 'text-red-600'
                                                }`}>
                                                    {syncAnomalies.filter(a => selectedMaterialIds.includes(a.materialId))
                                                        .reduce((sum, a) => sum + a.difference, 0)
                                                        .toFixed(3)} Unità
                                                </span>
                                            </div>
                                        </div>
                                        <div className="text-xs text-muted-foreground italic">
                                            * Mostrate solo le differenze rilevanti ({'>'} 0.001)
                                        </div>
                                    </div>
                                </Card>
                            )}

                            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                                <Card className="border-l-4 border-l-amber-500 shadow-sm">
                                    <CardHeader className="pb-2">
                                        <CardTitle className="text-sm font-medium text-muted-foreground uppercase">Anomalie Trovate</CardTitle>
                                    </CardHeader>
                                    <CardContent><div className="text-3xl font-bold">{summary?.totalAnomalies || 0}</div></CardContent>
                                </Card>
                                <Card className="border-l-4 border-l-red-500 shadow-sm">
                                    <CardHeader className="pb-2">
                                        <CardTitle className="text-sm font-medium text-muted-foreground uppercase">Peso Errato</CardTitle>
                                    </CardHeader>
                                    <CardContent><div className="text-3xl font-bold">{summary?.totalErroneousWeight?.toFixed(2) || "0.00"} KG</div></CardContent>
                                </Card>
                                <Card className="border-l-4 border-l-green-500 shadow-sm">
                                    <CardHeader className="pb-2">
                                        <CardTitle className="text-sm font-medium text-muted-foreground uppercase">Peso Atteso</CardTitle>
                                    </CardHeader>
                                    <CardContent><div className="text-3xl font-bold">{summary?.totalCorrectedWeight?.toFixed(2) || "0.00"} KG</div></CardContent>
                                </Card>
                                <Card className="border-l-4 border-l-blue-500 shadow-sm">
                                    <CardHeader className="pb-2">
                                        <CardTitle className="text-sm font-medium text-muted-foreground uppercase">Δ Correzione</CardTitle>
                                    </CardHeader>
                                    <CardContent><div className="text-3xl font-bold text-blue-600">-{summary?.savedWeightKg?.toFixed(2) || "0.00"} KG</div></CardContent>
                                </Card>
                            </div>

                            {anomalies.length > 0 && (
                                <Card className="shadow-lg">
                                    <Table>
                                        <TableHeader className="bg-muted/50">
                                            <TableRow>
                                                <TableHead className="font-bold">Materia Prima</TableHead>
                                                <TableHead className="font-bold">Lotto</TableHead>
                                                <TableHead className="text-right font-bold">Peso Corrotto</TableHead>
                                                <TableHead className="text-right font-bold">Peso Corretto</TableHead>
                                            </TableRow>
                                        </TableHeader>
                                        <TableBody>
                                            {anomalies.map((a) => (
                                                <TableRow key={a.id}>
                                                    <TableCell className="font-semibold">{a.materialCode}</TableCell>
                                                    <TableCell className="font-mono text-xs">{a.lotto}</TableCell>
                                                    <TableCell className="text-right text-red-600">{a.currentWeight.toFixed(3)} KG</TableCell>
                                                    <TableCell className="text-right text-green-600">{a.expectedWeight.toFixed(3)} KG</TableCell>
                                                </TableRow>
                                            ))}
                                        </TableBody>
                                    </Table>
                                </Card>
                            )}

                            {error && (
                                <Alert variant="destructive">
                                    <AlertCircle className="h-4 w-4" />
                                    <AlertTitle>Errore</AlertTitle>
                                    <AlertDescription>{error}</AlertDescription>
                                </Alert>
                            )}

                            {!loading && anomalies.length === 0 && !error && (
                                <div className="py-20 text-center border-2 border-dashed rounded-xl opacity-60">
                                    <ShieldCheck className="h-12 w-12 mx-auto text-muted-foreground mb-4" />
                                    <p className="text-muted-foreground">Nessuna anomalia di peso rilevata.</p>
                                </div>
                            )}
                        </TabsContent>

                        {/* --- TAB 2: ZOMBIE HUNTER --- */}
                        <TabsContent value="zombie" className="space-y-6">
                            <div className="flex justify-between items-center mb-4">
                                <div>
                                    <h2 className="text-2xl font-bold flex items-center gap-2">
                                        <Ghost className="text-red-500 h-6 w-6" /> Cacciatore di Sessioni Zombie
                                    </h2>
                                    <p className="text-sm text-muted-foreground">Scansione di fasi, prelievi e operatori rimasti bloccati.</p>
                                </div>
                                <div className="flex gap-4">
                                    <Button variant="outline" onClick={handleZombieAudit} disabled={zombieLoading || zombieExecuting}>
                                        {zombieLoading ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <ShieldCheck className="mr-2 h-4 w-4" />}
                                        Analizza Zombie
                                    </Button>
                                    {zombieAnomalies.length > 0 && (
                                        <Button variant="destructive" onClick={() => setIsZombieModalOpen(true)} disabled={zombieLoading || zombieExecuting || selectedZombieIds.length === 0}>
                                            {zombieExecuting ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Skull className="mr-2 h-4 w-4" />}
                                            Forza Chiusura Zombie ({selectedZombieIds.length})
                                        </Button>
                                    )}
                                </div>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                <Card className="border-l-4 border-l-red-500"><CardContent className="pt-6"><div className="text-xs uppercase text-muted-foreground mb-1">Fasi Appese</div><div className="text-3xl font-bold">{zombieAnomalies.filter(a => a.type === 'PHASE').length}</div></CardContent></Card>
                                <Card className="border-l-4 border-l-orange-500"><CardContent className="pt-6"><div className="text-xs uppercase text-muted-foreground mb-1">Prelievi Ghost</div><div className="text-3xl font-bold">{zombieAnomalies.filter(a => a.type === 'WITHDRAWAL').length}</div></CardContent></Card>
                                <Card className="border-l-4 border-l-blue-500"><CardContent className="pt-6"><div className="text-xs uppercase text-muted-foreground mb-1">Operatori Occupati</div><div className="text-3xl font-bold">{zombieAnomalies.filter(a => a.type === 'OPERATOR').length}</div></CardContent></Card>
                            </div>

                            {zombieAnomalies.length > 0 ? (
                                <Card className="shadow-md">
                                    <Table>
                                        <TableHeader className="bg-muted/50">
                                            <TableRow>
                                                <TableHead className="w-12">
                                                    <Checkbox 
                                                        checked={zombieAnomalies.length > 0 && selectedZombieIds.length === zombieAnomalies.length}
                                                        onCheckedChange={toggleAllZombies}
                                                        className="border-slate-400"
                                                    />
                                                </TableHead>
                                                <TableHead>Tipo</TableHead>
                                                <TableHead>Riferimento</TableHead>
                                                <TableHead>Operatore</TableHead>
                                                <TableHead>Dettaglio</TableHead>
                                            </TableRow>
                                        </TableHeader>
                                        <TableBody>
                                            {zombieAnomalies.map((a) => (
                                                <TableRow key={a.id} className={selectedZombieIds.includes(a.id) ? "" : "opacity-50"}>
                                                    <TableCell>
                                                        <Checkbox 
                                                            checked={selectedZombieIds.includes(a.id)}
                                                            onCheckedChange={() => toggleZombieSelection(a.id)}
                                                            className="border-slate-400"
                                                        />
                                                    </TableCell>
                                                    <TableCell><Badge variant={a.type === 'PHASE' ? 'destructive' : a.type === 'WITHDRAWAL' ? 'secondary' : 'default'}>{a.type}</Badge></TableCell>
                                                    <TableCell className="font-medium">{a.reference}</TableCell>
                                                    <TableCell>{a.operatorName}</TableCell>
                                                    <TableCell className="text-xs text-muted-foreground">{a.details}</TableCell>
                                                </TableRow>
                                            ))}
                                        </TableBody>
                                    </Table>
                                </Card>
                            ) : !zombieLoading && (
                                <div className="py-12 text-center border-2 border-dashed rounded-xl opacity-60">
                                    <ShieldCheck className="h-12 w-12 mx-auto text-muted-foreground mb-4" />
                                    <p className="text-muted-foreground">Nessun zombie rilevato.</p>
                                </div>
                            )}

                            <Dialog open={isZombieModalOpen} onOpenChange={setIsZombieModalOpen}>
                                <DialogContent>
                                    <DialogHeader>
                                        <DialogTitle className="text-red-600 flex items-center"><Skull className="mr-2" /> Conferma Chiusura Selettiva</DialogTitle>
                                        <DialogDescription className="py-4">Procedere con la chiusura forzata di {selectedZombieIds.length} sessioni zombie selezionate?</DialogDescription>
                                    </DialogHeader>
                                    <Input value={zombieConfirmText} onChange={e => setZombieConfirmText(e.target.value)} placeholder="CONFERMO" className="uppercase font-bold" />
                                    <DialogFooter>
                                        <Button variant="ghost" onClick={() => setIsZombieModalOpen(false)}>Annulla</Button>
                                        <Button variant="destructive" disabled={zombieConfirmText !== "CONFERMO"} onClick={handleExecuteZombieHealing}>Esegui Healing</Button>
                                    </DialogFooter>
                                </DialogContent>
                            </Dialog>
                        </TabsContent>

                        {/* --- TAB 3: LOT RECOVERY --- */}
                        <TabsContent value="recovery" className="space-y-6">
                            <div className="flex justify-between items-center mb-4">
                                <div>
                                    <h2 className="text-2xl font-bold flex items-center gap-2 text-orange-600">
                                        <RotateCcw className="h-6 w-6" /> Ripristino Carico Iniziale (Bug Materiale Finito)
                                    </h2>
                                    <p className="text-sm text-muted-foreground">Recupera i lotti con carico a zero ma con scarichi storici presenti.</p>
                                </div>
                                <div className="flex gap-4">
                                    <Button variant="outline" onClick={handleBrokenAudit} disabled={brokenLoading || brokenExecuting}>
                                        {brokenLoading ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Search className="mr-2 h-4 w-4" />}
                                        Analizza Corruzione
                                    </Button>
                                    {brokenLots.length > 0 && (
                                        <Button className="bg-orange-600 hover:bg-orange-700 text-white" onClick={() => setIsBrokenModalOpen(true)} disabled={brokenLoading || brokenExecuting}>
                                            {brokenExecuting ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <RotateCcw className="mr-2 h-4 w-4" />}
                                            Ripristina Sacralità Lotti
                                        </Button>
                                    )}
                                </div>
                            </div>

                            {brokenLots.length > 0 ? (
                                <div className="space-y-4">
                                    <Alert className="border-orange-500 bg-orange-50">
                                        <Info className="h-4 w-4 text-orange-500" />
                                        <AlertTitle className="text-orange-800">Lotti da Ripristinare</AlertTitle>
                                        <AlertDescription className="text-orange-700">
                                            Sono stati trovati {brokenLots.length} lotti dove il carico iniziale è stato erroneamente sovrascritto a zero. 
                                            Il ripristino calcolerà il nuovo carico come somma di tutti gli scarichi effettuati.
                                        </AlertDescription>
                                    </Alert>

                                    <Card className="shadow-md">
                                        <Table>
                                            <TableHeader className="bg-muted/50">
                                                <TableRow>
                                                    <TableHead>Codice Materiale</TableHead>
                                                    <TableHead>Lotto Corrotto</TableHead>
                                                    <TableHead className="text-right">Carico Attuale</TableHead>
                                                    <TableHead className="text-right">Nuovo Carico (Aggregato)</TableHead>
                                                    <TableHead className="text-right">Scarichi Trovati</TableHead>
                                                </TableRow>
                                            </TableHeader>
                                            <TableBody>
                                                {brokenLots.map((a) => (
                                                    <TableRow key={a.id}>
                                                        <TableCell className="font-bold">{a.materialCode}</TableCell>
                                                        <TableCell className="font-mono text-xs">{a.lotto}</TableCell>
                                                        <TableCell className="text-right text-red-500 font-bold">{a.currentNetQuantity.toFixed(2)}</TableCell>
                                                        <TableCell className="text-right text-green-600 font-bold">{a.expectedNetQuantity.toFixed(2)}</TableCell>
                                                        <TableCell className="text-right">{a.withdrawalCount}</TableCell>
                                                    </TableRow>
                                                ))}
                                            </TableBody>
                                        </Table>
                                    </Card>
                                </div>
                            ) : !brokenLoading && (
                                <div className="py-12 text-center border-2 border-dashed rounded-xl opacity-60">
                                    <ShieldCheck className="h-12 w-12 mx-auto text-muted-foreground mb-4" />
                                    <p className="text-muted-foreground">Nessuna corruzione da 'Materiale Finito' rilevata.</p>
                                </div>
                            )}

                            <Dialog open={isBrokenModalOpen} onOpenChange={setIsBrokenModalOpen}>
                                <DialogContent>
                                    <DialogHeader>
                                        <DialogTitle className="text-orange-600 flex items-center"><RotateCcw className="mr-2" /> Ripristino Lotti</DialogTitle>
                                        <DialogDescription className="py-4">
                                            Questa azione ripristinerà il carico iniziale per {brokenLots.length} lotti. 
                                            È un'operazione di chirurgia sui dati.
                                        </DialogDescription>
                                    </DialogHeader>
                                    <div className="space-y-4 py-2">
                                        <p className="text-sm font-medium">Scrivere <span className="font-bold text-orange-600">RIPRISTINA</span> per confermare:</p>
                                        <Input value={brokenConfirmText} onChange={e => setBrokenConfirmText(e.target.value)} placeholder="RIPRISTINA" className="uppercase font-bold border-orange-300 focus-visible:ring-orange-500" />
                                    </div>
                                    <DialogFooter>
                                        <Button variant="ghost" onClick={() => setIsBrokenModalOpen(false)}>Annulla</Button>
                                        <Button className="bg-orange-600 hover:bg-orange-700 text-white" disabled={brokenConfirmText !== "RIPRISTINA"} onClick={handleExecuteBrokenHealing}>ESEGUI RIPRISTINO</Button>
                                    </DialogFooter>
                                </DialogContent>
                            </Dialog>

                            {/* Section for Level 3 Healing: Erosion Fix */}
                            <Card className="border-t-4 border-t-purple-600 shadow-md mt-12">
                                <CardHeader>
                                    <CardTitle className="text-purple-700 flex items-center gap-2">
                                        <History className="h-5 w-5" /> Sanatoria Massiva Erosione Carichi (Violazione Read-Only)
                                    </CardTitle>
                                    <CardDescription>
                                        Questo strumento identifica AUTOMATICAMENTE tutti i lotti in cui il <span className="font-bold underline italic text-orange-700">netQuantity</span> è stato eroso dai prelievi (es. il caso 242 invece di 5000) 
                                        e lo ripristina al valore originale presente nel record di carico magazzino.
                                    </CardDescription>
                                </CardHeader>
                                <CardContent className="space-y-4">
                                    <Alert variant="default" className="bg-purple-50 border-purple-200">
                                        <ShieldCheck className="h-4 w-4 text-purple-600" />
                                        <AlertTitle className="text-purple-800">Sicurezza Garantita</AlertTitle>
                                        <AlertDescription className="text-purple-700 text-xs">
                                            L'algoritmo non raddoppia i valori: se un lotto è già correttamente in Read-Only (es. 5000), verrà ignorato. 
                                            Verranno curati solo i lotti dove <span className="font-mono">Carico Originale - netQuantity {">"} 0</span>.
                                        </AlertDescription>
                                    </Alert>
                                    
                                    <div className="pt-4">
                                        <Button 
                                            className="bg-purple-600 hover:bg-purple-700 text-white w-full py-6 text-lg font-bold shadow-lg"
                                            onClick={() => setIsErosionModalOpen(true)}
                                            disabled={erosionExecuting}
                                        >
                                            {erosionExecuting ? <Loader2 className="mr-2 h-6 w-6 animate-spin" /> : <Zap className="mr-2 h-6 w-6 text-yellow-300" />}
                                            AVVIA SANATORIA MASSIVA EROSIONE
                                        </Button>
                                    </div>
                                </CardContent>
                            </Card>

                            <Dialog open={isErosionModalOpen} onOpenChange={setIsErosionModalOpen}>
                                <DialogContent className="sm:max-w-[425px]">
                                    <DialogHeader>
                                        <DialogTitle className="text-purple-600 flex items-center">
                                            <TriangleAlert className="mr-2 h-6 w-6" /> Sanatoria Massiva Erosione
                                        </DialogTitle>
                                        <DialogDescription className="py-4 font-medium text-slate-700">
                                            Attenzione: Questo script scansionerà l'intera anagrafica materiali e ripristinerà TUTTI i carichi lotti.
                                        </DialogDescription>
                                    </DialogHeader>
                                    <div className="space-y-4 py-2 border-t pt-4">
                                        <p className="text-sm">Scrivere <span className="font-bold text-purple-600">SANATORIA SACRA</span> per confermare l'esecuzione:</p>
                                        <Input 
                                            value={erosionConfirmText} 
                                            onChange={e => setErosionConfirmText(e.target.value)} 
                                            placeholder="SANATORIA SACRA" 
                                            className="uppercase font-extrabold border-purple-300 h-12 text-center text-lg" 
                                        />
                                    </div>
                                    <DialogFooter className="mt-4">
                                        <Button variant="ghost" onClick={() => setIsErosionModalOpen(false)}>Annulla</Button>
                                        <Button 
                                            className="bg-purple-600 hover:bg-purple-700 text-white font-bold" 
                                            disabled={erosionConfirmText !== "SANATORIA SACRA"} 
                                            onClick={handleExecuteErosionHealing}
                                        >
                                            ESEGUI ORA
                                        </Button>
                                    </DialogFooter>
                                </DialogContent>
                            </Dialog>
                        </TabsContent>

                        {/* --- TAB 4: GROUP UNBLOCK --- */}
                        <TabsContent value="groups" className="space-y-6">
                            <div className="flex justify-between items-center mb-4">
                                <div>
                                    <h2 className="text-2xl font-bold flex items-center gap-2 text-blue-600">
                                        <Layers className="h-6 w-6" /> Gestione Gruppi Appesi (Force Unlock)
                                    </h2>
                                    <p className="text-sm text-muted-foreground">Identifica e forza lo scioglimento di gruppi bloccati da sessioni "fantasma".</p>
                                </div>
                                <Button variant="outline" onClick={handleGroupAudit} disabled={groupLoading || groupExecuting}>
                                    {groupLoading ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Search className="mr-2 h-4 w-4" />}
                                    Analizza Blocchi Gruppo
                                </Button>
                            </div>

                            {groupBlockers.length > 0 ? (
                                <div className="grid grid-cols-1 gap-6">
                                    {groupBlockers.map((gb) => (
                                        <Card key={gb.groupId} className="overflow-hidden border-blue-200">
                                            <CardHeader className="bg-blue-50/50 pb-4">
                                                <div className="flex items-center justify-between">
                                                    <div className="flex items-center gap-3">
                                                        <div className="h-10 w-10 rounded-full bg-blue-100 flex items-center justify-center text-blue-600">
                                                            <Layers className="h-5 w-5" />
                                                        </div>
                                                        <div>
                                                            <CardTitle className="text-lg">Gruppo {gb.groupRef}</CardTitle>
                                                            <CardDescription className="font-mono text-xs">ID: {gb.groupId}</CardDescription>
                                                        </div>
                                                    </div>
                                                    <Button 
                                                        variant="destructive" 
                                                        size="sm" 
                                                        onClick={() => {
                                                            setSelectedGroupId(gb.groupId);
                                                            setGroupConfirmText("");
                                                            setIsGroupModalOpen(true);
                                                        }}
                                                        disabled={groupExecuting}
                                                    >
                                                        <Unlink className="h-4 w-4 mr-2" /> Forza Sblocco e Sciogli
                                                    </Button>
                                                </div>
                                            </CardHeader>
                                            <CardContent className="pt-4">
                                                <div className="space-y-3">
                                                    <p className="text-xs font-bold text-muted-foreground uppercase tracking-wider mb-2">Elementi Bloccanti Rilevati:</p>
                                                    {gb.blockers.map((b, idx) => (
                                                        <div key={idx} className="flex items-start gap-3 p-3 rounded-lg border bg-slate-50">
                                                            <TriangleAlert className={`h-5 w-5 mt-0.5 ${b.type === 'PHASE_OPEN' ? 'text-amber-500' : 'text-red-500'}`} />
                                                            <div>
                                                                <p className="text-sm font-semibold">
                                                                    {b.type === 'OPERATOR_JOB' && "Operatore Occupato (Lavoro)"}
                                                                    {b.type === 'OPERATOR_MATERIAL' && "Operatore Occupato (Materiale)"}
                                                                    {b.type === 'PHASE_OPEN' && "Fase Aperta (Documento)"}
                                                                </p>
                                                                <p className="text-sm text-balance">
                                                                    {b.operatorName && <span className="font-bold underline mr-1">{b.operatorName}:</span>}
                                                                    {b.details}
                                                                </p>
                                                            </div>
                                                        </div>
                                                    ))}
                                                </div>
                                            </CardContent>
                                        </Card>
                                    ))}
                                </div>
                            ) : !groupLoading && (
                                <div className="py-20 text-center border-2 border-dashed rounded-xl opacity-60">
                                    <ShieldCheck className="h-12 w-12 mx-auto text-muted-foreground mb-4" />
                                    <p className="text-muted-foreground">Nessun gruppo bloccato rilevato.</p>
                                </div>
                            )}

                            <Dialog open={isGroupModalOpen} onOpenChange={setIsGroupModalOpen}>
                                <DialogContent>
                                    <DialogHeader>
                                        <DialogTitle className="text-red-600 flex items-center gap-2">
                                            <Skull className="h-5 w-5" /> Azione Nucleare: Sblocco Gruppo
                                        </DialogTitle>
                                        <DialogDescription className="py-4">
                                            Questa azione espellerà forzatamente gli operatori dal gruppo, chiuderà le fasi nel documento e tenterà lo scioglimento. 
                                            <br /><strong>Usare solo se il gruppo è realmente "zombie".</strong>
                                        </DialogDescription>
                                    </DialogHeader>
                                    <div className="space-y-4 py-2">
                                        <p className="text-sm font-medium">Scrivere <span className="font-bold text-red-600 uppercase">SBLOCCA</span> per confermare:</p>
                                        <Input 
                                            value={groupConfirmText} 
                                            onChange={e => setGroupConfirmText(e.target.value)} 
                                            placeholder="SBLOCCA" 
                                            className="uppercase font-bold border-red-300 focus-visible:ring-red-500" 
                                        />
                                    </div>
                                    <DialogFooter>
                                        <Button variant="ghost" onClick={() => { setIsGroupModalOpen(false); setSelectedGroupId(null); }}>Annulla</Button>
                                        <Button 
                                            variant="destructive"
                                            disabled={groupConfirmText !== "SBLOCCA"} 
                                            onClick={handleExecuteGroupUnlock}
                                        >
                                            ESEGUI SBLOCCO FORZATO
                                        </Button>
                                    </DialogFooter>
                                </DialogContent>
                            </Dialog>
                        </TabsContent>
                        {/* --- TAB 5: JOB SYNC --- */}
                        <TabsContent value="jobs" className="space-y-6">
                            <Card className="border-l-4 border-l-yellow-500 shadow-lg">
                                <CardHeader>
                                    <div className="flex items-center justify-between">
                                        <div className="space-y-1">
                                            <CardTitle className="text-2xl font-bold flex items-center gap-2">
                                                <Zap className="text-yellow-500 h-6 w-6" /> Sincronizzazione Globale Impegni
                                            </CardTitle>
                                            <CardDescription className="text-md">
                                                Allinea i materiali di tutte le commesse aperte alla Distinta Base attuale e ricalcola pesi/fabbisogni.
                                            </CardDescription>
                                        </div>
                                        <Button 
                                            variant="default" 
                                            className="bg-yellow-600 hover:bg-yellow-700 h-12 px-8 text-lg font-bold" 
                                            onClick={() => setIsSyncModalOpen(true)}
                                            disabled={syncExecuting}
                                        >
                                            {syncExecuting ? <Loader2 className="mr-2 h-5 w-5 animate-spin" /> : <Zap className="mr-2 h-5 w-5" />}
                                            Ricalcola e Sincronizza Tutto
                                        </Button>
                                    </div>
                                </CardHeader>
                                <CardContent className="space-y-6">
                                    <Alert variant="default" className="bg-yellow-50 border-yellow-200">
                                        <AlertTriangle className="h-5 w-5 text-yellow-600" />
                                        <AlertTitle className="font-bold text-yellow-800">Attenzione: Azione ad Alto Impatto</AlertTitle>
                                        <AlertDescription className="text-yellow-700">
                                            Questa operazione aggiornerà i record `billOfMaterials` di tutte le commesse in stato 'Pianificato' o 'In Produzione'. 
                                            <ul className="list-disc list-inside mt-2 space-y-1">
                                                <li>Ricalcola esplicitamente il <strong>Fabbisogno Totale</strong> (mm {'->'} mt).</li>
                                                <li>Ricalcola il <strong>Peso Stimato (KG)</strong> usando il fattore di conversione attuale.</li>
                                                <li>Aggiunge componenti mancanti dalla Distinta Base principale.</li>
                                                <li>Rimuove componenti obsoleti (solo se non ancora prelevati).</li>
                                            </ul>
                                        </AlertDescription>
                                    </Alert>

                                    <div className="bg-slate-50 p-6 rounded-lg border border-slate-200">
                                        <h4 className="font-bold mb-4 flex items-center gap-2"><Info className="h-4 w-4" /> Quando usare questo strumento?</h4>
                                        <p className="text-sm text-muted-foreground leading-relaxed">
                                            Usa questa funzione se noti che le commesse aperte mostrano pesi o quantità errate a causa di modifiche fatte in Anagrafica Articoli o Materiali dopo la creazione della commessa.
                                            Questo script "guarisce" lo snapshot della commessa forzando i valori attuali.
                                        </p>
                                    </div>

                                    {syncResults && (
                                        <div className="space-y-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
                                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                                <Card className="bg-green-50 border-green-200">
                                                    <CardHeader className="py-3">
                                                        <CardTitle className="text-sm text-green-800 flex items-center gap-2">
                                                            <CheckCircle2 className="h-4 w-4" /> Commesse Sincronizzate
                                                        </CardTitle>
                                                    </CardHeader>
                                                    <CardContent>
                                                        <div className="text-2xl font-bold text-green-700">{syncResults.processed}</div>
                                                    </CardContent>
                                                </Card>
                                                <Card className={syncResults.failed > 0 ? "bg-red-50 border-red-200" : "bg-slate-50 border-slate-200 opacity-50"}>
                                                    <CardHeader className="py-3">
                                                        <CardTitle className={`text-sm flex items-center gap-2 ${syncResults.failed > 0 ? "text-red-800" : "text-slate-600"}`}>
                                                            <AlertCircle className="h-4 w-4" /> Errori / Saltate
                                                        </CardTitle>
                                                    </CardHeader>
                                                    <CardContent>
                                                        <div className={`text-2xl font-bold ${syncResults.failed > 0 ? "text-red-700" : "text-slate-600"}`}>{syncResults.failed}</div>
                                                    </CardContent>
                                                </Card>
                                            </div>

                                            {syncResults.errors.length > 0 && (
                                                <Card className="border-red-200">
                                                    <CardHeader className="bg-red-50 py-2">
                                                        <CardTitle className="text-xs font-bold text-red-800 uppercase tracking-wider">Log Errori Dettagliato</CardTitle>
                                                    </CardHeader>
                                                    <CardContent className="p-0">
                                                        <div className="max-h-60 overflow-y-auto font-mono text-[10px] p-4 space-y-1 bg-slate-900 text-red-400">
                                                            {syncResults.errors.map((err, idx) => (
                                                                <div key={idx} className="flex gap-2">
                                                                    <span className="opacity-50">[{idx + 1}]</span>
                                                                    <span>{err}</span>
                                                                </div>
                                                            ))}
                                                        </div>
                                                    </CardContent>
                                                </Card>
                                            )}
                                        </div>
                                    )}
                                </CardContent>
                            </Card>

                            <Dialog open={isSyncModalOpen} onOpenChange={setIsSyncModalOpen}>
                                <DialogContent className="sm:max-w-md">
                                    <DialogHeader>
                                        <DialogTitle className="flex items-center gap-2 text-yellow-600">
                                            <AlertTriangle className="h-5 w-5" /> Conferma Sincronizzazione Globale
                                        </DialogTitle>
                                        <DialogDescription className="py-2">
                                            Stai per sovrascrivere gli impegni di tutte le commesse attive nel sistema. 
                                            Assicurati che nessuno stia effettuando prelievi in questo istante.
                                        </DialogDescription>
                                    </DialogHeader>
                                    <div className="space-y-4 py-4">
                                        <p className="text-sm font-medium">Scrivi <span className="font-mono font-bold text-yellow-600">SINCRONIZZA</span> per approvare:</p>
                                        <Input 
                                            value={syncConfirmText} 
                                            onChange={e => setSyncConfirmText(e.target.value)} 
                                            placeholder="SINCRONIZZA" 
                                            className="uppercase font-bold border-yellow-300 focus-visible:ring-yellow-500"
                                        />
                                    </div>
                                    <DialogFooter>
                                        <Button variant="ghost" onClick={() => setIsSyncModalOpen(false)}>Annulla</Button>
                                        <Button 
                                            variant="default" 
                                            className="bg-yellow-600 hover:bg-yellow-700" 
                                            disabled={syncConfirmText !== "SINCRONIZZA" || syncExecuting}
                                            onClick={handleExecuteJobSync}
                                        >
                                            AVVIA RICALCOLO
                                        </Button>
                                    </DialogFooter>
                                </DialogContent>
                            </Dialog>
                        </TabsContent>
                    </Tabs>
                </div>
            </AppShell>
        </AdminAuthGuard>
    );
}

"use client";

import React, { useState, useEffect, useTransition } from 'react';
import * as z from 'zod';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { useToast } from '@/hooks/use-toast';

import { type Department } from '@/types';
import { getDepartments, saveDepartment, deleteDepartments } from './actions';

import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Checkbox } from '@/components/ui/checkbox';
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from "@/components/ui/alert-dialog";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Input } from '@/components/ui/input';
import { ListTodo, PlusCircle, Edit, Trash2, Loader2 } from 'lucide-react';
import AdminAuthGuard from '@/components/AdminAuthGuard';
import AppShell from '@/components/layout/AppShell';

import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Switch } from '@/components/ui/switch';
import { Badge } from '@/components/ui/badge';

const departmentSchema = z.object({
  id: z.string().optional(),
  code: z.string().min(1, "Il codice è obbligatorio.").max(10, "Il codice non può superare i 10 caratteri."),
  name: z.string().min(3, "Il nome deve avere almeno 3 caratteri."),
  macroAreas: z.array(z.enum(['PREPARAZIONE', 'PRODUZIONE', 'QLTY_PACK'])).min(1, "Seleziona almeno una macro area."),
  dependsOnPreparation: z.boolean().default(false),
});

type DepartmentFormValues = z.infer<typeof departmentSchema>;

export default function DepartmentManagementPage() {
  const [departments, setDepartments] = useState<Department[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingDepartment, setEditingDepartment] = useState<Department | null>(null);
  const [selectedRows, setSelectedRows] = useState<string[]>([]);
  const [isPending, setIsPending] = useState(false);
  const { toast } = useToast();

  const form = useForm<DepartmentFormValues>({
    resolver: zodResolver(departmentSchema),
    defaultValues: { 
      id: undefined, 
      code: "", 
      name: "", 
      macroAreas: ['PRODUZIONE'], 
      dependsOnPreparation: false 
    },
  });

  const fetchData = async () => {
    setIsLoading(true);
    const data = await getDepartments();
    setDepartments(data);
    setIsLoading(false);
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleOpenDialog = (department: Department | null = null) => {
    setEditingDepartment(department);
    if (department) {
      form.reset({
        id: department.id,
        code: department.code,
        name: department.name,
        macroAreas: department.macroAreas || [],
        dependsOnPreparation: !!department.dependsOnPreparation
      });
    } else {
      form.reset({ 
        id: undefined, 
        code: "", 
        name: "", 
        macroAreas: ['PRODUZIONE'], 
        dependsOnPreparation: false 
      });
    }
    setIsDialogOpen(true);
  };

  const handleCloseDialog = () => {
    setIsDialogOpen(false);
    setEditingDepartment(null);
    form.reset();
  };

  const onSubmit = async (values: DepartmentFormValues) => {
    const formData = new FormData();
    formData.append('id', values.id || "");
    formData.append('code', values.code);
    formData.append('name', values.name);
    values.macroAreas.forEach(area => formData.append('macroAreas', area));
    if (values.dependsOnPreparation) formData.append('dependsOnPreparation', 'on');

    setIsPending(true);
    const result = await saveDepartment(formData);
    toast({
      title: result.success ? "Successo" : "Errore",
      description: result.message,
      variant: result.success ? "default" : "destructive",
    });

    if (result.success) {
      await fetchData();
      handleCloseDialog();
    }
    setIsPending(false);
  };

  const handleDeleteSelected = async () => {
    setIsPending(true);
    const result = await deleteDepartments(selectedRows);
    toast({
      title: result.success ? "Successo" : "Errore",
      description: result.message,
      variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
      await fetchData();
      setSelectedRows([]);
    }
    setIsPending(false);
  };

  const handleSelectAll = (checked: boolean | 'indeterminate') => {
    setSelectedRows(checked === true ? departments.map(d => d.id) : []);
  };

  const handleSelectRow = (id: string) => {
    setSelectedRows(prev => prev.includes(id) ? prev.filter(rowId => rowId !== id) : [...prev, id]);
  };

  const renderLoading = () => (
      <TableRow>
          <TableCell colSpan={5} className="h-24 text-center">
              <div className="flex items-center justify-center gap-2 text-muted-foreground">
                  <Loader2 className="h-5 w-5 animate-spin" />
                  <span>Caricamento reparti...</span>
              </div>
          </TableCell>
      </TableRow>
  );

  return (
    <AdminAuthGuard>
      <AppShell>
        <div className="space-y-6">
          <div className="flex justify-between items-center">
            <header>
              <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
                <ListTodo className="h-8 w-8 text-primary" />
                Gestione Reparti
              </h1>
              <p className="text-muted-foreground mt-2">
                Aggiungi, modifica o elimina i reparti produttivi e di servizio.
              </p>
            </header>
            <div className="flex items-center gap-2">
                {selectedRows.length > 0 && (
                  <AlertDialog>
                    <AlertDialogTrigger asChild>
                      <Button variant="destructive" disabled={isPending}>
                        {isPending ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <Trash2 className="mr-2 h-4 w-4" />}
                        Elimina ({selectedRows.length})
                      </Button>
                    </AlertDialogTrigger>
                    <AlertDialogContent>
                      <AlertDialogHeader>
                        <AlertDialogTitle>Sei sicuro?</AlertDialogTitle>
                        <AlertDialogDescription>
                          L'eliminazione di un reparto potrebbe causare problemi se è associato a operatori o fasi. Sei sicuro di voler eliminare {selectedRows.length} reparti?
                        </AlertDialogDescription>
                      </AlertDialogHeader>
                      <AlertDialogFooter>
                        <AlertDialogCancel>Annulla</AlertDialogCancel>
                        <AlertDialogAction onClick={handleDeleteSelected}>Continua</AlertDialogAction>
                      </AlertDialogFooter>
                    </AlertDialogContent>
                  </AlertDialog>
                )}
                <Button onClick={() => handleOpenDialog()} disabled={isLoading}>
                    <PlusCircle className="mr-2 h-4 w-4" />
                    Nuovo Reparto
                </Button>
            </div>
          </div>

          <Card>
            <CardHeader>
              <CardTitle>Elenco Reparti</CardTitle>
              <CardDescription>Questi reparti saranno selezionabili nella gestione degli operatori e delle fasi.</CardDescription>
            </CardHeader>
            <CardContent>
              <div className="overflow-x-auto">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead padding="checkbox">
                        <Checkbox
                          checked={!isLoading && selectedRows.length > 0 && selectedRows.length === departments.length ? true : !isLoading && selectedRows.length > 0 ? 'indeterminate' : false}
                          onCheckedChange={handleSelectAll}
                          aria-label="Seleziona tutti"
                          disabled={isLoading || departments.length === 0}
                        />
                      </TableHead>
                      <TableHead>Codice</TableHead>
                      <TableHead>Nome Reparto</TableHead>
                      <TableHead>Macro Area</TableHead>
                      <TableHead>Dip. Prep.</TableHead>
                      <TableHead className="text-right">Azioni</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {isLoading ? renderLoading() : departments.length > 0 ? (
                      departments.map((dept) => (
                        <TableRow key={dept.id} data-state={selectedRows.includes(dept.id) && "selected"}>
                          <TableCell padding="checkbox">
                            <Checkbox
                              checked={selectedRows.includes(dept.id)}
                              onCheckedChange={() => handleSelectRow(dept.id)}
                              aria-label={`Seleziona il reparto ${dept.name}`}
                            />
                          </TableCell>
                          <TableCell className="font-mono">{dept.code}</TableCell>
                          <TableCell className="font-medium">{dept.name}</TableCell>
                          <TableCell>
                            <div className="flex flex-wrap gap-1">
                              {dept.macroAreas?.map((area: string) => (
                                <Badge key={area} variant={area === 'PRODUZIONE' ? 'default' : area === 'PREPARAZIONE' ? 'secondary' : 'outline'}>
                                  {area}
                                </Badge>
                              ))}
                            </div>
                          </TableCell>
                          <TableCell>
                            {dept.dependsOnPreparation ? (
                              <Badge variant="warning">SI</Badge>
                            ) : (
                              <span className="text-muted-foreground text-xs">-</span>
                            )}
                          </TableCell>
                          <TableCell className="text-right">
                            <Button variant="outline" size="icon" onClick={() => handleOpenDialog(dept)}>
                              <Edit className="h-4 w-4" />
                            </Button>
                          </TableCell>
                        </TableRow>
                      ))
                    ) : (
                      <TableRow>
                        <TableCell colSpan={6} className="text-center h-24">Nessun reparto trovato.</TableCell>
                      </TableRow>
                    )}
                  </TableBody>
                </Table>
              </div>
            </CardContent>
          </Card>
        
        <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
          <DialogContent className="sm:max-w-md" onInteractOutside={(e) => {if (!isPending) handleCloseDialog();}}>
            <DialogHeader>
              <DialogTitle>{editingDepartment ? "Modifica Reparto" : "Aggiungi Nuovo Reparto"}</DialogTitle>
              <DialogDescription>
                Compila i campi per definire un nuovo reparto aziendale.
              </DialogDescription>
            </DialogHeader>
            <Form {...form}>
              <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4 py-4">
                <FormField control={form.control} name="code" render={({ field }) => (
                  <FormItem>
                    <FormLabel>Codice</FormLabel>
                    <FormControl><Input placeholder="Es. CP, MAG" {...field} disabled={!!editingDepartment} /></FormControl>
                    <FormMessage />
                  </FormItem>
                )} />
                <FormField control={form.control} name="name" render={({ field }) => (
                  <FormItem>
                    <FormLabel>Nome</FormLabel>
                    <FormControl><Input placeholder="Es. Controllo Qualità" {...field} /></FormControl>
                    <FormMessage />
                  </FormItem>
                )} />

                <FormItem>
                  <FormLabel>Macro Aree Pianificazione</FormLabel>
                  <div className="grid grid-cols-2 gap-2 rounded-lg border p-4 bg-muted/20">
                    {['PREPARAZIONE', 'PRODUZIONE', 'QLTY_PACK'].map((area) => (
                      <FormField
                        key={area}
                        control={form.control}
                        name="macroAreas"
                        render={({ field }) => {
                          const isChecked = field.value?.includes(area as any);
                          return (
                            <FormItem key={area} className="flex flex-row items-center space-x-3 space-y-0">
                              <FormControl>
                                <Checkbox
                                  checked={isChecked}
                                  onCheckedChange={(checked) => {
                                    const currentValues = field.value || [];
                                    const nextValues = checked
                                      ? [...currentValues, area as any]
                                      : currentValues.filter((v) => v !== area);
                                    field.onChange(nextValues);
                                  }}
                                />
                              </FormControl>
                              <FormLabel className="text-xs font-medium cursor-pointer uppercase">
                                {area === 'QLTY_PACK' ? 'QUALITÀ & PACK' : area}
                              </FormLabel>
                            </FormItem>
                          );
                        }}
                      />
                    ))}
                  </div>
                  <FormMessage />
                </FormItem>

                {!(form.watch('macroAreas') || []).includes('PREPARAZIONE') && (
                  <FormField
                    control={form.control}
                    name="dependsOnPreparation"
                    render={({ field }) => (
                      <FormItem className="flex flex-row items-center justify-between rounded-lg border p-3 shadow-sm text-sm">
                        <div className="space-y-0.5">
                          <FormLabel>Dipende da Preparazione</FormLabel>
                          <div className="text-[0.7rem] text-muted-foreground">
                            Se attivo, la produzione non può iniziare finché la preparazione non è conclusa.
                          </div>
                        </div>
                        <FormControl>
                          <Switch
                            checked={field.value}
                            onCheckedChange={field.onChange}
                          />
                        </FormControl>
                      </FormItem>
                    )}
                  />
                )}

                <DialogFooter>
                  <Button type="button" variant="outline" onClick={handleCloseDialog} disabled={isPending}>Annulla</Button>
                  <Button type="submit" disabled={isPending}>
                    {isPending ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : null}
                    {editingDepartment ? "Salva Modifiche" : "Crea Reparto"}
                  </Button>
                </DialogFooter>
              </form>
            </Form>
          </DialogContent>
        </Dialog>
      </div>
    </AppShell>
  </AdminAuthGuard>
  );
}

"use client";

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import * as XLSX from 'xlsx';
import { format, parseISO } from 'date-fns';
import { it } from 'date-fns/locale';
import Link from 'next/link';

import { Card, CardHeader, CardTitle, CardDescription, CardContent, CardFooter } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "@/components/ui/accordion"
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from "@/components/ui/collapsible"
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from '@/components/ui/badge';
import { Warehouse, Download, Check, X, Pencil, Loader2, Package, Undo2, Trash2, LinkIcon, Search, ChevronDown, ShieldCheck, ShieldX, RefreshCw } from 'lucide-react';
import { type InventoryRecord, type RawMaterial } from '@/types';
import { approveInventoryRecord, rejectInventoryRecord, revertInventoryRecordStatus, deleteInventoryRecords, approveMultipleInventoryRecords, rejectMultipleInventoryRecords, getMaterialById } from './actions';
import { useAuth } from '@/components/auth/AuthProvider';
import { useToast } from '@/hooks/use-toast';
import { useRouter } from 'next/navigation';
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from '@/components/ui/alert-dialog';
import InventoryRecordSheet from './InventoryRecordSheet';
import { Checkbox } from '@/components/ui/checkbox';
import { Input } from '@/components/ui/input';
import { cn } from '@/lib/utils';
import { Skeleton } from '@/components/ui/skeleton';
import { formatDisplayStock } from '@/lib/utils';



interface InventoryClientPageProps {
  initialRecords: InventoryRecord[];
}

const statusOrder: Record<InventoryRecord['status'], number> = {
  pending: 0,
  approved: 1,
  rejected: 2,
};

export default function InventoryClientPage({ initialRecords }: InventoryClientPageProps) {
  const [records, setRecords] = useState(initialRecords);
  const [selectedRecord, setSelectedRecord] = useState<InventoryRecord | null>(null);
  const [isSheetOpen, setIsSheetOpen] = useState(false);
  const [isPending, setIsPending] = useState<string | null>(null);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [selectedRecords, setSelectedRecords] = useState<string[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  
  const { user } = useAuth();
  const { toast } = useToast();
  const router = useRouter();

  useEffect(() => {
    setRecords(initialRecords);
    setSelectedRecords([]);
  }, [initialRecords]);


  const filteredRecordsBySearch = useMemo(() => {
    return searchTerm
      ? records.filter(record => 
          record.materialCode.toLowerCase().includes(searchTerm.toLowerCase()) ||
          record.lotto.toLowerCase().includes(searchTerm.toLowerCase()) ||
          (record.operatorName || '').toLowerCase().includes(searchTerm.toLowerCase())
        )
      : records;
  }, [records, searchTerm]);

  const groupedRecords = useMemo(() => {
    return filteredRecordsBySearch.reduce((acc, record) => {
      const date = format(parseISO(record.recordedAt as unknown as string), 'dd.MM.yyyy');
      if (!acc[date]) {
        acc[date] = {};
      }
      const materialCode = record.materialCode;
       if (!acc[date][materialCode]) {
        acc[date][materialCode] = [];
      }
      acc[date][materialCode].push(record);
      return acc;
    }, {} as Record<string, Record<string, InventoryRecord[]>>);
  }, [filteredRecordsBySearch]);

  const sortedDates = useMemo(() => Object.keys(groupedRecords).sort((a, b) => {
    const [dayA, monthA, yearA] = a.split('.').map(Number);
    const [dayB, monthB, yearB] = b.split('.').map(Number);
    return new Date(yearB, monthB - 1, dayB).getTime() - new Date(yearA, monthA - 1, dayA).getTime();
  }), [groupedRecords]);
  
  const refreshData = () => {
    setIsRefreshing(true);
    router.refresh();
    // The useEffect listening to initialRecords will update the state.
    // We can set a timeout to turn off the loading indicator after a bit.
    setTimeout(() => setIsRefreshing(false), 1000);
  };

  const handleApprove = async (recordId: string) => {
    if (!user) return;
    setIsPending(recordId);
    const result = await approveInventoryRecord(recordId, user.uid);
    toast({
        title: result.success ? "Approvato!" : "Errore",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
      refreshData();
    }
    setIsPending(null);
  };
  
  const handleReject = async (recordId: string) => {
    if (!user) return;
    setIsPending(recordId);
    const result = await rejectInventoryRecord(recordId, user.uid);
    toast({
        title: result.success ? "Rifiutato" : "Errore",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });
     if (result.success) {
      refreshData();
    }
    setIsPending(null);
  };

  const handleRevertStatus = async (recordId: string) => {
    if (!user) return;
    setIsPending(recordId);
    const result = await revertInventoryRecordStatus(recordId, user.uid);
    toast({
        title: result.success ? "Annullato" : "Errore",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
      refreshData();
    }
    setIsPending(null);
  };

  const handleOpenSheet = (record: InventoryRecord) => {
    setSelectedRecord(record);
    setIsSheetOpen(true);
  };

  const handleExport = (date: string, dailyRecords: Record<string, InventoryRecord[]>) => {
    const dataToExport = Object.values(dailyRecords).flat().map(r => {
      const qtaN = r.materialUnitOfMeasure === 'n' ? (r.inputUnit === 'n' ? r.inputQuantity : r.netWeight / (r.conversionFactor || 1)) : 0;
      const qtaMT = (r.materialUnitOfMeasure === 'mt' || r.rapportoKgMt) ? (r.inputUnit === 'mt' ? r.inputQuantity : r.netWeight / (r.rapportoKgMt || 1)) : 0;
      
      return {
        'Codice': r.materialCode,
        'Lotto': r.lotto,
        'Quantità (N)': qtaN > 0 ? Number(qtaN.toFixed(2)) : 0,
        'Quantità (MT)': qtaMT > 0 ? Number(qtaMT.toFixed(2)) : 0,
        'Quantità (KG)': r.netWeight,
        'Peso Lordo (kg)': r.grossWeight,
        'Peso Tara (kg)': r.tareWeight,
        'Peso Netto (kg)': r.netWeight,
        'Operatore': r.operatorName,
        'Data Registrazione': format(parseISO(r.recordedAt as unknown as string), 'dd/MM/yyyy HH:mm'),
        'Stato': r.status,
      };
    });
    const ws = XLSX.utils.json_to_sheet(dataToExport);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, `Inventario ${date}`);
    XLSX.writeFile(wb, `inventario_${date.replace(/\./g, '-')}.xlsx`);
  };

  const handleSelectAll = (checked: boolean) => {
    if (checked) {
      setSelectedRecords(filteredRecordsBySearch.map(r => r.id));
    } else {
      setSelectedRecords([]);
    }
  };

  const handleSelectRecord = (recordId: string) => {
    setSelectedRecords(prev => 
      prev.includes(recordId) 
        ? prev.filter(id => id !== recordId) 
        : [...prev, recordId]
    );
  };

  const handleDeleteSelected = async () => {
    if (selectedRecords.length === 0 || !user) return;
    setIsPending('delete-selected');
    const result = await deleteInventoryRecords(selectedRecords, user.uid);
    toast({
      title: result.success ? "Eliminazione Completata" : "Errore",
      description: result.message,
      variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
      refreshData();
    }
    setIsPending(null);
  };

  const handleApproveSelected = async () => {
    if (selectedRecords.length === 0 || !user) return;
    setIsPending('approve-selected');
    const result = await approveMultipleInventoryRecords(selectedRecords, user.uid);
     toast({
      title: result.success ? "Operazione Completata" : "Errore",
      description: result.message,
      variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
      refreshData();
    }
    setIsPending(null);
  };

  const handleRejectSelected = async () => {
     if (selectedRecords.length === 0 || !user) return;
    setIsPending('reject-selected');
    const result = await rejectMultipleInventoryRecords(selectedRecords, user.uid);
     toast({
      title: result.success ? "Operazione Completata" : "Errore",
      description: result.message,
      variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
      refreshData();
    }
    setIsPending(null);
  };


  return (
    <>
      <div className="space-y-8">
        <header className="space-y-2">
            <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
                <Warehouse className="h-8 w-8 text-primary" />
                Gestione Inventari
            </h1>
            <p className="text-muted-foreground">
                Visualizza, approva o rifiuta le registrazioni di inventario effettuate dagli operatori.
            </p>
        </header>
        
        <Card>
            <CardHeader>
              <div className="flex justify-between items-center flex-wrap gap-4">
                  <div>
                    <CardTitle>Registrazioni da Processare</CardTitle>
                    <CardDescription>
                        Elenco delle registrazioni di inventario raggruppate per data.
                    </CardDescription>
                  </div>
                   <div className="flex items-center gap-2 flex-wrap">
                       <Button onClick={refreshData} variant="outline" size="sm" disabled={isRefreshing}>
                           {isRefreshing ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <RefreshCw className="mr-2 h-4 w-4"/>}
                           Aggiorna Dati
                       </Button>
                      {selectedRecords.length > 0 && (
                        <div className="flex items-center gap-2">
                          <AlertDialog>
                            <AlertDialogTrigger asChild>
                              <Button variant="destructive" size="sm" disabled={isPending === 'delete-selected'}>
                                {isPending === 'delete-selected' ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <Trash2 className="mr-2 h-4 w-4" />}
                                Elimina ({selectedRecords.length})
                              </Button>
                            </AlertDialogTrigger>
                             <AlertDialogContent>
                                <AlertDialogHeader><AlertDialogTitle>Sei sicuro di voler eliminare?</AlertDialogTitle><AlertDialogDescription>Stai per eliminare {selectedRecords.length} registrazioni. Se sono state approvate, lo stock verrà stornato. Questa operazione è irreversibile.</AlertDialogDescription></AlertDialogHeader>
                                <AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={handleDeleteSelected} className="bg-destructive hover:bg-destructive/90">Sì, elimina</AlertDialogAction></AlertDialogFooter>
                              </AlertDialogContent>
                          </AlertDialog>
                           <AlertDialog>
                            <AlertDialogTrigger asChild>
                               <Button size="sm" variant="outline" className="border-amber-500 text-amber-500 hover:bg-amber-500/10 hover:text-amber-600" disabled={isPending === 'reject-selected'}>
                                {isPending === 'reject-selected' ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <ShieldX className="mr-2 h-4 w-4" />}
                                Rifiuta ({selectedRecords.length})
                              </Button>
                            </AlertDialogTrigger>
                             <AlertDialogContent>
                                <AlertDialogHeader><AlertDialogTitle>Confermi di rifiutare?</AlertDialogTitle><AlertDialogDescription>Stai per rifiutare {selectedRecords.length} registrazioni. Verranno marcate come "rifiutate".</AlertDialogDescription></AlertDialogHeader>
                                <AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={handleRejectSelected}>Sì, rifiuta</AlertDialogAction></AlertDialogFooter>
                              </AlertDialogContent>
                          </AlertDialog>
                           <AlertDialog>
                            <AlertDialogTrigger asChild>
                              <Button size="sm" className="bg-green-600 hover:bg-green-700 text-white" disabled={isPending === 'approve-selected'}>
                                {isPending === 'approve-selected' ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <ShieldCheck className="mr-2 h-4 w-4" />}
                                Approva ({selectedRecords.length})
                              </Button>
                            </AlertDialogTrigger>
                            <AlertDialogContent>
                                <AlertDialogHeader><AlertDialogTitle>Confermi di approvare?</AlertDialogTitle><AlertDialogDescription>Stai per approvare {selectedRecords.length} registrazioni. Lo stock dei materiali verrà aggiornato. L'azione non è reversibile.</AlertDialogDescription></AlertDialogHeader>
                                <AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={handleApproveSelected} className="bg-green-600 hover:bg-green-700">Sì, approva</AlertDialogAction></AlertDialogFooter>
                              </AlertDialogContent>
                          </AlertDialog>
                        </div>
                      )}
                      <div className="relative w-full sm:w-64">
                         <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                          <Input
                              placeholder="Cerca per lotto, codice, operatore..."
                              className="pl-9"
                              value={searchTerm}
                              onChange={(e) => setSearchTerm(e.target.value)}
                          />
                      </div>
                   </div>
              </div>
            </CardHeader>
            <CardContent>
              <div className="flex items-center gap-2 mb-4">
                  <Checkbox
                      id="select-all-records"
                      checked={filteredRecordsBySearch.length > 0 && selectedRecords.length === filteredRecordsBySearch.length}
                      onCheckedChange={handleSelectAll}
                  />
                  <label htmlFor="select-all-records" className="text-sm font-medium">Seleziona Tutto ({selectedRecords.length} / {filteredRecordsBySearch.length})</label>
              </div>
              {sortedDates.length > 0 ? (
                <Accordion type="multiple" className="w-full">
                  {sortedDates.map(date => {
                    const dailyRecordsByMaterial = groupedRecords[date];
                    const allDailyRecords = Object.values(dailyRecordsByMaterial).flat();
                    const pendingRecordsCount = allDailyRecords.filter(r => r.status === 'pending').length;
                    
                    return (
                      <AccordionItem value={date} key={date}>
                        <AccordionTrigger>
                          <div className="flex justify-between items-center w-full pr-4">
                            <span className="font-semibold text-lg">Inventario del {date}</span>
                            <Badge variant={pendingRecordsCount > 0 ? "destructive" : "default"}>
                              {pendingRecordsCount} in attesa
                            </Badge>
                          </div>
                        </AccordionTrigger>
                        <AccordionContent>
                          <div className="p-4 bg-muted/50 rounded-lg">
                            <div className="flex justify-between items-center mb-4">
                                <div className="flex items-center gap-2">
                                  <Checkbox
                                    id={`select-all-${date}`}
                                    checked={allDailyRecords.length > 0 && allDailyRecords.every(r => selectedRecords.includes(r.id))}
                                    onCheckedChange={(checked) => {
                                        const dailyIds = allDailyRecords.map(r => r.id);
                                        if (checked) {
                                            setSelectedRecords(prev => [...new Set([...prev, ...dailyIds])]);
                                        } else {
                                            setSelectedRecords(prev => prev.filter(id => !dailyIds.includes(id)));
                                        }
                                    }}
                                  />
                                  <label htmlFor={`select-all-${date}`} className="text-sm font-medium">Seleziona Tutto nel Giorno</label>
                                </div>
                                <Button variant="outline" size="sm" onClick={() => handleExport(date, dailyRecordsByMaterial)}>
                                  <Download className="mr-2 h-4 w-4" />
                                  Scarica Inventario del Giorno
                                </Button>
                            </div>
                            <div className="space-y-6">
                              {Object.entries(dailyRecordsByMaterial).sort(([codeA, recordsA], [codeB, recordsB]) => {
                                const aHasPending = recordsA.some(r => r.status === 'pending');
                                const bHasPending = recordsB.some(r => r.status === 'pending');
                                if (aHasPending && !bHasPending) return -1;
                                if (!aHasPending && bHasPending) return 1;
                                return codeA.localeCompare(codeB);
                              }).map(([materialCode, recordsForMaterial]) => {
                                const sortedRecords = [...recordsForMaterial].sort((a,b) => statusOrder[a.status] - statusOrder[b.status]);
                                const materialSample = recordsForMaterial[0]; // Use a sample record to get material info
                                
                                return (
                                <Collapsible key={materialCode} defaultOpen={recordsForMaterial.some(r => r.status === 'pending')}>
                                  <CollapsibleTrigger className="w-full">
                                      <div className="font-semibold text-md mb-2 flex items-center justify-between gap-2 hover:bg-background p-2 rounded-md group">
                                          <div className="flex items-center gap-2">
                                            <Package className="h-5 w-5 text-muted-foreground"/>
                                            <Link href={`/admin/raw-material-management?code=${encodeURIComponent(materialCode)}`} className="hover:text-primary hover:underline">
                                                {materialCode}
                                            </Link>
                                            <LinkIcon className="h-4 w-4 text-muted-foreground" />
                                          </div>
                                          <div className="flex items-center gap-2">
                                            {recordsForMaterial.some(r => r.status === 'pending') && <Badge variant="destructive">In Attesa</Badge>}
                                            <ChevronDown className="h-4 w-4 transition-transform duration-200 group-data-[state=open]:rotate-180" />
                                          </div>
                                      </div>
                                  </CollapsibleTrigger>
                                  <CollapsibleContent>
                                      <div className="overflow-x-auto border rounded-lg">
                                        <Table>
                                          <TableHeader>
                                            <TableRow>
                                               <TableHead padding="checkbox">
                                                <Checkbox
                                                  checked={recordsForMaterial.length > 0 && recordsForMaterial.every(r => selectedRecords.includes(r.id))}
                                                  onCheckedChange={(checked) => {
                                                    const recordIds = recordsForMaterial.map(r => r.id);
                                                    if (checked) {
                                                      setSelectedRecords(prev => [...new Set([...prev, ...recordIds])]);
                                                    } else {
                                                      setSelectedRecords(prev => prev.filter(id => !recordIds.includes(id)));
                                                    }
                                                  }}
                                                />
                                              </TableHead>
                                              <TableHead>Lotto</TableHead>
                                              <TableHead>Qtà (N)</TableHead>
                                              <TableHead>Qtà (MT)</TableHead>
                                              <TableHead>Qtà (KG)</TableHead>
                                              <TableHead>Peso Lordo</TableHead>
                                              <TableHead>Tara</TableHead>
                                              <TableHead>Peso Netto</TableHead>
                                              <TableHead>Operatore</TableHead>
                                              <TableHead>Stato</TableHead>
                                              <TableHead className="text-right">Azioni</TableHead>
                                            </TableRow>
                                          </TableHeader>
                                          <TableBody>
                                            {sortedRecords.map(record => {
                                                if (!record.materialUnitOfMeasure) {
                                                  return (
                                                    <TableRow key={record.id}>
                                                      <TableCell colSpan={11}>
                                                        <div className="flex items-center gap-2">
                                                          <Skeleton className="h-4 w-4 rounded-full" />
                                                          <Skeleton className="h-4 w-24" />
                                                        </div>
                                                      </TableCell>
                                                    </TableRow>
                                                  );
                                                }

                                                let qtaN = '-';
                                                let qtaMT = '-';
                                                let qtaKG = formatDisplayStock(record.netWeight, 'kg');

                                                if (record.materialUnitOfMeasure === 'n') {
                                                    const val = record.inputUnit === 'n' ? record.inputQuantity : record.netWeight / (record.conversionFactor || 1);
                                                    qtaN = formatDisplayStock(val, 'n');
                                                } else if (record.materialUnitOfMeasure === 'mt') {
                                                    const val = record.inputUnit === 'mt' ? record.inputQuantity : record.netWeight / (record.rapportoKgMt || 1);
                                                    qtaMT = formatDisplayStock(val, 'mt');
                                                }
                                                
                                                // High Contrast Fix: if it's a BOB (kg) but has rapportKgMt, show MT too
                                                if (record.materialUnitOfMeasure === 'kg' && record.rapportoKgMt && record.rapportoKgMt > 0) {
                                                    qtaMT = formatDisplayStock(record.netWeight / record.rapportoKgMt, 'mt');
                                                }

                                                return (
                                                  <TableRow key={record.id} data-state={selectedRecords.includes(record.id) ? 'selected' : ''} className={cn(record.status === 'pending' && 'bg-yellow-500/10')}>
                                                    <TableCell padding="checkbox">
                                                        <Checkbox
                                                        checked={selectedRecords.includes(record.id)}
                                                        onCheckedChange={() => handleSelectRecord(record.id)}
                                                        />
                                                    </TableCell>
                                                    <TableCell>{record.lotto}</TableCell>
                                                    
                                                    <TableCell className="font-mono font-semibold">
                                                      {qtaN}
                                                    </TableCell>
                                                    <TableCell className="font-mono font-semibold text-orange-600">
                                                      {qtaMT}
                                                    </TableCell>
                                                    <TableCell className="font-mono font-semibold text-primary">
                                                      {qtaKG}
                                                    </TableCell>

                                                    <TableCell className="font-mono">{formatDisplayStock(record.grossWeight, 'kg')} kg</TableCell>
                                                    <TableCell className="font-mono">{formatDisplayStock(record.tareWeight, 'kg')} kg</TableCell>
                                                    <TableCell className="font-mono font-semibold">{formatDisplayStock(record.netWeight, 'kg')} kg</TableCell>
                                                    <TableCell>{record.operatorName}</TableCell>
                                                    <TableCell>
                                                        <Badge variant={record.status === 'pending' ? 'destructive' : record.status === 'approved' ? 'default' : 'secondary'}>
                                                        {record.status === 'pending' ? 'In Attesa' : record.status === 'approved' ? 'Approvato' : 'Rifiutato'}
                                                        </Badge>
                                                    </TableCell>
                                                    <TableCell className="text-right space-x-2">
                                                        {isPending === record.id ? (
                                                        <Loader2 className="h-5 w-5 animate-spin ml-auto" />
                                                        ) : (
                                                        <>
                                                            <Button variant="ghost" size="icon" onClick={() => handleOpenSheet(record)} disabled={record.status !== 'pending'}>
                                                            <Pencil className="h-4 w-4"/>
                                                            </Button>
                                                            {record.status === 'pending' ? (
                                                            <>
                                                                <AlertDialog>
                                                                <AlertDialogTrigger asChild>
                                                                    <Button variant="ghost" size="icon" className="text-destructive hover:text-destructive">
                                                                    <X className="h-5 w-5"/>
                                                                    </Button>
                                                                </AlertDialogTrigger>
                                                                <AlertDialogContent>
                                                                    <AlertDialogHeader><AlertDialogTitle>Confermi di rifiutare?</AlertDialogTitle><AlertDialogDescription>La registrazione verrà marcata come "rifiutata" e non potrà essere modificata.</AlertDialogDescription></AlertDialogHeader>
                                                                    <AlertDialogFooter>
                                                                    <AlertDialogCancel>Annulla</AlertDialogCancel>
                                                                    <AlertDialogAction onClick={() => handleReject(record.id)} className="bg-destructive hover:bg-destructive/90">Sì, rifiuta</AlertDialogAction>
                                                                    </AlertDialogFooter>
                                                                </AlertDialogContent>
                                                                </AlertDialog>

                                                                <AlertDialog>
                                                                <AlertDialogTrigger asChild>
                                                                    <Button variant="ghost" size="icon" className="text-green-500 hover:text-green-500">
                                                                    <Check className="h-5 w-5"/>
                                                                    </Button>
                                                                </AlertDialogTrigger>
                                                                <AlertDialogContent>
                                                                    <AlertDialogHeader><AlertDialogTitle>Confermi di approvare?</AlertDialogTitle><AlertDialogDescription>Lo stock della materia prima verrà aggiornato con il peso netto di questa registrazione. L'azione non è reversibile.</AlertDialogDescription></AlertDialogHeader>
                                                                    <AlertDialogFooter>
                                                                    <AlertDialogCancel>Annulla</AlertDialogCancel>
                                                                    <AlertDialogAction onClick={() => handleApprove(record.id)} className="bg-green-600 hover:bg-green-700">Sì, approva</AlertDialogAction>
                                                                    </AlertDialogFooter>
                                                                </AlertDialogContent>
                                                                </AlertDialog>
                                                            </>
                                                            ) : (
                                                            <AlertDialog>
                                                                <AlertDialogTrigger asChild>
                                                                <Button variant="ghost" size="icon" className="text-amber-500 hover:text-amber-500">
                                                                    <Undo2 className="h-4 w-4"/>
                                                                </Button>
                                                                </AlertDialogTrigger>
                                                                <AlertDialogContent>
                                                                <AlertDialogHeader>
                                                                    <AlertDialogTitle>Annullare l'operazione?</AlertDialogTitle>
                                                                    <AlertDialogDescription>Questa azione riporterà la registrazione allo stato "In Attesa". Se approvata, lo stock verrà stornato.</AlertDialogDescription>
                                                                </AlertDialogHeader>
                                                                <AlertDialogFooter>
                                                                    <AlertDialogCancel>Chiudi</AlertDialogCancel>
                                                                    <AlertDialogAction onClick={() => handleRevertStatus(record.id)}>Sì, annulla</AlertDialogAction>
                                                                </AlertDialogFooter>
                                                                </AlertDialogContent>
                                                            </AlertDialog>
                                                            )}
                                                        </>
                                                        )}
                                                    </TableCell>
                                                  </TableRow>
                                            )})}
                                          </TableBody>
                                        </Table>
                                      </div>
                                    </CollapsibleContent>
                                </Collapsible>
                               )})}
                            </div>
                          </div>
                        </AccordionContent>
                      </AccordionItem>
                    );
                  })}
                </Accordion>
              ) : (
                <div className="flex flex-col items-center justify-center py-20 text-center border-2 border-dashed rounded-lg">
                    <p className="text-lg font-semibold text-muted-foreground">
                       {records.length === 0 ? "Nessuna registrazione di inventario trovata." : "Nessuna registrazione trovata per la tua ricerca."}
                    </p>
                </div>
              )}
            </CardContent>
        </Card>
      </div>

      {selectedRecord && (
         <InventoryRecordSheet 
            isOpen={isSheetOpen} 
            onOpenChange={setIsSheetOpen} 
            record={selectedRecord}
            onUpdateSuccess={refreshData}
          />
      )}
    </>
  );
}

"use client";

import React, { useState, useEffect, useMemo } from 'react';
import {
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
  SheetFooter,
  SheetClose,
} from "@/components/ui/sheet";
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { type InventoryRecord, type Packaging, type RawMaterial } from '@/types';
import { updateInventoryRecord, getPackagingItems, getMaterialById } from './actions';
import { useAuth } from '@/components/auth/AuthProvider';
import { useToast } from '@/hooks/use-toast';
import { Loader2, Save, Archive, Package } from 'lucide-react';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Switch } from '@/components/ui/switch';
import { Skeleton } from '@/components/ui/skeleton';

interface InventoryRecordSheetProps {
  isOpen: boolean;
  onOpenChange: (open: boolean) => void;
  record: InventoryRecord | null;
  onUpdateSuccess: () => void;
}

const formSchema = z.object({
  inputQuantity: z.coerce.number().positive("La quantità deve essere positiva."),
  packagingId: z.string().default('none'),
  inputUnit: z.enum(['n', 'mt', 'kg']),
});

type FormValues = z.infer<typeof formSchema>;

export default function InventoryRecordSheet({ isOpen, onOpenChange, record, onUpdateSuccess }: InventoryRecordSheetProps) {
  const { user } = useAuth();
  const { toast } = useToast();
  const [isPending, setIsPending] = useState(false);
  const [packagingItems, setPackagingItems] = useState<Packaging[]>([]);
  const [material, setMaterial] = useState<RawMaterial | null>(null);
  
  const form = useForm<FormValues>({
    resolver: zodResolver(formSchema),
    defaultValues: { packagingId: 'none' },
  });

  useEffect(() => {
    getPackagingItems().then(setPackagingItems);
  }, []);

  useEffect(() => {
    if (record) {
      getMaterialById(record.materialId).then(setMaterial);
      form.reset({ 
        inputQuantity: record.inputQuantity,
        inputUnit: record.inputUnit,
        packagingId: record.packagingId || 'none',
      });
    }
  }, [record, form]);
  
  const watchedValues = form.watch();
  
  const calculatedNetWeight = useMemo(() => {
    if (!material) return 0;
    const { inputQuantity, inputUnit, packagingId } = watchedValues;
    const tareWeight = packagingItems.find(p => p.id === packagingId)?.weightKg || 0;
    
    const factor = (inputUnit === 'kg') 
        ? 1 
        : (material.unitOfMeasure === 'mt' || inputUnit === 'mt' ? material.rapportoKgMt : material.conversionFactor) || 1;
        
    if (inputUnit === 'kg') return (inputQuantity || 0) - tareWeight;
    return (inputQuantity || 0) * factor;
  }, [material, watchedValues, packagingItems]);


  const onSubmit = async (values: FormValues) => {
    if (!record || !user || !material) return;
    setIsPending(true);
    const result = await updateInventoryRecord(
        record.id, 
        values.inputQuantity,
        values.inputUnit,
        values.packagingId || 'none',
        user.uid
    );
    toast({
        title: result.success ? "Aggiornato" : "Errore",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
      onUpdateSuccess();
      onOpenChange(false);
    }
    setIsPending(false);
  };
  
  if (!record) return null;

  return (
    <Sheet open={isOpen} onOpenChange={onOpenChange}>
      <SheetContent>
        <SheetHeader>
          <SheetTitle>Modifica Registrazione</SheetTitle>
          <SheetDescription>Correggi quantità o tara per l'invio all'approvazione.</SheetDescription>
        </SheetHeader>
        {!material ? <Skeleton className="h-96 w-full mt-6" /> : (
        <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)}>
            <div className="grid gap-6 py-6">
                <div className="space-y-1"><Label>Materiale</Label><p className="p-2 bg-muted rounded-md font-mono text-sm">{record.materialCode}</p></div>
                 <FormField control={form.control} name="inputUnit" render={({ field }) => (
                    <FormItem><div className="flex items-center space-x-2 rounded-lg border p-3 justify-center"><Label htmlFor="unit-switch">{material.unitOfMeasure.toUpperCase()}</Label><Switch id="unit-switch" checked={field.value === 'kg'} onCheckedChange={(checked) => field.onChange(checked ? 'kg' : material.unitOfMeasure)} /><Label htmlFor="unit-switch">KG</Label></div></FormItem>
                 )}/>
                <div className="space-y-2"><Label htmlFor="inputQuantity" className="flex items-center gap-2"><Package className="h-4 w-4"/> {form.watch('inputUnit') === 'kg' ? 'Quantità Lorda (KG)' : `Quantità Inserita (${material.unitOfMeasure.toUpperCase()})`} </Label><Input id="inputQuantity" type="number" step="any" {...form.register('inputQuantity')} /></div>
                <div className="space-y-2"><Label htmlFor="packagingId" className="flex items-center gap-2"><Archive className="mr-2 h-4 w-4"/> Tara Applicata (kg)</Label><Select onValueChange={(v) => form.setValue('packagingId', v)} value={form.watch('packagingId')}><SelectTrigger id="packagingId"><SelectValue /></SelectTrigger><SelectContent><SelectItem value="none">Nessuna Tara (0.00 kg)</SelectItem>{packagingItems.map(i => (<SelectItem key={i.id} value={i.id}>{i.name} ({i.weightKg.toFixed(3)} kg)</SelectItem>))}</SelectContent></Select></div>
                <div className="p-4 rounded-lg border bg-background text-center"><Label className="text-muted-foreground">Peso Netto Calcolato (kg)</Label><p className="text-2xl font-bold text-primary">{calculatedNetWeight >= 0 ? calculatedNetWeight.toFixed(3) : '---'}</p></div>
            </div>
            <SheetFooter><SheetClose asChild><Button type="button" variant="outline">Annulla</Button></SheetClose><Button type="submit" disabled={isPending || calculatedNetWeight < 0}>{isPending ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <Save className="mr-2 h-4 w-4" />} Salva Modifiche</Button></SheetFooter>
            </form>
        </Form>
        )}
      </SheetContent>
    </Sheet>
  );
}

"use client";

import React, { useState, useRef, useMemo } from 'react';
import * as XLSX from 'xlsx';
import { useToast } from '@/hooks/use-toast';
import { useAuth } from '@/components/auth/AuthProvider';

import { Card, CardContent, CardDescription, CardHeader, CardTitle, CardFooter } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Upload, Download, Loader2, List, Trash2, AlertTriangle, Send, ArrowLeft, FileUp, FileDown, XCircle } from 'lucide-react';
import { importCaricoFromFile, importScaricoFromFile } from './actions';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import type { Packaging, RawMaterial } from '@/types';
import { Badge } from '@/components/ui/badge';
import { ScrollArea } from '@/components/ui/scroll-area';
import { cn } from '@/lib/utils';

type Operation = 'carico' | 'scarico';

interface ParsedRow {
  [key: string]: string | number | undefined;
  __originalIndex?: number;
  'Unita'?: string;
  reason?: string;
}

interface MaterialImportClientPageProps {
  packagingItems: Packaging[];
  rawMaterials: RawMaterial[];
}

export default function MaterialImportClientPage({ packagingItems, rawMaterials }: MaterialImportClientPageProps) {
  const [operation, setOperation] = useState<Operation | null>(null);
  const [parsedData, setParsedData] = useState<ParsedRow[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [fileName, setFileName] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);
  const { toast } = useToast();
  const { user } = useAuth();
  
  const materialsMap = useMemo(() => new Map(rawMaterials.map(m => [m.code.toLowerCase(), m])), [rawMaterials]);

  const handleDownloadTemplate = () => {
    let templateData: any[];
    let fileName: string;
    let sheetName: string;

    if (operation === 'carico') {
      const packagingExamples = packagingItems.slice(0, 2).map(p => p.name);
      templateData = [
        { 
          "Codice Materiale": "CODICE-ESEMPIO-1", "Lotto": "LOTTO-A1", "DDT": "DDT-123",
          "Quantita Netta": 100.5, "Data": "2024-07-25", "Tara (Imballo)": packagingExamples[0] || "Nome Tara Esistente",
        },
        { 
          "Codice Materiale": "CODICE-ESEMPIO-2", "Lotto": "LOTTO-B2", "DDT": "DDT-124",
          "Quantita Netta": 50, "Data": 45497, "Tara (Imballo)": packagingExamples[1] || "",
        },
      ];
      fileName = "template_carico_magazzino.xlsx";
      sheetName = "Carico Magazzino";
    } else { // scarico
      templateData = [
        {
          "Codice Materiale": "CODICE-ESEMPIO-1", "Lotto": "LOTTO-A1", "Quantita da Scaricare": 10.5,
          "Unita": "kg", "Commessa Associata": "Comm-123/24", "Note": "Scarico per test",
        },
        {
          "Codice Materiale": "CODICE-ESEMPIO-2", "Lotto": "LOTTO-B2", "Quantita da Scaricare": 25,
          "Unita": "n", "Commessa Associata": "", "Note": "",
        },
      ];
      fileName = "template_scarico_magazzino.xlsx";
      sheetName = "Scarico Magazzino";
    }

    const ws = XLSX.utils.json_to_sheet(templateData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, sheetName);
    XLSX.writeFile(wb, fileName);
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setFileName(file.name);
    setIsProcessing(true);
    toast({ title: 'Lettura file in corso...' });

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'array', cellDates: true });
        const sheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[sheetName];
        
        const headers = operation === 'carico'
          ? ["Codice Materiale", "Lotto", "DDT", "Quantita Netta", "Data", "Tara (Imballo)"]
          : ["Codice Materiale", "Lotto", "Quantita da Scaricare", "Unita", "Commessa Associata", "Note"];
          
        const json: any[] = XLSX.utils.sheet_to_json(worksheet, { header: headers, range: 1 });
        
        const validData = json
            .map((row, index) => {
              // Client-side non passiamo rawMaterials se non per l'interfaccia, 
              // la validazione reale inclusa 'Unita' avverrà nel server
              if (operation === 'carico') {
                 // Per permettere l'anteprima forziamo temporaneamente l'unita a vuoto se non indicata,
                 // il server action imposterà quella corretta.
                 if (!row['Unita']) row['Unita'] = '??';
              }

              return { ...row, __originalIndex: index };
            })
            .filter(row => row['Codice Materiale'] && (row['Quantita Netta'] || row['Quantita da Scaricare']));

        setParsedData(validData);
        toast({ title: 'File analizzato', description: `${validData.length} righe valide trovate.` });
      } catch (error) {
        toast({ variant: 'destructive', title: 'Errore', description: 'Impossibile leggere o analizzare le file.' });
      } finally {
        setIsProcessing(false);
      }
    };
    reader.readAsArrayBuffer(file);
     if (fileInputRef.current) {
        fileInputRef.current.value = "";
    }
  };

  const handleConfirmImport = async () => {
    if (!user || !operation) {
        toast({ variant: "destructive", title: "Errore", description: "Operazione o utente non validi."});
        return;
    }
    setIsProcessing(true);
    
    const action = operation === 'carico' ? importCaricoFromFile : importScaricoFromFile;
    const result = await action(parsedData, user.uid);

    if (result.success) {
        toast({
            title: 'Importazione Completata',
            description: result.message,
            variant: 'default',
        });
        clearData();
    } else {
        toast({
            title: 'Importazione Parziale/Fallita',
            description: result.message,
            variant: 'destructive',
            duration: 9000,
        });
        setParsedData(result.failedRows || []);
    }
    
    setIsProcessing(false);
  };
  
  const clearData = () => {
    setParsedData([]);
    setFileName('');
  }

  const renderHeaderAndTable = () => {
    const hasReasons = parsedData.some(r => r.reason);
    
    if (operation === 'carico') {
        return (
            <>
                <TableHeader className="sticky top-0 bg-muted"><TableRow>
                    <TableHead>Codice Materiale</TableHead><TableHead>Lotto</TableHead><TableHead>DDT</TableHead>
                    <TableHead>Quantità Netta</TableHead>
                    <TableHead>Unità</TableHead>
                    <TableHead>Data</TableHead>
                    {hasReasons && <TableHead className="text-destructive">Errore</TableHead>}
                </TableRow></TableHeader>
                <TableBody>
                    {parsedData.map((row, index) => (
                        <TableRow key={row.__originalIndex ?? index}>
                            <TableCell>{row["Codice Materiale"]}</TableCell><TableCell>{row["Lotto"]}</TableCell>
                            <TableCell>{row["DDT"]}</TableCell><TableCell>{row["Quantita Netta"]}</TableCell>
                             <TableCell>
                                <Badge variant={row['Unita'] && row['Unita'] !== '??' ? 'secondary' : 'outline'}>
                                  {String(row['Unita'] || '???').toUpperCase()}
                                </Badge>
                             </TableCell>
                            <TableCell>{typeof row["Data"] === 'number' ? new Date(Date.UTC(1899, 11, 30 + (row["Data"] as number))).toLocaleDateString('it-IT') : new Date(row["Data"] as string).toLocaleDateString('it-IT')}</TableCell>
                            {row.reason && <TableCell className="text-destructive text-xs font-semibold">{row.reason}</TableCell>}
                        </TableRow>
                    ))}
                </TableBody>
            </>
        );
    } else { // scarico
         return (
            <>
                <TableHeader className="sticky top-0 bg-muted"><TableRow>
                    <TableHead>Codice Materiale</TableHead><TableHead>Lotto</TableHead>
                    <TableHead>Q.tà da Scaricare</TableHead><TableHead>Unità</TableHead>
                    <TableHead>Commessa</TableHead>
                    {hasReasons && <TableHead className="text-destructive">Errore</TableHead>}
                </TableRow></TableHeader>
                <TableBody>
                    {parsedData.map((row, index) => (
                        <TableRow key={row.__originalIndex ?? index}>
                            <TableCell>{row["Codice Materiale"]}</TableCell><TableCell>{row["Lotto"]}</TableCell>
                            <TableCell>{row["Quantita da Scaricare"]}</TableCell><TableCell>{row["Unita"]}</TableCell>
                            <TableCell>{row["Commessa Associata"]}</TableCell>
                            {row.reason && <TableCell className="text-destructive text-xs font-semibold">{row.reason}</TableCell>}
                        </TableRow>
                    ))}
                </TableBody>
            </>
        );
    }
  };

  return (
    <div className="space-y-6">
        {!operation ? (
            <Card>
                <CardHeader>
                    <CardTitle className="flex items-center gap-3"><Upload className="h-8 w-8 text-primary" />Carico/Scarico Merce da File</CardTitle>
                    <CardDescription>Seleziona l'operazione che vuoi eseguire.</CardDescription>
                </CardHeader>
                <CardContent className="grid grid-cols-1 md:grid-cols-2 gap-4 pt-6">
                    <Button onClick={() => setOperation('carico')} variant="outline" className="h-28 text-lg flex-col gap-2 border-green-500/50 hover:bg-green-500/10 hover:text-green-700 dark:hover:text-green-400">
                        <FileUp className="h-8 w-8 text-green-500" />
                        Carico Merce
                    </Button>
                    <Button onClick={() => setOperation('scarico')} variant="outline" className="h-28 text-lg flex-col gap-2 border-red-500/50 hover:bg-red-500/10 hover:text-red-700 dark:hover:text-red-400">
                        <FileDown className="h-8 w-8 text-red-500" />
                        Scarico Merce
                    </Button>
                </CardContent>
            </Card>
        ) : (
        <>
          <Button variant="ghost" onClick={() => { setOperation(null); clearData(); }}>
            <ArrowLeft className="mr-2"/>
            Torna alla selezione
          </Button>
          <Card>
            <CardHeader>
              <CardTitle className="capitalize">{operation} Merce da File</CardTitle>
              <CardDescription>Scarica il template, compilalo e carica il file per avviare l'importazione.</CardDescription>
            </CardHeader>
            <CardContent className="flex flex-wrap items-center gap-4">
              <Button onClick={handleDownloadTemplate} variant="secondary">
                <Download className="mr-2" />
                Scarica Template
              </Button>
               <input type="file" ref={fileInputRef} onChange={handleFileChange} accept=".xlsx, .xls" className="hidden" />
               <Button onClick={() => fileInputRef.current?.click()} disabled={isProcessing}>
                <Upload className="mr-2" />
                Seleziona File Excel
              </Button>
              {fileName && <p className="text-sm text-muted-foreground">File selezionato: {fileName}</p>}
            </CardContent>
          </Card>

          {parsedData.length > 0 && (
            <Card className={cn(parsedData.some(r => r.reason) && "border-destructive")}>
                <CardHeader>
                    <div className="flex justify-between items-center">
                        <div className="space-y-1">
                            <CardTitle className="flex items-center gap-2">
                                {parsedData.some(r => r.reason) ? <XCircle className="text-destructive"/> : <List className="h-6 w-6"/>}
                                Anteprima Dati
                            </CardTitle>
                            <CardDescription>
                                {parsedData.some(r => r.reason) 
                                    ? "Alcune righe presentano errori. Correggi il file Excel o procedi ignorando le righe errate." 
                                    : "Controlla i dati letti dal file. Se sono corretti, procedi con l'importazione."
                                }
                            </CardDescription>
                        </div>
                        <Button variant="destructive" size="sm" onClick={clearData}>
                            <Trash2 className="mr-2"/>
                            Annulla e Svuota
                        </Button>
                    </div>
                </CardHeader>
                <CardContent>
                    <ScrollArea className="h-96 border rounded-lg">
                        <Table>{renderHeaderAndTable()}</Table>
                    </ScrollArea>
                </CardContent>
                <CardFooter>
                     <AlertDialog>
                        <AlertDialogTrigger asChild>
                          <Button className="w-full" disabled={isProcessing || parsedData.length === 0}>
                            {isProcessing ? <Loader2 className="mr-2 animate-spin"/> : <Send className="mr-2" />}
                            Conferma e Importa {parsedData.filter(r => !r.reason).length} righe valide
                          </Button>
                        </AlertDialogTrigger>
                        <AlertDialogContent>
                          <AlertDialogHeader>
                            <AlertDialogTitle className="flex items-center gap-2"><AlertTriangle/> Sei assolutamente sicuro?</AlertDialogTitle>
                            <AlertDialogDescription>
                               Stai per eseguire un {operation} massivo per {parsedData.filter(r => !r.reason).length} righe. L'operazione aggiornerà lo stock dei materiali. Questa azione non può essere annullata facilmente.
                            </AlertDialogDescription>
                          </AlertDialogHeader>
                          <AlertDialogFooter>
                            <AlertDialogCancel>Annulla</AlertDialogCancel>
                            <AlertDialogAction onClick={handleConfirmImport} disabled={isProcessing}>
                                {isProcessing ? <Loader2 className="mr-2 animate-spin"/> : null}
                                Sì, importa
                            </AlertDialogAction>
                          </AlertDialogFooter>
                        </AlertDialogContent>
                      </AlertDialog>
                </CardFooter>
            </Card>
          )}
        </>
        )}
    </div>
  );
}

"use client";

import React, { useState, useEffect } from 'react';
import * as z from 'zod';
import { useForm, useFieldArray } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { useToast } from '@/hooks/use-toast';
import * as XLSX from 'xlsx';

import { type Operator, type Department, type WorkPhaseTemplate } from '@/types';
import { saveOperator, deleteOperator } from './actions';
import { cn } from '@/lib/utils';
import type { StatoOperatore, OperatorRole } from '@/types';

import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from "@/components/ui/alert-dialog";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage, FormDescription } from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Checkbox } from '@/components/ui/checkbox';
import { Badge } from '@/components/ui/badge';
import { Users, PlusCircle, Edit, Trash2, CheckCircle2, ShieldAlert, Download, Mail, Loader2, Warehouse, MinusSquare, UserCheck, UserX, LayoutDashboard } from 'lucide-react';
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from '@/components/ui/tooltip';
import { useRouter } from 'next/navigation';
import { Switch } from '@/components/ui/switch';


const operatorFormSchema = z.object({
  id: z.string().optional(),
  nome: z.string().min(1, "Il nome è obbligatorio."),
  email: z.string().email("Formato email non valido.").refine(email => email.endsWith('@prodfastxcan.app'), {
    message: "L'email deve terminare con @prodfastxcan.app",
  }),
  reparto: z.array(z.string()).max(3, "Puoi selezionare al massimo 3 reparti.").optional(),
  role: z.enum(['admin', 'supervisor', 'operator']),
  canAccessInventory: z.boolean().optional(),
  canAccessMaterialWithdrawal: z.boolean().optional(),
  canManageMaterialSessions: z.boolean().optional(),
  isReal: z.boolean().optional(),
  skills: z.array(z.object({
    phaseId: z.string().min(1, "Seleziona fase di lavorazione"),
    isHardSkill: z.boolean(),
    efficiencyPercent: z.number().min(1).max(100)
  })).optional(),
}).refine(data => {
  if (data.role === 'operator') {
    return data.reparto && data.reparto.length > 0;
  }
  return true;
}, {
  message: "Selezionare almeno un reparto per il ruolo operatore.",
  path: ["reparto"],
});

type OperatorFormValues = z.infer<typeof operatorFormSchema>;

const StatusBadge = ({ status }: { status: StatoOperatore }) => (
  <Badge
    className={cn(
      "text-xs font-semibold",
      status === 'attivo' && "bg-green-500/20 text-green-700 border-green-400",
      status === 'inattivo' && "bg-gray-500/20 text-gray-700 border-gray-400",
      status === 'in pausa' && "bg-orange-500/20 text-orange-700 border-orange-400"
    )}
    variant="outline"
  >
    {status.charAt(0).toUpperCase() + status.slice(1)}
  </Badge>
);

interface OperatorManagementClientPageProps {
  initialOperators: Operator[];
  initialDepartments: Department[];
  initialPhases: WorkPhaseTemplate[];
}

export default function OperatorManagementClientPage({ initialOperators, initialDepartments, initialPhases }: OperatorManagementClientPageProps) {
  const [operators, setOperators] = useState<Operator[]>(initialOperators);
  const [departments, setDepartments] = useState<Department[]>(initialDepartments);
  const [phases, setPhases] = useState<WorkPhaseTemplate[]>(initialPhases);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingOperator, setEditingOperator] = useState<Operator | null>(null);
  const { toast } = useToast();
  const router = useRouter();

  const form = useForm<OperatorFormValues>({
    resolver: zodResolver(operatorFormSchema),
    defaultValues: {
      id: undefined,
      nome: "",
      email: "",
      reparto: [],
      role: 'operator',
      canAccessInventory: false,
      canAccessMaterialWithdrawal: false,
      canManageMaterialSessions: false,
      isReal: true,
      skills: [],
    },
  });

  const { fields: skillFields, append: appendSkill, remove: removeSkill } = useFieldArray({
    control: form.control,
    name: "skills",
  });

  const watchedRole = form.watch('role');
  const roles: OperatorRole[] = ['admin', 'supervisor', 'operator'];

  useEffect(() => {
    setDepartments(initialDepartments);
    setPhases(initialPhases);
  }, [initialDepartments, initialPhases]);

  useEffect(() => {
    if (watchedRole === 'admin' || watchedRole === 'supervisor') {
      form.setValue('reparto', []);
    }
  }, [watchedRole, form]);

  const refreshData = () => {
    router.refresh();
  };

  const handleOpenDialog = (operator: Operator | null = null) => {
    setEditingOperator(operator);
    if (operator) {
      form.reset({
        id: operator.id,
        nome: operator.nome,
        email: operator.email || '',
        reparto: operator.reparto || [],
        role: operator.role,
        canAccessInventory: operator.canAccessInventory || false,
        canAccessMaterialWithdrawal: operator.canAccessMaterialWithdrawal || false,
        canManageMaterialSessions: operator.canManageMaterialSessions || false,
        isReal: operator.isReal !== undefined ? operator.isReal : true,
        skills: operator.skills || [],
      });
    } else {
      form.reset({ id: undefined, nome: "", email: "", reparto: [], role: 'operator', canAccessInventory: false, canAccessMaterialWithdrawal: false, canManageMaterialSessions: false, isReal: true, skills: [] });
    }
    setIsDialogOpen(true);
  };

  const handleCloseDialog = () => {
    setIsDialogOpen(false);
    setEditingOperator(null);
    form.reset();
  }

  const onSubmit = async (values: OperatorFormValues) => {
    const result = await saveOperator(values);

    if (result.success) {
      toast({ title: "Successo", description: result.message });
      refreshData();
      handleCloseDialog();
    } else {
      toast({
        variant: "destructive",
        title: "Errore",
        description: result.message || "Impossibile salvare l'operatore.",
      });
    }
  };

  const handleDelete = async (id: string) => {
    const result = await deleteOperator(id);
    if (result.success) {
      toast({ title: "Successo", description: result.message });
      refreshData();
    } else {
      toast({ variant: "destructive", title: "Errore", description: result.message });
    }
  };

  const handleExport = () => {
    const dataToExport = operators.map(op => ({
      'ID': op.id,
      'Nome': op.nome,
      'Email': op.email,
      'Reparto': (op.reparto || []).map(r => departments.find(d => d.code === r)?.name || r).join(', '),
      'Ruolo': op.role,
      'Stato': op.stato,
      'Operatore Reale': op.isReal ? 'Sì' : 'No',
      'Privacy Firmata': op.privacySigned ? 'Sì' : 'No',
      'Accesso Inventario': op.canAccessInventory ? 'Sì' : 'No',
      'Accesso Scarico Materiale': op.canAccessMaterialWithdrawal ? 'Sì' : 'No',
    }));
    const ws = XLSX.utils.json_to_sheet(dataToExport);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Operatori");
    XLSX.writeFile(wb, "elenco_operatori.xlsx");
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-start gap-4 flex-wrap">
        <header>
          <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
            <Users className="h-8 w-8 text-primary" />
            Gestione Operatori
          </h1>
          <p className="text-muted-foreground mt-1">
            Aggiungi, modifica o elimina gli account degli operatori.
          </p>
        </header>
        <div className="flex items-center gap-2 pt-2">
          <Button onClick={handleExport} variant="outline" disabled={operators.length === 0}>
            <Download className="mr-2 h-4 w-4" />
            Esporta Operatori
          </Button>
          <Button onClick={() => handleOpenDialog()}>
            <PlusCircle className="mr-2 h-4 w-4" />
            Aggiungi Operatore
          </Button>
        </div>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Elenco Operatori</CardTitle>
          <CardDescription>Aggiungi, modifica o elimina gli account degli operatori.</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="overflow-x-auto">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Reale</TableHead>
                  <TableHead>Nome</TableHead>
                  <TableHead>Email</TableHead>
                  <TableHead>Reparto</TableHead>
                  <TableHead>Ruolo</TableHead>
                  <TableHead>Stato</TableHead>
                  <TableHead>Privacy</TableHead>
                  <TableHead>Permessi</TableHead>
                  <TableHead className="text-right">Azioni</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {operators.length > 0 ? (
                  operators.map((op) => {
                    const opReparti = op.reparto || [];

                    return (
                      <TableRow key={op.id}>
                        <TableCell className="text-center">
                          <TooltipProvider>
                            <Tooltip>
                              <TooltipTrigger asChild>
                                <div className="flex justify-center">
                                  {op.isReal !== false ? (
                                    <UserCheck className="h-5 w-5 text-green-500" />
                                  ) : (
                                    <UserX className="h-5 w-5 text-muted-foreground opacity-50" />
                                  )}
                                </div>
                              </TooltipTrigger>
                              <TooltipContent>
                                <p>{op.isReal !== false ? 'Lavoratore Reale (Incluso in Capacità)' : 'Profilo Sviluppo/Test'}</p>
                              </TooltipContent>
                            </Tooltip>
                          </TooltipProvider>
                        </TableCell>
                        <TableCell className="font-medium">{op.nome}</TableCell>
                        <TableCell>{op.email}</TableCell>
                        <TableCell>
                          <div className="flex flex-wrap gap-1">
                            {op.role === 'supervisor' ? (
                              <Badge variant="secondary">Officina</Badge>
                            ) : (
                              opReparti.map(r => <Badge key={r} variant="secondary">{departments.find(d => d.code === r)?.name || r}</Badge>)
                            )}
                          </div>
                        </TableCell>
                        <TableCell className="capitalize">{op.role}</TableCell>
                        <TableCell><StatusBadge status={op.stato} /></TableCell>
                        <TableCell>
                          <TooltipProvider>
                            <Tooltip>
                              <TooltipTrigger asChild>
                                <div className="flex items-center justify-center">
                                  {op.privacySigned ? (
                                    <CheckCircle2 className="h-5 w-5 text-green-500" />
                                  ) : (
                                    <ShieldAlert className="h-5 w-5 text-yellow-500" />
                                  )}
                                </div>
                              </TooltipTrigger>
                              <TooltipContent>
                                <p>{op.privacySigned ? 'Informativa Firmata' : 'Informativa Non Firmata'}</p>
                              </TooltipContent>
                            </Tooltip>
                          </TooltipProvider>
                        </TableCell>
                        <TableCell>
                          <div className="flex items-center justify-center gap-2">
                            <TooltipProvider>
                              <Tooltip>
                                <TooltipTrigger asChild>
                                  <div>
                                    {op.canAccessInventory ? (
                                      <Warehouse className="h-5 w-5 text-green-500" />
                                    ) : (
                                      <Warehouse className="h-5 w-5 text-muted-foreground opacity-50" />
                                    )}
                                  </div>
                                </TooltipTrigger>
                                <TooltipContent>
                                  <p>{op.canAccessInventory ? 'Accesso Inventario Abilitato' : 'Accesso Inventario Disabilitato'}</p>
                                </TooltipContent>
                              </Tooltip>
                            </TooltipProvider>
                            <TooltipProvider>
                              <Tooltip>
                                <TooltipTrigger asChild>
                                  <div>
                                    {op.canAccessMaterialWithdrawal ? (
                                      <MinusSquare className="h-5 w-5 text-green-500" />
                                    ) : (
                                      <MinusSquare className="h-5 w-5 text-muted-foreground opacity-50" />
                                    )}
                                  </div>
                                </TooltipTrigger>
                                <TooltipContent>
                                  <p>{op.canAccessMaterialWithdrawal ? 'Accesso Scarico Materiale Abilitato' : 'Accesso Scarico Materiale Disabilitato'}</p>
                                </TooltipContent>
                              </Tooltip>
                            </TooltipProvider>
                            <TooltipProvider>
                              <Tooltip>
                                <TooltipTrigger asChild>
                                  <div>
                                    {op.canManageMaterialSessions ? (
                                      <LayoutDashboard className="h-5 w-5 text-primary" />
                                    ) : (
                                      <LayoutDashboard className="h-5 w-5 text-muted-foreground opacity-30" />
                                    )}
                                  </div>
                                </TooltipTrigger>
                                <TooltipContent>
                                  <p>{op.canManageMaterialSessions ? 'Gestione Sessioni Globali Abilitata' : 'Gestione Sessioni Globali Disabilitata'}</p>
                                </TooltipContent>
                              </Tooltip>
                            </TooltipProvider>
                          </div>
                        </TableCell>
                        <TableCell className="text-right space-x-2">
                          <Button variant="outline" size="icon" onClick={() => handleOpenDialog(op)}>
                            <Edit className="h-4 w-4" />
                            <span className="sr-only">Modifica</span>
                          </Button>
                          <AlertDialog>
                            <AlertDialogTrigger asChild>
                              <Button variant="destructive" size="icon">
                                <Trash2 className="h-4 w-4" />
                                <span className="sr-only">Elimina</span>
                              </Button>
                            </AlertDialogTrigger>
                            <AlertDialogContent>
                              <AlertDialogHeader>
                                <AlertDialogTitle>Sei sicuro?</AlertDialogTitle>
                                <AlertDialogDescription>
                                  Questa azione non può essere annullata. L'operatore verrà eliminato definitivamente.
                                </AlertDialogDescription>
                              </AlertDialogHeader>
                              <AlertDialogFooter>
                                <AlertDialogCancel>Annulla</AlertDialogCancel>
                                <AlertDialogAction onClick={() => handleDelete(op.id)}>Continua</AlertDialogAction>
                              </AlertDialogFooter>
                            </AlertDialogContent>
                          </AlertDialog>
                        </TableCell>
                      </TableRow>
                    )
                  })
                ) : (
                  <TableRow>
                    <TableCell colSpan={9} className="text-center h-24">Nessun operatore trovato.</TableCell>
                  </TableRow>
                )}
              </TableBody>
            </Table>
          </div>
        </CardContent>
      </Card>

      <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
        <DialogContent className="sm:max-w-2xl max-h-[90vh] flex flex-col" onInteractOutside={(e) => { e.preventDefault(); handleCloseDialog(); }} onEscapeKeyDown={(e) => { e.preventDefault(); handleCloseDialog(); }}>
          <DialogHeader>
            <DialogTitle>{editingOperator ? "Modifica Operatore" : "Aggiungi Nuovo Operatore"}</DialogTitle>
            <DialogDescription>
              {editingOperator ? "Modifica i dettagli dell'operatore." : "Compila i campi per aggiungere un nuovo operatore. L'email deve corrispondere a quella dell'utente creato in Firebase Authentication."}
            </DialogDescription>
          </DialogHeader>
          <div className="flex-1 overflow-y-auto pr-2 -mr-2">
          <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4 py-4">
              <FormField control={form.control} name="nome" render={({ field }) => (
                <FormItem>
                  <FormLabel>Nome</FormLabel>
                  <FormControl><Input placeholder="Es. Mario" {...field} /></FormControl>
                  <FormMessage />
                </FormItem>
              )} />
              <FormField control={form.control} name="email" render={({ field }) => (
                <FormItem>
                  <FormLabel className="flex items-center"><Mail className="mr-2 h-4 w-4" />Email (per il login)</FormLabel>
                  <FormControl><Input type="email" placeholder="es. m.rossi@prodfastxcan.app" {...field} /></FormControl>
                  <FormMessage />
                </FormItem>
              )} />
              <FormField control={form.control} name="role" render={({ field }) => (
                <FormItem>
                  <FormLabel>Ruolo</FormLabel>
                  <Select onValueChange={field.onChange} value={field.value}>
                    <FormControl>
                      <SelectTrigger>
                        <SelectValue placeholder="Seleziona un ruolo" />
                      </SelectTrigger>
                    </FormControl>
                    <SelectContent>
                      {roles.map(r => <SelectItem key={r} value={r} className="capitalize">{r}</SelectItem>)}
                    </SelectContent>
                  </Select>
                  <FormMessage />
                </FormItem>
              )} />
              {watchedRole === 'operator' && (
                <FormField
                  control={form.control}
                  name="reparto"
                  render={({ field }) => (
                    <FormItem>
                      <div className="mb-4">
                        <FormLabel>Reparti di Competenza</FormLabel>
                        <FormDescription>
                          Seleziona uno o più reparti (max 3).
                        </FormDescription>
                      </div>
                      <div className="space-y-2">
                        {departments.map((item) => (
                          <FormItem
                            key={item.id}
                            className="flex flex-row items-start space-x-3 space-y-0"
                          >
                            <FormControl>
                              <Checkbox
                                checked={field.value?.includes(item.code)}
                                onCheckedChange={(checked) => {
                                  const currentValue = field.value || [];
                                  const newValue = checked
                                    ? [...currentValue, item.code]
                                    : currentValue.filter(
                                      (value) => value !== item.code
                                    );
                                  field.onChange(newValue);
                                }}
                              />
                            </FormControl>
                            <FormLabel className="font-normal">
                              {item.code} ({item.name})
                            </FormLabel>
                          </FormItem>
                        ))}
                      </div>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              )}

              <FormField
                control={form.control}
                name="isReal"
                render={({ field }) => (
                  <FormItem className="flex flex-row items-center justify-between rounded-lg border p-4 bg-primary/5 border-primary/20">
                    <div className="space-y-0.5">
                      <FormLabel className="text-base flex items-center gap-2">
                        <UserCheck className="h-5 w-5 text-primary" />
                        Lavoratore Reale
                      </FormLabel>
                      <FormDescription>
                        Spegni se il profilo è usato solo per test o sviluppo.
                      </FormDescription>
                    </div>
                    <FormControl>
                      <Switch
                        checked={field.value}
                        onCheckedChange={field.onChange}
                      />
                    </FormControl>
                  </FormItem>
                )}
              />

              <FormField
                control={form.control}
                name="canAccessInventory"
                render={({ field }) => (
                  <FormItem className="flex flex-row items-center justify-between rounded-lg border p-4">
                    <div className="space-y-0.5">
                      <FormLabel className="text-base flex items-center gap-2">
                        <Warehouse className="h-5 w-5" />
                        Accesso a Inventario
                      </FormLabel>
                      <FormDescription>
                        Consenti a questo operatore di accedere alla sezione Inventario.
                      </FormDescription>
                    </div>
                    <FormControl>
                      <Checkbox
                        checked={field.value}
                        onCheckedChange={field.onChange}
                      />
                    </FormControl>
                  </FormItem>
                )}
              />
              <FormField
                control={form.control}
                name="canAccessMaterialWithdrawal"
                render={({ field }) => (
                  <FormItem className="flex flex-row items-center justify-between rounded-lg border p-4">
                    <div className="space-y-0.5">
                      <FormLabel className="text-base flex items-center gap-2">
                        <MinusSquare className="h-5 w-5" />
                        Accesso Scarico Materiale
                      </FormLabel>
                      <FormDescription>
                        Consenti di registrare uno scarico manuale di materiale.
                      </FormDescription>
                    </div>
                    <FormControl>
                      <Checkbox
                        checked={field.value}
                        onCheckedChange={field.onChange}
                      />
                    </FormControl>
                  </FormItem>
                )}
              />

              <FormField
                control={form.control}
                name="canManageMaterialSessions"
                render={({ field }) => (
                  <FormItem className="flex flex-row items-center justify-between rounded-lg border p-4 bg-primary/5 border-primary/20">
                    <div className="space-y-0.5">
                      <FormLabel className="text-base flex items-center gap-2 font-bold">
                        <LayoutDashboard className="h-5 w-5 text-primary" />
                        Gestione Sessioni Globali
                      </FormLabel>
                      <FormDescription className="text-xs">
                        Consente di vedere e gestire tutte le bobine aperte in officina (Dashboard Supervisore).
                      </FormDescription>
                    </div>
                    <FormControl>
                      <Switch
                        checked={field.value}
                        onCheckedChange={field.onChange}
                      />
                    </FormControl>
                  </FormItem>
                )}
              />

              {(watchedRole === 'operator' || watchedRole === 'supervisor') && (
                <div className="space-y-4 rounded-lg border p-4 bg-muted/20">
                  <div className="flex justify-between items-center mb-2">
                    <div className="space-y-0.5">
                      <FormLabel className="text-base font-semibold flex items-center gap-2">
                        <CheckCircle2 className="h-5 w-5 text-primary" />
                        Matrice Competenze (Skills)
                      </FormLabel>
                      <FormDescription className="text-xs">Assegna Microaree e % di Rendimento per i logaritmi del Gantt.</FormDescription>
                    </div>
                    <Button type="button" variant="outline" size="sm" onClick={() => appendSkill({ phaseId: '', isHardSkill: true, efficiencyPercent: 100 })}>
                      <PlusCircle className="mr-2 h-4 w-4" /> Aggiungi Skill
                    </Button>
                  </div>
                  {skillFields.map((field, index) => (
                    <div key={field.id} className="grid grid-cols-12 gap-3 items-end border-b pb-4 last:border-0 last:pb-0">
                      <div className="col-span-12 sm:col-span-5">
                        <FormField
                          control={form.control}
                          name={`skills.${index}.phaseId`}
                          render={({ field: selectField }) => {
                            const watchedReparto = form.watch('reparto') || [];
                            const filteredPhases = phases.filter(p => !watchedReparto || watchedReparto.length === 0 || (p.departmentCodes && p.departmentCodes.some(d => watchedReparto.includes(d))));
                            return (
                              <FormItem>
                                <FormLabel className="text-xs">Fase Lavorazione</FormLabel>
                                <Select onValueChange={selectField.onChange} value={selectField.value}>
                                  <FormControl>
                                    <SelectTrigger>
                                      <SelectValue placeholder="Seleziona..." />
                                    </SelectTrigger>
                                  </FormControl>
                                  <SelectContent>
                                    {filteredPhases.map(ws => <SelectItem key={ws.id} value={ws.id}>{ws.name} ({departments.filter(d => ws.departmentCodes?.includes(d.code)).map(d => d.code).join(', ')})</SelectItem>)}
                                  </SelectContent>
                                </Select>
                                <FormMessage />
                              </FormItem>
                            );
                          }}
                        />
                      </div>
                      <div className="col-span-5 sm:col-span-3">
                        <FormField
                          control={form.control}
                          name={`skills.${index}.efficiencyPercent`}
                          render={({ field: effField }) => (
                            <FormItem>
                              <FormLabel className="text-xs">Rendimento %</FormLabel>
                              <FormControl>
                                <Input type="number" min="1" max="100" {...effField} onChange={e => effField.onChange(parseInt(e.target.value) || 0)} />
                              </FormControl>
                              <FormMessage />
                            </FormItem>
                          )}
                        />
                      </div>
                      <div className="col-span-5 sm:col-span-3">
                        <FormField
                            control={form.control}
                            name={`skills.${index}.isHardSkill`}
                            render={({ field: hardField }) => (
                              <FormItem className="flex items-center space-x-2 space-y-0 h-10 border rounded px-2 bg-background mt-3 sm:mt-0">
                                <FormControl>
                                  <Checkbox
                                    checked={hardField.value}
                                    onCheckedChange={hardField.onChange}
                                  />
                                </FormControl>
                                <FormLabel className="text-xs font-normal mb-0 pb-0">
                                  Hard Skill
                                </FormLabel>
                              </FormItem>
                            )}
                          />
                      </div>
                      <div className="col-span-2 sm:col-span-1 text-right flex justify-end">
                        <Button type="button" variant="ghost" size="icon" className="text-destructive h-10 w-10" onClick={() => removeSkill(index)}>
                          <Trash2 className="h-4 w-4" />
                        </Button>
                      </div>
                    </div>
                  ))}
                  {skillFields.length === 0 && <p className="text-center text-sm text-muted-foreground pt-4">Nessuna competenza inserita.</p>}
                </div>
              )}

              <DialogFooter className="pt-4">
                <Button type="button" variant="outline" onClick={handleCloseDialog}>Annulla</Button>
                <Button type="submit">{editingOperator ? "Salva Modifiche" : "Aggiungi Operatore"}</Button>
              </DialogFooter>
            </form>
          </Form>
          </div>
        </DialogContent>
      </Dialog>

    </div>
  );
}

"use client";

import React, { useState, useEffect, useTransition } from 'react';
import * as z from 'zod';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { useToast } from '@/hooks/use-toast';

import { type Packaging, type PackagingAssociation } from '@/types';
import { RawMaterialTypeValues } from '@/lib/mock-data';
import { getPackagingItems, savePackagingItem, deletePackagingItem } from './actions';

import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from "@/components/ui/alert-dialog";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage, FormDescription } from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Checkbox } from '@/components/ui/checkbox';
import { Badge } from '@/components/ui/badge';
import { Archive, PlusCircle, Edit, Trash2, Loader2, Weight, Link2 } from 'lucide-react';
import AdminAuthGuard from '@/components/AdminAuthGuard';
import AppShell from '@/components/layout/AppShell';

const packagingAssociationTypes: PackagingAssociation[] = [...RawMaterialTypeValues, 'PRODOTTO'];

const packagingSchema = z.object({
  id: z.string().optional(),
  name: z.string().min(3, 'Il nome deve avere almeno 3 caratteri.'),
  description: z.string().optional(),
  weightKg: z.coerce.number().min(0, 'Il peso non può essere negativo.'),
  associatedTypes: z.array(z.string()).optional(),
});

type PackagingFormValues = z.infer<typeof packagingSchema>;

export default function PackagingManagementPage() {
  const [items, setItems] = useState<Packaging[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<Packaging | null>(null);
  const [isPending, setIsPending] = useState(false);
  const { toast } = useToast();

  const form = useForm<PackagingFormValues>({
    resolver: zodResolver(packagingSchema),
    defaultValues: { id: undefined, name: "", description: "", weightKg: 0, associatedTypes: [] },
  });

  const fetchData = async () => {
    setIsLoading(true);
    const data = await getPackagingItems();
    setItems(data);
    setIsLoading(false);
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleOpenDialog = (item: Packaging | null = null) => {
    setEditingItem(item);
    if (item) {
      form.reset({
        ...item,
        associatedTypes: item.associatedTypes || [],
      });
    } else {
      form.reset({ id: undefined, name: "", description: "", weightKg: 0, associatedTypes: [] });
    }
    setIsDialogOpen(true);
  };

  const handleCloseDialog = () => {
    setIsDialogOpen(false);
    setEditingItem(null);
    form.reset();
  };

  const onSubmit = async (values: PackagingFormValues) => {
    const formData = new FormData();
    Object.entries(values).forEach(([key, value]) => {
      if (key === 'associatedTypes' && Array.isArray(value)) {
        value.forEach(v => formData.append(key, v));
      } else if (value !== undefined && value !== null) {
        formData.append(key, String(value));
      }
    });
    
    setIsPending(true);
    const result = await savePackagingItem(formData);
    toast({
        title: result.success ? "Successo" : "Errore",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });

    if (result.success) {
        await fetchData();
        handleCloseDialog();
    }
    setIsPending(false);
  };

  const handleDelete = async (id: string) => {
    setIsPending(true);
    const result = await deletePackagingItem(id);
    toast({
        title: result.success ? "Successo" : "Errore",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });
    if (result.success) await fetchData();
    setIsPending(false);
  };
  
  const renderLoading = () => (
      <TableRow>
          <TableCell colSpan={5} className="h-24 text-center">
              <div className="flex items-center justify-center gap-2 text-muted-foreground">
                  <Loader2 className="h-5 w-5 animate-spin" />
                  <span>Caricamento imballi...</span>
              </div>
          </TableCell>
      </TableRow>
  );

  return (
    <AdminAuthGuard>
      <AppShell>
        <div className="space-y-6">
          <div className="flex justify-between items-center">
            <header>
              <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
                <Archive className="h-8 w-8 text-primary" />
                Gestione Imballi (Tare)
              </h1>
              <p className="text-muted-foreground mt-2">
                Definisci gli imballi e le relative tare da associare ai materiali.
              </p>
            </header>
            <div className="flex items-center gap-2">
                <Button onClick={() => handleOpenDialog()} disabled={isLoading}>
                    <PlusCircle className="mr-2 h-4 w-4" />
                    Nuovo Imballo
                </Button>
            </div>
          </div>

          <Card>
            <CardHeader>
              <CardTitle>Anagrafica Imballi</CardTitle>
              <CardDescription>Elenco degli imballi, del loro peso (tara) e a cosa sono associati.</CardDescription>
            </CardHeader>
            <CardContent>
              <div className="overflow-x-auto">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Nome Imballo</TableHead>
                      <TableHead>Descrizione</TableHead>
                      <TableHead>Peso (Kg)</TableHead>
                      <TableHead>Associazione</TableHead>
                      <TableHead className="text-right">Azioni</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {isLoading ? renderLoading() : items.length > 0 ? (
                      items.map((item) => (
                        <TableRow key={item.id}>
                          <TableCell className="font-medium">{item.name}</TableCell>
                          <TableCell>{item.description || 'N/D'}</TableCell>
                          <TableCell>{Number(item.weightKg)}</TableCell>
                           <TableCell>
                            <div className="flex flex-wrap gap-1">
                                {item.associatedTypes && item.associatedTypes.length > 0 ? 
                                item.associatedTypes.map(type => <Badge key={type} variant="outline">{type}</Badge>) :
                                <span className="text-xs text-muted-foreground">Nessuna</span>
                                }
                            </div>
                           </TableCell>
                          <TableCell className="text-right space-x-2">
                            <Button variant="outline" size="icon" onClick={() => handleOpenDialog(item)}>
                              <Edit className="h-4 w-4" />
                            </Button>
                            <AlertDialog>
                              <AlertDialogTrigger asChild>
                                <Button variant="destructive" size="icon">
                                  <Trash2 className="h-4 w-4" />
                                </Button>
                              </AlertDialogTrigger>
                              <AlertDialogContent>
                                <AlertDialogHeader>
                                  <AlertDialogTitle>Sei sicuro?</AlertDialogTitle>
                                  <AlertDialogDescription>
                                    Questa azione non può essere annullata. L'imballo verrà eliminato.
                                  </AlertDialogDescription>
                                </AlertDialogHeader>
                                <AlertDialogFooter>
                                  <AlertDialogCancel>Annulla</AlertDialogCancel>
                                  <AlertDialogAction onClick={() => handleDelete(item.id)}>Continua</AlertDialogAction>
                                </AlertDialogFooter>
                              </AlertDialogContent>
                            </AlertDialog>
                          </TableCell>
                        </TableRow>
                      ))
                    ) : (
                      <TableRow>
                        <TableCell colSpan={5} className="text-center h-24">Nessun imballo trovato.</TableCell>
                      </TableRow>
                    )}
                  </TableBody>
                </Table>
              </div>
            </CardContent>
          </Card>
        
        <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
          <DialogContent className="sm:max-w-md" onInteractOutside={(e) => {if (!isPending) handleCloseDialog();}}>
            <DialogHeader>
              <DialogTitle>{editingItem ? "Modifica Imballo" : "Aggiungi Nuovo Imballo"}</DialogTitle>
              <DialogDescription>
                Compila i campi per definire un nuovo tipo di imballo e la sua tara.
              </DialogDescription>
            </DialogHeader>
            <Form {...form}>
              <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4 py-4 max-h-[70vh] overflow-y-auto pr-4">
                <FormField control={form.control} name="name" render={({ field }) => (
                  <FormItem>
                    <FormLabel>Nome</FormLabel>
                    <FormControl><Input placeholder="Es. Rocchetto Grande" {...field} /></FormControl>
                    <FormMessage />
                  </FormItem>
                )} />
                <FormField control={form.control} name="description" render={({ field }) => (
                  <FormItem>
                    <FormLabel>Descrizione (Opzionale)</FormLabel>
                    <FormControl><Input placeholder="Materiale, dimensioni, etc." {...field} /></FormControl>
                    <FormMessage />
                  </FormItem>
                )} />
                <FormField control={form.control} name="weightKg" render={({ field }) => (
                  <FormItem>
                    <FormLabel>Peso / Tara (Kg)</FormLabel>
                     <div className="relative">
                        <Weight className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                        <FormControl><Input type="number" step="0.001" placeholder="Es. 0.150" className="pl-9" {...field} /></FormControl>
                     </div>
                    <FormMessage />
                  </FormItem>
                )} />

                <FormField
                    control={form.control}
                    name="associatedTypes"
                    render={() => (
                      <FormItem>
                        <div className="mb-4">
                          <FormLabel className="flex items-center gap-2"><Link2 className="h-4 w-4"/> Associazione</FormLabel>
                          <FormDescription>
                            Seleziona per cosa può essere usato questo imballo.
                          </FormDescription>
                        </div>
                        <div className="grid grid-cols-2 gap-2 p-4 border rounded-md">
                        {packagingAssociationTypes.map((item) => (
                          <FormField
                            key={item}
                            control={form.control}
                            name="associatedTypes"
                            render={({ field }) => {
                              return (
                                <FormItem
                                  key={item}
                                  className="flex flex-row items-start space-x-3 space-y-0"
                                >
                                  <FormControl>
                                    <Checkbox
                                      checked={field.value?.includes(item)}
                                      onCheckedChange={(checked) => {
                                        const currentValue = field.value || [];
                                        return checked
                                          ? field.onChange([...currentValue, item])
                                          : field.onChange(currentValue.filter((value) => value !== item));
                                      }}
                                    />
                                  </FormControl>
                                  <FormLabel className="font-normal">
                                    {item}
                                  </FormLabel>
                                </FormItem>
                              )
                            }}
                          />
                        ))}
                        </div>
                        <FormMessage />
                      </FormItem>
                    )}
                  />


                <DialogFooter>
                  <Button type="button" variant="outline" onClick={handleCloseDialog} disabled={isPending}>Annulla</Button>
                  <Button type="submit" disabled={isPending}>
                    {isPending ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : null}
                    {editingItem ? "Salva Modifiche" : "Crea Imballo"}
                  </Button>
                </DialogFooter>
              </form>
            </Form>
          </DialogContent>
        </Dialog>
      </div>
    </AppShell>
  </AdminAuthGuard>
  );
}

"use client";

import React, { useState, useEffect } from 'react';
import AdminAuthGuard from '@/components/AdminAuthGuard';
import AppShell from '@/components/layout/AppShell';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { useToast } from '@/hooks/use-toast';
import { LockKeyhole, Save, Loader2, RefreshCw } from 'lucide-react';
import { getPrivacyPolicy, savePrivacyPolicy } from './actions';
import { useAuth } from '@/components/auth/AuthProvider';
import { format } from 'date-fns';
import { it } from 'date-fns/locale';
import { Textarea } from '@/components/ui/textarea';
import { Skeleton } from '@/components/ui/skeleton';


export default function PrivacyManagementPage() {
  const [policy, setPolicy] = useState<{ content: string, lastUpdated: string | null }>({ content: '', lastUpdated: null });
  const [editedContent, setEditedContent] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [isPending, setIsPending] = useState(false);
  const { user } = useAuth();
  const { toast } = useToast();
  
  const fetchPolicy = async () => {
    setIsLoading(true);
    try {
        const data = await getPrivacyPolicy();
        setPolicy(data);
        // Convert simple HTML to text for textarea
        setEditedContent(data.content.replace(/<p>/g, '').replace(/<\/p>/g, '\n\n').replace(/<strong>/g, '').replace(/<\/strong>/g, '').trim());
    } catch (error) {
        toast({
            variant: "destructive",
            title: "Errore",
            description: "Impossibile caricare l'informativa sulla privacy.",
        });
    }
    setIsLoading(false);
  };

  useEffect(() => {
    fetchPolicy();
  }, []);

  const handleSave = async () => {
    if (!user) return;
    setIsPending(true);
    // Convert text back to simple HTML
    const htmlContent = editedContent
      .split('\n')
      .filter(p => p.trim() !== '')
      .map(p => `<p>${p}</p>`)
      .join('');
      
    const result = await savePrivacyPolicy(htmlContent, user.uid);
    toast({
      title: result.success ? "Operazione Completata" : "Operazione Fallita",
      description: result.message,
      variant: result.success ? "default" : "destructive",
      duration: 9000,
    });
    if (result.success) {
      await fetchPolicy();
    }
    setIsPending(false);
  };

  return (
    <AdminAuthGuard>
      <AppShell>
        <div className="space-y-6">
          <header className="space-y-2">
            <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
              <LockKeyhole className="h-8 w-8 text-primary" />
              Gestione Informativa Privacy
            </h1>
            <p className="text-muted-foreground">
              Modifica il testo dell'informativa sulla privacy che gli operatori devono accettare al primo accesso o dopo una modifica.
            </p>
          </header>

          <Card>
            <CardHeader>
              <div className="flex justify-between items-center flex-wrap gap-2">
                <div>
                    <CardTitle>Editor Informativa</CardTitle>
                    <CardDescription>
                        {policy.lastUpdated 
                            ? `Ultimo aggiornamento: ${format(new Date(policy.lastUpdated), 'dd MMMM yyyy HH:mm', { locale: it })}`
                            : "Nessuna modifica ancora salvata."}
                    </CardDescription>
                </div>
                <Button onClick={handleSave} disabled={isPending || isLoading || editedContent === policy.content}>
                    {isPending ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <Save className="mr-2 h-4 w-4" />}
                    Salva e Richiedi Nuova Firma
                </Button>
              </div>
            </CardHeader>
            <CardContent>
              {isLoading ? (
                <div className="space-y-2">
                  <Skeleton className="h-40 w-full" />
                </div>
              ) : (
                <Textarea
                    value={editedContent}
                    onChange={(e) => setEditedContent(e.target.value)}
                    className="w-full h-80 p-4 border rounded-md bg-background"
                    placeholder="Scrivi qui il testo dell'informativa..."
                />
              )}
            </CardContent>
          </Card>
        </div>
      </AppShell>
    </AdminAuthGuard>
  );
}

import type { JobOrder, JobPhase, Operator, OverallStatus } from '@/types';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card';
import { Progress } from '@/components/ui/progress';
import { StatusBadge } from '@/components/production-console/StatusBadge';
import { Package, Building, Circle, Hourglass, CheckCircle2, ShieldAlert, PauseCircle, Calendar, Printer, MoreVertical, FastForward, CheckSquare, CornerDownRight, CornerUpLeft, Undo2, ClipboardList, Factory, Users, PowerOff, RefreshCcw, EyeOff, ListOrdered, ArrowUp, ArrowDown, ArchiveRestore, Boxes, User, BarChart3, Copy, Timer, HelpCircle, ChevronDown } from 'lucide-react';
import { format, parseISO, isPast, differenceInSeconds } from 'date-fns';
import Link from 'next/link';
import { it } from 'date-fns/locale';
import { cn } from '@/lib/utils';
import { Button } from '@/components/ui/button';
import { TooltipProvider, Tooltip, TooltipTrigger, TooltipContent } from '@/components/ui/tooltip';
import React, { useState, useMemo, useEffect } from 'react';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
  DropdownMenuSeparator,
} from "@/components/ui/dropdown-menu";
import {
  ContextMenu,
  ContextMenuContent,
  ContextMenuItem,
  ContextMenuTrigger,
} from "@/components/ui/context-menu";
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from "@/components/ui/collapsible";
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import { Checkbox } from '@/components/ui/checkbox';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import { Separator } from '@/components/ui/separator';
import type { ProductionTimeData } from '@/app/admin/production-console/actions';
import { Loader2 } from 'lucide-react';


interface ActivePhaseInfo {
  phaseId: string;
  phaseName: string;
  operators: { id: string; name: string }[];
}

function getPhaseIcon(status: JobPhase['status']) {
  switch (status) {
    case 'pending': return <Circle className="h-4 w-4 text-muted-foreground" />;
    case 'in-progress': return <Hourglass className="h-4 w-4 text-blue-500 animate-spin" />;
    case 'paused': return <PauseCircle className="h-4 w-4 text-orange-500" />;
    case 'completed': return <CheckCircle2 className="h-4 w-4 text-primary" />;
    case 'skipped': return <EyeOff className="h-4 w-4 text-muted-foreground" />;
    default: return <Circle className="h-4 w-4 text-muted-foreground" />;
  }
}

function formatTime(seconds: number): string {
    if (seconds < 0) seconds = 0;
    const totalMinutes = Math.round(seconds / 60);
    const h = Math.floor(totalMinutes / 60);
    const m = totalMinutes % 60;
    return `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}`;
}

function PhaseLiveTimer({ phase }: { phase: JobPhase }) {
  const [elapsedTime, setElapsedTime] = useState('00:00');

  useEffect(() => {
    let interval: NodeJS.Timeout;

    const activeWorkPeriod = phase.workPeriods?.find(wp => wp.end === null);

    if (phase.status === 'in-progress' && activeWorkPeriod) {
      const startTime = new Date(activeWorkPeriod.start).getTime();
      
      const updateTimer = () => {
        const now = Date.now();
        const totalSeconds = Math.floor((now - startTime) / 1000);
        setElapsedTime(formatTime(totalSeconds));
      };

      updateTimer(); // Initial update
      interval = setInterval(updateTimer, 1000);
    } else {
        const totalSeconds = (phase.workPeriods || []).reduce((acc, wp) => {
            if(wp.end) {
                return acc + differenceInSeconds(new Date(wp.end), new Date(wp.start));
            }
            return acc;
        }, 0);
        setElapsedTime(formatTime(totalSeconds));
    }

    return () => clearInterval(interval);
  }, [phase]);

  return <p className="font-mono text-lg">{elapsedTime}</p>;
}


export default function JobOrderCard({ 
    jobOrder,
    allOperators,
    analysisData,
    onFetchAnalysis,
    isAnalysisLoading,
    groupPhases,
    onProblemClick, 
    onForceFinishClick,
    onRevertForceFinishClick,
    onToggleGuainaClick, 
    onRevertPhaseClick, 
    onForcePauseClick,
    onForceCompleteClick,
    onResetJobOrderClick,
    onOpenPhaseManager,
    onOpenMaterialManager,
    onRevertCompletionClick,
    isSelected,
    onSelect,
    overallStatus,
    onNavigateToAnalysis,
    onCopyArticleCode,
}: { 
    jobOrder: JobOrder;
    allOperators: Operator[];
    analysisData?: ProductionTimeData | null;
    onFetchAnalysis: () => void;
    isAnalysisLoading: boolean;
    groupPhases?: JobPhase[];
    onProblemClick: () => void; 
    onForceFinishClick: (jobId: string) => void;
    onRevertForceFinishClick: (jobId: string) => void;
    onToggleGuainaClick: (jobId: string, phaseId: string, currentState: 'default' | 'postponed') => void; 
    onRevertPhaseClick: (jobId: string, phaseId: string) => void; 
    onForcePauseClick: (jobId: string, operatorIds: string[]) => void; 
    onForceCompleteClick: (jobId: string) => void;
    onResetJobOrderClick: (jobId: string) => void;
    onOpenPhaseManager: (item: JobOrder) => void;
    onOpenMaterialManager: (item: JobOrder) => void;
    onRevertCompletionClick: (jobId: string) => void;
    isSelected: boolean;
    onSelect: (jobId: string) => void;
    overallStatus: OverallStatus;
    onNavigateToAnalysis: (articleCode: string) => void;
    onCopyArticleCode: (articleCode: string) => void;
}) {
  const [isPauseDialogOpen, setIsPauseDialogOpen] = useState(false);
  const [selectedOperatorsToPause, setSelectedOperatorsToPause] = useState<string[]>([]);
  const hasMaterialMissing = jobOrder.phases.some(p => p.materialStatus === 'missing');
  const [remainingTime, setRemainingTime] = useState<string | null>(null);

   const updateRemainingTime = React.useCallback(() => {
    if (!analysisData || !analysisData.isTimeCalculationReliable) {
      setRemainingTime(null);
      return;
    }
    const completedPhasesTotalMinutes = jobOrder.phases
      .filter(p => p.status === 'completed' && analysisData.phases[p.name])
      .reduce((acc, p) => acc + (analysisData.phases[p.name].averageMinutesPerPiece * jobOrder.qta), 0);

    const totalEstimatedMinutes = analysisData.averageMinutesPerPiece * jobOrder.qta;
    const remainingMinutes = totalEstimatedMinutes - completedPhasesTotalMinutes;
    
    setRemainingTime(formatTime(remainingMinutes * 60));
  }, [analysisData, jobOrder]);
  
  useEffect(() => {
    // We only automatically calculate the time if the data is already present.
    if (analysisData) {
      updateRemainingTime();
    }
  }, [analysisData, updateRemainingTime]);


  const activePhasesWithOperators = useMemo((): ActivePhaseInfo[] => {
    const activePhasesMap = new Map<string, ActivePhaseInfo>();
    const phasesToInspect = groupPhases || jobOrder.phases || [];
    
    phasesToInspect.forEach(phase => {
        if (phase.status === 'in-progress') {
            const phaseOperators: ActivePhaseInfo['operators'] = [];
            (phase.workPeriods || []).forEach(wp => {
                if (wp.end === null) {
                    const operator = allOperators.find(op => op.id === wp.operatorId);
                    if (operator) {
                        phaseOperators.push({ id: operator.id, name: operator.nome });
                    }
                }
            });

            // Filter out duplicates before adding to the map
            const uniqueOperators = Array.from(new Map(phaseOperators.map(op => [op.id, op])).values());

            if (uniqueOperators.length > 0) {
                if (!activePhasesMap.has(phase.id)) {
                    activePhasesMap.set(phase.id, {
                        phaseId: phase.id,
                        phaseName: phase.name,
                        operators: [],
                    });
                }
                activePhasesMap.get(phase.id)!.operators.push(...uniqueOperators);
            }
        }
    });

    return Array.from(activePhasesMap.values());
  }, [jobOrder, groupPhases, allOperators]);
  
  const handleOpenPauseDialog = () => {
    setSelectedOperatorsToPause([]);
    setIsPauseDialogOpen(true);
  };
  
  const handleConfirmPause = () => {
    if (selectedOperatorsToPause.length > 0) {
      onForcePauseClick(jobOrder.id, selectedOperatorsToPause);
    }
    setIsPauseDialogOpen(false);
  };

  const toggleOperatorSelection = (opId: string) => {
    setSelectedOperatorsToPause(prev =>
      prev.includes(opId) ? prev.filter(currentId => currentId !== opId) : [...prev, opId]
    );
  };

  const toggleSelectAll = () => {
    const allActiveOperatorIds = activePhasesWithOperators.flatMap(p => p.operators.map(op => op.id));
    if (selectedOperatorsToPause.length === allActiveOperatorIds.length) {
      setSelectedOperatorsToPause([]);
    } else {
      setSelectedOperatorsToPause(allActiveOperatorIds);
    }
  };
  
  const completedPhasesCount = jobOrder.phases.filter(p => p.status === 'completed' || p.status === 'skipped').length;
  const progressPercentage = jobOrder.phases.length > 0 ? (completedPhasesCount / jobOrder.phases.length) * 100 : 0;
  
  const deliveryDateString = jobOrder.dataConsegnaFinale;
  const deliveryDate = deliveryDateString && /^\d{4}-\d{2}-\d{2}$/.test(deliveryDateString)
    ? parseISO(deliveryDateString)
    : null;
    
  const isOverdue = deliveryDate && isPast(new Date(deliveryDate.toDateString())) && overallStatus !== 'Completata';
  
  const isAnyPhaseInProgress = activePhasesWithOperators.length > 0;
  const canForceFinish = ['In Preparazione', 'Pronto per Produzione', 'In Lavorazione'].includes(overallStatus);
  const canForceComplete = !isAnyPhaseInProgress && overallStatus !== 'Completata';

  const isForcedToFinish = jobOrder.phases.some(p => p.forced);


  const guainaPhase = jobOrder.phases.find(p => p.name === "Taglio Guaina");
  
  const firstProductionPhase = jobOrder.phases
      .filter(p => p.type === 'production')
      .sort((a,b) => a.sequence - b.sequence)[0];
      
  const isGuainaPostponed = guainaPhase && firstProductionPhase && guainaPhase.sequence > firstProductionPhase.sequence;

  const isWorkInProgress = jobOrder.phases.some(p => p.status === 'in-progress' || p.status === 'paused');
  const canToggleGuaina = guainaPhase && (guainaPhase.status === 'pending' || guainaPhase.status === 'paused') && !isWorkInProgress;
  
  const isPartOfGroup = !!jobOrder.workGroupId;

  return (
    <>
      <Collapsible
        asChild
        className="w-full"
      >
        <Card
            className={cn(
            "relative flex flex-col h-full bg-card hover:bg-card/90 transition-all duration-300", 
            (jobOrder.isProblemReported || hasMaterialMissing) && "cursor-pointer border-destructive/50 hover:border-destructive",
            isSelected && "border-primary ring-2 ring-primary/50",
            isPartOfGroup && "shadow-none border-border/70",
            isOverdue && 'border-destructive/30'
            )}
            onClick={(jobOrder.isProblemReported || hasMaterialMissing) ? onProblemClick : undefined}
        >
          <div className="flex-grow">
            <CardHeader className="pb-4 space-y-2">
                <div className="flex justify-between items-center gap-4">
                    <div className="flex items-center gap-3">
                        {!isPartOfGroup && (
                          <Checkbox
                              checked={isSelected}
                              onCheckedChange={() => onSelect(jobOrder.id)}
                              aria-label={`Seleziona commessa ${jobOrder.id}`}
                              className="h-4 w-4"
                          />
                        )}
                        <CollapsibleTrigger asChild>
                          <div className="flex items-center gap-2 cursor-pointer group">
                              <CardTitle className="font-headline text-lg">{jobOrder.ordinePF}</CardTitle>
                               <ChevronDown className="h-5 w-5 text-muted-foreground transition-transform duration-200 group-data-[state=open]:-rotate-180" />
                          </div>
                        </CollapsibleTrigger>
                    </div>
                    <StatusBadge status={overallStatus} />
                </div>
                <div className="flex justify-between items-center gap-4">
                    <CardDescription className="flex items-center gap-2">
                        <Building className="h-4 w-4 text-muted-foreground" />
                        {jobOrder.cliente}
                    </CardDescription>
                    <div className="flex items-center gap-1">
                        {!isPartOfGroup && (
                            <TooltipProvider>
                                <Tooltip>
                                    <TooltipTrigger asChild>
                                        <Button asChild variant="ghost" size="icon" className="h-8 w-8 text-muted-foreground">
                                            <Link href={`/admin/reports/${jobOrder.id}`}><CheckSquare className="h-4 w-4" /></Link>
                                        </Button>
                                    </TooltipTrigger>
                                    <TooltipContent><p>Vedi Dettagli Report</p></TooltipContent>
                                </Tooltip>
                                <Tooltip>
                                    <TooltipTrigger asChild>
                                        <Button asChild variant="ghost" size="icon" className="h-8 w-8 text-muted-foreground">
                                            <Link href={`/admin/data-management/print?jobId=${encodeURIComponent(jobOrder.id)}`} target="_blank"><Printer className="h-4 w-4" /></Link>
                                        </Button>
                                    </TooltipTrigger>
                                    <TooltipContent><p>Stampa Scheda</p></TooltipContent>
                                </Tooltip>
                            </TooltipProvider>
                        )}
                        {!isPartOfGroup && (
                          <DropdownMenu>
                              <DropdownMenuTrigger asChild>
                                  <Button variant="ghost" size="icon" className="h-8 w-8" onClick={e => e.stopPropagation()}>
                                      <MoreVertical className="h-4 w-4" />
                                  </Button>
                              </DropdownMenuTrigger>
                              <DropdownMenuContent align="end">
                                 <DropdownMenuItem onSelect={() => onOpenPhaseManager(jobOrder)} disabled={overallStatus === 'Completata'}>
                                      <ListOrdered className="mr-2 h-4 w-4" />
                                      <span>Gestisci Fasi</span>
                                  </DropdownMenuItem>
                                  <DropdownMenuItem onSelect={() => onOpenMaterialManager(jobOrder)} disabled={overallStatus === 'Completata'}>
                                      <Boxes className="mr-2 h-4 w-4" />
                                      <span>Gestisci Materiali</span>
                                  </DropdownMenuItem>
                                  {canToggleGuaina && guainaPhase && (
                                      <AlertDialog>
                                          <AlertDialogTrigger asChild>
                                              <DropdownMenuItem onSelect={(e) => e.preventDefault()}>
                                              {isGuainaPostponed ? <CornerUpLeft className="mr-2 h-4 w-4" /> : <CornerDownRight className="mr-2 h-4 w-4" />}
                                              <span>{isGuainaPostponed ? 'Ripristina Guaina' : 'Posticipa Guaina'}</span>
                                              </DropdownMenuItem>
                                          </AlertDialogTrigger>
                                          <AlertDialogContent>
                                              <AlertDialogHeader>
                                                  <AlertDialogTitle>Conferma Spostamento Fase</AlertDialogTitle>
                                                  <AlertDialogDescription>
                                                  Stai per {isGuainaPostponed ? 'riportare la fase "Taglio Guaina" alla sua posizione originale.' : 'posticipare la fase "Taglio Guaina" a dopo la produzione.'} Vuoi continuare?
                                                  </AlertDialogDescription>
                                              </AlertDialogHeader>
                                              <AlertDialogFooter>
                                                  <AlertDialogCancel>Annulla</AlertDialogCancel>
                                                  <AlertDialogAction onClick={() => onToggleGuainaClick(jobOrder.id, guainaPhase.id, isGuainaPostponed ? 'postponed' : 'default')}>Conferma</AlertDialogAction>
                                              </AlertDialogFooter>
                                          </AlertDialogContent>
                                      </AlertDialog>
                                  )}
                                   <DropdownMenuSeparator />
                                   <DropdownMenuItem onSelect={handleOpenPauseDialog} disabled={!isAnyPhaseInProgress}>
                                      <Users className="mr-2 h-4 w-4" />
                                      <span>Forza Pausa Operatori</span>
                                  </DropdownMenuItem>
                                   {canForceFinish && (
                                      <AlertDialog>
                                          <AlertDialogTrigger asChild><DropdownMenuItem onSelect={(e) => e.preventDefault()}><FastForward className="mr-2 h-4 w-4" />Forza a Finitura</DropdownMenuItem></AlertDialogTrigger>
                                          <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Conferma Azione</AlertDialogTitle><AlertDialogDescription>Forzare tutte le fasi di produzione a 'completata'?</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={() => onForceFinishClick(jobOrder.id)}>Conferma</AlertDialogAction></AlertDialogFooter></AlertDialogContent>
                                      </AlertDialog>
                                  )}
                                   {isForcedToFinish && (
                                      <AlertDialog>
                                          <AlertDialogTrigger asChild><DropdownMenuItem onSelect={(e) => e.preventDefault()} className="text-amber-600 focus:text-amber-700"><Undo2 className="mr-2 h-4 w-4" />Annulla Forzatura</DropdownMenuItem></AlertDialogTrigger>
                                          <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Annullare la Forzatura?</AlertDialogTitle><AlertDialogDescription>Le fasi completate forzatamente verranno resettate allo stato 'in attesa'.</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={() => onRevertForceFinishClick(jobOrder.id)}>Sì, annulla</AlertDialogAction></AlertDialogFooter></AlertDialogContent>
                                      </AlertDialog>
                                  )}
                                  {canForceComplete && (
                                      <AlertDialog>
                                          <AlertDialogTrigger asChild><DropdownMenuItem onSelect={(e) => e.preventDefault()}><PowerOff className="mr-2 h-4 w-4" />Forza Chiusura Commessa</DropdownMenuItem></AlertDialogTrigger>
                                          <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Conferma Azione</AlertDialogTitle><AlertDialogDescription>Stai per impostare manualmente questa commessa come 'Completata'.</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={() => onForceCompleteClick(jobOrder.id)}>Conferma</AlertDialogAction></AlertDialogFooter></AlertDialogContent>
                                      </AlertDialog>
                                  )}
                                   {jobOrder.forcedCompletion && (
                                    <AlertDialog>
                                      <AlertDialogTrigger asChild>
                                        <DropdownMenuItem onSelect={(e) => e.preventDefault()} className="text-amber-600 focus:text-amber-700">
                                          <ArchiveRestore className="mr-2 h-4 w-4" />
                                          <span>Riapri Commessa</span>
                                        </DropdownMenuItem>
                                      </AlertDialogTrigger>
                                      <AlertDialogContent>
                                        <AlertDialogHeader>
                                          <AlertDialogTitle>Sei sicuro di voler riaprire?</AlertDialogTitle>
                                          <AlertDialogDescription>
                                            Questa azione riporterà la commessa al suo ultimo stato di avanzamento, annullando la chiusura forzata.
                                          </AlertDialogDescription>
                                        </AlertDialogHeader>
                                        <AlertDialogFooter>
                                          <AlertDialogCancel>Annulla</AlertDialogCancel>
                                          <AlertDialogAction onClick={() => onRevertCompletionClick(jobOrder.id)}>Sì, riapri</AlertDialogAction>
                                        </AlertDialogFooter>
                                      </AlertDialogContent>
                                    </AlertDialog>
                                  )}
                                  <DropdownMenuSeparator />
                                  <AlertDialog>
                                      <AlertDialogTrigger asChild>
                                      <DropdownMenuItem onSelect={(e) => e.preventDefault()} className="text-destructive focus:text-destructive">
                                          <RefreshCcw className="mr-2 h-4 w-4" />
                                          <span>Annulla e Resetta</span>
                                      </DropdownMenuItem>
                                      </AlertDialogTrigger>
                                      <AlertDialogContent>
                                      <AlertDialogHeader>
                                          <AlertDialogTitle>Sei assolutamente sicuro?</AlertDialogTitle>
                                          <AlertDialogDescription>
                                          Questa azione è irreversibile. La commessa <span className="font-bold">{jobOrder.ordinePF}</span> verrà riportata allo stato "pianificata", le lavorazioni azzerate e lo stock dei materiali consumati verrà ripristinato.
                                          </AlertDialogDescription>
                                      </AlertDialogHeader>
                                      <AlertDialogFooter>
                                          <AlertDialogCancel>Annulla</AlertDialogCancel>
                                          <AlertDialogAction onClick={() => onResetJobOrderClick(jobOrder.id)} className="bg-destructive hover:bg-destructive/90">Sì, annulla e resetta</AlertDialogAction>
                                      </AlertDialogFooter>
                                      </AlertDialogContent>
                                  </AlertDialog>
                              </DropdownMenuContent>
                          </DropdownMenu>
                        )}
                    </div>
                </div>

                {(jobOrder.isProblemReported || hasMaterialMissing) && (
                    <p className="text-sm text-destructive font-semibold mt-2 flex items-center">
                        <ShieldAlert className="mr-2 h-4 w-4" /> 
                        {jobOrder.isProblemReported ? "Problema segnalato!" : "Materiale mancante!"}
                    </p>
                )}
            </CardHeader>
            <CardContent className="pt-0 pb-4 px-6 space-y-4">
                <div className="flex justify-between items-start gap-4">
                    <div className="space-y-3 text-sm">
                        <p className="flex items-center gap-2 text-muted-foreground">
                            <ClipboardList className="h-4 w-4" />
                            <span className="font-semibold text-foreground">{jobOrder.numeroODLInterno || 'N/D'}</span>
                        </p>
                        <p className="flex items-center gap-2 text-muted-foreground">
                            <Factory className="h-4 w-4" />
                            {jobOrder.department}
                        </p>
                        <ContextMenu>
                          <ContextMenuTrigger>
                            <p className="flex items-center gap-2 text-muted-foreground hover:text-primary cursor-pointer">
                                <Package className="h-4 w-4" />
                                <span className="hover:underline">{jobOrder.details}</span>
                            </p>
                          </ContextMenuTrigger>
                           <ContextMenuContent>
                              <ContextMenuItem onSelect={() => onNavigateToAnalysis(jobOrder.details)}>
                                  <BarChart3 className="mr-2 h-4 w-4"/>
                                  Analisi Tempi Articolo
                              </ContextMenuItem>
                              <ContextMenuItem onSelect={() => onCopyArticleCode(jobOrder.details)}>
                                  <Copy className="mr-2 h-4 w-4"/>
                                  Copia Codice Articolo
                              </ContextMenuItem>
                          </ContextMenuContent>
                        </ContextMenu>
                        {deliveryDate && (
                            <p className={cn("flex items-center gap-2 font-medium", isOverdue ? "text-destructive" : "text-muted-foreground")}>
                                <Calendar className="h-4 w-4" />
                                <span>Consegna: {format(deliveryDate, 'dd MMM yyyy', { locale: it })}</span>
                            </p>
                        )}
                    </div>
                    <div className="text-right flex-shrink-0">
                        <div className="flex items-center gap-1 justify-end">
                          <Package className="h-4 w-4 text-muted-foreground" />
                          <span className="font-bold">{jobOrder.qta}</span>
                          <span className="text-muted-foreground text-xs">pz</span>
                        </div>
                    </div>
                </div>

                {isAnyPhaseInProgress && (
                  <div className="rounded-lg border-2 border-cyan-400/50 bg-cyan-900/20 p-3 space-y-3 animate-pulse">
                      <h4 className="text-sm font-semibold text-foreground/90 flex items-center gap-2">
                          <Hourglass className="h-4 w-4 text-cyan-500"/>
                          Operatori Attivi
                      </h4>
                      {activePhasesWithOperators.map(info => (
                          <div key={info.phaseId} className="pl-2">
                            <p className="font-semibold text-primary">{info.phaseName}:</p>
                            <div className="flex flex-wrap gap-2 pt-1">
                                {info.operators.map(op => (
                                    <Badge key={op.id} variant="outline" className="flex items-center gap-1.5 py-1 bg-background">
                                        <User className="h-3 w-3" />
                                        {op.name}
                                    </Badge>
                                ))}
                            </div>
                          </div>
                      ))}
                  </div>
                )}
                
                <div className="p-3 rounded-lg border bg-background/50 space-y-2">
                    {remainingTime ? (
                        <>
                            <div className="flex justify-between items-center">
                                <div className="flex items-center gap-2 text-sm font-semibold">
                                    <Timer className="h-4 w-4 text-primary"/>
                                    Ore Rimanenti Stimate
                                </div>
                                <TooltipProvider>
                                    <Tooltip>
                                        <TooltipTrigger asChild>
                                            <Button variant="ghost" size="icon" className="h-6 w-6" onClick={(e) => { e.stopPropagation(); updateRemainingTime(); }}>
                                                <RefreshCcw className="h-4 w-4" />
                                            </Button>
                                        </TooltipTrigger>
                                        <TooltipContent><p>Aggiorna stima</p></TooltipContent>
                                    </Tooltip>
                                </TooltipProvider>
                            </div>
                            <p className="font-mono text-xl font-bold text-primary text-center">{remainingTime}</p>
                        </>
                    ) : (
                        <Button onClick={onFetchAnalysis} disabled={isAnalysisLoading} className="w-full">
                            {isAnalysisLoading ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Timer className="mr-2 h-4 w-4" />}
                            Calcola Stima Tempi
                        </Button>
                    )}
                </div>
                
                <div className="w-full pt-2">
                    <div className="flex justify-between text-xs text-muted-foreground mb-1">
                        <span>Progresso</span>
                        <span>{Math.round(progressPercentage)}%</span>
                    </div>
                    <Progress value={progressPercentage} className="h-2" />
                </div>
            </CardContent>
          </div>
          
          <CollapsibleContent>
            <CardContent className="flex-grow space-y-4 pt-4 px-6">
              <Separator />
              <div className="space-y-2">
                <h4 className="text-sm font-semibold text-foreground/80">Avanzamento Fasi</h4>
                {jobOrder.phases && jobOrder.phases.length > 0 ? (
                    jobOrder.phases.sort((a,b) => a.sequence - b.sequence).map(phase => (
                        <div key={phase.id} className="p-2 rounded-lg border bg-background/50 space-y-2">
                            <div className="flex items-center justify-between gap-2">
                                <div className="flex items-center gap-2">
                                    {getPhaseIcon(phase.status)}
                                    <span className={cn("text-xs font-semibold uppercase tracking-wider", phase.status === 'skipped' && 'line-through text-muted-foreground')}>{phase.name}</span>
                                </div>
                                {phase.status === 'completed' && overallStatus !== 'Completata' && !isPartOfGroup && (
                                    <AlertDialog>
                                        <AlertDialogTrigger asChild>
                                            <Button variant="ghost" size="icon" className="h-6 w-6 text-muted-foreground hover:text-destructive">
                                                <Undo2 className="h-4 w-4" />
                                            </Button>
                                        </AlertDialogTrigger>
                                        <AlertDialogContent>
                                            <AlertDialogHeader><AlertDialogTitle>Ripristinare la fase?</AlertDialogTitle><AlertDialogDescription>Questa azione riporterà la fase "{phase.name}" allo stato di pausa, conservando il tempo di lavoro già registrato. Sei sicuro?</AlertDialogDescription></AlertDialogHeader>
                                            <AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={() => onRevertPhaseClick(jobOrder.id, phase.id)}>Sì, ripristina</AlertDialogAction></AlertDialogFooter>
                                        </AlertDialogContent>
                                    </AlertDialog>
                                )}
                            </div>
                            <div className="grid grid-cols-2 gap-2 text-center">
                                 <div className="p-1 rounded-md bg-muted/50">
                                     <Label className="text-xs text-muted-foreground">Tempo eff.</Label>
                                     <PhaseLiveTimer phase={phase} />
                                 </div>
                                 <div className="p-1 rounded-md bg-muted/50">
                                     <Label className="text-xs text-muted-foreground">Tempo Stimato</Label>
                                     <p className="font-mono text-lg">
                                         {(analysisData?.phases[phase.name] && analysisData?.phases[phase.name].averageMinutesPerPiece > 0)
                                             ? formatTime(analysisData.phases[phase.name].averageMinutesPerPiece * jobOrder.qta * 60)
                                             : 'N/D'
                                         }
                                     </p>
                                 </div>
                            </div>
                        </div>
                    ))
                ) : (
                    <p className="text-sm text-muted-foreground">Nessuna fase definita per questa commessa.</p>
                )}
            </div>
            </CardContent>
          </CollapsibleContent>
        </Card>
      </Collapsible>

      <Dialog open={isPauseDialogOpen} onOpenChange={setIsPauseDialogOpen}>
          <DialogContent>
              <DialogHeader>
                  <DialogTitle>Seleziona Operatori da Mettere in Pausa</DialogTitle>
                  <DialogDescription>
                      Scegli quali operatori attivi sulla commessa <span className="font-bold">{jobOrder.ordinePF}</span> vuoi mettere in pausa.
                  </DialogDescription>
              </DialogHeader>
              <div className="py-4 space-y-3">
                   <div className="flex items-center space-x-2">
                      <Checkbox
                          id="select-all"
                          checked={selectedOperatorsToPause.length === activePhasesWithOperators.flatMap(p => p.operators).length && activePhasesWithOperators.length > 0}
                          onCheckedChange={toggleSelectAll}
                      />
                      <Label htmlFor="select-all">Seleziona Tutti</Label>
                  </div>
                  {activePhasesWithOperators.flatMap(p => p.operators).map(op => (
                      <div key={op.id} className="flex items-center space-x-2 p-2 rounded-md border">
                           <Checkbox
                              id={op.id}
                              checked={selectedOperatorsToPause.includes(op.id)}
                              onCheckedChange={() => toggleOperatorSelection(op.id)}
                           />
                           <Label htmlFor={op.id} className="flex-1">
                              <span className="font-semibold">{op.name}</span>
                           </Label>
                      </div>
                  ))}
                  {activePhasesWithOperators.length === 0 && <p className="text-sm text-muted-foreground text-center py-4">Nessun operatore attivo su questa commessa.</p>}
              </div>
              <DialogFooter>
                  <Button variant="outline" onClick={() => setIsPauseDialogOpen(false)}>Annulla</Button>
                  <Button onClick={handleConfirmPause} disabled={selectedOperatorsToPause.length === 0}>
                      Metti in Pausa Selezionati ({selectedOperatorsToPause.length})
                  </Button>
              </DialogFooter>
          </DialogContent>
      </Dialog>
    </>
  );
}

"use client";

import React, { useState, useMemo, useEffect, useCallback, useRef } from 'react';
import { useSearchParams, useRouter } from 'next/navigation';
import { Button } from '@/components/ui/button';
import { Card, CardHeader, CardTitle, CardDescription, CardContent } from '@/components/ui/card';
import { 
  Briefcase, 
  Loader2, 
  ShieldAlert, 
  Unlock, 
  Search, 
  Combine, 
  PowerOff, 
  Activity, 
  Calendar as CalendarIcon, 
  FastForward, 
  MoreVertical, 
  Undo2, 
  Unlink, 
  ListOrdered, 
  ArrowUp, 
  ArrowDown, 
  Circle, 
  CheckCircle2,
  Hourglass, 
  PauseCircle, 
  EyeOff, 
  RefreshCcw, 
  BarChart3, 
  Copy, 
  PlayCircle, 
  CheckSquare, 
  Boxes, 
  PackageX, 
  Package2, 
  PackageCheck,
  ChevronDown,
  AlertCircle,
  CalendarDays,
  Clock
} from 'lucide-react';
import type { JobOrder, JobPhase, Operator, WorkGroup, RawMaterial, WorkingHoursConfig, OperatorAssignment, Article, OverallStatus, ProductionSettings } from '@/types';
import { useMasterData } from '@/contexts/MasterDataProvider';
import JobOrderCard from '@/components/production-console/JobOrderCard';
import WorkGroupCard from '@/components/production-console/WorkGroupCard';
import GanttBoard from '@/components/production-console/GanttBoard';
import { getOperatorAssignments } from '@/app/admin/resource-planning/actions';
import { useToast } from '@/hooks/use-toast';
import { collection, query, where, getDocs, getDoc, doc, orderBy, limit } from 'firebase/firestore';
import { db } from '@/lib/firebase';
import { useDebounce } from '../../../hooks/use-debounce';


import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import { resolveJobProblem } from '@/app/scan-job/actions';
import { 
  forceFinishProduction, 
  toggleGuainaPhasePosition, 
  revertPhaseCompletion, 
  forcePauseOperators, 
  forceCompleteJob, 
  resetSingleCompletedJobOrder, 
  revertForceFinish, 
  forceFinishMultiple, 
  forceCompleteMultiple, 
  updatePhasesForJob, 
  revertCompletion, 
  reportMaterialMissing, 
  resolveMaterialMissing, 
  updateJobDeliveryDate,
  updateJobPrepDate,
  getAnalysisForArticle,
  getArticlesByCodes,
  getRawMaterialsByCodes,
  type ProductionTimeData
} from '@/app/admin/production-console/actions';
import { getProductionSettings } from '@/app/admin/production-settings/actions';
import { getOverallStatus } from '@/lib/types';
import { dissolveWorkGroup } from '@/app/admin/work-group-management/actions';
import { useAuth } from '@/components/auth/AuthProvider';
import { Input } from '@/components/ui/input';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { Calendar } from '@/components/ui/calendar';
import { format, isSameDay, isPast, parseISO, startOfWeek, endOfWeek, getWeek, isValid, addWeeks } from 'date-fns';
import { it } from 'date-fns/locale';
import { Label } from '@/components/ui/label';
import { Switch } from '@/components/ui/switch';
import { Checkbox } from '@/components/ui/checkbox';
import { cn } from '@/lib/utils';
import { Badge } from '@/components/ui/badge';
import { getWorkingHoursConfig } from '@/app/admin/working-hours/actions';


type FilterStatus = OverallStatus | 'all' | 'LIVE';

interface WeeklyGroup {
    weekNumber: number;
    weekLabel: string;
    items: (JobOrder | WorkGroup)[];
    totalPcs: number;
}

export default function ProductionConsoleClientPage() {
  const { 
    operators: cachedOperators, 
    articlesMap, 
    settings: cachedSettings, 
    workingHours: cachedWorkingHours,
    isLoading: isMasterLoading 
  } = useMasterData();

  const [viewMode, setViewMode] = useState<'list'|'gantt'>('list');

  const [jobOrders, setJobOrders] = useState<JobOrder[]>([]);
  const [workGroups, setWorkGroups] = useState<WorkGroup[]>([]);
  const [assignments, setAssignments] = useState<OperatorAssignment[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const isReallyLoading = isLoading || isMasterLoading;
  const [activeFilter, setActiveFilter] = useState<FilterStatus>('all');
  const [problemJob, setProblemJob] = useState<JobOrder | WorkGroup | null>(null);
  const [phaseManagedItem, setPhaseManagedItem] = useState<JobOrder | WorkGroup | null>(null);
  const [materialManagedItem, setMaterialManagedItem] = useState<JobOrder | WorkGroup | null>(null);
  const [analysisDataMap, setAnalysisDataMap] = useState<Map<string, ProductionTimeData | null>>(new Map());
  const [jobsWithLoadingAnalysis, setJobsWithLoadingAnalysis] = useState<Set<string>>(new Set());

  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [isDataRefreshing, setIsDataRefreshing] = useState(false);
  
  const searchParams = useSearchParams();
  const groupIdFromUrl = searchParams.get('groupId');
  const searchFromUrl = searchParams.get('search');
  
  const [searchTerm, setSearchTerm] = useState(groupIdFromUrl || searchFromUrl || '');
  const [isTargetedLoad, setIsTargetedLoad] = useState(!!(groupIdFromUrl || searchFromUrl));
  const debouncedSearchTerm = useDebounce(searchTerm, 500);

  const [completedDateFilter, setCompletedDateFilter] = useState<Date | undefined>(new Date());
  const [isDateFilterActive, setIsDateFilterActive] = useState(false);
  const [showOnlyOverdue, setShowOnlyOverdue] = useState(false);
  const [showCompleted, setShowCompleted] = useState(false);

  
  const [editablePhases, setEditablePhases] = useState<JobPhase[]>([]);
  const [isOrderChanged, setIsOrderChanged] = useState(false);

  const { toast } = useToast();
  const { user, operator } = useAuth();
  const router = useRouter();
  
  const jobsLoadedRef = useRef(false);
  const groupsLoadedRef = useRef(false);

  const isJobLive = useCallback((item: JobOrder | WorkGroup): boolean => {
      return (item.phases || []).some(p => p.status === 'in-progress');
  }, []);
  
  const isOverdueItem = (item: JobOrder | WorkGroup) => {
    const deliveryDateString = item.dataConsegnaFinale;
    if (!deliveryDateString || !/^\d{4}-\d{2}-\d{2}$/.test(deliveryDateString)) return false;
    const deliveryDate = parseISO(deliveryDateString);
    return isPast(deliveryDate) && getOverallStatus(item) !== 'Completata';
  };

  const loadAllData = useCallback(async (isManualRefresh = false) => {
    if (isManualRefresh) setIsDataRefreshing(true);
    else setIsLoading(true);
    
    try {
        const currentGroupId = searchParams.get('groupId');
        const currentSearch = searchParams.get('search');
        let jobsQuery = query(collection(db, "jobOrders"), where("status", "in", ["production", "suspended", "paused"]));
        let groupsQuery = query(collection(db, "workGroups"), where("status", "in", ["production", "suspended", "paused"]));

        if (showCompleted) {
            jobsQuery = query(collection(db, "jobOrders"), where("status", "==", "completed"), limit(100));
            groupsQuery = query(collection(db, "workGroups"), where("status", "==", "completed"), limit(50));
        }

        const [jobsSnap, groupsSnap] = await Promise.all([
            getDocs(jobsQuery),
            getDocs(groupsQuery)
        ]);

        const jobs = jobsSnap.docs.map(d => d.data() as JobOrder);
        const groups = groupsSnap.docs.map(d => d.data() as WorkGroup);

        setIsTargetedLoad(false);

        // Apply timestamp conversion
        const processItem = (item: any) => JSON.parse(JSON.stringify(item, (key, value) => {
            if ((['start', 'end', 'overallStartTime', 'overallEndTime', 'odlCreationDate', 'createdAt']).includes(key) && value && typeof value === 'object' && value.seconds !== undefined) return new Date(value.seconds * 1000);
            return value;
        }));

        const finalJobs = jobs.map(processItem);
        const finalGroups = groups.map(processItem);

        setJobOrders(finalJobs);
        setWorkGroups(finalGroups);

        const start = format(startOfWeek(new Date(), { weekStartsOn: 1 }), 'yyyy-MM-dd');
        const end = format(addWeeks(parseISO(start), 4), 'yyyy-MM-dd');
        getOperatorAssignments(start, end).then(setAssignments);

        if (isManualRefresh) toast({ title: "Dati LIVE Aggiornati", description: "Le commesse sono state sincronizzate." });
    } catch (error) {
        console.error("Error loading console data:", error);
        toast({ variant: "destructive", title: "Errore", description: "Impossibile caricare i dati." });
    } finally {
        setIsLoading(false);
        setIsDataRefreshing(false);
    }
  }, [toast, showCompleted, searchParams]);

  useEffect(() => {
    // If we are in targeted load and search term becomes empty, trigger full load
    if (isTargetedLoad && searchTerm === '') {
        setIsTargetedLoad(false);
        router.replace('/admin/production-console'); // Clear query params
        loadAllData(true);
    }
  }, [searchTerm, isTargetedLoad, loadAllData, router]);

  useEffect(() => {
    loadAllData();
  }, [loadAllData]);

  
  const workGroupsMap = useMemo(() => new Map(workGroups.map(g => [g.id, g])), [workGroups]);
  
  const { standaloneJobs, jobsByGroupId } = useMemo(() => {
    const grouped = new Map<string, JobOrder[]>();
    const standalone: JobOrder[] = [];
    jobOrders.forEach(job => {
      if (job.workGroupId && workGroupsMap.has(job.workGroupId)) {
        if (!grouped.has(job.workGroupId)) grouped.set(job.workGroupId, []);
        grouped.get(job.workGroupId)!.push(job);
      } else standalone.push(job);
    });
    return { standaloneJobs: standalone, jobsByGroupId: grouped };
  }, [jobOrders, workGroupsMap]);

  const applyFilters = <T extends JobOrder | WorkGroup>(items: T[]): T[] => {
      let f = items;
      if (showCompleted) {
          f = f.filter(i => getOverallStatus(i) === 'Completata');
          if (isDateFilterActive && completedDateFilter) f = f.filter(i => i.overallEndTime && isSameDay(new Date(i.overallEndTime), completedDateFilter));
      } else {
          f = f.filter(i => getOverallStatus(i) !== 'Completata');
          if (activeFilter !== 'all') f = activeFilter === 'LIVE' ? f.filter(isJobLive) : f.filter(i => getOverallStatus(i) === activeFilter);
      }
      if (showOnlyOverdue) f = f.filter(isOverdueItem);
      if (debouncedSearchTerm) {
          const l = debouncedSearchTerm.toLowerCase();
          f = f.filter(i => {
              const isG = 'jobOrderIds' in i;
              if (isG) return (i as WorkGroup).id.toLowerCase().includes(l) || (i as WorkGroup).details.toLowerCase().includes(l) || (jobsByGroupId.get(i.id) || []).some(j => j.ordinePF.toLowerCase().includes(l));
              return (i as JobOrder).ordinePF.toLowerCase().includes(l) || (i as JobOrder).details.toLowerCase().includes(l) || (i as JobOrder).cliente.toLowerCase().includes(l);
          });
      }

      return f;
  };

  const filteredItems = useMemo(() => {
      const filteredStandalone = applyFilters(standaloneJobs);
      const filteredGroups = applyFilters(Array.from(workGroupsMap.values()));
      return [...filteredStandalone, ...filteredGroups];
  }, [standaloneJobs, workGroupsMap, activeFilter, debouncedSearchTerm, showCompleted, isDateFilterActive, completedDateFilter, showOnlyOverdue, isJobLive, jobsByGroupId]);


  const { weeklyGroups, daVerificare } = useMemo(() => {
      const weeksMap = new Map<string, WeeklyGroup>();
      const daVerificare: (JobOrder | WorkGroup)[] = [];

      filteredItems.forEach(item => {
          const dateStr = item.dataConsegnaFinale;
          if (!dateStr || dateStr === 'N/D' || !isValid(parseISO(dateStr))) {
              daVerificare.push(item);
              return;
          }

          const date = parseISO(dateStr);
          const weekNum = getWeek(date, { weekStartsOn: 1 });
          const weekStart = startOfWeek(date, { weekStartsOn: 1 });
          const weekEnd = endOfWeek(date, { weekStartsOn: 1 });
          const year = format(date, 'yyyy');
          const key = `${year}-W${String(weekNum).padStart(2, '0')}`;

          if (!weeksMap.has(key)) {
              weeksMap.set(key, {
                  weekNumber: weekNum,
                  weekLabel: `Settimana ${weekNum} (${format(weekStart, 'dd/MM')} - ${format(weekEnd, 'dd/MM')})`,
                  items: [],
                  totalPcs: 0
              });
          }

          const group = weeksMap.get(key)!;
          group.items.push(item);
          group.totalPcs += ('totalQuantity' in item) ? (item.totalQuantity || 0) : (item.qta || 0);
      });

      const sortedWeeks = Array.from(weeksMap.entries())
          .sort((a, b) => a[0].localeCompare(b[0]))
          .map(([_, group]) => group);

      return { weeklyGroups: sortedWeeks, daVerificare };
  }, [filteredItems]);

  const handleSelectAll = () => {
    if (selectedIds.length === filteredItems.length) {
      setSelectedIds([]);
    } else {
      setSelectedIds(filteredItems.map(i => i.id));
    }
  };
  
  const handleSelectItem = (itemId: string) => {
    setSelectedIds(prev =>
      prev.includes(itemId) ? prev.filter(selectedId => selectedId !== itemId) : [...prev, itemId]
    );
  };
  
  const handleBulkForceFinish = async () => {
    if (!user || selectedIds.length === 0) return;
    const result = await forceFinishMultiple(selectedIds, user.uid);
    toast({ title: result.success ? "Operazione Riuscita" : "Errore", description: result.message, variant: result.success ? "default" : "destructive" });
    if (result.success) setSelectedIds([]);
  };

  const handleBulkForceComplete = async () => {
    if (!user || selectedIds.length === 0) return;
    const result = await forceCompleteMultiple(selectedIds, user.uid);
    toast({ title: result.success ? "Operazione Riuscita" : "Errore", description: result.message, variant: result.success ? "default" : "destructive" });
    if (result.success) setSelectedIds([]);
  };
  
  const handleBulkReset = async () => {
     if (selectedIds.length === 0 || !user) return;
     setIsLoading(true);
     for (const id of selectedIds) { await resetSingleCompletedJobOrder(id, user.uid); }
     toast({ title: "Reset Completato" });
     setSelectedIds([]); setIsLoading(false);
  };

  const handleResolveProblem = async () => {
    if (!problemJob || !user) return;
    const result = await resolveJobProblem(problemJob.id, user.uid);
    toast({ title: result.success ? "Problema Risolto" : "Errore", description: result.message, variant: result.success ? "default" : "destructive" });
    setProblemJob(null);
  };

  const handleFilterClick = (filter: FilterStatus) => {
    setActiveFilter(filter);
    setShowCompleted(false);
  };

  const handleForceFinish = async (jobId: string) => { if (!user) return; await forceFinishProduction(jobId, user.uid); };
  const handleRevertForceFinish = async (jobId: string) => { if (!user) return; await revertForceFinish(jobId, user.uid); };
  const handleForceComplete = async (jobId: string) => { if (!user) return; await forceCompleteJob(jobId, user.uid); };
  const handleToggleGuaina = async (jobId: string, phaseId: string, currentState: 'default' | 'postponed') => { if (!user) return; await toggleGuainaPhasePosition(jobId, phaseId, currentState); };
  const handleRevertPhase = async (jobId: string, phaseId: string) => { if (!user) return; await revertPhaseCompletion(jobId, phaseId, user.uid); };
  const handleRevertCompletion = async (itemId: string) => { if (!user) return; await revertCompletion(itemId, user.uid); };
  const handleForcePause = async (jobId: string, ops: string[], reason?: string, notes?: string) => { if (!user) return; await forcePauseOperators(jobId, ops, user.uid, reason, notes); };
  const onResetJobOrderClick = async (jobId: string) => { if (!user) return; await resetSingleCompletedJobOrder(jobId, user.uid); };
  const handleUpdateDeliveryDate = async (itemId: string, newDate: string) => { if (!user) return; await updateJobDeliveryDate(itemId, newDate, user.uid); };
  const handleUpdatePrepDate = async (itemId: string, newDate: string) => { if (!user) return; await updateJobPrepDate(itemId, newDate, user.uid); };
  const handleDissolveGroup = async (groupId: string) => { await dissolveWorkGroup(groupId); };

  const handleOpenPhaseManager = (item: JobOrder | WorkGroup) => {
    setPhaseManagedItem(item);
    setEditablePhases([...item.phases].sort((a,b) => a.sequence - b.sequence));
    setIsOrderChanged(false);
  };
  
  const handlePhaseStatusToggle = (phaseId: string) => {
    setEditablePhases(prev => {
      const news = prev.map(p => {
        if (p.id === phaseId) {
          if (p.status === 'pending') return { ...p, status: 'skipped' as const };
          if (p.status === 'skipped') return { ...p, status: 'pending' as const };
        }
        return p;
      });
      setIsOrderChanged(true); return news;
    });
  };

  const handleMovePhase = (index: number, direction: 'up' | 'down') => {
    setEditablePhases(prev => {
        const news = [...prev];
        const targetIndex = direction === 'up' ? index - 1 : index + 1;
        if (targetIndex >= 0 && targetIndex < news.length) {
            const temp = news[index];
            news[index] = news[targetIndex];
            news[targetIndex] = temp;
        }
        setIsOrderChanged(true); return news;
    });
  };
  
  const handleSaveChanges = async () => {
    if (!user || !phaseManagedItem) return;
    const res = await updatePhasesForJob(phaseManagedItem.id, editablePhases, user.uid);
    if (res.success) {
        toast({ title: "Fasi aggiornate" });
        setPhaseManagedItem(null);
    } else {
        toast({ variant: "destructive", title: "Errore", description: res.message });
    }
  };

  const handleFetchAnalysis = async (job: JobOrder) => {
    if (!job.id || !job.details) return;
    setJobsWithLoadingAnalysis(prev => new Set(prev).add(job.id));
    try {
        const analysis = await getAnalysisForArticle(job.details);
        if (analysis) {
            setAnalysisDataMap(prev => new Map(prev).set(job.id, analysis));
        } else {
            toast({ title: "Nessuna Analisi", description: "Dati insufficienti per generare una stima." });
        }
    } catch (e) { 
        toast({ variant: "destructive", title: "Errore Analisi" }); 
    } finally { 
        setJobsWithLoadingAnalysis(prev => { const n = new Set(prev); n.delete(job.id); return n; }); 
    }
  };

  const handleNavigateToAnalysis = (articleCode: string) => {
    router.push(`/admin/production-time-analysis?articleCode=${encodeURIComponent(articleCode)}`);
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    toast({ title: "Copiato!" });
  };

  const handleMaterialStatusToggle = async (itemId: string, phaseId: string, currentStatus?: string) => {
      if (!user) return;
      if (currentStatus === 'missing') {
          await resolveMaterialMissing(itemId, phaseId, user.uid);
      } else {
          await reportMaterialMissing(itemId, phaseId, user.uid);
      }
  };

  function getPhaseIconLocal(status: JobPhase['status']) {
    switch (status) {
      case 'pending': return <Circle className="h-4 w-4 text-muted-foreground" />;
      case 'in-progress': return <Hourglass className="h-4 w-4 text-blue-500 animate-spin" />;
      case 'paused': return <PauseCircle className="h-4 w-4 text-orange-500" />;
      case 'completed': return <CheckCircle2 className="h-4 w-4 text-primary" />;
      case 'skipped': return <EyeOff className="h-4 w-4 text-muted-foreground" />;
      default: return <Circle className="h-4 w-4 text-muted-foreground" />;
    }
  }

  const renderItem = (item: JobOrder | WorkGroup) => {
      const isGroup = 'jobOrderIds' in item;
      if (isGroup) {
          return (
            <WorkGroupCard 
                key={item.id} 
                group={item as WorkGroup} 
                jobsInGroup={jobsByGroupId.get(item.id) || []} 
                allOperators={cachedOperators} 
                onProblemClick={() => setProblemJob(item as WorkGroup)} 
                onForceFinishClick={handleForceFinish} 
                onForcePauseClick={handleForcePause} 
                onForceCompleteClick={handleForceComplete} 
                onDissolveGroupClick={handleDissolveGroup} 
                onOpenPhaseManager={handleOpenPhaseManager} 
                onOpenMaterialManager={() => setMaterialManagedItem(item as WorkGroup)} 
                onToggleGuainaClick={handleToggleGuaina} 
                onUpdateDeliveryDate={handleUpdateDeliveryDate} 
                onUpdatePrepDate={handleUpdatePrepDate}
                isSelected={selectedIds.includes(item.id)} 
                onSelect={handleSelectItem} 
                overallStatus={getOverallStatus(item as WorkGroup)} 
                getOverallStatus={getOverallStatus} 
                onNavigateToAnalysis={handleNavigateToAnalysis} 
                onCopyArticleCode={handleCopy}
            />
          );
      }
      return (
        <JobOrderCard 
            key={item.id} 
            jobOrder={item as JobOrder} 
            allOperators={cachedOperators} 
            analysisData={analysisDataMap.get(item.id)} 
            onFetchAnalysis={() => handleFetchAnalysis(item as JobOrder)} 
            isAnalysisLoading={jobsWithLoadingAnalysis.has(item.id)} 
            onProblemClick={() => setProblemJob(item as JobOrder)} 
            onForceFinishClick={handleForceFinish} 
            onRevertForceFinishClick={handleRevertForceFinish} 
            onToggleGuainaClick={handleToggleGuaina} 
            onRevertPhaseClick={handleRevertPhase} 
            onRevertCompletionClick={handleRevertCompletion} 
            onForcePauseClick={handleForcePause} 
            onForceCompleteClick={handleForceComplete} 
            onResetJobOrderClick={onResetJobOrderClick} 
            onOpenPhaseManager={handleOpenPhaseManager} 
            onOpenMaterialManager={() => setMaterialManagedItem(item as JobOrder)} 
            onUpdateDeliveryDate={handleUpdateDeliveryDate} 
            onUpdatePrepDate={handleUpdatePrepDate}
            isSelected={selectedIds.includes(item.id)} 
            onSelect={handleSelectItem} 
            overallStatus={getOverallStatus(item as JobOrder)} 
            onNavigateToAnalysis={handleNavigateToAnalysis} 
            onCopyArticleCode={handleCopy}
            forceAllowActions={true}
        />
      );
  };

  return (
    <>
      <div className="space-y-6">
        <header className="flex flex-col sm:flex-row justify-between items-start gap-4">
            <div>
              <h1 className="text-3xl font-bold font-headline flex items-center gap-3">
                <Briefcase className="h-8 w-8 text-primary" /> Console Controllo Produzione
              </h1>
            </div>
            <div className="flex bg-muted p-1 rounded-lg items-center">
              <button onClick={() => setViewMode('list')} className={`px-4 py-1.5 flex items-center text-sm font-medium rounded-md transition-all ${viewMode === 'list' ? 'bg-background shadow text-foreground' : 'text-muted-foreground hover:text-foreground'}`}>
                <ListOrdered className="w-4 h-4 mr-2" />
                Elenco
              </button>
              <button onClick={() => setViewMode('gantt')} className={`px-4 py-1.5 flex items-center text-sm font-medium rounded-md transition-all ${viewMode === 'gantt' ? 'bg-background shadow text-foreground' : 'text-muted-foreground hover:text-foreground'}`}>
                <CalendarDays className="w-4 h-4 mr-2" />
                Gantt
              </button>
            </div>
            {viewMode === 'list' && (
              <div className="flex flex-col sm:flex-row items-center gap-4 w-full sm:w-auto">
                <Button 
                  variant="outline" 
                  size="sm" 
                  onClick={() => loadAllData(true)} 
                  disabled={isDataRefreshing || isLoading}
                  className={cn("h-10", isDataRefreshing && "opacity-50")}
                >
                  {isDataRefreshing ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : <RefreshCcw className="h-4 w-4 mr-2" />}
                  Aggiorna Dati
                </Button>
                <div className="relative w-full sm:max-w-xs">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                  <Input placeholder="Cerca..." className="pl-9" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
                </div>
              </div>
            )}

        </header>

        {viewMode === 'gantt' && cachedSettings ? (
          <GanttBoard 
            jobOrders={filteredItems as JobOrder[]} 
            operators={cachedOperators} 
            assignments={assignments} 
            settings={cachedSettings}
            articles={Array.from(articlesMap.values())}
          />
        ) : (
          <>
            <Card className="p-2 space-y-2">
          <div className="flex flex-wrap items-center justify-center gap-1">
              {[
                { label: 'Tutte', value: 'all', icon: Briefcase },
                { label: 'In Corso (Live)', value: 'LIVE', icon: Activity },
                { label: 'In Lavorazione', value: 'In Lavorazione', icon: Hourglass },
                { label: 'Sospesa', value: 'Sospesa', icon: PauseCircle },
                { label: 'Problema', value: 'Problema', icon: ShieldAlert },
                { label: 'Manca Materiale', value: 'Manca Materiale', icon: PackageX },
              ].map(f => (
                <Button key={f.value} variant={activeFilter === f.value && !showCompleted ? 'secondary' : 'ghost'} onClick={() => handleFilterClick(f.value as any)} className="text-xs sm:text-sm">
                  <f.icon className={cn("mr-2 h-4 w-4", f.value === 'LIVE' && "text-red-400 animate-pulse")} /> {f.label}
                </Button>
              ))}
          </div>
           <div className="border-t pt-2 flex items-center justify-center gap-4 flex-wrap">
                  <div className="flex items-center space-x-2"><Switch id="over-sw" checked={showOnlyOverdue} onCheckedChange={setShowOnlyOverdue} /><Label htmlFor="over-sw" className="text-destructive">Filtra Ritardi</Label></div>
                  <div className="flex items-center space-x-2"><Switch id="comp-sw" checked={showCompleted} onCheckedChange={setShowCompleted} /><Label htmlFor="comp-sw">Mostra Completate</Label></div>
                  {showCompleted && (
                    <div className="flex items-center gap-2">
                      <Switch id="dt-sw" checked={isDateFilterActive} onCheckedChange={setIsDateFilterActive} /><Label htmlFor="dt-sw">Filtra Data</Label>
                      <Popover><PopoverTrigger asChild><Button variant="outline" className={cn("w-[200px] justify-start", !isDateFilterActive && "opacity-50")} disabled={!isDateFilterActive}><CalendarIcon className="mr-2 h-4 w-4" />{completedDateFilter ? format(completedDateFilter, "PPP", { locale: it }) : "Data"}</Button></PopoverTrigger>
                      <PopoverContent className="w-auto p-0"><Calendar mode="single" selected={completedDateFilter} onSelect={setCompletedDateFilter} initialFocus /></PopoverContent></Popover>
                    </div>
                  )}
           </div>
        </Card>
        
         {filteredItems.length > 0 && (
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2">
                  <Checkbox id="sel-all" checked={selectedIds.length > 0 && selectedIds.length === filteredItems.length} onCheckedChange={handleSelectAll} />
                  <Label htmlFor="sel-all">Seleziona Tutte ({filteredItems.length})</Label>
              </div>
              {selectedIds.length > 0 && (
                  <DropdownMenu>
                    <DropdownMenuTrigger asChild><Button variant="outline" size="sm">Azioni di Gruppo ({selectedIds.length}) <MoreVertical className="ml-2 h-4 w-4" /></Button></DropdownMenuTrigger>
                     <DropdownMenuContent align="start">
                        <AlertDialog><AlertDialogTrigger asChild><DropdownMenuItem onSelect={e => e.preventDefault()}><FastForward className="mr-2 h-4 w-4" /> Forza a Finitura</DropdownMenuItem></AlertDialogTrigger>
                        <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Confermi l'avanzamento forzato?</AlertDialogTitle></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={handleBulkForceFinish}>Conferma</AlertDialogAction></AlertDialogFooter></AlertDialogContent></AlertDialog>
                        
                        <AlertDialog><AlertDialogTrigger asChild><DropdownMenuItem onSelect={e => e.preventDefault()}><PowerOff className="mr-2 h-4 w-4" /> Chiudi Item</DropdownMenuItem></AlertDialogTrigger>
                        <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Confermi la chiusura forzata?</AlertDialogTitle></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={handleBulkForceComplete}>Conferma</AlertDialogAction></AlertDialogFooter></AlertDialogContent></AlertDialog>
                        
                        <DropdownMenuSeparator />
                        <AlertDialog><AlertDialogTrigger asChild><DropdownMenuItem onSelect={e => e.preventDefault()} className="text-destructive"><RefreshCcw className="mr-2 h-4 w-4" /> Annulla e Resetta</DropdownMenuItem></AlertDialogTrigger>
                        <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Sei sicuro di voler resettare?</AlertDialogTitle></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={handleBulkReset} className="bg-destructive">Sì, Resetta</AlertDialogAction></AlertDialogFooter></AlertDialogContent></AlertDialog>
                    </DropdownMenuContent>
                  </DropdownMenu>
              )}
          </div>
        )}

        {isLoading ? (
            <div className="flex flex-col items-center justify-center py-20"><Loader2 className="h-12 w-12 animate-spin text-primary" /><p className="mt-4 text-muted-foreground">Aggiornamento...</p></div>
        ) : filteredItems.length > 0 ? (
          <div className="space-y-12">
            
            {daVerificare.length > 0 && (
                <section className="space-y-4">
                    <div className="flex items-center gap-3 border-b-2 border-destructive/20 pb-2">
                        <AlertCircle className="h-6 w-6 text-destructive" />
                        <h2 className="text-xl font-black uppercase tracking-tight text-destructive">Da Gestire e Verificare (N/D)</h2>
                        <Badge variant="destructive">{daVerificare.length}</Badge>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                        {daVerificare.map(renderItem)}
                    </div>
                </section>
            )}

            {weeklyGroups.map((group) => (
                <section key={group.weekLabel} className="space-y-4">
                    <div className="flex flex-col sm:flex-row sm:items-end justify-between gap-4 border-b-2 border-primary/20 pb-2">
                        <div className="flex items-center gap-3">
                            <CalendarDays className="h-6 w-6 text-primary" />
                            <h2 className="text-xl font-black uppercase tracking-tight text-primary">{group.weekLabel}</h2>
                            <Badge variant="outline" className="border-primary text-primary">{group.items.length} Item</Badge>
                        </div>
                        <div className="flex items-center gap-4 text-sm font-bold text-muted-foreground">
                            <div className="flex items-center gap-1.5"><Package2 className="h-4 w-4"/> {group.totalPcs} pz totali</div>
                        </div>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                        {group.items.map(renderItem)}
                    </div>
                </section>
            ))}

          </div>
        ) : (
          <div className="flex flex-col items-center justify-center py-20 border-2 border-dashed rounded-lg mt-8"><Package2 className="h-16 w-16 text-muted-foreground mb-4" /><h2 className="text-xl font-semibold text-muted-foreground">Nessuna Commessa Trovata</h2></div>
        )}
        </>
      )}
      </div>
      
      <Dialog open={!!phaseManagedItem} onOpenChange={o => !o && setPhaseManagedItem(null)}>
        <DialogContent className="max-w-xl"><DialogHeader><DialogTitle>Gestione Fasi: {phaseManagedItem?.id}</DialogTitle></DialogHeader>
           <div className="py-4 space-y-2 max-h-[60vh] overflow-y-auto">
            {editablePhases.map((phase, index) => (
                <div key={phase.id} className={cn("flex items-center justify-between p-3 rounded-md", (phase.status !== 'pending' && phase.status !== 'skipped') && 'bg-muted/50 opacity-70')}>
                  <div className="flex items-center gap-3">{getPhaseIconLocal(phase.status)}<span className={cn('font-medium', phase.status === 'skipped' && 'line-through text-muted-foreground')}>{phase.name}</span></div>
                  <div className="flex items-center gap-1">
                    {(phase.status === 'pending' || phase.status === 'skipped') ? (
                      <>
                        <Button size="icon" variant="ghost" onClick={() => handleMovePhase(index, 'up')} disabled={index === 0}><ArrowUp className="h-4 w-4" /></Button>
                        <Button size="icon" variant="ghost" onClick={() => handleMovePhase(index, 'down')} disabled={index === editablePhases.length - 1}><ArrowDown className="h-4 w-4" /></Button>
                        <Button size="sm" variant="outline" onClick={() => handlePhaseStatusToggle(phase.id)}>{phase.status === 'pending' ? <EyeOff className="mr-2 h-4 w-4" /> : <Undo2 className="mr-2 h-4 w-4" />}{phase.status === 'pending' ? 'Bypassa' : 'Ripristina'}</Button>
                      </>
                    ) : <Badge variant="secondary">{phase.status}</Badge>}
                  </div>
                </div>
            ))}
          </div>
          <DialogFooter><Button variant="outline" onClick={() => setPhaseManagedItem(null)}>Annulla</Button><Button onClick={handleSaveChanges} className={cn(isOrderChanged && 'bg-amber-500 animate-pulse')}>Salva Modifiche</Button></DialogFooter>
        </DialogContent>
      </Dialog>
      
      <Dialog open={!!materialManagedItem} onOpenChange={o => !o && setMaterialManagedItem(null)}>
        <DialogContent className="max-w-xl"><DialogHeader><DialogTitle>Mancanza Materiale: {materialManagedItem?.id}</DialogTitle></DialogHeader>
           <div className="py-4 space-y-2">
            {(materialManagedItem?.phases || []).filter(p => p.type === 'preparation').map(phase => (
                <div key={phase.id} className="flex items-center justify-between p-3 rounded-md">
                  <div className="flex items-center gap-3">{phase.materialStatus === 'missing' ? <PackageX className="h-5 w-5 text-destructive" /> : <PackageCheck className="h-5 w-5 text-green-500" />}<span>{phase.name}</span></div>
                  <Button size="sm" variant={phase.materialStatus === 'missing' ? 'secondary' : 'destructive'} onClick={() => handleMaterialStatusToggle(materialManagedItem!.id, phase.id, phase.materialStatus)}>{phase.materialStatus === 'missing' ? <Unlock className="mr-2 h-4 w-4" /> : <PlayCircle className="mr-2 h-4 w-4" />}{phase.materialStatus === 'missing' ? 'Risolvi' : 'Segnala'}</Button>
                </div>
            ))}
          </div>
        </DialogContent>
      </Dialog>

       <Dialog open={!!problemJob} onOpenChange={o => !o && setProblemJob(null)}>
        <DialogContent><DialogHeader><DialogTitle>Dettaglio Problema: {problemJob?.id}</DialogTitle></DialogHeader>
            <div className="space-y-4 text-sm pt-4">
                {problemJob?.problemType === 'MANCA_MATERIALE' && (
                    <ul className="list-disc pl-5 text-destructive">{(problemJob?.phases || []).filter(p => p.materialStatus === 'missing').map(p => <li key={p.id}>{p.name}</li>)}</ul>
                )}
                {problemJob?.problemNotes && <p className="text-muted-foreground p-2 bg-muted rounded-md">{problemJob.problemNotes}</p>}
            </div>
            <DialogFooter>
                <Button variant="outline" onClick={() => setProblemJob(null)}>Chiudi</Button>
                { (operator?.role === 'supervisor' || operator?.role === 'admin') && (
                  <Button onClick={handleResolveProblem} className="bg-green-600 hover:bg-green-700">
                     <Unlock className="mr-2 h-4 w-4"/> Sblocca Commessa
                  </Button>
                )}
            </DialogFooter>
        </DialogContent>
      </Dialog>
    </>
  );
}

import type { JobOrder, WorkGroup, JobPhase, OverallStatus, Operator } from '@/types';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card';
import { Progress } from '@/components/ui/progress';
import { StatusBadge } from '@/components/production-console/StatusBadge';
import { Package, Building, Circle, Hourglass, CheckCircle2, ShieldAlert, PauseCircle, MoreVertical, FastForward, CornerUpLeft, CornerDownRight, ListOrdered, Boxes, Users, PowerOff, Unlink, View, Combine, User, EyeOff, ChevronDown, Timer, Loader2 } from 'lucide-react';
import { cn } from '@/lib/utils';
import { Button } from '@/components/ui/button';
import { TooltipProvider, Tooltip, TooltipTrigger, TooltipContent } from '@/components/ui/tooltip';
import React, { useState, useMemo } from 'react';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
  DropdownMenuSeparator,
} from "@/components/ui/dropdown-menu";
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from "@/components/ui/collapsible";
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import { Checkbox } from '@/components/ui/checkbox';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import JobOrderCard from './JobOrderCard';
import { Separator } from '@/components/ui/separator';
import type { ProductionTimeData } from '@/app/admin/production-console/actions';


interface ActivePhaseInfo {
  phaseId: string;
  phaseName: string;
  operators: { id: string; name: string }[];
}

function getPhaseIcon(status: JobPhase['status']) {
  switch (status) {
    case 'pending': return <Circle className="h-4 w-4 text-muted-foreground" />;
    case 'in-progress': return <Hourglass className="h-4 w-4 text-blue-500 animate-spin" />;
    case 'paused': return <PauseCircle className="h-4 w-4 text-orange-500" />;
    case 'completed': return <CheckCircle2 className="h-4 w-4 text-primary" />;
    case 'skipped': return <EyeOff className="h-4 w-4 text-muted-foreground" />;
    default: return <Circle className="h-4 w-4 text-muted-foreground" />;
  }
}

export default function WorkGroupCard({ 
    group,
    jobsInGroup,
    allOperators,
    onProblemClick,
    onForceFinishClick,
    onForcePauseClick,
    onForceCompleteClick,
    onDissolveGroupClick,
    onOpenPhaseManager,
    onOpenMaterialManager,
    onToggleGuainaClick,
    isSelected,
    onSelect,
    overallStatus,
    getOverallStatus,
}: { 
    group: WorkGroup;
    jobsInGroup: JobOrder[];
    allOperators: Operator[];
    onProblemClick: () => void;
    onForceFinishClick: (groupId: string) => void;
    onForcePauseClick: (groupId: string, operatorIds: string[]) => void;
    onForceCompleteClick: (groupId: string) => void;
    onDissolveGroupClick: (groupId: string) => void;
    onOpenPhaseManager: (item: JobOrder | WorkGroup) => void;
    onOpenMaterialManager: (item: JobOrder | WorkGroup) => void;
    onToggleGuainaClick: (itemId: string, phaseId: string, currentState: 'default' | 'postponed') => void;
    isSelected: boolean;
    onSelect: (groupId: string) => void;
    overallStatus: OverallStatus;
    getOverallStatus: (job: JobOrder) => OverallStatus;
}) {
  const [isPauseDialogOpen, setIsPauseDialogOpen] = useState(false);
  const [isExplodeViewOpen, setIsExplodeViewOpen] = useState(false);
  const [selectedOperatorsToPause, setSelectedOperatorsToPause] = useState<string[]>([]);
  const hasMaterialMissing = group.phases.some(p => p.materialStatus === 'missing');

  const activePhasesWithOperators = useMemo((): ActivePhaseInfo[] => {
    const activePhasesMap = new Map<string, ActivePhaseInfo>();
    
    (group.phases || []).forEach(phase => {
        if (phase.status === 'in-progress') {
            const phaseOperators: { id: string; name: string }[] = [];
            (phase.workPeriods || []).forEach(wp => {
                if (wp.end === null) {
                    const operator = allOperators.find(op => op.id === wp.operatorId);
                    if (operator) {
                        phaseOperators.push({ id: operator.id, name: operator.nome });
                    }
                }
            });

            // Filter out duplicates before adding to the map
            const uniqueOperators = Array.from(new Map(phaseOperators.map(op => [op.id, op])).values());

            if (uniqueOperators.length > 0) {
                if (!activePhasesMap.has(phase.id)) {
                    activePhasesMap.set(phase.id, {
                        phaseId: phase.id,
                        phaseName: phase.name,
                        operators: [],
                    });
                }
                activePhasesMap.get(phase.id)!.operators.push(...uniqueOperators);
            }
        }
    });

    return Array.from(activePhasesMap.values());
  }, [group, allOperators]);
  
  const handleOpenPauseDialog = () => {
    setSelectedOperatorsToPause([]);
    setIsPauseDialogOpen(true);
  };
  
  const handleConfirmPause = () => {
    if (selectedOperatorsToPause.length > 0) {
      onForcePauseClick(group.id, selectedOperatorsToPause);
    }
    setIsPauseDialogOpen(false);
  };

  const toggleOperatorSelection = (opId: string) => {
    setSelectedOperatorsToPause(prev =>
      prev.includes(opId) ? prev.filter(currentId => currentId !== opId) : [...prev, opId]
    );
  };

  const toggleSelectAll = () => {
    const allActiveOperatorIds = activePhasesWithOperators.flatMap(p => p.operators.map(op => op.id));
    if (selectedOperatorsToPause.length === allActiveOperatorIds.length) {
      setSelectedOperatorsToPause([]);
    } else {
      setSelectedOperatorsToPause(allActiveOperatorIds);
    }
  };

  const completedPhasesCount = group.phases.filter(p => p.status === 'completed' || p.status === 'skipped').length;
  const progressPercentage = group.phases.length > 0 ? (completedPhasesCount / group.phases.length) * 100 : 0;
  
  const canForceFinish = ['In Preparazione', 'Pronto per Produzione', 'In Lavorazione'].includes(overallStatus);
  const isAnyPhaseInProgress = activePhasesWithOperators.length > 0;
  const canForceComplete = !isAnyPhaseInProgress && overallStatus !== 'Completata';
  
  const guainaPhase = group.phases.find(p => p.name === "Taglio Guaina");
  const isWorkInProgress = group.phases.some(p => p.status === 'in-progress' || p.status === 'paused');
  const canToggleGuaina = guainaPhase && (guainaPhase.status === 'pending' || guainaPhase.status === 'paused') && !isWorkInProgress;
  
  const firstProductionPhase = group.phases
      .filter(p => p.type === 'production')
      .sort((a,b) => a.sequence - b.sequence)[0];
  const isGuainaPostponed = guainaPhase && firstProductionPhase && guainaPhase.sequence > firstProductionPhase.sequence;


  return (
    <>
    <Collapsible asChild>
      <Card 
        className={cn(
            "relative flex flex-col h-full bg-card hover:bg-card/90 transition-all duration-300 border-2 border-teal-500/70", 
            (group.isProblemReported || hasMaterialMissing) && "cursor-pointer border-destructive/50 hover:border-destructive",
            isSelected && "border-primary ring-2 ring-primary/50",
        )}
        onClick={(group.isProblemReported || hasMaterialMissing) ? onProblemClick : undefined}
      >
        <div className="flex-grow">
            <CardHeader className="pb-3 space-y-2">
                <div className="flex justify-between items-center gap-4">
                    <div className="flex items-center gap-3">
                        <Checkbox
                            checked={isSelected}
                            onCheckedChange={() => onSelect(group.id)}
                            aria-label={`Seleziona gruppo ${group.id}`}
                            className="h-4 w-4"
                        />
                         <TooltipProvider>
                            <Tooltip>
                                <TooltipTrigger>
                                    <Combine className="h-5 w-5 text-teal-400" />
                                </TooltipTrigger>
                                <TooltipContent>
                                    <p>Gruppo: {group.id}</p>
                                </TooltipContent>
                            </Tooltip>
                        </TooltipProvider>
                        <CollapsibleTrigger asChild>
                           <div className="flex items-center gap-2 cursor-pointer group">
                                <CardTitle className="font-headline text-base font-mono">{group.id}</CardTitle>
                                <ChevronDown className="h-5 w-5 text-muted-foreground transition-transform duration-200 group-data-[state=open]:-rotate-180" />
                            </div>
                        </CollapsibleTrigger>
                    </div>
                    <StatusBadge status={overallStatus} />
                </div>
                <div className="flex justify-between items-center gap-4">
                    <CardDescription className="flex items-center gap-2">
                        <Building className="h-4 w-4 text-muted-foreground" />
                        {group.cliente}
                    </CardDescription>
                    <div className="flex items-center gap-1">
                        <DropdownMenu>
                            <DropdownMenuTrigger asChild>
                                <Button variant="ghost" size="icon" className="h-8 w-8" onClick={(e) => e.stopPropagation()}>
                                    <MoreVertical className="h-4 w-4" />
                                </Button>
                            </DropdownMenuTrigger>
                            <DropdownMenuContent align="end">
                                <DropdownMenuItem onSelect={() => onOpenPhaseManager(group)} disabled={overallStatus === 'Completata'}>
                                    <ListOrdered className="mr-2 h-4 w-4" />
                                    <span>Gestisci Fasi</span>
                                </DropdownMenuItem>
                                <DropdownMenuItem onSelect={() => onOpenMaterialManager(group)} disabled={overallStatus === 'Completata'}>
                                    <Boxes className="mr-2 h-4 w-4" />
                                    <span>Gestisci Materiali</span>
                                </DropdownMenuItem>
                                {canToggleGuaina && guainaPhase && (
                                    <AlertDialog>
                                        <AlertDialogTrigger asChild>
                                            <DropdownMenuItem onSelect={(e) => e.preventDefault()}>
                                            {isGuainaPostponed ? <CornerUpLeft className="mr-2 h-4 w-4" /> : <CornerDownRight className="mr-2 h-4 w-4" />}
                                            <span>{isGuainaPostponed ? 'Ripristina Guaina' : 'Posticipa Guaina'}</span>
                                            </DropdownMenuItem>
                                        </AlertDialogTrigger>
                                        <AlertDialogContent>
                                            <AlertDialogHeader>
                                                <AlertDialogTitle>Conferma Spostamento Fase</AlertDialogTitle>
                                                <AlertDialogDescription>
                                                Stai per {isGuainaPostponed ? 'riportare la fase "Taglio Guaina" alla sua posizione originale.' : 'posticipare la fase "Taglio Guaina" a dopo la produzione.'} L'esecuzione di questa azione su un gruppo ne causerà lo scioglimento immediato. Vuoi continuare?
                                                </AlertDialogDescription>
                                            </AlertDialogHeader>
                                            <AlertDialogFooter>
                                                <AlertDialogCancel>Annulla</AlertDialogCancel>
                                                <AlertDialogAction onClick={() => onToggleGuainaClick(group.id, guainaPhase.id, isGuainaPostponed ? 'postponed' : 'default')}>Conferma e Sciogli</AlertDialogAction>
                                            </AlertDialogFooter>
                                        </AlertDialogContent>
                                    </AlertDialog>
                                )}
                                <DropdownMenuSeparator />
                                <DropdownMenuItem onSelect={handleOpenPauseDialog} disabled={!isAnyPhaseInProgress}>
                                    <Users className="mr-2 h-4 w-4" />
                                    <span>Forza Pausa Operatori</span>
                                </DropdownMenuItem>
                                {canForceFinish && (
                                    <AlertDialog>
                                        <AlertDialogTrigger asChild><DropdownMenuItem onSelect={(e) => e.preventDefault()}><FastForward className="mr-2 h-4 w-4" />Forza a Finitura</DropdownMenuItem></AlertDialogTrigger>
                                        <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Conferma Azione</AlertDialogTitle><AlertDialogDescription>Forzare tutte le fasi di produzione del gruppo a 'completata'?</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={() => onForceFinishClick(group.id)}>Conferma</AlertDialogAction></AlertDialogFooter></AlertDialogContent>
                                    </AlertDialog>
                                )}
                                {canForceComplete && (
                                    <AlertDialog>
                                        <AlertDialogTrigger asChild><DropdownMenuItem onSelect={(e) => e.preventDefault()}><PowerOff className="mr-2 h-4 w-4" />Forza Chiusura Gruppo</DropdownMenuItem></AlertDialogTrigger>
                                        <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Conferma Azione</AlertDialogTitle><AlertDialogDescription>Stai per impostare manualmente questo gruppo come 'Completato'.</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={() => onForceCompleteClick(group.id)}>Conferma</AlertDialogAction></AlertDialogFooter></AlertDialogContent>
                                    </AlertDialog>
                                )}
                                <DropdownMenuSeparator />
                                <AlertDialog>
                                    <AlertDialogTrigger asChild>
                                        <DropdownMenuItem onSelect={(e) => e.preventDefault()} className="text-destructive focus:text-destructive">
                                            <Unlink className="mr-2 h-4 w-4" />
                                            <span>Annulla Gruppo</span>
                                        </DropdownMenuItem>
                                    </AlertDialogTrigger>
                                    <AlertDialogContent>
                                        <AlertDialogHeader><AlertDialogTitle>Sei sicuro di voler annullare il gruppo?</AlertDialogTitle><AlertDialogDescription>Le commesse torneranno individuali e dovranno essere gestite singolarmente. L'avanzamento verrà ereditato dal gruppo.</AlertDialogDescription></AlertDialogHeader>
                                        <AlertDialogFooter><AlertDialogCancel>Chiudi</AlertDialogCancel><AlertDialogAction onClick={() => onDissolveGroupClick(group.id)} className="bg-destructive hover:bg-destructive/90">Sì, annulla gruppo</AlertDialogAction></AlertDialogFooter>
                                    </AlertDialogContent>
                                </AlertDialog>
                            </DropdownMenuContent>
                        </DropdownMenu>
                    </div>
                </div>

                {(group.isProblemReported || hasMaterialMissing) && (
                    <p className="text-sm text-destructive font-semibold mt-2 flex items-center">
                        <ShieldAlert className="mr-2 h-4 w-4" /> 
                        {group.isProblemReported ? "Problema segnalato!" : "Materiale mancante!"}
                    </p>
                )}
            </CardHeader>
            <CardContent className="flex-grow space-y-4 pt-0">
                <div className="flex justify-between items-start gap-4">
                    <div className="space-y-3 text-sm">
                        <p className="flex items-center gap-2 text-muted-foreground">
                            <Package className="h-4 w-4" />
                            {group.details}
                        </p>
                    </div>
                    <div className="text-right flex-shrink-0">
                        <div className="flex items-center gap-1 justify-end">
                        <Package className="h-4 w-4 text-muted-foreground" />
                        <span className="font-bold">{group.qta}</span>
                        <span className="text-muted-foreground text-xs">pz totali</span>
                        </div>
                    </div>
                </div>

                <div className="space-y-1 text-sm">
                    <p className="font-semibold text-foreground/80">Commesse nel Gruppo:</p>
                    <div className="flex flex-wrap gap-1">
                        {group.jobOrderPFs?.map(pf => <Badge key={pf} variant="secondary">{pf}</Badge>)}
                    </div>
                </div>
                
                {isAnyPhaseInProgress && (
                  <div className="rounded-lg border-2 border-cyan-400/50 bg-cyan-900/20 p-3 space-y-3 animate-pulse">
                      <h4 className="text-sm font-semibold text-foreground/90 flex items-center gap-2">
                          <Hourglass className="h-4 w-4 text-cyan-500"/>
                          Operatori Attivi
                      </h4>
                      {activePhasesWithOperators.map(info => (
                          <div key={info.phaseId} className="pl-2">
                            <p className="font-semibold text-primary">{info.phaseName}:</p>
                            <div className="flex flex-wrap gap-2 pt-1">
                                {info.operators.map(op => (
                                    <Badge key={op.id} variant="outline" className="flex items-center gap-1.5 py-1 bg-background">
                                        <User className="h-3 w-3" />
                                        {op.name}
                                    </Badge>
                                ))}
                            </div>
                          </div>
                      ))}
                  </div>
                )}
            </CardContent>
        </div>
        <CardFooter className="flex-col items-start gap-2 pt-4">
          <div className="w-full">
              <div className="flex justify-between text-xs text-muted-foreground mb-1">
                  <span>Progresso</span>
                  <span>{Math.round(progressPercentage)}%</span>
              </div>
              <Progress value={progressPercentage} className="h-2" />
          </div>
        </CardFooter>
        <CollapsibleContent>
             <div className="space-y-2 p-4">
                <Separator />
                <h4 className="text-sm font-semibold text-foreground/80 pt-2">Avanzamento Fasi</h4>
                {group.phases && group.phases.length > 0 ? (
                    group.phases.sort((a,b) => a.sequence - b.sequence).map(phase => (
                        <div key={phase.id} className="flex items-center gap-3 text-sm text-muted-foreground">
                            {getPhaseIcon(phase.status)}
                            <span className={cn("flex-1", phase.status === 'skipped' && 'line-through')}>{phase.name}</span>
                        </div>
                    ))
                ) : (
                    <p className="text-sm text-muted-foreground">Nessuna fase definita per questo gruppo.</p>
                )}
                 <Button variant="secondary" size="sm" className="w-full mt-4" onClick={() => setIsExplodeViewOpen(true)}>
                      <View className="mr-2 h-4 w-4" />
                      Esplodi e Vedi Dettagli Commesse ({jobsInGroup.length})
                  </Button>
            </div>
        </CollapsibleContent>
      </Card>
      </Collapsible>

      <Dialog open={isPauseDialogOpen} onOpenChange={setIsPauseDialogOpen}>
          <DialogContent>
              <DialogHeader>
                  <DialogTitle>Seleziona Operatori da Mettere in Pausa</DialogTitle>
                  <DialogDescription>
                      Scegli quali operatori attivi sul gruppo <span className="font-bold">{group.id}</span> vuoi mettere in pausa.
                  </DialogDescription>
              </DialogHeader>
              <div className="py-4 space-y-3">
                   <div className="flex items-center space-x-2">
                      <Checkbox
                          id="select-all"
                          checked={selectedOperatorsToPause.length === activePhasesWithOperators.flatMap(p => p.operators).length && activePhasesWithOperators.length > 0}
                          onCheckedChange={toggleSelectAll}
                      />
                      <Label htmlFor="select-all">Seleziona Tutti</Label>
                  </div>
                  {activePhasesWithOperators.flatMap(p => p.operators).map(op => (
                      <div key={op.id} className="flex items-center space-x-2 p-2 rounded-md border">
                           <Checkbox
                              id={op.id}
                              checked={selectedOperatorsToPause.includes(op.id)}
                              onCheckedChange={() => toggleOperatorSelection(op.id)}
                           />
                           <Label htmlFor={op.id} className="flex-1">
                              <span className="font-semibold">{op.name}</span>
                           </Label>
                      </div>
                  ))}
                  {activePhasesWithOperators.length === 0 && <p className="text-sm text-muted-foreground text-center py-4">Nessun operatore attivo su questo gruppo.</p>}
              </div>
              <DialogFooter>
                  <Button variant="outline" onClick={() => setIsPauseDialogOpen(false)}>Annulla</Button>
                  <Button onClick={handleConfirmPause} disabled={selectedOperatorsToPause.length === 0}>
                      Metti in Pausa Selezionati ({selectedOperatorsToPause.length})
                  </Button>
              </DialogFooter>
          </DialogContent>
      </Dialog>
      
      <Dialog open={isExplodeViewOpen} onOpenChange={setIsExplodeViewOpen}>
          <DialogContent className="max-w-7xl h-[90vh]">
              <DialogHeader>
                  <DialogTitle>Dettaglio Commesse nel Gruppo: {group.id}</DialogTitle>
              </DialogHeader>
              <div className="h-full overflow-y-auto p-2">
                 <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                      {jobsInGroup.map(job => (
                          <JobOrderCard
                              key={job.id}
                              jobOrder={job}
                              groupPhases={group.phases}
                              allOperators={allOperators}
                              onProblemClick={() => {}}
                              onFetchAnalysis={() => {}}
                              isAnalysisLoading={false}
                              onForceFinishClick={() => {}}
                              onRevertForceFinishClick={() => {}}
                              onToggleGuainaClick={() => {}}
                              onRevertPhaseClick={() => {}}
                              onRevertCompletionClick={() => {}}
                              onForcePauseClick={() => {}}
                              onForceCompleteClick={() => {}}
                              onResetJobOrderClick={() => {}}
                              onOpenPhaseManager={() => {}}
                              onOpenMaterialManager={() => {}}
                              isSelected={false}
                              onSelect={() => {}}
                              overallStatus={getOverallStatus(job)}
                              onNavigateToAnalysis={() => {}}
                              onCopyArticleCode={() => {}}
                          />
                      ))}
                  </div>
              </div>
          </DialogContent>
      </Dialog>
    </>
  );
}

"use client";

import React, { useState, useEffect } from 'react';
import * as z from 'zod';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import AdminAuthGuard from '@/components/AdminAuthGuard';
import AppShell from '@/components/layout/AppShell';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { useToast } from '@/hooks/use-toast';
import { Factory, Save, Loader2, Info } from 'lucide-react';
import { getProductionSettings, saveProductionSettings } from './actions';
import type { ProductionSettings } from '@/types';
import { useAuth } from '@/components/auth/AuthProvider';
import { Skeleton } from '@/components/ui/skeleton';
import { Form, FormControl, FormDescription, FormField, FormItem, FormLabel, FormMessage } from '@/components/ui/form';
import { Input } from '@/components/ui/input';
import { Switch } from '@/components/ui/switch';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';

const settingsSchema = z.object({
  capacityBufferPercent: z.coerce
    .number()
    .int("Deve essere un intero")
    .min(10, "Minimo 10%")
    .max(100, "Massimo 100%"),
  autoUpdateGanttIntervalHours: z.coerce
    .number()
    .min(0.5, "Minimo mezz'ora")
    .max(24, "Massimo 24 ore"),
  prioritizeActualTime: z.boolean(),
});

export default function ProductionSettingsPage() {
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const { user } = useAuth();
  const { toast } = useToast();

  const form = useForm<z.infer<typeof settingsSchema>>({
    resolver: zodResolver(settingsSchema),
    defaultValues: {
      capacityBufferPercent: 85,
      autoUpdateGanttIntervalHours: 1,
      prioritizeActualTime: true,
    },
  });

  const fetchSettings = async () => {
    setIsLoading(true);
    try {
        const data = await getProductionSettings();
        form.reset(data);
    } catch (error) {
        toast({
            variant: "destructive",
            title: "Errore",
            description: "Impossibile caricare le impostazioni di produzione.",
        });
    }
    setIsLoading(false);
  };

  useEffect(() => {
    fetchSettings();
  }, []);

  const onSubmit = async (values: z.infer<typeof settingsSchema>) => {
    if (!user) return;
    setIsSaving(true);
    const result = await saveProductionSettings(values, user.uid);
    toast({
      title: result.success ? "Impostazioni Salvate" : "Errore",
      description: result.message,
      variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
      await fetchSettings();
    }
    setIsSaving(false);
  };

  return (
    <AdminAuthGuard>
      <AppShell>
        <div className="space-y-8 max-w-4xl mx-auto">
          <header className="space-y-2">
            <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
              <Factory className="h-8 w-8 text-primary" />
              Impostazioni Produzione Globale
            </h1>
            <p className="text-muted-foreground">
              Regole fondamentali per lo Schedulatore Gantt e il controllo avanzamento di produzione (MES).
            </p>
          </header>

          <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)}>
              <Card>
                <CardHeader>
                  <CardTitle>Parametri Pianificazione (MRP)</CardTitle>
                  <CardDescription>
                    Modifica i valori algoritmici su cui si basa il calcolo del Diagramma di Gantt.
                  </CardDescription>
                </CardHeader>
                <CardContent className="space-y-6">
                  {isLoading ? (
                    <div className="space-y-4">
                      <Skeleton className="h-10 w-full" />
                      <Skeleton className="h-10 w-full" />
                      <Skeleton className="h-10 w-full" />
                    </div>
                  ) : (
                    <>
                      <FormField
                        control={form.control}
                        name="capacityBufferPercent"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Capacità Schedulabile Massima (%)</FormLabel>
                            <FormControl>
                              <Input type="number" {...field} />
                            </FormControl>
                            <FormDescription>
                              Percentuale di ore operatore/macchina impegnabili a sistema (es. 85%). Mantenere un margine (15%) serve ad assorbire urgenze, ritardi o imprevisti senza far crollare il Gantt.
                            </FormDescription>
                            <FormMessage />
                          </FormItem>
                        )}
                      />

                      <FormField
                        control={form.control}
                        name="autoUpdateGanttIntervalHours"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Frequenza Auto-Aggiornamento Avanzamento (Ore)</FormLabel>
                            <FormControl>
                              <Input type="number" step="0.5" {...field} />
                            </FormControl>
                            <FormDescription>
                              Se l'operatore non dichiara nulla, ogni quante ore di lavoro il sistema deve aggiornare in background lo stato progressivo della barra di produzione sul Gantt?
                            </FormDescription>
                            <FormMessage />
                          </FormItem>
                        )}
                      />

                      <FormField
                        control={form.control}
                        name="prioritizeActualTime"
                        render={({ field }) => (
                          <FormItem className="flex flex-row items-center justify-between rounded-lg border p-4 bg-primary/5">
                            <div className="space-y-0.5 pr-4">
                              <FormLabel className="text-base font-semibold">Priorità Tempo Effettivo</FormLabel>
                              <FormDescription>
                                Se abilitato, l'algoritmo del Gantt userà storicamente il Tempo Rilevato (se consolidato) anziché il Tempo Teorico d'Anagrafica per disegnare l'occupazione oraria.
                              </FormDescription>
                            </div>
                            <FormControl>
                              <Switch
                                checked={field.value}
                                onCheckedChange={field.onChange}
                              />
                            </FormControl>
                          </FormItem>
                        )}
                      />
                    </>
                  )}
                </CardContent>
                <CardFooter>
                  <Button type="submit" disabled={isSaving || isLoading} className="w-full sm:w-auto">
                    {isSaving ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <Save className="mr-2 h-4 w-4" />}
                    Salva Impostazioni
                  </Button>
                </CardFooter>
              </Card>
            </form>
          </Form>
          
           <Alert variant="default" className="border-amber-500/50 bg-amber-500/10 text-amber-900 dark:text-amber-200">
             <Info className="h-5 w-5 text-amber-600 dark:text-amber-400" />
            <AlertTitle className="text-amber-800 dark:text-amber-300">Come influisce la Capacità Massima?</AlertTitle>
            <AlertDescription>
             Se un operatore lavora 8 ore al giorno e la capacità massima è impostata all'85%, l'allocatore automatico del Gantt gli assegnerà compiti produttivi al massimo per **6.8 ore**. I restanti slot serviranno come cuscinetto flessibile.
            </AlertDescription>
          </Alert>
        </div>
      </AppShell>
    </AdminAuthGuard>
  );
}

"use client";

import React, { useState, useMemo, useEffect } from 'react';
import * as XLSX from 'xlsx';
import { useSearchParams, useRouter } from 'next/navigation';

import { Card, CardHeader, CardTitle, CardDescription, CardContent } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Accordion, AccordionContent, AccordionItem, AccordionTrigger } from '@/components/ui/accordion';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Timer, Package, Download, ChevronRight, Search, BarChart, Copy, ClipboardList, PackagePlus, Workflow, TestTube } from 'lucide-react';
import type { ProductionTimeAnalysisReport } from '../reports/actions';
import { Badge } from '@/components/ui/badge';
import {
    Collapsible,
    CollapsibleContent,
    CollapsibleTrigger,
} from "@/components/ui/collapsible";
import {
    ContextMenu,
    ContextMenuContent,
    ContextMenuItem,
    ContextMenuTrigger,
} from "@/components/ui/context-menu";
import { cn } from '@/lib/utils';
import { TooltipProvider, Tooltip, TooltipTrigger, TooltipContent } from '@/components/ui/tooltip';
import { useToast } from '@/hooks/use-toast';
import { Separator } from '@/components/ui/separator';

interface ProductionTimeAnalysisClientPageProps {
    report: ProductionTimeAnalysisReport[];
}

const phaseTypeTitles: Record<string, { title: string, icon: React.ElementType }> = {
    preparation: { title: 'Fasi di Preparazione', icon: PackagePlus },
    production: { title: 'Fasi di Produzione', icon: Workflow },
    quality: { title: 'Controllo Qualità', icon: TestTube },
    packaging: { title: 'Packaging', icon: Package },
};


export default function ProductionTimeAnalysisClientPage({ report }: ProductionTimeAnalysisClientPageProps) {
    const [searchTerm, setSearchTerm] = useState('');
    const [openAccordion, setOpenAccordion] = useState<string | undefined>(undefined);
    const searchParams = useSearchParams();
    const articleCodeFromUrl = searchParams.get('articleCode');
    const router = useRouter();
    const { toast } = useToast();

    useEffect(() => {
        if (articleCodeFromUrl) {
            setSearchTerm(articleCodeFromUrl);
            setOpenAccordion(articleCodeFromUrl);
        }
    }, [articleCodeFromUrl]);

    const filteredReport = useMemo(() => {
        if (!searchTerm) {
            return report;
        }
        const lowercasedFilter = searchTerm.toLowerCase();
        return report.filter(item =>
            item.articleCode.toLowerCase().includes(lowercasedFilter)
        );
    }, [report, searchTerm]);

    const handleExport = (articleReport: ProductionTimeAnalysisReport) => {
        const dataToExport: any[] = [];

        // Add average phase times first
        dataToExport.push({ 'Dettaglio': 'TEMPI MEDI PER FASE' });
        articleReport.averagePhaseTimes.forEach(phase => {
            dataToExport.push({
                'Dettaglio': phase.name,
                'Tempo Medio/Pezzo': phase.averageMinutesPerPiece.toFixed(4),
            });
        });
        dataToExport.push({}); // Add empty row for separation

        // Add job details
        dataToExport.push({ 'Dettaglio': 'DETTAGLIO PER COMMESSA' });
        articleReport.jobs.forEach(job => {
            // Main job row
            dataToExport.push({
                'Dettaglio': `Commessa: ${job.id}`,
                'Cliente': job.cliente,
                'Quantità': job.qta,
                'Calcolo Affidabile': job.isTimeCalculationReliable ? 'Sì' : 'No',
                'Fase': 'TOTALE COMMESSA',
                'Tempo Totale (min)': job.totalTimeMinutes.toFixed(2),
                'Tempo Medio/Pezzo': job.minutesPerPiece.toFixed(4),
            });
            // Phase rows
            job.phases.forEach(phase => {
                dataToExport.push({
                    'Fase': phase.name,
                    'Tempo Totale (min)': phase.totalTimeMinutes.toFixed(2),
                    'Tempo Medio/Pezzo': phase.minutesPerPiece.toFixed(4),
                });
            })
        });

        const ws = XLSX.utils.json_to_sheet(dataToExport);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, `Analisi ${articleReport.articleCode}`);
        XLSX.writeFile(wb, `analisi_tempi_${articleReport.articleCode}.xlsx`);
    };

    const handleCopy = (text: string) => {
        navigator.clipboard.writeText(text);
        toast({
            title: "Copiato!",
            description: `Il codice "${text}" è stato copiato negli appunti.`,
        });
    }


    return (
        <div className="space-y-6">
            <header className="space-y-2">
                <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
                    <Timer className="h-8 w-8 text-primary" />
                    Analisi Tempi di Produzione per Articolo
                </h1>
                <p className="text-muted-foreground">
                    Riepilogo dei tempi medi di lavorazione raggruppati per codice articolo.
                </p>
            </header>

            <Card>
                <CardHeader>
                    <div className="flex justify-between items-center flex-wrap gap-4">
                        <div>
                            <CardTitle>Report Articoli</CardTitle>
                            <CardDescription>
                                Espandi ogni articolo per visualizzare il dettaglio delle commesse e dei relativi tempi di produzione.
                            </CardDescription>
                        </div>
                        <div className="relative w-full sm:w-auto">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                            <Input
                                placeholder="Cerca per codice articolo..."
                                className="pl-9 w-full sm:w-64"
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                            />
                        </div>
                    </div>
                </CardHeader>
                <CardContent>
                    {report.length > 0 ? (
                        <Accordion type="single" collapsible className="w-full" value={openAccordion} onValueChange={setOpenAccordion}>
                            {filteredReport.map((item) => {
                                const groupedPhases = item.averagePhaseTimes.reduce((acc, phase) => {
                                    const type = phase.type || 'production';
                                    if (!acc[type]) {
                                        acc[type] = [];
                                    }
                                    acc[type].push(phase);
                                    return acc;
                                }, {} as Record<string, typeof item.averagePhaseTimes>);

                                return (
                                    <AccordionItem value={item.articleCode} key={item.articleCode}>
                                        <AccordionTrigger>
                                            <div className="flex justify-between items-center w-full pr-4">
                                                <div className="flex items-center gap-3">
                                                    <Package className="h-5 w-5 text-primary" />
                                                    <ContextMenu>
                                                        <ContextMenuTrigger>
                                                            <span className="font-semibold text-lg hover:text-primary hover:underline cursor-pointer">{item.articleCode}</span>
                                                        </ContextMenuTrigger>
                                                        <ContextMenuContent>
                                                            <ContextMenuItem onSelect={() => handleCopy(item.articleCode)}>
                                                                <Copy className="mr-2 h-4 w-4" />
                                                                Copia Codice Articolo
                                                            </ContextMenuItem>
                                                        </ContextMenuContent>
                                                    </ContextMenu>
                                                </div>
                                                <div className="text-right">
                                                    <TooltipProvider>
                                                        <Tooltip>
                                                            <TooltipTrigger>
                                                                <div className="text-sm text-muted-foreground">
                                                                    Tempo Medio/Pz
                                                                    <span className={cn(
                                                                        "ml-1 font-semibold",
                                                                        item.averageMinutesPerPiece > 0 ? "text-green-600 dark:text-green-500" : "text-amber-600 dark:text-amber-500"
                                                                    )}>
                                                                        ({item.averageMinutesPerPiece > 0 ? 'Affidabile' : 'Parziale'})
                                                                    </span>
                                                                </div>
                                                            </TooltipTrigger>
                                                            <TooltipContent>
                                                                <p>Calcolato solo su commesse completate senza forzature.</p>
                                                            </TooltipContent>
                                                        </Tooltip>
                                                    </TooltipProvider>
                                                    <div className="font-bold text-lg text-primary">{item.averageMinutesPerPiece > 0 ? `${item.averageMinutesPerPiece.toFixed(4)} min` : 'N/D'}</div>
                                                </div>
                                            </div>
                                        </AccordionTrigger>
                                        <AccordionContent>
                                            <div className="p-4 bg-muted/50 rounded-lg space-y-6">
                                                <div className="space-y-4">
                                                    <h4 className="font-semibold text-base mb-2 flex items-center gap-2"><BarChart className="h-5 w-5 text-primary" />Riepilogo Tempi Medi per Fase</h4>
                                                    {Object.entries(groupedPhases).map(([type, phases]) => {
                                                        const phaseInfo = phaseTypeTitles[type] || { title: type, icon: BarChart };
                                                        const Icon = phaseInfo.icon;
                                                        return (
                                                            <div key={type}>
                                                                <div className="flex items-center gap-2 mb-2">
                                                                    <Icon className="h-4 w-4 text-muted-foreground" />
                                                                    <h5 className="font-semibold text-muted-foreground">{phaseInfo.title}</h5>
                                                                </div>
                                                                <div className="overflow-x-auto border rounded-lg">
                                                                    <Table>
                                                                        <TableHeader>
                                                                            <TableRow>
                                                                                <TableHead>Fase di Lavorazione</TableHead>
                                                                                <TableHead className="text-right">Tempo Medio/Pezzo</TableHead>
                                                                            </TableRow>
                                                                        </TableHeader>
                                                                        <TableBody>
                                                                            {phases.map(phase => (
                                                                                <TableRow key={phase.name}>
                                                                                    <TableCell>{phase.name}</TableCell>
                                                                                    <TableCell className="text-right font-mono">{phase.averageMinutesPerPiece.toFixed(4)} min</TableCell>
                                                                                </TableRow>
                                                                            ))}
                                                                        </TableBody>
                                                                    </Table>
                                                                </div>
                                                                <Separator className="my-4" />
                                                            </div>
                                                        )
                                                    })}
                                                    {item.averagePhaseTimes.length === 0 && (
                                                        <p className="text-center text-sm text-muted-foreground py-4">Nessun dato aggregato disponibile per le fasi.</p>
                                                    )}
                                                </div>

                                                <div>
                                                    <div className="flex justify-between items-center mb-2">
                                                        <h4 className="font-semibold text-base flex items-center gap-2">Dettaglio Commesse ({item.totalJobs})</h4>
                                                        <Button variant="outline" size="sm" onClick={() => handleExport(item)}>
                                                            <Download className="mr-2 h-4 w-4" />
                                                            Esporta Dettaglio
                                                        </Button>
                                                    </div>
                                                    <div className="space-y-4">
                                                        {item.jobs.map(job => (
                                                            <Collapsible key={job.id} className="border-t pt-4">
                                                                <CollapsibleTrigger asChild>
                                                                    <div className="flex justify-between items-center w-full cursor-pointer hover:bg-background/50 p-2 rounded-md group">
                                                                        <div className="flex-1">
                                                                            <div className="font-mono text-base font-semibold">{job.id} <Badge variant="secondary" className="ml-2">Cliente: {job.cliente}</Badge></div>
                                                                            <div className="text-sm text-muted-foreground">Q.tà: {job.qta}</div>
                                                                        </div>
                                                                        <div className="text-right">
                                                                            <div className={cn("font-semibold", job.isTimeCalculationReliable ? "text-green-600 dark:text-green-500" : "text-amber-600 dark:text-amber-500")}>{job.minutesPerPiece.toFixed(4)} min/pz</div>
                                                                            <div className="text-xs text-muted-foreground">Tot: {job.totalTimeMinutes.toFixed(2)} min</div>
                                                                        </div>
                                                                        <ChevronRight className="h-4 w-4 ml-2 transition-transform duration-200 group-data-[state=open]:rotate-90" />
                                                                    </div>
                                                                </CollapsibleTrigger>
                                                                <CollapsibleContent>
                                                                    <div className="pl-6 pt-2">
                                                                        <Table>
                                                                            <TableHeader>
                                                                                <TableRow>
                                                                                    <TableHead>Fase (con tempo tracciato)</TableHead>
                                                                                    <TableHead className="text-right">Tempo Totale Fase</TableHead>
                                                                                    <TableHead className="text-right">Minuti/Pezzo</TableHead>
                                                                                </TableRow>
                                                                            </TableHeader>
                                                                            <TableBody>
                                                                                {job.phases.map((phase, index) => (
                                                                                    <TableRow key={index}>
                                                                                        <TableCell>{phase.name}</TableCell>
                                                                                        <TableCell className="text-right">{phase.totalTimeMinutes.toFixed(2)} min</TableCell>
                                                                                        <TableCell className="text-right font-medium">{phase.minutesPerPiece.toFixed(4)} min</TableCell>
                                                                                    </TableRow>
                                                                                ))}
                                                                            </TableBody>
                                                                        </Table>
                                                                    </div>
                                                                </CollapsibleContent>
                                                            </Collapsible>
                                                        ))}
                                                    </div>
                                                </div>
                                            </div>
                                        </AccordionContent>
                                    </AccordionItem>
                                )
                            })}
                            {filteredReport.length === 0 && (
                                <div className="text-center py-10 text-muted-foreground">
                                    Nessun articolo trovato per "{searchTerm}".
                                </div>
                            )}
                        </Accordion>
                    ) : (
                        <div className="flex flex-col items-center justify-center py-10 text-center">
                            <Package className="h-16 w-16 text-muted-foreground mb-4" />
                            <p className="text-lg font-semibold text-muted-foreground">Nessun dato disponibile.</p>
                            <p className="text-sm text-muted-foreground">
                                Non ci sono ancora commesse con tempi di lavorazione registrati.
                            </p>
                        </div>
                    )}
                </CardContent>
            </Card>
        </div>
    );
}

"use client";

import React, { useState, useRef, useMemo, useEffect } from 'react';
import * as XLSX from 'xlsx';
import { format, parseISO } from 'date-fns';
import { useToast } from '@/hooks/use-toast';
import { useAuth } from '@/components/auth/AuthProvider';
import { Card, CardHeader, CardTitle, CardDescription, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Badge } from '@/components/ui/badge';
import { 
  Truck, 
  PlusCircle, 
  Search, 
  Trash2, 
  Upload, 
  Loader2, 
  Calendar as CalendarIcon, 
  Save, 
  ChevronsUpDown, 
  Check, 
  Pencil, 
  Plus, 
  X, 
  Boxes, 
  ArrowUpDown,
  CheckCircle2,
  Package2
} from 'lucide-react';
import { getPurchaseOrders, deleteOrderGroup, importPurchaseOrders, savePurchaseOrder, closePurchaseOrder } from './actions';
import { getRawMaterials } from '../raw-material-management/actions';
import { 
  AlertDialog, 
  AlertDialogAction, 
  AlertDialogCancel, 
  AlertDialogContent, 
  AlertDialogDescription, 
  AlertDialogFooter, 
  AlertDialogHeader, 
  AlertDialogTitle,
  AlertDialogTrigger
} from '@/components/ui/alert-dialog';
import { 
  Dialog, 
  DialogContent, 
  DialogHeader, 
  DialogTitle,
  DialogFooter
} from '@/components/ui/dialog';
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from '@/components/ui/form';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { Command, CommandEmpty, CommandGroup, CommandInput, CommandItem, CommandList } from '@/components/ui/command';
import { Calendar } from '@/components/ui/calendar';
import { type PurchaseOrder, type RawMaterial } from '@/types';
import { useForm, useFieldArray } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { cn } from '@/lib/utils';
import { ScrollArea } from '@/components/ui/scroll-area';
import { useSearchParams } from 'next/navigation';
import { Accordion, AccordionContent, AccordionItem, AccordionTrigger } from '@/components/ui/accordion';

const itemSchema = z.object({
  id: z.string().optional(),
  materialCode: z.string().min(1, "Il codice materiale è obbligatorio."),
  quantity: z.coerce.number().positive("La quantità deve essere positiva."),
  unitOfMeasure: z.enum(['n', 'mt', 'kg']),
  expectedDeliveryDate: z.date({ required_error: "La data di consegna è obbligatoria." }),
});

const orderFormSchema = z.object({
  orderNumber: z.string().min(1, "Il numero ordine è obbligatorio."),
  supplierName: z.string().optional(),
  items: z.array(itemSchema).min(1, "Aggiungere almeno un materiale."),
});

type OrderFormValues = z.infer<typeof orderFormSchema>;

export default function PurchaseOrderManagementClientPage({ 
  initialOrders,
  rawMaterials
}: { 
  initialOrders: PurchaseOrder[],
  rawMaterials: RawMaterial[]
}) {
  const searchParams = useSearchParams();
  const materialCodeParam = searchParams.get('materialCode');
  
  const [orders, setOrders] = useState<PurchaseOrder[]>(initialOrders);
  const [searchTerm, setSearchTerm] = useState(materialCodeParam || '');
  const [isImporting, setIsImporting] = useState(false);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [editingOrderNumber, setEditingOrderNumber] = useState<string | null>(null);
  const [sortDirection, setSortDirection] = useState<'asc' | 'desc'>('asc');
  
  const [openComboboxIndex, setOpenComboboxIndex] = useState<number | null>(null);
  
  const [materialSuggestions, setMaterialSuggestions] = useState<RawMaterial[]>([]);
  const [isSearchingMaterials, setIsSearchingMaterials] = useState(false);
  const searchTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  const handleSearchMaterial = (term: string) => {
      if (searchTimeoutRef.current) clearTimeout(searchTimeoutRef.current);
      if (term.length < 2) {
          setMaterialSuggestions([]);
          setIsSearchingMaterials(false);
          return;
      }
      setIsSearchingMaterials(true);
      searchTimeoutRef.current = setTimeout(async () => {
          try {
             const res = await getRawMaterials(term);
             setMaterialSuggestions(res);
          } catch(e) {} finally {
             setIsSearchingMaterials(false);
          }
      }, 400);
  };
  
  const fileInputRef = useRef<HTMLInputElement>(null);
  const { toast } = useToast();
  const { user } = useAuth();

  useEffect(() => {
    if (materialCodeParam) {
      setSearchTerm(materialCodeParam);
    }
  }, [materialCodeParam]);

  const form = useForm<OrderFormValues>({
    resolver: zodResolver(orderFormSchema),
    defaultValues: {
      orderNumber: '',
      supplierName: '',
      items: [{ materialCode: '', quantity: 0, unitOfMeasure: 'n', expectedDeliveryDate: new Date() }]
    }
  });

  const { fields, append, remove } = useFieldArray({
    control: form.control,
    name: "items"
  });

  const groupedOrders = useMemo(() => {
    const groups: Record<string, {
        orderNumber: string;
        supplierName: string;
        items: PurchaseOrder[];
        earliestDelivery: string;
        status: 'pending' | 'received';
    }> = {};

    orders.forEach(o => {
        if (!groups[o.orderNumber]) {
            groups[o.orderNumber] = {
                orderNumber: o.orderNumber,
                supplierName: o.supplierName || 'N/D',
                items: [],
                earliestDelivery: '',
                status: 'received'
            };
        }
        groups[o.orderNumber].items.push(o);
        if (o.status === 'pending' || o.status === 'partially_received') {
            groups[o.orderNumber].status = 'pending';
        }
    });

    Object.values(groups).forEach(group => {
        const pendingItems = group.items.filter(i => i.status === 'pending' || i.status === 'partially_received');
        if (pendingItems.length > 0) {
            group.earliestDelivery = pendingItems.reduce((min, i) => 
                (min === '' || i.expectedDeliveryDate < min) ? i.expectedDeliveryDate : min, ''
            );
        } else {
            group.earliestDelivery = group.items.reduce((min, i) => 
                (min === '' || i.expectedDeliveryDate < min) ? i.expectedDeliveryDate : min, ''
            );
        }
    });

    let result = Object.values(groups);

    if (searchTerm) {
        const lower = searchTerm.toLowerCase();
        result = result.filter(g => 
            g.orderNumber.toLowerCase().includes(lower) ||
            g.supplierName.toLowerCase().includes(lower) ||
            g.items.some(i => i.materialCode.toLowerCase().includes(lower))
        );
    }

    result.sort((a, b) => {
        const dateA = new Date(a.earliestDelivery).getTime();
        const dateB = new Date(b.earliestDelivery).getTime();
        return sortDirection === 'asc' ? dateA - dateB : dateB - dateA;
    });

    return result;
  }, [orders, searchTerm, sortDirection]);

  const handleOpenDialog = (orderToEdit?: any) => {
    if (orderToEdit) {
        setEditingOrderNumber(orderToEdit.orderNumber);
        form.reset({
            orderNumber: orderToEdit.orderNumber,
            supplierName: orderToEdit.supplierName,
            items: orderToEdit.items.map((item: PurchaseOrder) => ({
                id: item.id,
                materialCode: item.materialCode,
                quantity: item.quantity,
                unitOfMeasure: item.unitOfMeasure,
                expectedDeliveryDate: new Date(item.expectedDeliveryDate)
            }))
        });
    } else {
        setEditingOrderNumber(null);
        form.reset({
            orderNumber: '',
            supplierName: '',
            items: [{ materialCode: '', quantity: 0, unitOfMeasure: 'n', expectedDeliveryDate: new Date() }]
        });
    }
    setIsDialogOpen(true);
  };

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file || !user) return;
    setIsImporting(true);
    try {
      const data = await file.arrayBuffer();
      const workbook = XLSX.read(data, { type: 'array', cellDates: true });
      const json: any[] = XLSX.utils.sheet_to_json(workbook.Sheets[workbook.SheetNames[0]]);
      const result = await importPurchaseOrders(json, user.uid);
      if (result.success) {
        toast({ title: "Importazione Riuscita" });
        const updated = await getPurchaseOrders();
        setOrders(updated);
      } else toast({ variant: 'destructive', title: "Errore", description: result.message });
    } catch (e) { toast({ variant: 'destructive', title: "Errore File" }); }
    finally { setIsImporting(false); }
  };

  const onManualSubmit = async (values: OrderFormValues) => {
    if (!user) return;
    setIsSaving(true);
    const payload = { 
        orderNumber: values.orderNumber, 
        supplierName: values.supplierName || '', 
        items: values.items.map(item => ({ 
            ...item, 
            expectedDeliveryDate: item.expectedDeliveryDate.toISOString() 
        })) 
    };
    
    const result = await savePurchaseOrder(payload, user.uid);
    if (result.success) {
      toast({ title: editingOrderNumber ? "Ordine Aggiornato" : "Ordini Salvati" });
      const updated = await getPurchaseOrders();
      setOrders(updated);
      setIsDialogOpen(false);
      form.reset();
    } else toast({ variant: "destructive", title: "Errore", description: result.message });
    setIsSaving(false);
  };

  const handleDeleteOrder = async (orderNumber: string) => {
      if (!user) return;
      const res = await deleteOrderGroup(orderNumber, user.uid);
      if (res.success) {
          toast({ title: "Ordine Eliminato" });
          setOrders(prev => prev.filter(o => o.orderNumber !== orderNumber));
      } else {
          toast({ variant: "destructive", title: "Errore", description: res.message });
      }
  };

  const handleCloseItem = async (itemId: string) => {
      if (!user) return;
      const res = await closePurchaseOrder(itemId, user.uid);
      if (res.success) {
          toast({ title: "Riga chiusa" });
          const updated = await getPurchaseOrders();
          setOrders(updated);
      } else {
          toast({ variant: "destructive", title: "Errore", description: res.message });
      }
  };

  return (
    <div className="space-y-6">
      <header className="flex flex-col sm:flex-row justify-between items-start gap-4">
        <div><h1 className="text-3xl font-bold font-headline flex items-center gap-3"><Truck className="h-8 w-8 text-primary" /> Ordini Fornitore</h1></div>
        <div className="flex items-center gap-2 pt-2 flex-wrap">
          <input type="file" ref={fileInputRef} onChange={handleFileChange} accept=".xlsx, .xls" className="hidden" />
          <Button onClick={() => fileInputRef.current?.click()} variant="outline" size="sm" disabled={isImporting}><Upload className="mr-2 h-4 w-4" /> Importa Excel</Button>
          <Button size="sm" onClick={() => handleOpenDialog()}><PlusCircle className="mr-2 h-4 w-4" /> Nuovo Ordine</Button>
        </div>
      </header>

      <Card>
        <CardHeader>
            <div className="flex flex-col md:flex-row justify-between items-center gap-4">
                <div>
                    <CardTitle>Riepilogo Ordini Raggruppati</CardTitle>
                    <CardDescription>Visualizza e gestisci gli ordini completi per fornitore.</CardDescription>
                </div>
                <div className="flex items-center gap-2 w-full md:w-auto">
                    <div className="relative flex-1 md:w-64">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                        <Input 
                            placeholder="Cerca ordine, materiale..." 
                            className="pl-9" 
                            value={searchTerm} 
                            onChange={(e) => setSearchTerm(e.target.value)} 
                        />
                    </div>
                    <Button 
                        variant="outline" 
                        size="sm" 
                        onClick={() => setSortDirection(prev => prev === 'asc' ? 'desc' : 'asc')}
                        className="whitespace-nowrap"
                    >
                        <ArrowUpDown className="mr-2 h-4 w-4" />
                        Scadenza {sortDirection === 'asc' ? '↑' : '↓'}
                    </Button>
                </div>
            </div>
        </CardHeader>
        <CardContent>
          <ScrollArea className="h-[600px] pr-4">
            <Accordion type="multiple" className="space-y-4">
                {groupedOrders.length > 0 ? groupedOrders.map((group) => (
                    <AccordionItem key={group.orderNumber} value={group.orderNumber} className="border rounded-lg bg-card overflow-hidden">
                        <AccordionTrigger className="px-4 py-3 hover:no-underline hover:bg-muted/30">
                            <div className="flex flex-1 items-center justify-between gap-4 text-left">
                                <div className="flex items-center gap-4">
                                    <Badge 
                                        className={cn(
                                            "min-w-[100px] justify-center uppercase font-bold",
                                            group.status === 'pending' ? "bg-amber-500 hover:bg-amber-600" : "bg-green-600 hover:bg-green-700"
                                        )}
                                    >
                                        {group.status === 'pending' ? 'In Attesa' : 'Ricevuto'}
                                    </Badge>
                                    <div>
                                        <p className="font-bold text-lg font-mono">{group.orderNumber}</p>
                                        <p className="text-xs text-muted-foreground">{group.supplierName}</p>
                                    </div>
                                </div>
                                <div className="text-right mr-4">
                                    <p className="text-[10px] uppercase font-bold text-muted-foreground">Scadenza Prossima</p>
                                    <p className="font-semibold text-sm flex items-center gap-1 justify-end">
                                        <CalendarIcon className="h-3 w-3" />
                                        {group.earliestDelivery ? format(parseISO(group.earliestDelivery), 'dd/MM/yy') : '---'}
                                    </p>
                                </div>
                            </div>
                        </AccordionTrigger>
                        <AccordionContent className="px-4 pb-4 border-t pt-2">
                            <div className="flex justify-end gap-2 mb-4 mt-2">
                                <Button size="sm" variant="outline" onClick={() => handleOpenDialog(group)}>
                                    <Pencil className="mr-2 h-4 w-4" /> Modifica Ordine
                                </Button>
                                <AlertDialog>
                                    <AlertDialogTrigger asChild>
                                        <Button size="sm" variant="destructive">
                                            <Trash2 className="mr-2 h-4 w-4" /> Elimina
                                        </Button>
                                    </AlertDialogTrigger>
                                    <AlertDialogContent>
                                        <AlertDialogHeader>
                                            <AlertDialogTitle>Sei sicuro di voler eliminare l'intero ordine?</AlertDialogTitle>
                                            <AlertDialogDescription>
                                                Questa azione eliminerà tutte le {group.items.length} righe dell'ordine {group.orderNumber}.
                                            </AlertDialogDescription>
                                        </AlertDialogHeader>
                                        <AlertDialogFooter>
                                            <AlertDialogCancel>Annulla</AlertDialogCancel>
                                            <AlertDialogAction onClick={() => handleDeleteOrder(group.orderNumber)} className="bg-destructive">Elimina Tutto</AlertDialogAction>
                                        </AlertDialogFooter>
                                    </AlertDialogContent>
                                </AlertDialog>
                            </div>
                            <Table>
                                <TableHeader>
                                    <TableRow>
                                        <TableHead>Materiale</TableHead>
                                        <TableHead>Quantità</TableHead>
                                        <TableHead>Ricevuta</TableHead>
                                        <TableHead>Data Consegna</TableHead>
                                        <TableHead>Stato</TableHead>
                                        <TableHead className="text-right">Azioni</TableHead>
                                    </TableRow>
                                </TableHeader>
                                <TableBody>
                                    {group.items.map(item => (
                                        <TableRow key={item.id}>
                                            <TableCell className="font-semibold">{item.materialCode}</TableCell>
                                            <TableCell>{item.quantity} {item.unitOfMeasure.toUpperCase()}</TableCell>
                                            <TableCell>{item.receivedQuantity || 0} {item.unitOfMeasure.toUpperCase()}</TableCell>
                                            <TableCell>{format(parseISO(item.expectedDeliveryDate), 'dd/MM/yy')}</TableCell>
                                            <TableCell>
                                                <Badge variant={item.status === 'received' ? 'default' : 'outline'} className={cn(item.status === 'received' && 'bg-green-600 hover:bg-green-700')}>
                                                    {item.status === 'received' ? 'OK' : item.status === 'partially_received' ? 'Parziale' : 'In Attesa'}
                                                </Badge>
                                            </TableCell>
                                            <TableCell className="text-right">
                                                {item.status !== 'received' && (
                                                    <AlertDialog>
                                                        <AlertDialogTrigger asChild>
                                                            <Button size="sm" variant="ghost" className="h-8 text-xs text-blue-600 hover:text-blue-700 hover:bg-blue-50">
                                                                <CheckCircle2 className="mr-1 h-3 w-3" /> Chiudi
                                                            </Button>
                                                        </AlertDialogTrigger>
                                                        <AlertDialogContent>
                                                            <AlertDialogHeader>
                                                                <AlertDialogTitle>Chiudere forzatamente la riga?</AlertDialogTitle>
                                                                <AlertDialogDescription>
                                                                    La quantità ordinata ({item.quantity}) verrà equiparata a quella ricevuta ({item.receivedQuantity || 0}). 
                                                                    La riga non risulterà più come "in arrivo".
                                                                </AlertDialogDescription>
                                                            </AlertDialogHeader>
                                                            <AlertDialogFooter>
                                                                <AlertDialogCancel>Annulla</AlertDialogCancel>
                                                                <AlertDialogAction onClick={() => handleCloseItem(item.id)}>Conferma Chiusura</AlertDialogAction>
                                                            </AlertDialogFooter>
                                                        </AlertDialogContent>
                                                    </AlertDialog>
                                                )}
                                            </TableCell>
                                        </TableRow>
                                    ))}
                                </TableBody>
                            </Table>
                        </AccordionContent>
                    </AccordionItem>
                )) : (
                    <div className="flex flex-col items-center justify-center py-20 text-muted-foreground">
                        <Package2 className="h-16 w-16 opacity-20 mb-4" />
                        <p>Nessun ordine trovato.</p>
                    </div>
                )}
            </Accordion>
          </ScrollArea>
        </CardContent>
      </Card>

      <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
        <DialogContent className="max-w-4xl max-h-[90vh] flex flex-col">
          <DialogHeader>
            <DialogTitle>{editingOrderNumber ? `Modifica Ordine: ${editingOrderNumber}` : 'Crea Nuovo Ordine Fornitore'}</DialogTitle>
          </DialogHeader>
          <Form {...form}>
            <form onSubmit={form.handleSubmit(onManualSubmit)} className="flex-1 overflow-hidden flex flex-col">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 pb-4 border-b">
                <FormField control={form.control} name="orderNumber" render={({ field }) => ( 
                    <FormItem>
                        <FormLabel>N° Ordine</FormLabel>
                        <FormControl><Input {...field} disabled={!!editingOrderNumber} placeholder="Es. 123/G" /></FormControl>
                        <FormMessage />
                    </FormItem> 
                )} />
                <FormField control={form.control} name="supplierName" render={({ field }) => ( 
                    <FormItem>
                        <FormLabel>Fornitore</FormLabel>
                        <FormControl><Input {...field} placeholder="Nome Fornitore" /></FormControl>
                        <FormMessage />
                    </FormItem> 
                )} />
              </div>
              <ScrollArea className="flex-1 py-4">
                <div className="space-y-4">
                  <h4 className="font-semibold flex items-center gap-2"><Boxes className="h-4 w-4"/> Righe Materiale</h4>
                  {fields.map((item, index) => (
                    <div key={item.id} className="p-4 border rounded-lg grid grid-cols-12 gap-3 items-end bg-muted/20 relative">
                      <div className="col-span-12 sm:col-span-4">
                        <FormField control={form.control} name={`items.${index}.materialCode`} render={({ field }) => (
                          <FormItem className="flex flex-col"><FormLabel>Materiale</FormLabel>
                            <Popover open={openComboboxIndex === index} onOpenChange={(open) => setOpenComboboxIndex(open ? index : null)}>
                              <PopoverTrigger asChild><FormControl><Button variant="outline" className="w-full justify-between">{field.value || "Seleziona..."}<ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-50" /></Button></FormControl></PopoverTrigger>
                              <PopoverContent className="w-[--radix-popover-trigger-width] p-0"><Command><CommandInput placeholder="Cerca minimo 2 char..." onValueChange={handleSearchMaterial} /><CommandList><CommandEmpty>{isSearchingMaterials ? <Loader2 className="h-4 w-4 animate-spin mx-auto my-2" /> : "Nessun materiale."}</CommandEmpty><CommandGroup>
                                {materialSuggestions.map((m) => (<CommandItem key={m.id} value={m.code} onSelect={() => { form.setValue(`items.${index}.materialCode`, m.code); form.setValue(`items.${index}.unitOfMeasure`, m.unitOfMeasure); setOpenComboboxIndex(null); }}>{m.code}</CommandItem>))}
                              </CommandGroup></CommandList></Command></PopoverContent>
                            </Popover>
                          </FormItem>
                        )} />
                      </div>
                      <div className="col-span-6 sm:col-span-2"><FormField control={form.control} name={`items.${index}.quantity`} render={({ field }) => ( <FormItem><FormLabel>Quantità</FormLabel><FormControl><Input type="number" step="any" {...field} /></FormControl></FormItem> )} /></div>
                      <div className="col-span-6 sm:col-span-2"><FormField control={form.control} name={`items.${index}.unitOfMeasure`} render={({ field }) => ( <FormItem><FormLabel>UM</FormLabel><FormControl><Input readOnly {...field} className="bg-muted"/></FormControl></FormItem> )} /></div>
                      <div className="col-span-10 sm:col-span-3"><FormField control={form.control} name={`items.${index}.expectedDeliveryDate`} render={({ field }) => ( <FormItem><FormLabel>Consegna</FormLabel><Popover><PopoverTrigger asChild><Button variant="outline" className="w-full justify-start">{field.value ? format(field.value, "dd/MM/yy") : "Data"}</Button></PopoverTrigger><PopoverContent className="w-auto p-0"><Calendar mode="single" selected={field.value} onSelect={field.onChange} initialFocus /></PopoverContent></Popover></FormItem> )} /></div>
                      <div className="col-span-2 sm:col-span-1">
                        <Button type="button" variant="ghost" size="icon" onClick={() => remove(index)} className="text-destructive">
                            <X className="h-4 w-4" />
                        </Button>
                      </div>
                    </div>
                  ))}
                  <Button type="button" variant="outline" className="w-full border-dashed" onClick={() => append({ materialCode: '', quantity: 0, unitOfMeasure: 'n', expectedDeliveryDate: new Date() })}><Plus className="mr-2 h-4 w-4"/> Aggiungi riga materiale</Button>
                </div>
              </ScrollArea>
              <DialogFooter className="pt-4 border-t">
                <Button type="submit" disabled={isSaving}>
                    {isSaving ? <Loader2 className="animate-spin mr-2" /> : <Save className="mr-2" />} 
                    {editingOrderNumber ? "Salva Modifiche" : "Registra Ordine"}
                </Button>
              </DialogFooter>
            </form>
          </Form>
        </DialogContent>
      </Dialog>
    </div>
  );
}

"use client";

import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import * as z from 'zod';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { useToast } from '@/hooks/use-toast';
import { format, parseISO, parse, isValid } from 'date-fns';
import { it } from 'date-fns/locale';
import * as XLSX from 'xlsx';

import { type ManualCommitment, type Article, type RawMaterial, type RawMaterialBatch } from '@/types';
import { saveManualCommitment, deleteManualCommitment, importManualCommitments, revertManualCommitmentFulfillment, declareCommitmentFulfillment, type LotSelectionPayload, getMaterialsByCodes, getLotInfoForMaterial, type LotInfo } from './actions';
import { getArticles } from '../article-management/actions';
import { useAuth } from '@/components/auth/AuthProvider';

import { Button } from '@/components/ui/button';
import { Card, CardHeader, CardTitle, CardDescription, CardContent } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Dialog, DialogTrigger, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter, DialogClose } from '@/components/ui/dialog';
import { AlertDialog, AlertDialogTrigger, AlertDialogContent, AlertDialogHeader, AlertDialogTitle, AlertDialogDescription, AlertDialogFooter, AlertDialogCancel, AlertDialogAction } from '@/components/ui/alert-dialog';
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Input } from '@/components/ui/input';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { Command, CommandEmpty, CommandGroup, CommandInput, CommandItem, CommandList } from '@/components/ui/command';
import { Calendar } from '@/components/ui/calendar';
import { Badge } from '@/components/ui/badge';
import { CalendarIcon, Check, ChevronsUpDown, FileCheck2, Loader2, PlusCircle, Trash2, CheckCircle2, Circle, Upload, Download, Undo2, TestTube, Send, Search } from 'lucide-react';
import { cn, formatDisplayStock } from '@/lib/utils';
import { Label } from '@/components/ui/label';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Skeleton } from '@/components/ui/skeleton';
import { Select, SelectTrigger, SelectValue, SelectContent, SelectItem } from '@/components/ui/select';
import { Checkbox } from '@/components/ui/checkbox';
import { calculateBOMRequirement } from '@/lib/inventory-utils';
import { GlobalSettings } from '@/lib/settings-types';
import { getGlobalSettings } from '@/lib/settings-actions';

// Schemas and types at top level
const declarationSchema = z.object({
  goodPieces: z.coerce.number().min(0, "La quantità non può essere negativa."),
  scrapPieces: z.coerce.number().min(0, "La quantità non può essere negativa.").default(0),
});
type DeclarationFormValues = z.infer<typeof declarationSchema>;


// Declaration Dialog Component moved to top level
function DeclarationDialog({
  isOpen,
  onOpenChange,
  commitment,
  articleCode,
  onDeclare,
  globalSettings
}: {
  isOpen: boolean;
  onOpenChange: (open: boolean) => void;
  commitment: ManualCommitment;
  articleCode: string;
  onDeclare: (values: DeclarationFormValues, lotSelections: LotSelectionPayload[]) => void;
  globalSettings: GlobalSettings | null;
}) {
  const { toast } = useToast();
  const form = useForm<DeclarationFormValues>({
    resolver: zodResolver(declarationSchema),
  });

  const [article, setArticle] = useState<Article | undefined>();
  const [componentMaterials, setComponentMaterials] = useState<RawMaterial[]>([]);
  const [lotInfo, setLotInfo] = useState<LotInfo[]>([]);
  const [isLoadingMaterials, setIsLoadingMaterials] = useState(false);
  const [selectedLottos, setSelectedLottos] = useState<Set<string>>(new Set());

  const { goodPieces, scrapPieces } = form.watch();

  useEffect(() => {
    if (isOpen) {
      form.reset({ goodPieces: commitment.quantity, scrapPieces: 0 });
      setSelectedLottos(new Set()); // Reset selections

        const fetchComponentMaterialsAndLots = async () => {
          setIsLoadingMaterials(true);
          try {
             // Fetch Article first
             const fetchedArticles = await getArticles(articleCode);
             const currentArticle = fetchedArticles.find(a => a.code === articleCode);
             setArticle(currentArticle);

             const componentCode = currentArticle?.billOfMaterials?.[0]?.component;
             if (componentCode) {
               const materials = await getMaterialsByCodes([componentCode]);
               const material = materials[0];
               if (material) {
                 setComponentMaterials([material]);
                 const lotData = await getLotInfoForMaterial(material.id);
                 setLotInfo(lotData);
               } else {
                 setComponentMaterials([]);
                 setLotInfo([]);
               }
             } else {
               setComponentMaterials([]);
               setLotInfo([]);
             }
          } catch(e) {
             console.error(e);
          } finally {
             setIsLoadingMaterials(false);
          }
        };
        fetchComponentMaterialsAndLots();
    }
  }, [isOpen, articleCode, commitment.quantity, form]);

  const bomItem = useMemo(() => article?.billOfMaterials?.[0], [article]);
  const material = componentMaterials[0];

  const reqDetails = useMemo(() => {
    if (!bomItem || !material || !globalSettings) return null;
    const totalPieces = (Number(goodPieces) || 0) + (Number(scrapPieces) || 0);
    const config = globalSettings.rawMaterialTypes.find(t => t.id === material.type) || { defaultUnit: material.unitOfMeasure };
    return calculateBOMRequirement(totalPieces, bomItem, material, config as any);
  }, [bomItem, material, goodPieces, scrapPieces, globalSettings]);

  const totalRequirement = reqDetails?.totalInBaseUnits || 0;
  const displayUnit = reqDetails?.totalMeters !== undefined ? 'mt' : reqDetails?.baseUnit || 'n';

  const sortedSelectedLottos = useMemo(() => {
    return lotInfo
      .filter(l => selectedLottos.has(l.lotto))
      .sort((a, b) => new Date(a.batches[0].date).getTime() - new Date(b.batches[0].date).getTime());
  }, [lotInfo, selectedLottos]);

  const { consumptionMap, totalSelected, isRequirementMet } = useMemo(() => {
    const newConsumptionMap = new Map<string, number>();
    let remainingRequirement = totalRequirement;

    for (const lot of sortedSelectedLottos) {
      if (remainingRequirement <= 0.001) break;
      const consumedFromThisLot = Math.min(remainingRequirement, lot.available);
      newConsumptionMap.set(lot.lotto, consumedFromThisLot);
      remainingRequirement -= consumedFromThisLot;
    }

    const totalSelectedAmount = Array.from(newConsumptionMap.values()).reduce((sum, val) => sum + val, 0);

    return {
      consumptionMap: newConsumptionMap,
      totalSelected: totalSelectedAmount,
      isRequirementMet: totalRequirement === 0 || totalSelectedAmount >= totalRequirement - 0.001,
    };
  }, [sortedSelectedLottos, totalRequirement]);

  const handleDeclareSubmit = (values: DeclarationFormValues) => {
    if (!isRequirementMet) {
      toast({ variant: "destructive", title: "Fabbisogno non soddisfatto", description: "Selezionare lotti sufficienti a coprire il fabbisogno." });
      return;
    }

    const selectionsPayload: LotSelectionPayload[] = [];
    consumptionMap.forEach((consumed, lotto) => {
      if (consumed > 0) {
        if (material) {
          selectionsPayload.push({
            materialId: material.id,
            componentCode: material.code,
            lotto: lotto,
            consumed: consumed
          });
        }
      }
    });

    onDeclare(values, selectionsPayload);
  };

  return (
    <Dialog open={isOpen} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-4xl h-[90vh] flex flex-col p-0">
        <DialogHeader className="p-6 pb-2">
          <DialogTitle>Dichiarazione di Produzione</DialogTitle>
          <DialogDescription>
            Conferma la quantità prodotta, eventuali scarti e seleziona i lotti da cui scaricare il materiale per la commessa <span className="font-bold">{commitment.jobOrderCode}</span>.
          </DialogDescription>
        </DialogHeader>
        <Form {...form}>
          <form onSubmit={form.handleSubmit(handleDeclareSubmit)} className="flex-1 flex flex-col overflow-hidden">
            <div className="px-6 pt-4">
              <div className="grid grid-cols-2 gap-4">
                <FormField control={form.control} name="goodPieces" render={({ field }) => (
                  <FormItem>
                    <FormLabel>Pezzi Prodotti</FormLabel>
                    <FormControl><Input type="number" {...field} /></FormControl>
                    <FormMessage />
                  </FormItem>
                )} />
                <FormField control={form.control} name="scrapPieces" render={({ field }) => (
                  <FormItem>
                    <FormLabel className="flex items-center gap-2"><TestTube className="h-4 w-4 text-destructive" /> Pezzi di Scarto</FormLabel>
                    <FormControl><Input type="number" {...field} /></FormControl>
                    <FormMessage />
                  </FormItem>
                )} />
              </div>
            </div>
            <div className="flex-1 px-6 py-4 min-h-0">
              <ScrollArea className="h-full pr-6">
                {isLoadingMaterials ? (
                  <div className="space-y-4"> <Skeleton className="h-24 w-full" /> <Skeleton className="h-24 w-full" /> </div>
                ) : bomItem ? (
                  <div className="p-4 border rounded-lg">
                    <div className="flex justify-between items-center mb-4 flex-wrap gap-2">
                      <h4 className="font-semibold">{bomItem.component}</h4>
                      <div className="text-right text-sm">
                        <p>Fabbisogno: <span className="font-bold">{formatDisplayStock(totalRequirement, displayUnit)} {displayUnit}</span></p>
                        <p>Selezionato: <span className={cn("font-bold", !isRequirementMet && totalRequirement > 0 ? 'text-destructive' : 'text-green-600')}>{formatDisplayStock(totalSelected, displayUnit)} {displayUnit}</span></p>
                      </div>
                    </div>
                    <Table>
                      <TableHeader>
                        <TableRow>
                          <TableHead className="w-[50px]">Sel.</TableHead>
                          <TableHead>Lotto</TableHead>
                          <TableHead>Disponibile</TableHead>
                          <TableHead className="text-right">Da Usare</TableHead>
                        </TableRow>
                      </TableHeader>
                      <TableBody>
                        {lotInfo.map(lot => {
                          const consumed = consumptionMap.get(lot.lotto) || 0;
                          return (
                            <TableRow key={lot.lotto} data-state={selectedLottos.has(lot.lotto) && "selected"}>
                              <TableCell>
                                <Checkbox
                                  checked={selectedLottos.has(lot.lotto)}
                                  onCheckedChange={(checked) => {
                                    setSelectedLottos(prev => {
                                      const newSet = new Set(prev);
                                      if (checked) {
                                        newSet.add(lot.lotto);
                                      } else {
                                        newSet.delete(lot.lotto);
                                      }
                                      return newSet;
                                    })
                                  }}
                                />
                              </TableCell>
                              <TableCell>{lot.lotto}</TableCell>
                              <TableCell>{formatDisplayStock(lot.available, displayUnit)} {displayUnit}</TableCell>
                              <TableCell className="text-right font-mono font-semibold text-primary">{formatDisplayStock(consumed, displayUnit)} {displayUnit}</TableCell>
                            </TableRow>
                          )
                        })}
                      </TableBody>
                    </Table>
                  </div>
                ) : null}
              </ScrollArea>
            </div>
            <DialogFooter className="p-6 pt-4 border-t sticky bottom-0 bg-background">
              <Button type="button" variant="outline" onClick={() => onOpenChange(false)}>Annulla</Button>
              <Button type="submit" disabled={form.formState.isSubmitting || !isRequirementMet || isLoadingMaterials}>
                {form.formState.isSubmitting ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Send className="mr-2 h-4 w-4" />}
                Dichiara e Scarica Stock
              </Button>
            </DialogFooter>
          </form>
        </Form>
      </DialogContent>
    </Dialog>
  );
}

// Main Component
export default function CommitmentManagementClientPage({
  initialCommitments,
  initialArticles,
}: {
  initialCommitments: ManualCommitment[];
  initialArticles: Article[];
}) {
  const [commitments, setCommitments] = useState(initialCommitments);
  const [searchTerm, setSearchTerm] = useState('');
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [isPending, setIsPending] = useState(false);
  const [declarationTarget, setDeclarationTarget] = useState<ManualCommitment | null>(null);
  const [globalSettings, setGlobalSettings] = useState<GlobalSettings | null>(null);

  const { toast } = useToast();
  const { user } = useAuth();
  const router = useRouter();
  const [dateString, setDateString] = useState<string>('');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isImporting, setIsImporting] = useState(false);

  // New state for article popover
  const [isArticlePopoverOpen, setIsArticlePopoverOpen] = useState(false);
  const [articleSuggestions, setArticleSuggestions] = useState<Article[]>([]);
  const [isSearchingArticles, setIsSearchingArticles] = useState(false);
  const searchTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  useEffect(() => {
    getGlobalSettings().then(setGlobalSettings);
  }, []);

  const handleSearchArticle = (term: string) => {
      if (searchTimeoutRef.current) clearTimeout(searchTimeoutRef.current);
      if (term.length < 2) {
          setArticleSuggestions([]);
          setIsSearchingArticles(false);
          return;
      }
      setIsSearchingArticles(true);
      searchTimeoutRef.current = setTimeout(async () => {
          try {
             const res = await getArticles(term);
             setArticleSuggestions(res);
          } catch(e) {} finally {
             setIsSearchingArticles(false);
          }
      }, 400);
  };

  const commitmentFormSchema = z.object({
    id: z.string().optional(),
    jobOrderCode: z.string().min(1, "Il codice commessa è obbligatorio."),
    articleCode: z.string().min(1, "Selezionare un articolo."),
    quantity: z.coerce.number().positive("La quantità deve essere un numero positivo."),
    deliveryDate: z.date({ required_error: "La data di consegna è obbligatoria." }),
  });
  type CommitmentFormValues = z.infer<typeof commitmentFormSchema>;

  const form = useForm<CommitmentFormValues>({
    resolver: zodResolver(commitmentFormSchema),
  });

  useEffect(() => {
    setCommitments(initialCommitments);
  }, [initialCommitments]);

  useEffect(() => {
    if (isFormOpen) {
      const deliveryDate = form.getValues('deliveryDate');
      if (deliveryDate && isValid(deliveryDate)) {
        setDateString(format(deliveryDate, 'dd/MM/yyyy'));
      } else {
        setDateString('');
      }
    }
  }, [isFormOpen, form]);

  const filteredCommitments = useMemo(() => {
    if (!searchTerm) {
      return commitments;
    }
    const lowercasedFilter = searchTerm.toLowerCase();
    return commitments.filter(c =>
      c.jobOrderCode.toLowerCase().includes(lowercasedFilter) ||
      c.articleCode.toLowerCase().includes(lowercasedFilter)
    );
  }, [commitments, searchTerm]);

  const onSubmit = async (values: CommitmentFormValues) => {
    if (!user) return;
    setIsPending(true);
    const result = await saveManualCommitment(values, user.uid);
    toast({
      title: result.success ? "Successo" : "Errore",
      description: result.message,
      variant: result.success ? "default" : "destructive",
    });

    if (result.success) {
      router.refresh();
      setIsFormOpen(false);
      form.reset();
    }
    setIsPending(false);
  };

  const handleDelete = async (commitmentId: string) => {
    setIsPending(true);
    const result = await deleteManualCommitment(commitmentId);
    toast({
      title: result.success ? "Successo" : "Errore",
      description: result.message,
      variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
      router.refresh();
    }
    setIsPending(false);
  };

  const handleDeclare = async (values: DeclarationFormValues, lotSelections: LotSelectionPayload[]) => {
    if (!user || !declarationTarget) return;
    setIsPending(true);

    const result = await declareCommitmentFulfillment(
      declarationTarget.id,
      values.goodPieces,
      values.scrapPieces,
      lotSelections,
      user.uid
    );

    toast({
      title: result.success ? "Successo" : "Errore",
      description: result.message,
      variant: result.success ? "default" : "destructive",
      duration: 9000
    });

    if (result.success) {
      router.refresh();
      setDeclarationTarget(null);
    }
    setIsPending(false);
  };

  const handleRevertFulfillment = async (commitmentId: string) => {
    if (!user) return;
    setIsPending(true);
    const result = await revertManualCommitmentFulfillment(commitmentId, user.uid);
    toast({
      title: result.success ? "Operazione Annullata" : "Errore",
      description: result.message,
      variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
      router.refresh();
    }
    setIsPending(false);
  };

  const handleDownloadTemplate = () => {
    const templateData = [
      {
        "Commessa": "COMM-001/24",
        "Codice Articolo": "ART-001",
        "Quantita": 100,
        "Data Consegna": "25/07/2024",
      },
    ];
    const ws = XLSX.utils.json_to_sheet(templateData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Impegni Manuali");
    XLSX.writeFile(wb, "template_impegni_manuali.xlsx");
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file || !user) return;

    setIsImporting(true);
    toast({ title: 'Importazione in corso...', description: 'Lettura e validazione del file Excel in corso.' });

    try {
      const data = await file.arrayBuffer();
      const workbook = XLSX.read(data, { type: 'array', cellDates: true });
      const sheetName = workbook.SheetNames[0];
      const worksheet = workbook.Sheets[sheetName];
      const json: any[] = XLSX.utils.sheet_to_json(worksheet);

      if (json.length === 0) {
        toast({ variant: 'destructive', title: "File Vuoto", description: "Il file non contiene righe da importare." });
        setIsImporting(false);
        return;
      }

      const result = await importManualCommitments(json, user.uid);

      toast({
        title: result.success ? "Importazione Completata" : "Errore di Importazione",
        description: result.message,
        variant: result.success ? "default" : "destructive",
        duration: 9000,
      });

      if (result.success) {
        router.refresh();
      }

    } catch (error) {
      toast({
        variant: "destructive",
        title: "Errore Importazione",
        description: error instanceof Error ? error.message : "Impossibile leggere o processare il file.",
      });
    } finally {
      setIsImporting(false);
      if (fileInputRef.current) fileInputRef.current.value = "";
    }
  };

  return (
    <>
      <Card>
        <CardHeader>
          <div className="flex justify-between items-center">
            <CardTitle className="font-headline">Impegni Manuali su Commessa</CardTitle>
            <div className="flex items-center gap-2">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                  placeholder="Cerca..."
                  className="pl-9"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
              </div>
              <input type="file" ref={fileInputRef} onChange={handleFileChange} accept=".xlsx, .xls" className="hidden" />
              <Button onClick={handleDownloadTemplate} variant="outline" size="sm">
                <Download className="mr-2 h-4 w-4" />
                Scarica Template
              </Button>
              <Button onClick={handleImportClick} variant="outline" size="sm" disabled={isImporting}>
                {isImporting ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Upload className="mr-2 h-4 w-4" />}
                Carica da File
              </Button>
              <Dialog open={isFormOpen} onOpenChange={setIsFormOpen}>
                <DialogTrigger asChild>
                  <Button><PlusCircle className="mr-2 h-4 w-4" /> Aggiungi Impegno</Button>
                </DialogTrigger>
                <DialogContent className="sm:max-w-xl">
                  <DialogHeader>
                    <DialogTitle>Aggiungi Nuovo Impegno Manuale</DialogTitle>
                    <DialogDescription>
                      Inserisci i dettagli per creare un nuovo impegno di materiale su una commessa.
                    </DialogDescription>
                  </DialogHeader>
                  <Form {...form}>
                    <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4 py-4">
                      <FormField control={form.control} name="jobOrderCode" render={({ field }) => (<FormItem> <FormLabel>Commessa di Riferimento</FormLabel> <FormControl><Input placeholder="Es. Comm-1234/24" {...field} /></FormControl> <FormMessage /> </FormItem>)} />
                      <FormField control={form.control} name="articleCode" render={({ field }) => (
                        <FormItem className="flex flex-col">
                          <FormLabel>Codice Articolo</FormLabel>
                          <Popover open={isArticlePopoverOpen} onOpenChange={setIsArticlePopoverOpen}><PopoverTrigger asChild><FormControl>
                            <Button variant="outline" role="combobox" className={cn("w-full justify-between", !field.value && "text-muted-foreground")}>
                              {field.value || "Seleziona articolo..."}
                              <ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-50" />
                            </Button>
                          </FormControl></PopoverTrigger>
                            <PopoverContent className="w-[--radix-popover-trigger-width] p-0"><Command>
                              <CommandInput placeholder="Cerca minimo 2 char..." onValueChange={handleSearchArticle} />
                              <CommandList>
                                <CommandEmpty>{isSearchingArticles ? <Loader2 className="h-4 w-4 animate-spin mx-auto my-2" /> : "Nessun articolo."}</CommandEmpty>
                                <CommandGroup>
                                  {articleSuggestions.map((article) => (
                                    <CommandItem value={article.code} key={article.id} onSelect={() => { form.setValue("articleCode", article.code); setIsArticlePopoverOpen(false); }}>
                                      <Check className={cn("mr-2 h-4 w-4", article.code === field.value ? "opacity-100" : "opacity-0")} />
                                      {article.code}
                                    </CommandItem>
                                  ))}
                                </CommandGroup>
                              </CommandList>
                            </Command></PopoverContent></Popover>
                          <FormMessage />
                        </FormItem>
                      )} />
                      <FormField control={form.control} name="quantity" render={({ field }) => (<FormItem> <FormLabel>Quantità da Produrre</FormLabel> <FormControl><Input type="number" {...field} /></FormControl> <FormMessage /> </FormItem>)} />
                      <FormField
                        control={form.control}
                        name="deliveryDate"
                        render={({ field }) => (
                          <FormItem className="flex flex-col">
                            <FormLabel>Data Consegna Prevista</FormLabel>
                            <Popover>
                              <div className="relative flex items-center">
                                <FormControl>
                                  <Input
                                    placeholder="gg/mm/aaaa"
                                    value={dateString}
                                    onChange={(e) => {
                                      let value = e.target.value.replace(/\D/g, "");
                                      if (value.length > 8) {
                                        value = value.slice(0, 8);
                                      }
                                      let formattedValue = value;
                                      if (value.length > 4) {
                                        formattedValue = `${value.slice(0, 2)}/${value.slice(2, 4)}/${value.slice(4, 8)}`;
                                      } else if (value.length > 2) {
                                        formattedValue = `${value.slice(0, 2)}/${value.slice(2)}`;
                                      }
                                      setDateString(formattedValue);

                                      if (formattedValue.length === 10) {
                                        const parsedDate = parse(formattedValue, 'dd/MM/yyyy', new Date());
                                        if (isValid(parsedDate)) {
                                          field.onChange(parsedDate);
                                        } else {
                                          field.onChange(undefined);
                                        }
                                      } else {
                                        field.onChange(undefined);
                                      }
                                    }}
                                  />
                                </FormControl>
                                <PopoverTrigger asChild>
                                  <Button
                                    variant={"ghost"}
                                    className="absolute right-1 h-8 w-8 p-0"
                                    aria-label="Apri calendario"
                                  >
                                    <CalendarIcon className="h-4 w-4 text-muted-foreground" />
                                  </Button>
                                </PopoverTrigger>
                              </div>
                              <PopoverContent className="w-auto p-0" align="start">
                                <Calendar
                                  mode="single"
                                  selected={field.value}
                                  onSelect={(date) => {
                                    field.onChange(date);
                                    if (date && isValid(date)) {
                                      setDateString(format(date, 'dd/MM/yyyy'));
                                    } else {
                                      setDateString('');
                                    }
                                  }}
                                  initialFocus
                                />
                              </PopoverContent>
                            </Popover>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                      <DialogFooter>
                        <DialogClose asChild><Button type="button" variant="outline" disabled={isPending}>Annulla</Button></DialogClose>
                        <Button type="submit" disabled={isPending}>{isPending ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : null} Salva Impegno</Button>
                      </DialogFooter>
                    </form>
                  </Form>
                </DialogContent>
              </Dialog>
            </div>
          </div>
        </CardHeader>
        <CardContent>
          <div className="overflow-x-auto">
            <Table>
              <TableHeader><TableRow>
                <TableHead>Stato</TableHead><TableHead>Commessa</TableHead><TableHead>Articolo</TableHead>
                <TableHead>Quantità</TableHead><TableHead>Data Consegna</TableHead>
                <TableHead className="text-right">Azioni</TableHead>
              </TableRow></TableHeader>
              <TableBody>
                {filteredCommitments.length > 0 ? filteredCommitments.map(c => (
                  <TableRow key={c.id}>
                    <TableCell>
                      <Badge variant={c.status === 'fulfilled' ? 'default' : 'secondary'}>
                        {c.status === 'fulfilled' ? <CheckCircle2 className="mr-2 h-4 w-4" /> : <Circle className="mr-2 h-4 w-4" />}
                        {c.status === 'fulfilled' ? 'Evaso' : 'In Attesa'}
                      </Badge>
                    </TableCell>
                    <TableCell>{c.jobOrderCode}</TableCell><TableCell>{c.articleCode}</TableCell>
                    <TableCell>{c.quantity}</TableCell>
                    <TableCell>{format(parseISO(c.deliveryDate as any), "dd/MM/yyyy")}</TableCell>
                    <TableCell className="text-right space-x-2">
                      {c.status === 'pending' ? (
                        <Button size="sm" disabled={isPending} onClick={() => setDeclarationTarget(c)}>
                          <FileCheck2 className="mr-2 h-4 w-4" />Dichiara
                        </Button>
                      ) : (
                        <AlertDialog>
                          <AlertDialogTrigger asChild><Button size="sm" variant="secondary" disabled={isPending}><Undo2 className="mr-2 h-4 w-4" />Annulla Evasione</Button></AlertDialogTrigger>
                          <AlertDialogContent>
                            <AlertDialogHeader><AlertDialogTitle>Annullare l'evasione?</AlertDialogTitle><AlertDialogDescription>Questa azione riporterà l'impegno allo stato 'In Attesa' e ripristinerà lo stock dei materiali precedentemente scaricati (inclusi gli scarti). Sei sicuro?</AlertDialogDescription></AlertDialogHeader>
                            <AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={() => handleRevertFulfillment(c.id)}>Sì, Annulla Evasione</AlertDialogAction></AlertDialogFooter>
                          </AlertDialogContent>
                        </AlertDialog>
                      )}
                      <AlertDialog>
                        <AlertDialogTrigger asChild><Button size="icon" variant="destructive" disabled={isPending}><Trash2 className="h-4 w-4" /></Button></AlertDialogTrigger>
                        <AlertDialogContent>
                          <AlertDialogHeader><AlertDialogTitle>Sei sicuro?</AlertDialogTitle><AlertDialogDescription>Questa azione eliminerà l'impegno. Se è stato evaso, lo stock NON verrà ripristinato. Per ripristinare lo stock, usa "Annulla Evasione".</AlertDialogDescription></AlertDialogHeader>
                          <AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={() => handleDelete(c.id)}>Sì, Elimina</AlertDialogAction></AlertDialogFooter>
                        </AlertDialogContent>
                      </AlertDialog>
                    </TableCell>
                  </TableRow>
                )) : (
                  <TableRow><TableCell colSpan={6} className="h-24 text-center">{searchTerm ? "Nessun impegno trovato per la ricerca." : "Nessun impegno manuale trovato."}</TableCell></TableRow>
                )}
              </TableBody>
            </Table>
          </div>
        </CardContent>
      </Card>

      {declarationTarget && (
        <DeclarationDialog
          isOpen={!!declarationTarget}
          onOpenChange={(open) => !open && setDeclarationTarget(null)}
          commitment={declarationTarget}
          articleCode={declarationTarget.articleCode}
          onDeclare={handleDeclare}
          globalSettings={globalSettings}
        />
      )}
    </>
  );
}

"use client";

import React, { useState, useEffect, useMemo, useTransition } from 'react';
import Link from 'next/link';
import * as XLSX from 'xlsx';
import { DateRange } from "react-day-picker"
import { format, subDays } from "date-fns"
import { it } from 'date-fns/locale';

import { Card, CardHeader, CardTitle, CardDescription, CardContent } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Checkbox } from '@/components/ui/checkbox';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import { Badge } from '@/components/ui/badge';
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Calendar } from "@/components/ui/calendar";
import { BarChart3, Users, Briefcase, ChevronRight, Download, Calendar as CalendarIcon, Boxes, Loader2, Trash2, Search, Package, Copy, Eye, EyeOff, ClipboardCheck } from 'lucide-react';
import { getMaterialWithdrawals, deleteSelectedWithdrawals, deleteAllWithdrawals, getOperatorsReport as fetchOperatorsReport, getJobsReport, type JobsReport, type EnrichedMaterialWithdrawal, declareWithdrawals } from './actions';
import { cn } from '@/lib/utils';
import { useAuth } from '@/components/auth/AuthProvider';
import type { OverallStatus, RawMaterialType } from '@/types';
import { useRouter } from 'next/navigation';
import {
  ContextMenu,
  ContextMenuContent,
  ContextMenuItem,
  ContextMenuTrigger,
} from "@/components/ui/context-menu";
import { useToast } from '@/hooks/use-toast';
import { formatDisplayStock } from '@/lib/utils';

type OperatorsReport = Awaited<ReturnType<typeof fetchOperatorsReport>>;


const allMaterialTypes: RawMaterialType[] = ['BOB', 'TUBI', 'PF3V0', 'GUAINA', 'BARRA'];

function StatusBadge({ status }: { status: OverallStatus }) {
  return (
    <Badge
      className={cn(
        "text-xs font-semibold",
        status === "In Lavorazione" && "bg-accent text-accent-foreground",
        status === "Completata" && "bg-primary text-primary-foreground",
        status === "Problema" && "bg-destructive text-destructive-foreground",
        status === "Sospesa" && "bg-yellow-500 text-white"
      )}
    >
      {status}
    </Badge>
  );
}

export default function ReportsClientPage({
  initialJobsReport,
}: {
  initialJobsReport: JobsReport;
}) {
  const [jobsReport, setJobsReport] = useState<JobsReport>(initialJobsReport);
  const [operatorsReport, setOperatorsReport] = useState<OperatorsReport>([]);
  const [withdrawalsReport, setWithdrawalsReport] = useState<EnrichedMaterialWithdrawal[]>([]);
  
  const [jobsLoaded, setJobsLoaded] = useState(false);
  const [operatorsLoaded, setOperatorsLoaded] = useState(false);
  const [withdrawalsLoaded, setWithdrawalsLoaded] = useState(false);

  const [isPendingJobs, setIsPendingJobs] = useState(false);
  const [isPendingWithdrawals, setIsPendingWithdrawals] = useState(false);
  const [isPendingOperators, setIsPendingOperators] = useState(false);

  const [operatorDate, setOperatorDate] = useState<Date | undefined>(new Date());
  const [withdrawalsDateRange, setWithdrawalsDateRange] = React.useState<DateRange | undefined>({
    from: subDays(new Date(), 29),
    to: new Date(),
  });

  const [selectedWithdrawals, setSelectedWithdrawals] = useState<string[]>([]);
  const [isDeleting, setIsDeleting] = useState(false);
  const [isDeclaring, setIsDeclaring] = useState(false);
  const [hideDeclared, setHideDeclared] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [jobsSearchTerm, setJobsSearchTerm] = useState('');
  const { user } = useAuth();
  const router = useRouter();
  const { toast } = useToast();

  const fetchJobs = React.useCallback(async () => {
    setIsPendingJobs(true);
    const data = await getJobsReport();
    setJobsReport(data);
    setJobsLoaded(true);
    setIsPendingJobs(false);
  }, []);

  const fetchWithdrawals = React.useCallback(async () => {
    setIsPendingWithdrawals(true);
    const data = await getMaterialWithdrawals({ from: withdrawalsDateRange?.from, to: withdrawalsDateRange?.to });
    setWithdrawalsReport(data);
    setWithdrawalsLoaded(true);
    setIsPendingWithdrawals(false);
  }, [withdrawalsDateRange]);
  
  const fetchOperators = React.useCallback(async () => {
    if (!operatorDate) return;
    setIsPendingOperators(true);

    const timezoneOffset = operatorDate.getTimezoneOffset() * 60000;
    const adjustedDate = new Date(operatorDate.getTime() - timezoneOffset);
    
    const data = await fetchOperatorsReport(adjustedDate.toISOString());
    setOperatorsReport(data);
    setOperatorsLoaded(true);
    setIsPendingOperators(false);
  }, [operatorDate]);
  
  const filteredAndGroupedWithdrawals = useMemo(() => {
    const filtered = searchTerm
        ? withdrawalsReport.filter(w =>
            w.jobOrderPFs.join(', ').toLowerCase().includes(searchTerm.toLowerCase()) ||
            w.materialCode.toLowerCase().includes(searchTerm.toLowerCase()) ||
            (w.operatorName || '').toLowerCase().includes(searchTerm.toLowerCase())
        )
        : withdrawalsReport;

    const finalFiltered = hideDeclared ? filtered.filter(w => !w.isDeclared) : filtered;

    return finalFiltered.reduce((acc, withdrawal) => {
        const type = withdrawal.materialType || 'Sconosciuto';
        if (!acc[type]) {
            acc[type] = [];
        }
        acc[type].push(withdrawal);
        return acc;
    }, {} as Record<string, EnrichedMaterialWithdrawal[]>);
  }, [withdrawalsReport, searchTerm]);
  
  const filteredJobsReport = useMemo(() => {
    if (!jobsSearchTerm) {
      return jobsReport;
    }
    const lowercasedFilter = jobsSearchTerm.toLowerCase();
    return jobsReport.filter(job =>
      job.id.toLowerCase().includes(lowercasedFilter) ||
      job.details.toLowerCase().includes(lowercasedFilter)
    );
  }, [jobsReport, jobsSearchTerm]);


  const handleSelectAllForGroup = (group: EnrichedMaterialWithdrawal[], checked: boolean | 'indeterminate') => {
    const groupIds = group.map(w => w.id);
    if (checked) {
        setSelectedWithdrawals(prev => [...new Set([...prev, ...groupIds])]);
    } else {
        setSelectedWithdrawals(prev => prev.filter(id => !groupIds.includes(id)));
    }
  };

  const handleSelectWithdrawalRow = (id: string) => {
    setSelectedWithdrawals(prev =>
      prev.includes(id) ? prev.filter(rowId => rowId !== id) : [...prev, id]
    );
  };

  const handleDeleteSelected = async () => {
    if (selectedWithdrawals.length === 0) return;
    setIsDeleting(true);
    const result = await deleteSelectedWithdrawals(selectedWithdrawals);
    if (result.success) {
      toast({ title: "Eliminazione Completata", description: result.message });
      setSelectedWithdrawals([]);
      fetchWithdrawals();
    } else {
       toast({ variant: "destructive", title: "Errore", description: result.message });
    }
    setIsDeleting(false);
  };
  
  const handleDeleteAll = async () => {
    setIsDeleting(true);
    const result = await deleteAllWithdrawals();
    toast({ title: "Operazione Completata", description: result.message });
    setSelectedWithdrawals([]);
    fetchWithdrawals();
    setIsDeleting(false);
  };

  const handleExportJobs = () => {
    const dataToExport = filteredJobsReport.map(job => ({
      'Commessa (PF)': job.id,
      'Articolo': job.details,
      'Cliente': job.cliente,
      'Stato': job.status,
      'Tempo Trascorso': job.timeElapsed,
      'Operatori': job.operators,
      'Data Consegna': job.deliveryDate,
    }));
    const ws = XLSX.utils.json_to_sheet(dataToExport);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Report Commesse");
    XLSX.writeFile(wb, "report_commesse.xlsx");
  };

  const handleExportOperators = () => {
     const dataToExport = operatorsReport.map(op => ({
      'Operatore': op.name,
      'Reparto': op.department,
      'Stato': op.status,
      'Ore Giorno': op.timeToday,
      'Ore Settimana': op.timeWeek,
      'Ore Mese': op.timeMonth,
    }));
    const ws = XLSX.utils.json_to_sheet(dataToExport);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Report Operatori");
    XLSX.writeFile(wb, "report_operatori.xlsx");
  };

  const handleExportWithdrawals = (specificWithdrawals?: EnrichedMaterialWithdrawal[]) => {
    const list = specificWithdrawals || withdrawalsReport;
    const dataToExport = list.map(w => ({
      'Tipo Materiale': w.materialType || 'Sconosciuto',
      'Commessa/e': w.jobOrderPFs.join(', '),
      'Materiale': w.materialCode,
      'Lotto': w.lotto || '-',
      'Consumo (n)': w.materialUnitOfMeasure === 'n' && w.consumedUnits ? formatDisplayStock(w.consumedUnits, 'n') : '',
      'Consumo (mt)': w.materialUnitOfMeasure === 'mt' && w.consumedUnits ? formatDisplayStock(w.consumedUnits, 'mt') : '',
      'Peso Consumato (Kg)': formatDisplayStock(w.consumedWeight, 'kg'),
      'Data Prelievo': format(new Date(w.withdrawalDate), 'dd/MM/yyyy HH:mm', { locale: it }),
      'Operatore': w.operatorName,
      'Stato': w.isDeclared ? 'Dichiarato' : 'Da Dichiarare'
    }));
    const ws = XLSX.utils.json_to_sheet(dataToExport);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Report Prelievi");
    const fileName = specificWithdrawals ? `dichiarazione_prelievi_${format(new Date(), 'yyyyMMdd_HHmm')}.xlsx` : "report_prelievi_magazzino.xlsx";
    XLSX.writeFile(wb, fileName);
  };

  const handleDeclareSelected = async (targetIds?: string[]) => {
    const idsToProcess = targetIds || selectedWithdrawals;
    if (idsToProcess.length === 0 || !user) return;
    
    setIsDeclaring(true);
    try {
        // 1. Export standard per questi prelievi
        const toExport = withdrawalsReport.filter(w => idsToProcess.includes(w.id));
        handleExportWithdrawals(toExport);

        // 2. Aggiorna stato su DB
        const result = await declareWithdrawals(idsToProcess, user.uid);
        if (result.success) {
            toast({ title: "Dichiarazione Inviata", description: result.message });
            // Rimuovi quelli dichiarati dalla selezione globale
            setSelectedWithdrawals(prev => prev.filter(id => !idsToProcess.includes(id)));
            fetchWithdrawals();
        } else {
            toast({ variant: "destructive", title: "Errore", description: result.message });
        }
    } catch (error) {
        toast({ variant: "destructive", title: "Errore", description: "Impossibile completare la dichiarazione." });
    } finally {
        setIsDeclaring(false);
    }
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    toast({
        title: "Copiato!",
        description: `"${text}" è stato copiato negli appunti.`,
    });
  }

  const handleNavigateToAnalysis = (articleCode: string) => {
    router.push(`/admin/production-time-analysis?articleCode=${encodeURIComponent(articleCode)}`);
  };
  
  const handleTabChange = (value: string) => {
    if (value === 'commesse' && !jobsLoaded) {
      fetchJobs();
    }
    if (value === 'operatori' && !operatorsLoaded) {
      fetchOperators();
    }
    if (value === 'prelievi' && !withdrawalsLoaded) {
      fetchWithdrawals();
    }
  };

  const renderLoadingRow = (colspan: number) => (
    <TableRow>
      <TableCell colSpan={colspan} className="h-24 text-center">
        <div className="flex items-center justify-center gap-2 text-muted-foreground">
            <Loader2 className="h-5 w-5 animate-spin" />
            <span>Caricamento report...</span>
        </div>
      </TableCell>
    </TableRow>
  );

  const withdrawalGroups = Object.keys(filteredAndGroupedWithdrawals);
  const reportMetadata = operatorsReport[0] || {};

  return (
      <div className="space-y-6">
        <header>
          <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
              <BarChart3 className="h-8 w-8 text-primary" />
              Reportistica Avanzata
          </h1>
          <p className="text-muted-foreground mt-1">
            Analizza le performance di produzione per commesse, operatori e prelievi di materiale.
          </p>
        </header>

        <Tabs onValueChange={handleTabChange}>
          <TabsList className="grid w-full grid-cols-3">
            <TabsTrigger value="commesse">
              <Briefcase className="mr-2 h-4 w-4"/>
              Report Commesse
            </TabsTrigger>
            <TabsTrigger value="operatori">
              <Users className="mr-2 h-4 w-4"/>
              Report Operatori
            </TabsTrigger>
              <TabsTrigger value="prelievi">
              <Boxes className="mr-2 h-4 w-4"/>
              Prelievi da Magazzino
            </TabsTrigger>
          </TabsList>

          <TabsContent value="commesse">
            <Card>
              <CardHeader>
                  <div className="flex justify-between items-center flex-wrap gap-4">
                      <CardTitle className="font-headline">Riepilogo Lavorazioni per Commessa</CardTitle>
                      <div className="flex items-center gap-2 flex-wrap">
                          <div className="relative w-full sm:w-auto">
                              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                              <Input
                                  placeholder="Cerca per commessa o articolo..."
                                  className="pl-9 w-full sm:w-64"
                                  value={jobsSearchTerm}
                                  onChange={(e) => setJobsSearchTerm(e.target.value)}
                              />
                          </div>
                          <Button onClick={handleExportJobs} variant="outline" size="sm" disabled={jobsReport.length === 0}>
                              <Download className="mr-2 h-4 w-4" />
                              Esporta Excel
                          </Button>
                      </div>
                  </div>
              </CardHeader>
              <CardContent>
                <div className="overflow-x-auto">
                  <Table>
                    <TableHeader>
                      <TableRow>
                        <TableHead>Commessa (PF)</TableHead>
                        <TableHead>Articolo</TableHead>
                        <TableHead>Stato</TableHead>
                        <TableHead>Tempo Trascorso</TableHead>
                        <TableHead>Operatori</TableHead>
                        <TableHead>Dettagli</TableHead>
                      </TableRow>
                    </TableHeader>
                    <TableBody>
                        {isPendingJobs ? renderLoadingRow(6) : (
                            filteredJobsReport.length > 0 ? filteredJobsReport.map((job) => (
                                <TableRow key={job.id}>
                                <TableCell className="font-medium">{job.id}</TableCell>
                                <TableCell>
                                    <ContextMenu>
                                        <ContextMenuTrigger className="hover:text-primary hover:underline cursor-pointer">
                                        {job.details}
                                        </ContextMenuTrigger>
                                        <ContextMenuContent>
                                        <ContextMenuItem onSelect={() => handleNavigateToAnalysis(job.details)}>
                                            <BarChart3 className="mr-2 h-4 w-4"/>
                                            Analisi Tempi Articolo
                                        </ContextMenuItem>
                                        <ContextMenuItem onSelect={() => handleCopy(job.details)}>
                                            <Copy className="mr-2 h-4 w-4"/>
                                            Copia Codice Articolo
                                        </ContextMenuItem>
                                        </ContextMenuContent>
                                    </ContextMenu>
                                </TableCell>
                                <TableCell><StatusBadge status={job.status as OverallStatus} /></TableCell>
                                <TableCell>{job.timeElapsed}</TableCell>
                                <TableCell className="max-w-[200px] truncate">{job.operators}</TableCell>
                                <TableCell>
                                    <Button asChild variant="outline" size="sm">
                                    <Link href={`/admin/reports/${job.id}`}>
                                        Vedi Dettagli
                                        <ChevronRight className="ml-2 h-4 w-4" />
                                    </Link>
                                    </Button>
                                </TableCell>
                                </TableRow>
                            )) : (
                                <TableRow>
                                <TableCell colSpan={6} className="text-center h-24">{jobsLoaded ? "Nessuna commessa trovata." : "Seleziona una scheda per visualizzare il report."}</TableCell>
                                </TableRow>
                            )
                        )}
                    </TableBody>
                  </Table>
                </div>
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="operatori">
            <Card>
              <CardHeader>
                <div className="flex justify-between items-center">
                    <CardTitle className="font-headline">Riepilogo Ore per Operatore</CardTitle>
                    <div className="flex items-center gap-2">
                        <Popover>
                            <PopoverTrigger asChild>
                                <Button variant={"outline"}>
                                    <CalendarIcon className="mr-2 h-4 w-4" />
                                    {operatorDate ? format(operatorDate, "PPP", { locale: it }) : <span>Scegli una data</span>}
                                </Button>
                            </PopoverTrigger>
                            <PopoverContent className="w-auto p-0">
                                <Calendar mode="single" selected={operatorDate} onSelect={setOperatorDate} initialFocus />
                            </PopoverContent>
                        </Popover>
                         <Button onClick={fetchOperators} variant="secondary" size="sm" disabled={isPendingOperators}>
                              {isPendingOperators ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <Search className="mr-2 h-4 w-4"/>}
                              Cerca
                          </Button>
                        <Button onClick={handleExportOperators} variant="outline" size="sm" disabled={operatorsReport.length === 0}>
                            <Download className="mr-2 h-4 w-4" />
                            Esporta Excel
                        </Button>
                    </div>
                </div>
              </CardHeader>
              <CardContent>
                  <div className="overflow-x-auto">
                      <Table>
                      <TableHeader>
                          <TableRow>
                            <TableHead>Operatore</TableHead>
                            <TableHead>Reparto</TableHead>
                            <TableHead>Stato</TableHead>
                            <TableHead>
                                Ore Giorno
                                <div className="text-xs font-normal text-muted-foreground">{reportMetadata.todayDate || ''}</div>
                            </TableHead>
                            <TableHead>
                                Ore Settimana
                                <div className="text-xs font-normal text-muted-foreground">{reportMetadata.weekLabel || ''}</div>
                            </TableHead>
                            <TableHead>
                                Ore Mese
                                <div className="text-xs font-normal text-muted-foreground">{reportMetadata.monthLabel || ''}</div>
                            </TableHead>
                            <TableHead className="text-right">Dettagli</TableHead>
                          </TableRow>
                      </TableHeader>
                      <TableBody>
                         {isPendingOperators ? renderLoadingRow(7) : (
                          operatorsLoaded && operatorsReport.length > 0 ? operatorsReport.map((op) => (
                          <TableRow key={op.id}>
                              <TableCell className="font-medium">{op.name}</TableCell>
                              <TableCell>{op.department}</TableCell>
                              <TableCell>
                                <Badge variant={op.status === 'attivo' ? 'default' : 'secondary'}>{op.status}</Badge>
                              </TableCell>
                              <TableCell>{op.timeToday}</TableCell>
                              <TableCell>{op.timeWeek}</TableCell>
                              <TableCell>{op.timeMonth}</TableCell>
                              <TableCell className="text-right">
                                  <Button asChild variant="outline" size="sm">
                                  <Link href={`/admin/reports/operator/${op.id}?date=${operatorDate?.toISOString() || ''}`}>
                                      Vedi Dettagli
                                      <ChevronRight className="ml-2 h-4 w-4" />
                                  </Link>
                                  </Button>
                              </TableCell>
                          </TableRow>
                          )) : (
                          <TableRow>
                              <TableCell colSpan={7} className="text-center h-24">{operatorsLoaded ? "Nessun dato per la data selezionata." : "Seleziona una data e premi Cerca per visualizzare il report."}</TableCell>
                          </TableRow>
                          )
                         )}
                      </TableBody>
                      </Table>
                  </div>
              </CardContent>
            </Card>
          </TabsContent>
          
          <TabsContent value="prelievi">
                <Card>
                  <CardHeader>
                      <div className="flex justify-between items-center flex-wrap gap-4">
                          <CardTitle className="font-headline">Report Prelievi da Magazzino</CardTitle>
                          <div className="flex items-center gap-2 flex-wrap">
                            <div className="relative w-full sm:w-auto">
                                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                                <Input
                                    placeholder="Cerca per commessa, materiale..."
                                    className="pl-9 w-full sm:w-64"
                                    value={searchTerm}
                                    onChange={(e) => setSearchTerm(e.target.value)}
                                />
                            </div>
                              <Popover>
                                <PopoverTrigger asChild>
                                    <Button
                                    id="date"
                                    variant={"outline"}
                                    className={cn(
                                        "w-full sm:w-[260px] justify-start text-left font-normal",
                                        !withdrawalsDateRange && "text-muted-foreground"
                                    )}
                                    >
                                    <CalendarIcon className="mr-2 h-4 w-4" />
                                    {withdrawalsDateRange?.from ? (
                                        withdrawalsDateRange.to ? (
                                        <>
                                            {format(withdrawalsDateRange.from, "LLL dd, y")} -{" "}
                                            {format(withdrawalsDateRange.to, "LLL dd, y")}
                                        </>
                                        ) : (
                                        format(withdrawalsDateRange.from, "LLL dd, y")
                                        )
                                    ) : (
                                        <span>Scegli un range</span>
                                    )}
                                    </Button>
                                </PopoverTrigger>
                                <PopoverContent className="w-auto p-0" align="end">
                                    <Calendar
                                    initialFocus
                                    mode="range"
                                    defaultMonth={withdrawalsDateRange?.from}
                                    selected={withdrawalsDateRange}
                                    onSelect={setWithdrawalsDateRange}
                                    numberOfMonths={2}
                                    locale={it}
                                    />
                                </PopoverContent>
                            </Popover>
                             <Button onClick={fetchWithdrawals} variant="secondary" size="sm" disabled={isPendingWithdrawals}>
                                {isPendingWithdrawals ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <Search className="mr-2 h-4 w-4"/>}
                                Cerca
                            </Button>
                            <Button onClick={() => handleExportWithdrawals()} variant="outline" size="sm" disabled={isPendingWithdrawals || isDeleting || withdrawalsReport.length === 0}>
                                <Download className="mr-2 h-4 w-4" />
                                Esporta Tutto
                            </Button>
                          </div>
                      </div>
                  </CardHeader>
                  <CardContent>
                       {isPendingWithdrawals ? (
                         <div className="flex items-center justify-center h-64">
                            <Loader2 className="h-8 w-8 animate-spin text-primary" />
                         </div>
                       ) : !withdrawalsLoaded ? (
                            <div className="text-center py-24 text-muted-foreground">
                                Seleziona un intervallo di date e premi Cerca per visualizzare i prelievi.
                            </div>
                       ) : (
                            <Tabs defaultValue={allMaterialTypes[0]} className="w-full">
                                <TabsList>
                                    {allMaterialTypes.map(type => (
                                        <TabsTrigger key={type} value={type}>
                                             <Package className="mr-2 h-4 w-4" />
                                            {type}
                                        </TabsTrigger>
                                    ))}
                                </TabsList>
                                {allMaterialTypes.map(type => {
                                    const group = filteredAndGroupedWithdrawals[type] || [];
                                    const groupIds = group.map(w => w.id);
                                    const selectedInGroupCount = selectedWithdrawals.filter(id => groupIds.includes(id)).length;
                                    
                                     return (
                                     <TabsContent value={type} key={type}>
                                        <div className="flex justify-between items-center mb-4 p-2 bg-slate-500/5 rounded-lg border border-slate-500/10">
                                            <div className="flex items-center gap-4">
                                                <Badge variant="outline" className="text-[10px] uppercase font-bold tracking-wider">
                                                    {type} - {group.length} record
                                                </Badge>
                                                <div className="flex items-center gap-2">
                                                    <Checkbox 
                                                        id={`hide-declared-${type}`}
                                                        checked={hideDeclared}
                                                        onCheckedChange={(checked) => setHideDeclared(!!checked)}
                                                    />
                                                    <label htmlFor={`hide-declared-${type}`} className="text-xs text-muted-foreground cursor-pointer select-none">
                                                        Nascondi già dichiarati
                                                    </label>
                                                </div>
                                            </div>
                                            <div className="flex items-center gap-2">
                                                {selectedInGroupCount > 0 && (
                                                    <Button 
                                                        onClick={() => handleDeclareSelected(selectedWithdrawals.filter(id => groupIds.includes(id)))} 
                                                        variant="default" 
                                                        size="sm" 
                                                        disabled={isDeclaring}
                                                        className="bg-green-600 hover:bg-green-700 text-white h-8 text-xs animate-in fade-in zoom-in duration-200"
                                                    >
                                                        {isDeclaring ? <Loader2 className="mr-2 h-3 w-3 animate-spin"/> : <ClipboardCheck className="mr-2 h-3 w-3"/>}
                                                        Avvia Dichiarazione {type} ({selectedInGroupCount})
                                                    </Button>
                                                )}
                                            </div>
                                        </div>
                                        {group.length > 0 ? (
                                            <div className="overflow-x-auto">
                                                <Table>
                                                    <TableHeader>
                                                        <TableRow>
                                                            <TableHead padding="checkbox">
                                                                <Checkbox
                                                                checked={selectedInGroupCount > 0 ? (selectedInGroupCount === group.length ? true : 'indeterminate') : false}
                                                                onCheckedChange={(checked) => handleSelectAllForGroup(group, !!checked)}
                                                                aria-label={`Seleziona tutti i prelievi per ${type}`}
                                                                />
                                                            </TableHead>
                                                            <TableHead>Commessa/e</TableHead>
                                                            <TableHead>Materiale</TableHead>
                                                            <TableHead>Lotto</TableHead>
                                                            <TableHead>Stato</TableHead>
                                                            <TableHead>Consumo (n)</TableHead>
                                                            <TableHead>Consumo (mt)</TableHead>
                                                            <TableHead>Peso Consumato (Kg)</TableHead>
                                                            <TableHead>Data Prelievo</TableHead>
                                                            <TableHead>Operatore</TableHead>
                                                        </TableRow>
                                                    </TableHeader>
                                                    <TableBody>
                                                        {group.map((w) => (
                                                            <TableRow key={w.id} data-state={selectedWithdrawals.includes(w.id) ? "selected" : undefined}>
                                                                <TableCell padding="checkbox">
                                                                    <Checkbox
                                                                    checked={selectedWithdrawals.includes(w.id)}
                                                                    onCheckedChange={() => handleSelectWithdrawalRow(w.id)}
                                                                    aria-label={`Seleziona prelievo ${w.id}`}
                                                                    />
                                                                </TableCell>
                                                                <TableCell className="font-medium">{w.jobOrderPFs.join(', ')}</TableCell>
                                                                <TableCell>{w.materialCode}</TableCell>
                                                                <TableCell className="font-mono text-[10px]">{w.lotto || '-'}</TableCell>
                                                                <TableCell>
                                                                    {w.isDeclared ? (
                                                                        <Badge variant="outline" className="bg-green-500/10 text-green-500 border-green-500/20 flex items-center gap-1 w-fit">
                                                                            <ClipboardCheck className="h-3 w-3" />
                                                                            Dichiarato
                                                                        </Badge>
                                                                    ) : (
                                                                        <Badge variant="outline" className="text-muted-foreground flex items-center gap-1 w-fit">
                                                                            Da Dichiarare
                                                                        </Badge>
                                                                    )}
                                                                </TableCell>
                                                                <TableCell>
                                                                    {w.materialUnitOfMeasure === 'n' && w.consumedUnits ? formatDisplayStock(w.consumedUnits, 'n') : '-'}
                                                                </TableCell>
                                                                <TableCell>
                                                                    {w.materialUnitOfMeasure === 'mt' && w.consumedUnits ? formatDisplayStock(w.consumedUnits, 'mt') : '-'}
                                                                </TableCell>
                                                                <TableCell>{formatDisplayStock(w.consumedWeight, 'kg')}</TableCell>
                                                                <TableCell>{format(new Date(w.withdrawalDate), 'dd/MM/yyyy HH:mm', { locale: it })}</TableCell>
                                                                <TableCell>{w.operatorName}</TableCell>
                                                            </TableRow>
                                                        ))}
                                                    </TableBody>
                                                </Table>
                                            </div>
                                        ) : (
                                            <div className="py-12 text-center text-muted-foreground">
                                                Nessun prelievo registrato per questa tipologia nel periodo selezionato.
                                            </div>
                                        )}
                                    </TabsContent>
                                    )
                                })}
                            </Tabs>
                       )}
                  </CardContent>
                </Card>
          </TabsContent>

        </Tabs>
      </div>
  );
}

"use client";

import React, { useState, useEffect } from 'react';
import Link from 'next/link';
import AdminAuthGuard from '@/components/AdminAuthGuard';
import AppShell from '@/components/layout/AppShell';
import { Card, CardHeader, CardTitle, CardDescription, CardContent } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Button } from '@/components/ui/button';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { Calendar } from '@/components/ui/calendar';
import { getOperatorDetailReport } from '@/app/admin/reports/actions';
import { ArrowLeft, User, Clock, Calendar as CalendarIcon, Loader2, Briefcase } from 'lucide-react';
import { format } from 'date-fns';
import { it } from 'date-fns/locale';
import { useSearchParams } from 'next/navigation';

type OperatorDetailReport = Awaited<ReturnType<typeof getOperatorDetailReport>>;

export default function OperatorReportDetailPage({ params }: { params: { operatorId: string } }) {
  const searchParams = useSearchParams();
  const dateFromParams = searchParams.get('date');

  const [report, setReport] = useState<OperatorDetailReport | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [selectedDate, setSelectedDate] = useState<Date | undefined>(
    dateFromParams ? new Date(dateFromParams) : new Date()
  );

  useEffect(() => {
    const fetchReport = async () => {
      if (!selectedDate) return;
      setIsLoading(true);
      const dateStringForServer = selectedDate.toISOString();
      const newReport = await getOperatorDetailReport(params.operatorId, dateStringForServer);
      setReport(newReport);
      setIsLoading(false);
    };

    if (params.operatorId && selectedDate) {
      fetchReport();
    }
  }, [params.operatorId, selectedDate]);
  
  if (isLoading || !report) {
    return (
      <AdminAuthGuard>
        <AppShell>
            <div className="flex items-center justify-center h-64">
              <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
        </AppShell>
      </AdminAuthGuard>
    )
  }

  return (
    <AdminAuthGuard>
      <AppShell>
        <div className="space-y-6 max-w-2xl mx-auto">
          <Button asChild variant="outline" className="w-fit">
            <Link href="/admin/reports">
              <ArrowLeft className="mr-2 h-4 w-4" />
              Torna ai Report
            </Link>
          </Button>

          <header>
            <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
              <User className="h-8 w-8 text-primary" />
              Dettaglio Operatore: {report.operator.nome}
            </h1>
            <p className="text-muted-foreground">Report dettagliato delle attività e delle ore di lavoro.</p>
          </header>

          <Card>
            <CardHeader className="flex-row items-center justify-between">
              <CardTitle>Riepilogo Ore</CardTitle>
              <Popover>
                <PopoverTrigger asChild>
                    <Button variant={"outline"}>
                        <CalendarIcon className="mr-2 h-4 w-4" />
                        {selectedDate ? format(selectedDate, "PPP", { locale: it }) : <span>Scegli una data</span>}
                    </Button>
                </PopoverTrigger>
                <PopoverContent className="w-auto p-0">
                    <Calendar mode="single" selected={selectedDate} onSelect={setSelectedDate} initialFocus />
                </PopoverContent>
              </Popover>
            </CardHeader>
            <CardContent className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 text-sm">
                <div className="flex items-center gap-3 p-4 bg-background rounded-lg border">
                    <Clock className="h-6 w-6 text-primary"/>
                    <div>
                        <p className="text-muted-foreground">Ore Lavorate (Giorno)</p>
                        <p className="font-semibold text-lg">{report.timeToday}</p>
                         <p className="text-xs text-muted-foreground">{report.dateLabels.today}</p>
                    </div>
                </div>
                 <div className="flex items-center gap-3 p-4 bg-background rounded-lg border">
                    <CalendarIcon className="h-6 w-6 text-primary"/>
                    <div>
                        <p className="text-muted-foreground">Ore Lavorate (Settimana)</p>
                        <p className="font-semibold text-lg">{report.timeWeek}</p>
                        <p className="text-xs text-muted-foreground">{report.dateLabels.week}</p>
                    </div>
                </div>
                 <div className="flex items-center gap-3 p-4 bg-background rounded-lg border">
                    <CalendarIcon className="h-6 w-6 text-primary"/>
                    <div>
                        <p className="text-muted-foreground">Ore Lavorate (Mese)</p>
                        <p className="font-semibold text-lg">{report.timeMonth}</p>
                        <p className="text-xs text-muted-foreground">{report.dateLabels.month}</p>
                    </div>
                </div>
            </CardContent>
          </Card>
          
          <Card>
             <CardHeader>
                <CardTitle className="flex items-center gap-3">
                    <Briefcase className="h-6 w-6 text-primary"/>
                    Commesse Lavorate nel Giorno Selezionato
                </CardTitle>
                <CardDescription>Elenco delle commesse a cui l'operatore ha contribuito nel giorno {report.dateLabels.today}.</CardDescription>
            </CardHeader>
            <CardContent>
                 <div className="overflow-x-auto">
                    <Table>
                      <TableHeader>
                        <TableRow>
                          <TableHead>Commessa (PF)</TableHead>
                          <TableHead>Articolo</TableHead>
                          <TableHead>Cliente</TableHead>
                          <TableHead>Fase Lavorata</TableHead>
                          <TableHead>Tempo Impiegato</TableHead>
                        </TableRow>
                      </TableHeader>
                      <TableBody>
                        {report.jobsWorkedOn.length > 0 ? report.jobsWorkedOn.flatMap((job: any) => 
                          (job.phases as any[]).map((phase: any, index: number) => (
                            <TableRow key={`${job.id}-${phase.date}-${phase.name}`}>
                              {index === 0 ? (
                                <>
                                  <TableCell rowSpan={job.phases.length} className="font-medium align-top border-b">{job.id}</TableCell>
                                  <TableCell rowSpan={job.phases.length} className="align-top border-b">{job.details}</TableCell>
                                  <TableCell rowSpan={job.phases.length} className="align-top border-b">{job.cliente}</TableCell>
                                </>
                              ) : null}
                              <TableCell>{phase.name}</TableCell>
                              <TableCell>{phase.time}</TableCell>
                            </TableRow>
                          ))
                        ) : (
                             <TableRow>
                                <TableCell colSpan={5} className="text-center h-24">Nessuna attività registrata per questo operatore nel giorno selezionato.</TableCell>
                            </TableRow>
                        )}
                      </TableBody>
                    </Table>
                  </div>
            </CardContent>
          </Card>
        </div>
      </AppShell>
    </AdminAuthGuard>
  );
}

'use client';

import React, { useState, useMemo } from 'react';
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
    DialogFooter,
} from "@/components/ui/dialog";
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Users, Star, TrendingUp, Info, Search, Factory, ShieldCheck, Zap } from 'lucide-react';
import { cn } from '@/lib/utils';
import { Input } from '@/components/ui/input';
import { ScrollArea } from '@/components/ui/scroll-area';
import type { Operator, Department, Article } from '@/types';

interface OperatorSkillLoanDialogProps {
    isOpen: boolean;
    onClose: () => void;
    targetDept: string;
    week: number;
    year: number;
    operators: Operator[];
    currentAllocations: string[]; // IDs di operatori già assegnati
    onSelect: (operatorId: string) => void;
}

export default function OperatorSkillLoanDialog({
    isOpen,
    onClose,
    targetDept,
    week,
    year,
    operators,
    currentAllocations,
    onSelect
}: OperatorSkillLoanDialogProps) {
    const [searchTerm, setSearchTerm] = useState('');

    const recommendedOperators = useMemo(() => {
        // 1. Escludi chi è già assegnato
        const available = operators.filter(op => !currentAllocations.includes(op.id));

        // 2. Calcola punteggio di affinità
        return available.map(op => {
            // Affinità di Reparto (Booleano)
            const isDeptCompatible = op.reparto.includes(targetDept);

            // Skill specifica (se esiste una skill che mappa sul reparto o mansione principale)
            // In una produzione reale, targetDept mappa su una o più PhaseId
            // Qui cerchiamo la skill con il punteggio più alto tra quelle dell'operatore
            const bestSkill = op.skills?.reduce((prev, curr) => (curr.efficiencyPercent > prev ? curr.efficiencyPercent : prev), 0) || 0;

            // Punteggio finale: Compatibilità Reparto (1000 punti) + Skill Efficiency (0-100)
            const score = (isDeptCompatible ? 1000 : 0) + bestSkill;

            return { ...op, score, isDeptCompatible, bestSkill };
        })
        .filter(op => {
            const matchesSearch = !searchTerm || op.nome.toLowerCase().includes(searchTerm.toLowerCase());
            return matchesSearch;
        })
        .sort((a, b) => b.score - a.score);
    }, [operators, currentAllocations, targetDept, searchTerm]);

    return (
        <Dialog open={isOpen} onOpenChange={onClose}>
            <DialogContent className="max-w-2xl bg-white rounded-3xl border-none shadow-2xl overflow-hidden p-0">
                <div className="bg-blue-600 p-6 text-white overflow-hidden relative">
                    <div className="absolute top-0 right-0 p-4 opacity-10">
                        <Users className="h-24 w-24" />
                    </div>
                    <DialogHeader>
                        <DialogTitle className="text-2xl font-black uppercase tracking-tighter flex items-center gap-3">
                            <Zap className="h-6 w-6 text-yellow-300" /> Ricerca Prestito Intelligente
                        </DialogTitle>
                        <DialogDescription className="text-blue-100 font-bold opacity-90">
                            Suggerimenti basati su **Skills** e **Affinità di Reparto** per {targetDept} (S{week})
                        </DialogDescription>
                    </DialogHeader>

                    <div className="mt-6 relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-white/50" />
                        <Input 
                            placeholder="Cerca operatore per nome..." 
                            className="h-11 pl-10 bg-white/20 border-white/30 text-white placeholder:text-white/50 font-bold rounded-xl focus-visible:ring-white"
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                    </div>
                </div>

                <div className="p-6">
                    <h3 className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-4 flex items-center gap-2">
                        <TrendingUp className="h-3 w-3" /> Operatori Suggeriti (Pool Globale)
                    </h3>

                    <ScrollArea className="h-[350px] pr-4">
                        <div className="space-y-3">
                            {recommendedOperators.map((op, idx) => (
                                <div 
                                    key={op.id} 
                                    className={cn(
                                        "flex items-center justify-between p-4 rounded-2xl border-2 transition-all hover:bg-slate-50 group cursor-pointer",
                                        idx === 0 ? "border-emerald-100 bg-emerald-50/20" : "border-slate-100"
                                    )}
                                    onClick={() => onSelect(op.id)}
                                >
                                    <div className="flex items-center gap-4">
                                        <div className="h-10 w-10 bg-slate-200 rounded-full flex items-center justify-center text-slate-500 font-black">
                                            {op.nome.substring(0, 2).toUpperCase()}
                                        </div>
                                        <div className="flex flex-col">
                                            <div className="flex items-center gap-2">
                                                <span className="text-sm font-black text-slate-800">{op.nome}</span>
                                                {idx === 0 && <Badge className="bg-emerald-500 text-[8px] font-black uppercase h-4 px-1">Top Match</Badge>}
                                            </div>
                                            <div className="flex items-center gap-2 mt-0.5">
                                                {op.isDeptCompatible ? (
                                                    <Badge variant="outline" className="text-[7px] font-black bg-emerald-50 text-emerald-600 border-emerald-100 uppercase py-0 leading-none">Abilitato {targetDept}</Badge>
                                                ) : (
                                                    <Badge variant="outline" className="text-[7px] font-black bg-slate-100 text-slate-400 border-slate-200 uppercase py-0 leading-none">Fuori Reparto</Badge>
                                                )}
                                                <div className="flex items-center gap-1 text-[9px] font-bold text-slate-400">
                                                    <Star className={cn("h-3 w-3", op.bestSkill > 80 ? "text-amber-500 fill-amber-500" : "")} />
                                                    Efficienza: {op.bestSkill}%
                                                </div>
                                            </div>
                                        </div>
                                    </div>

                                    <Button variant="ghost" size="sm" className="h-9 w-9 rounded-full opacity-0 group-hover:opacity-100 transition-opacity bg-white border shadow-sm">
                                        <PlusCircleIcon className="h-5 w-5 text-blue-600" />
                                    </Button>
                                </div>
                            ))}
                        </div>
                    </ScrollArea>
                </div>

                <DialogFooter className="p-6 bg-slate-50/50 border-t flex items-center justify-between space-x-0">
                    <div className="flex items-center gap-2 text-slate-400">
                        <Info className="h-4 w-4" />
                        <span className="text-[10px] font-bold italic">L'efficienza è calcolata sulla miglior skill rilevata</span>
                    </div>
                    <Button variant="outline" onClick={onClose} className="rounded-xl font-bold uppercase text-xs h-10 px-6">Chiudi</Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

