"use client";

import React, { useState, useEffect } from 'react';
import { format, addDays, startOfWeek, isSameDay, parseISO } from 'date-fns';
import { it } from 'date-fns/locale';
import { 
  Users, 
  Save, 
  X, 
  Check, 
  ArrowRightLeft, 
  ChevronRight, 
  Calendar as CalendarIcon,
  UserPlus,
  Trash2,
  Copy,
  Zap
} from 'lucide-react';

import { 
  Dialog, 
  DialogContent, 
  DialogDescription, 
  DialogFooter, 
  DialogHeader, 
  DialogTitle 
} from "@/components/ui/dialog";
import { Button } from '@/components/ui/button';
import { 
  Table, 
  TableBody, 
  TableCell, 
  TableHead, 
  TableHeader, 
  TableRow 
} from "@/components/ui/table";
import { 
  Select, 
  SelectContent, 
  SelectItem, 
  SelectTrigger, 
  SelectValue 
} from "@/components/ui/select";
import { Checkbox } from '@/components/ui/checkbox';
import { Badge } from '@/components/ui/badge';
import { useToast } from '@/hooks/use-toast';
import { cn } from '@/lib/utils';
import { type Operator, type Department, type OperatorAssignment } from '@/types';
import { bulkSaveOperatorAssignments } from './actions';

interface ResourceAssignmentDialogProps {
  isOpen: boolean;
  onClose: () => void;
  operators: Operator[];
  departments: Department[];
  initialAssignments: OperatorAssignment[];
  currentDate: Date;
  uid: string;
}

export default function ResourceAssignmentDialog({
  isOpen,
  onClose,
  operators,
  departments,
  initialAssignments,
  currentDate,
  uid
}: ResourceAssignmentDialogProps) {
  const [localAssignments, setLocalAssignments] = useState<Record<string, Record<string, string>>>({});
  const [selectedOperators, setSelectedOperators] = useState<string[]>([]);
  const [isSaving, setIsSaving] = useState(false);
  const { toast } = useToast();

  const startOfSelectedWeek = startOfWeek(currentDate, { weekStartsOn: 1 });
  const weekDays = Array.from({ length: 5 }).map((_, i) => addDays(startOfSelectedWeek, i));

  // Filter allowed departments for assignment
  const allowedDeptCodes = ['CG', 'CP', 'BF', 'SUPPORT'];
  const filteredDepartments = departments.filter(d => allowedDeptCodes.includes(d.code));

  // Initialize local state from initialAssignments
  useEffect(() => {
    if (isOpen) {
      const state: Record<string, Record<string, string>> = {};
      
      operators.forEach(op => {
        state[op.id] = {};
        weekDays.forEach(day => {
          const ds = format(day, 'yyyy-MM-dd');
          const existing = initialAssignments.find(a => 
            a.operatorId === op.id && 
            ds >= a.startDate && 
            ds <= a.endDate
          );
          state[op.id][ds] = existing?.departmentCode || 'none';
        });
      });
      
      setLocalAssignments(state);
      setSelectedOperators([]);
    }
  }, [isOpen, initialAssignments, operators, currentDate]);

  const handleCellChange = (operatorId: string, dateStr: string, deptCode: string) => {
    setLocalAssignments(prev => ({
      ...prev,
      [operatorId]: {
        ...prev[operatorId],
        [dateStr]: deptCode
      }
    }));
  };

  const handleRowBulkAssign = (operatorId: string, deptCode: string) => {
    setLocalAssignments(prev => {
      const newOpState = { ...prev[operatorId] };
      weekDays.forEach(day => {
        newOpState[format(day, 'yyyy-MM-dd')] = deptCode;
      });
      return { ...prev, [operatorId]: newOpState };
    });
  };

  const handleSelectionBulkAssign = (deptCode: string) => {
    if (selectedOperators.length === 0) return;
    
    setLocalAssignments(prev => {
      const newState = { ...prev };
      selectedOperators.forEach(opId => {
        const newOpState = { ...newState[opId] };
        weekDays.forEach(day => {
          newOpState[format(day, 'yyyy-MM-dd')] = deptCode;
        });
        newState[opId] = newOpState;
      });
      return newState;
    });
    
    toast({
      title: "Assegnazione completata",
      description: `Assegnati ${selectedOperators.length} operatori ${deptCode === 'none' ? 'alla rimozione assegnazione' : 'al reparto ' + deptCode} per tutta la settimana.`
    });
  };

  const toggleOperatorSelection = (opId: string) => {
    setSelectedOperators(prev => 
      prev.includes(opId) ? prev.filter(id => id !== opId) : [...prev, opId]
    );
  };

  const toggleAllSelection = () => {
    setSelectedOperators(prev => 
      prev.length === operators.length ? [] : operators.map(op => op.id)
    );
  };

  const handleSave = async () => {
    setIsSaving(true);
    try {
      const assignmentsToSave: Omit<OperatorAssignment, 'id' | 'createdAt'>[] = [];
      
      // Group contiguous days for the same operator and department to minimize documents
      operators.forEach(op => {
        const opDays = localAssignments[op.id];
        if (!opDays) return;

        let currentDept = '';
        let currentStart = '';
        let currentEnd = '';

        weekDays.forEach((day, index) => {
          const ds = format(day, 'yyyy-MM-dd');
          let dept = opDays[ds];
          if (dept === 'none') dept = ''; // Convert back for storage

          if (dept !== currentDept) {
            // Push previous range if exists
            if (currentDept) {
              assignmentsToSave.push({
                operatorId: op.id,
                departmentCode: currentDept,
                startDate: currentStart,
                endDate: currentEnd,
                type: op.reparto?.includes(currentDept) ? 'base' : 'loan'
              });
            }
            // Start new range
            currentDept = dept;
            currentStart = ds;
            currentEnd = ds;
          } else {
            // Extend existing range
            currentEnd = ds;
          }

          // Final day handler
          if (index === weekDays.length - 1 && currentDept) {
            assignmentsToSave.push({
              operatorId: op.id,
              departmentCode: currentDept,
              startDate: currentStart,
              endDate: currentEnd,
              type: op.reparto?.includes(currentDept) ? 'base' : 'loan'
            });
          }
        });
      });

      const res = await bulkSaveOperatorAssignments(
        assignmentsToSave, 
        format(weekDays[0], 'yyyy-MM-dd'), 
        format(weekDays[weekDays.length - 1], 'yyyy-MM-dd'),
        uid
      );

      if (res.success) {
        toast({ title: "Salvataggio completato", description: res.message });
        onClose();
      } else {
        toast({ variant: "destructive", title: "Errore", description: res.message });
      }
    } catch (error) {
      toast({ variant: "destructive", title: "Errore", description: "Impossibile salvare le assegnazioni." });
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-5xl max-h-[90vh] flex flex-col p-0 overflow-hidden bg-[#0a0e14] border-slate-800 text-slate-200">
        <DialogHeader className="p-6 pb-2 border-b border-slate-800">
          <div className="flex justify-between items-center">
            <div>
              <DialogTitle className="text-xl flex items-center gap-2">
                <Users className="h-5 w-5 text-blue-400" />
                Assegnazione Risorse Settimanale
              </DialogTitle>
              <DialogDescription className="text-slate-400 mt-1">
                Settimana dal {format(weekDays[0], 'd MMMM', { locale: it })} al {format(weekDays[4], 'd MMMM yyyy', { locale: it })}
              </DialogDescription>
            </div>
            
            <div className="flex items-center gap-3">
               {selectedOperators.length > 0 && (
                 <div className="flex items-center gap-2 bg-blue-500/10 border border-blue-500/30 px-3 py-1.5 rounded-lg animate-in fade-in slide-in-from-right-2">
                    <span className="text-xs font-semibold text-blue-400">{selectedOperators.length} selezionati</span>
                    <div className="h-4 w-px bg-blue-500/30 mx-1" />
                    <Select onValueChange={handleSelectionBulkAssign}>
                      <SelectTrigger className="h-7 w-40 bg-transparent border-none focus:ring-0 text-xs text-blue-300">
                        <Zap className="h-3 w-3 mr-1" />
                        <SelectValue placeholder="Assegna a tutti..." />
                      </SelectTrigger>
                      <SelectContent className="bg-[#151c27] border-slate-700">
                        {filteredDepartments.map(d => (
                          <SelectItem key={d.code} value={d.code}>{d.name}</SelectItem>
                        ))}
                        <SelectItem value="none">Senza Assegnazione</SelectItem>
                      </SelectContent>
                    </Select>
                 </div>
               )}
            </div>
          </div>
        </DialogHeader>

        <div className="flex-1 overflow-auto p-0">
          <Table>
            <TableHeader className="sticky top-0 bg-[#0a0e14] z-10 shadow-sm">
              <TableRow className="border-slate-800 hover:bg-transparent">
                <TableHead className="w-12 text-center">
                  <Checkbox 
                    checked={selectedOperators.length === operators.length && operators.length > 0}
                    onCheckedChange={toggleAllSelection}
                  />
                </TableHead>
                <TableHead className="w-48 text-slate-400 italic font-normal">Operatore</TableHead>
                {weekDays.map(day => (
                  <TableHead key={day.toISOString()} className="text-center w-32 border-l border-slate-800 pb-1">
                    <div className="flex flex-col items-center">
                      <span className="text-[10px] uppercase tracking-wider text-slate-500">{format(day, 'EEEE', { locale: it })}</span>
                      <span className="text-sm font-bold text-slate-300">{format(day, 'd MMM', { locale: it })}</span>
                    </div>
                  </TableHead>
                ))}
                <TableHead className="w-24 text-center border-l border-slate-800 text-slate-500 font-normal">Azioni</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {operators.map((op) => (
                <TableRow key={op.id} className="border-slate-900 hover:bg-white/5 transition-colors">
                  <TableCell className="text-center">
                    <Checkbox 
                      checked={selectedOperators.includes(op.id)}
                      onCheckedChange={() => toggleOperatorSelection(op.id)}
                    />
                  </TableCell>
                  <TableCell className="font-medium py-4">
                    <div className="flex flex-col">
                       <span className={selectedOperators.includes(op.id) ? "text-blue-400" : ""}>{op.nome}</span>
                       <div className="flex gap-1 mt-1">
                          {op.reparto?.map(r => (
                            <span key={r} className="text-[9px] px-1 bg-slate-800 text-slate-400 rounded uppercase">{r}</span>
                          ))}
                       </div>
                    </div>
                  </TableCell>
                  {weekDays.map(day => {
                    const ds = format(day, 'yyyy-MM-dd');
                    const currentVal = localAssignments[op.id]?.[ds] || 'none';
                    const isLoan = currentVal !== 'none' && currentVal !== '' && !op.reparto?.includes(currentVal);

                    return (
                      <TableCell key={ds} className="p-1 border-l border-slate-900">
                        <Select 
                          value={currentVal} 
                          onValueChange={(v) => handleCellChange(op.id, ds, v)}
                        >
                          <SelectTrigger className={cn(
                            "h-9 w-full bg-slate-900/50 border-none focus:ring-1 focus:ring-blue-500/50 text-xs",
                            isLoan ? "text-amber-400 font-semibold" : "text-slate-300"
                          )}>
                            <SelectValue placeholder="-" />
                          </SelectTrigger>
                          <SelectContent className="bg-[#151c27] border-slate-700">
                          {filteredDepartments.map(d => (
                              <SelectItem key={d.code} value={d.code}>
                                <div className="flex items-center gap-2">
                                  <span className="font-bold w-6">{d.code}</span>
                                  <span className="text-xs opacity-60">{d.name}</span>
                                </div>
                              </SelectItem>
                            ))}
                            <SelectItem value="none">Nessuno</SelectItem>
                          </SelectContent>
                        </Select>
                      </TableCell>
                    );
                  })}
                  <TableCell className="text-center border-l border-slate-900 p-2">
                    <div className="flex justify-center gap-1">
                      <Select onValueChange={(v) => handleRowBulkAssign(op.id, v)}>
                        <SelectTrigger className="h-8 w-8 p-0 flex items-center justify-center bg-slate-800 border-none hover:bg-slate-700">
                          <Zap className="h-4 w-4 text-blue-400" />
                        </SelectTrigger>
                        <SelectContent className="bg-[#151c27] border-slate-700">
                          <div className="px-2 py-1 text-[10px] text-slate-500 uppercase">Imposta tutta la settimana</div>
                          {filteredDepartments.map(d => (
                            <SelectItem key={d.code} value={d.code}>{d.name}</SelectItem>
                          ))}
                          <SelectItem value="none">Svuota Settimana</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </div>

        <DialogFooter className="p-6 border-t border-slate-800 bg-slate-900/20">
          <Button variant="ghost" onClick={onClose} disabled={isSaving}>Annulla</Button>
          <Button 
            className="bg-blue-600 hover:bg-blue-700 px-8" 
            onClick={handleSave} 
            disabled={isSaving}
          >
            {isSaving ? (
              <span className="flex items-center gap-2 italic text-blue-200">
                <Zap className="h-4 w-4 animate-spin" />
                Salvataggio...
              </span>
            ) : (
              <span className="flex items-center gap-2">
                <Save className="h-4 w-4" />
                Salva Assegnazioni
              </span>
            )}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { 
    Calendar as CalendarIcon, 
    ChevronLeft, 
    ChevronRight, 
    Loader2, 
    RefreshCcw, 
    LayoutGrid, 
    Settings2, 
    Zap
} from 'lucide-react';
import { format, addWeeks, subWeeks, startOfWeek, getWeek } from 'date-fns';
import { useToast } from '@/hooks/use-toast';
import { Badge } from '@/components/ui/badge';
import { cn } from '@/lib/utils';

import { useMasterData } from '@/contexts/MasterDataProvider';
import { useAuth } from '@/components/auth/AuthProvider';

import WeeklyCapacityBoard from './WeeklyCapacityBoard';
import MasterConsole from './MasterConsole';
import OperatorSkillLoanDialog from './OperatorSkillLoanDialog';
import BacklogDrawer from './BacklogDrawer';
import { getWeeklyBoardData, saveWeeklyAllocation, advanceJobStatus, migrateJobOrderStatuses } from './weekly-actions';
import { assignJobToDate } from './actions';

import { DragDropContext, DropResult } from '@hello-pangea/dnd';

export default function ResourcePlanningClientPage() {
    const { toast } = useToast();
    const { user } = useAuth();
    const uid = user?.uid || '';

    const [currentDate, setCurrentDate] = useState(new Date());
    const [loading, setLoading] = useState(true);
    const [isRefreshing, setIsRefreshing] = useState(false);
    const [activeView, setActiveView] = useState<'board' | 'console'>('board');
    const [isBacklogOpen, setIsBacklogOpen] = useState(false);

    const { 
        operators: cachedOperators, 
        articles: cachedArticles, 
        departments: cachedDepartments, 
        isLoading: isMasterLoading 
    } = useMasterData();

    const [boardData, setBoardData] = useState<{
        jobOrders: any[],
        unassignedJobs: any[],
        allocations: Record<string, string[]>
    }>({ jobOrders: [], unassignedJobs: [], allocations: {} });

    const [isLoanDialogOpen, setIsLoanDialogOpen] = useState(false);
    const [selectedSlot, setSelectedSlot] = useState<{ deptId: string, week: number, year: number } | null>(null);

    // Migrazione automatica all'avvio
    useEffect(() => {
        if (uid) {
            migrateJobOrderStatuses(uid).then(res => {
                if (res.success && res.count && res.count > 0) {
                    toast({ title: "Dati Sincronizzati", description: `${res.count} commesse aggiornate alla nuova pipeline.` });
                }
            });
        }
    }, [uid]);

    useEffect(() => {
        loadData();
    }, [currentDate]);

    async function loadData(force: boolean = false) {
        if (force) setIsRefreshing(true);
        else setLoading(true);

        try {
            const week = getWeek(currentDate, { weekStartsOn: 1 });
            const year = currentDate.getFullYear();

            const data = await getWeeklyBoardData(year, week);
            setBoardData(data);
        } catch (error) {
            toast({ title: 'Errore', description: 'Impossibile caricare i dati settimanali.', variant: 'destructive' });
        } finally {
            setLoading(false);
            setIsRefreshing(false);
        }
    }

    const handlePrevWeek = () => setCurrentDate(subWeeks(currentDate, 1));
    const handleNextWeek = () => setCurrentDate(addWeeks(currentDate, 1));

    const handleJobMove = async (jobId: string, targetDate: string, targetDeptId?: string) => {
        // Ottimistico
        const jobToMove = [...boardData.jobOrders, ...boardData.unassignedJobs].find(j => j.id === jobId);
        if (!jobToMove) return;

        // Se targetDate è null/empty, stiamo tornando al backlog (non gestito qui per ora ma predisposto)
        const updatedAssigned = [...boardData.jobOrders.filter(j => j.id !== jobId), { ...jobToMove, assignedDate: targetDate, department: targetDeptId || jobToMove.department }];
        const updatedUnassigned = boardData.unassignedJobs.filter(j => j.id !== jobId);

        setBoardData({ ...boardData, jobOrders: updatedAssigned, unassignedJobs: updatedUnassigned });

        // Aggiorniamo sia la data che il reparto se necessario
        const res = await assignJobToDate(jobId, targetDate, targetDeptId);
        if (!res.success) {
            toast({ title: 'Errore Spostamento', description: res.message, variant: 'destructive' });
            loadData();
        }
    };

    const handleDragEnd = (result: DropResult) => {
        if (!result.destination) return;
        const jobId = result.draggableId;
        const destId = result.destination.droppableId;

        if (destId === 'BACKLOG') return; // Ritorno al backlog non ancora implementato lato server

        // Dest format: "DEPT_ID|ISO_DATE"
        const [deptId, dateStr] = destId.split('|');
        if (dateStr) {
            handleJobMove(jobId, dateStr, deptId);
        }
    };

    const handleStatusAdvance = async (jobId: string) => {
        const res = await advanceJobStatus(jobId);
        if (res.success) {
            toast({ title: 'Stato avanzato', description: `Commessa ora in ${res.newStatus}` });
            const updatedJobs = boardData.jobOrders.map(j => 
                j.id === jobId ? { ...j, status: res.newStatus } : j
            );
            const updatedUnassigned = boardData.unassignedJobs.map(j => 
                j.id === jobId ? { ...j, status: res.newStatus } : j
            );
            setBoardData({ ...boardData, jobOrders: updatedJobs, unassignedJobs: updatedUnassigned });
        }
    };

    const handleLoanSelect = async (operatorId: string) => {
        if (!selectedSlot) return;
        const { deptId, week, year } = selectedSlot;

        const key = `${year}_${week}_${deptId}`;
        const currentIds = boardData.allocations[key] || [];
        const newIds = [...new Set([...currentIds, operatorId])];

        const res = await saveWeeklyAllocation(year, week, deptId, newIds, uid);
        if (res.success) {
            setBoardData(prev => ({
                ...prev,
                allocations: {
                    ...prev.allocations,
                    [key]: newIds
                }
            }));
            setIsLoanDialogOpen(false);
            toast({ title: "Incarico salvato", description: "Operatore aggiunto per questa settimana." });
        }
    };

    if (loading && !boardData.jobOrders.length && !boardData.unassignedJobs.length) return (
        <div className="flex flex-col items-center justify-center p-24 space-y-4 h-[60vh]">
            <Loader2 className="h-10 w-10 animate-spin text-blue-600" />
            <p className="text-sm font-black uppercase tracking-widest text-slate-400 animate-pulse">Accessing Weekly Capacity Grid...</p>
        </div>
    );

    return (
        <DragDropContext onDragEnd={handleDragEnd}>
            <div className="space-y-6 flex flex-col h-full min-h-[calc(100vh-10rem)] p-4 md:p-8 bg-slate-50">
                {/* Header Master */}
                <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6 bg-white p-8 rounded-[2.5rem] shadow-xl shadow-slate-200/50 border-2 border-slate-100">
                    <div className="flex items-center gap-6">
                        <div className="h-16 w-16 bg-blue-700 rounded-3xl flex items-center justify-center text-white shadow-2xl shadow-blue-200">
                            <Zap className="h-8 w-8" />
                        </div>
                        <div>
                            <h1 className="text-4xl font-black tracking-tighter uppercase italic text-slate-900">Power-Planning V2</h1>
                            <div className="flex items-center gap-3 mt-1.5">
                                <Badge variant="secondary" className="bg-emerald-600 text-white font-black uppercase text-[10px] tracking-[0.1em] px-3 py-0.5 rounded-full">Live Factory Core</Badge>
                                <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">Capacità Vasi Comunicanti</span>
                            </div>
                        </div>
                    </div>

                    <div className="flex items-center gap-4">
                        <Button 
                            variant="ghost" 
                            className="h-14 px-6 rounded-2xl bg-slate-900 text-white hover:bg-blue-600 transition-all font-black text-xs uppercase tracking-widest gap-3 shadow-lg"
                            onClick={() => setIsBacklogOpen(true)}
                        >
                            <LayoutGrid className="h-5 w-5" />
                            Commesse da Pianificare
                            <Badge className="bg-blue-500 text-white border-none ml-2">{boardData.unassignedJobs.length}</Badge>
                        </Button>

                        <div className="h-10 w-px bg-slate-200 mx-2" />

                        <div className="flex items-center gap-1.5 bg-slate-100 p-1.5 rounded-2xl border-2 border-slate-200 shadow-inner">
                            <Button variant="ghost" size="icon" className="h-10 w-10 rounded-xl hover:bg-white" onClick={handlePrevWeek}><ChevronLeft className="h-6 w-6" /></Button>
                            <div className="px-6 font-black text-sm text-slate-900 min-w-[220px] text-center uppercase tracking-tighter">
                                SETT. {getWeek(currentDate, { weekStartsOn: 1 })} — {currentDate.getFullYear()}
                            </div>
                            <Button variant="ghost" size="icon" className="h-10 w-10 rounded-xl hover:bg-white" onClick={handleNextWeek}><ChevronRight className="h-6 w-6" /></Button>
                        </div>

                        <div className="flex items-center gap-1.5 bg-slate-50 p-1.5 rounded-2xl border-2 border-slate-100">
                            <Button 
                                variant={activeView === 'board' ? 'default' : 'ghost'} 
                                size="sm" 
                                className={cn("h-10 font-black text-[10px] uppercase px-6 rounded-xl transition-all", activeView === 'board' ? "bg-blue-700 shadow-lg shadow-blue-200" : "text-slate-400")}
                                onClick={() => setActiveView('board')}
                            >
                                TABELLONE
                            </Button>
                            <Button 
                                variant={activeView === 'console' ? 'default' : 'ghost'} 
                                size="sm" 
                                className={cn("h-10 font-black text-[10px] uppercase px-6 rounded-xl transition-all", activeView === 'console' ? "bg-blue-700 shadow-lg shadow-blue-200" : "text-slate-400")}
                                onClick={() => setActiveView('console')}
                            >
                                CONSOLE MASTER
                            </Button>
                        </div>

                        <Button 
                            variant="outline" 
                            size="icon"
                            className="h-12 w-12 border-2 rounded-2xl hover:bg-blue-50 hover:border-blue-300 text-slate-400 hover:text-blue-600 transition-all shadow-sm"
                            onClick={() => loadData(true)} 
                            disabled={isRefreshing}
                        >
                            <RefreshCcw className={cn("h-6 w-6", isRefreshing && "animate-spin")} />
                        </Button>
                    </div>
                </div>

                {/* Contenuto dinamico */}
                <div className="flex-1">
                    {activeView === 'board' ? (
                        <WeeklyCapacityBoard 
                            jobOrders={boardData.jobOrders}
                            operators={cachedOperators}
                            departments={cachedDepartments}
                            articles={cachedArticles}
                            allocations={boardData.allocations}
                            currentDate={currentDate}
                            onStatusAdvance={handleStatusAdvance}
                            onManageAllocations={(deptId, week, year) => {
                                setSelectedSlot({ deptId, week, year });
                                setIsLoanDialogOpen(true);
                            }}
                        />
                    ) : (
                        <MasterConsole 
                            jobOrders={[...boardData.jobOrders, ...boardData.unassignedJobs]}
                            articles={cachedArticles}
                            onRefresh={() => loadData(true)}
                        />
                    )}
                </div>

                {/* Drawer Backlog */}
                <BacklogDrawer 
                    isOpen={isBacklogOpen}
                    onClose={() => setIsBacklogOpen(false)}
                    unassignedJobs={boardData.unassignedJobs}
                />

                {selectedSlot && (
                    <OperatorSkillLoanDialog 
                        isOpen={isLoanDialogOpen}
                        onClose={() => setIsLoanDialogOpen(false)}
                        targetDept={selectedSlot.deptId}
                        week={selectedSlot.week}
                        year={selectedSlot.year}
                        operators={cachedOperators}
                        currentAllocations={boardData.allocations[`${selectedSlot.year}_${selectedSlot.week}_${selectedSlot.deptId}`] || []}
                        onSelect={handleLoanSelect}
                    />
                )}
            </div>
        </DragDropContext>
    );
}

'use client';

import React, { useState, useEffect } from 'react';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
