        <div className="flex-1 overflow-auto p-12 scrollbar-thin scrollbar-thumb-gray-300 scrollbar-track-transparent">
           <div className="mx-auto bg-white shadow-[0_35px_60px_-15px_rgba(0,0,0,0.3)] origin-top transition-all duration-500 rounded-sm overflow-hidden" style={{ width: '297mm' }}>
              <ODLPrintTemplate 
                job={MOCK_JOB as any} 
                article={MOCK_ARTICLE as any} 
                materials={MOCK_MATERIALS as any} 
                config={config} 
                qrRule={qrRule}
              />
           </div>
           
           {/* Mock Pagination Indicator */}
           <div className="mt-10 mx-auto w-[297mm] flex justify-center pb-20">
               <div className="flex gap-1.5 p-2 bg-gray-200/50 backdrop-blur-md rounded-2xl shadow-inner border border-white">
                   <div className="w-8 h-8 rounded-xl bg-blue-600 text-white flex items-center justify-center font-bold shadow-lg">1</div>
                   <div className="w-8 h-8 rounded-xl bg-white text-gray-400 flex items-center justify-center font-bold border border-gray-100 italic text-[10px]">...next</div>
               </div>
           </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import React, { useState, useEffect } from 'react';
import AdminAuthGuard from '@/components/AdminAuthGuard';
import AppShell from '@/components/layout/AppShell';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Switch } from '@/components/ui/switch';
import { Loader2, Save, Plus, Trash2, Settings2, Boxes, Ruler, AlertCircle, Layers } from 'lucide-react';
import { useToast } from '@/hooks/use-toast';
import { useAuth } from '@/components/auth/AuthProvider';
import { getGlobalSettings, updateGlobalSettings } from '@/lib/settings-actions';
import { GlobalSettings, RawMaterialTypeConfig } from '@/lib/settings-types';

export default function GlobalParametersPage() {
  const { user } = useAuth();
  const { toast } = useToast();
  const [settings, setSettings] = useState<GlobalSettings | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);

  useEffect(() => {
    getGlobalSettings().then(setSettings).finally(() => setIsLoading(false));
  }, []);

  const handleSave = async () => {
    if (!settings || !user) return;
    setIsSaving(true);
    const res = await updateGlobalSettings(settings, user.uid);
    if (res.success) {
      toast({ title: 'Impostazioni salvate', description: 'I parametri globali sono stati aggiornati.' });
    } else {
      toast({ variant: 'destructive', title: 'Errore', description: res.message });
    }
    setIsSaving(false);
  };

  const addRawMaterialType = () => {
    if (!settings) return;
    const newType: RawMaterialTypeConfig = {
      id: `NEW_${Date.now()}`,
      label: 'Nuova Tipologia',
      defaultUnit: 'mt',
      hasConversion: false
    };
    setSettings({ ...settings, rawMaterialTypes: [...settings.rawMaterialTypes, newType] });
  };

  const updateRawMaterialType = (index: number, updates: Partial<RawMaterialTypeConfig>) => {
    if (!settings) return;
    const newTypes = [...settings.rawMaterialTypes];
    newTypes[index] = { ...newTypes[index], ...updates };
    setSettings({ ...settings, rawMaterialTypes: newTypes });
  };

  const removeRawMaterialType = (index: number) => {
    if (!settings) return;
    const newTypes = settings.rawMaterialTypes.filter((_, i) => i !== index);
    setSettings({ ...settings, rawMaterialTypes: newTypes });
  };

  const addListItem = (key: keyof Pick<GlobalSettings, 'unitsOfMeasure' | 'materialSessionCategories'>) => {
    if (!settings) return;
    setSettings({ ...settings, [key]: [...settings[key] as string[], ''] });
  };

  const updateListItem = (key: keyof Pick<GlobalSettings, 'unitsOfMeasure' | 'materialSessionCategories'>, index: number, value: string) => {
    if (!settings) return;
    const newList = [...settings[key] as string[]];
    newList[index] = value;
    setSettings({ ...settings, [key]: newList });
  };

  const removeListItem = (key: keyof Pick<GlobalSettings, 'unitsOfMeasure' | 'materialSessionCategories'>, index: number) => {
    if (!settings) return;
    const newList = (settings[key] as string[]).filter((_, i) => i !== index);
    setSettings({ ...settings, [key]: newList });
  };

  const addProblemType = () => {
    if (!settings) return;
    setSettings({ 
      ...settings, 
      productionProblemTypes: [...settings.productionProblemTypes, { id: `PROB_${Date.now()}`, label: 'Nuovo Problema' }] 
    });
  };

  const updateProblemType = (index: number, label: string) => {
    if (!settings) return;
    const newList = [...settings.productionProblemTypes];
    newList[index] = { ...newList[index], label, id: label.toUpperCase().replace(/\s+/g, '_') };
    setSettings({ ...settings, productionProblemTypes: newList });
  };

  if (isLoading) {
    return (
      <AppShell>
        <div className="flex justify-center items-center h-[60vh]">
          <Loader2 className="h-8 w-8 animate-spin text-primary" />
        </div>
      </AppShell>
    );
  }

  if (!settings) return null;

  return (
    <AdminAuthGuard>
      <AppShell>
        <div className="space-y-6">
          <header className="flex justify-between items-center">
            <div>
              <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
                <Settings2 className="h-8 w-8 text-primary" />
                Parametri Globali
              </h1>
              <p className="text-muted-foreground">Configura le tipologie, le unità di misura e i parametri di sistema dell'officina.</p>
            </div>
            <Button onClick={handleSave} disabled={isSaving} className="gap-2">
              {isSaving ? <Loader2 className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
              Salva Tutto
            </Button>
          </header>

          <Tabs defaultValue="materials" className="w-full">
            <TabsList className="grid w-full grid-cols-4 max-w-2xl">
              <TabsTrigger value="materials" className="gap-2"><Boxes className="h-4 w-4" /> Materiali</TabsTrigger>
              <TabsTrigger value="units" className="gap-2"><Ruler className="h-4 w-4" /> Unità</TabsTrigger>
              <TabsTrigger value="problems" className="gap-2"><AlertCircle className="h-4 w-4" /> Problemi</TabsTrigger>
              <TabsTrigger value="sessions" className="gap-2"><Layers className="h-4 w-4" /> Sessioni</TabsTrigger>
              <TabsTrigger value="general" className="gap-2"><Settings2 className="h-4 w-4" /> Generali</TabsTrigger>
            </TabsList>

            {/* RAW MATERIAL TYPES */}
            <TabsContent value="materials" className="space-y-4 pt-4">
              <Card>
                <CardHeader className="flex flex-row items-center justify-between space-y-0">
                  <div>
                    <CardTitle>Tipologie Materie Prime</CardTitle>
                    <CardDescription>Definisci i tipi di materiale (es. BOB, TUBI) e le loro logiche di default.</CardDescription>
                  </div>
                  <Button variant="outline" size="sm" onClick={addRawMaterialType} className="gap-1">
                    <Plus className="h-4 w-4" /> Aggiungi Tipo
                  </Button>
                </CardHeader>
                <CardContent className="space-y-6">
                  {settings.rawMaterialTypes.map((type, index) => (
                    <div key={index} className="grid grid-cols-1 md:grid-cols-4 gap-4 p-4 border rounded-lg bg-muted/5 relative group">
                      <div className="space-y-2">
                        <Label>Codice/ID</Label>
                        <Input value={type.id} onChange={(e) => updateRawMaterialType(index, { id: e.target.value.toUpperCase() })} placeholder="Es. BOB" />
                      </div>
                      <div className="space-y-2">
                        <Label>Etichetta</Label>
                        <Input value={type.label} onChange={(e) => updateRawMaterialType(index, { label: e.target.value })} placeholder="Es. Bobina" />
                      </div>
                      <div className="space-y-2">
                        <Label>Unità Default</Label>
                        <Select value={type.defaultUnit} onValueChange={(val: any) => updateRawMaterialType(index, { defaultUnit: val })}>
                          <SelectTrigger>
                            <SelectValue />
                          </SelectTrigger>
                          <SelectContent>
                            {settings.unitsOfMeasure.map(u => <SelectItem key={u} value={u}>{u}</SelectItem>)}
                          </SelectContent>
                        </Select>
                      </div>
                      <div className="flex flex-col justify-end space-y-3 pb-1">
                          <div className="flex items-center justify-between gap-2 px-1">
                             <Label className="text-[10px] uppercase font-bold text-muted-foreground">Usa Conversione</Label>
                             <Switch checked={type.hasConversion} onCheckedChange={(val) => updateRawMaterialType(index, { hasConversion: val })} />
                          </div>
                          <div className="flex items-center justify-between gap-2 px-1">
                             <Label className="text-[10px] uppercase font-bold text-muted-foreground">Richiede Taglio (mm)</Label>
                             <Switch checked={type.requiresCutLength ?? false} onCheckedChange={(val) => updateRawMaterialType(index, { requiresCutLength: val })} />
                          </div>
                          {type.hasConversion && (
                             <Select value={type.conversionType} onValueChange={(val: any) => updateRawMaterialType(index, { conversionType: val })}>
                                 <SelectTrigger className="h-8 text-xs">
                                     <SelectValue placeholder="Tipo conv." />
                                 </SelectTrigger>
                                 <SelectContent>
                                     <SelectItem value="kg/mt">Peso specifico (KG/MT)</SelectItem>
                                     <SelectItem value="kg/unit">Peso unitario (KG/PZ)</SelectItem>
                                 </SelectContent>
                             </Select>
                          )}
                      </div>
                      <Button 
                        variant="ghost" 
                        size="icon" 
                        className="absolute -top-2 -right-2 h-7 w-7 rounded-full bg-destructive/10 text-destructive opacity-0 group-hover:opacity-100 transition-opacity"
                        onClick={() => removeRawMaterialType(index)}
                      >
                        <Trash2 className="h-3 w-3" />
                      </Button>
                    </div>
                  ))}
                </CardContent>
              </Card>
            </TabsContent>

            {/* UNITS OF MEASURE */}
            <TabsContent value="units" className="space-y-4 pt-4">
              <Card>
                <CardHeader className="flex flex-row items-center justify-between">
                  <div>
                    <CardTitle>Unità di Misura</CardTitle>
                    <CardDescription>Definisci le unità utilizzabili a sistema.</CardDescription>
                  </div>
                  <Button variant="outline" size="sm" onClick={() => addListItem('unitsOfMeasure')} className="gap-1">
                    <Plus className="h-4 w-4" /> Aggiungi Unità
                  </Button>
                </CardHeader>
                <CardContent>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                        {settings.unitsOfMeasure.map((unit, index) => (
                            <div key={index} className="flex gap-2">
                                <Input value={unit} onChange={(e) => updateListItem('unitsOfMeasure', index, e.target.value.toLowerCase())} placeholder="es. cm" />
                                <Button variant="ghost" size="icon" onClick={() => removeListItem('unitsOfMeasure', index)} className="text-destructive shrink-0">
                                    <Trash2 className="h-4 w-4" />
                                </Button>
                            </div>
                        ))}
                    </div>
                </CardContent>
              </Card>
            </TabsContent>

            {/* PROBLEM TYPES */}
            <TabsContent value="problems" className="space-y-4 pt-4">
               <Card>
                <CardHeader className="flex flex-row items-center justify-between">
                  <div>
                    <CardTitle>Tipi di Problemi</CardTitle>
                    <CardDescription>Personalizza i motivi di segnalazione problemi in produzione.</CardDescription>
                  </div>
                  <Button variant="outline" size="sm" onClick={addProblemType} className="gap-1">
                    <Plus className="h-4 w-4" /> Aggiungi Motivo
                  </Button>
                </CardHeader>
                <CardContent className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {settings.productionProblemTypes.map((prob, index) => (
                        <div key={index} className="flex gap-2 p-2 border rounded items-center">
                            <div className="flex-1 space-y-1">
                                <Label className="text-[10px] uppercase text-muted-foreground">ID: {prob.id}</Label>
                                <Input value={prob.label} onChange={(e) => updateProblemType(index, e.target.value)} />
                            </div>
                            <Button variant="ghost" size="icon" onClick={() => {
                                const newList = settings.productionProblemTypes.filter((_, i) => i !== index);
                                setSettings({ ...settings, productionProblemTypes: newList });
                            }} className="text-destructive mt-4">
                                <Trash2 className="h-4 w-4" />
                            </Button>
                        </div>
                    ))}
                </CardContent>
              </Card>
            </TabsContent>

            {/* MATERIAL SESSION CATEGORIES */}
            <TabsContent value="sessions" className="space-y-4 pt-4">
                <Card>
                <CardHeader className="flex flex-row items-center justify-between">
                  <div>
                    <CardTitle>Categorie Sessioni Materiale</CardTitle>
                    <CardDescription>Raggruppamenti per la gestione dei carichi attivi dei materiali.</CardDescription>
                  </div>
                  <Button variant="outline" size="sm" onClick={() => addListItem('materialSessionCategories')} className="gap-1">
                    <Plus className="h-4 w-4" /> Aggiungi Categoria
                  </Button>
                </CardHeader>
                <CardContent>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                        {settings.materialSessionCategories.map((cat, index) => (
                            <div key={index} className="flex gap-2">
                                <Input value={cat} onChange={(e) => updateListItem('materialSessionCategories', index, e.target.value.toUpperCase())} />
                                <Button variant="ghost" size="icon" onClick={() => removeListItem('materialSessionCategories', index)} className="text-destructive shrink-0">
                                    <Trash2 className="h-4 w-4" />
                                </Button>
                            </div>
                        ))}
                    </div>
                </CardContent>
              </Card>
            </TabsContent>

            {/* GENERAL SETTINGS */}
            <TabsContent value="general" className="space-y-4 pt-4">
               <Card>
                <CardHeader>
                  <CardTitle>Impostazioni Generali</CardTitle>
                  <CardDescription>Regole di formattazione e comportamenti globali del sistema.</CardDescription>
                </CardHeader>
                <CardContent className="space-y-6">
                  <div className="space-y-2 border p-4 rounded-lg bg-muted/5 max-w-2xl">
                    <Label className="text-base font-semibold">Regola Generazione QR Code Commessa</Label>
                    <p className="text-sm text-muted-foreground pb-2">
                      Definisci il formato del QR code generato per l'ODL. Puoi usare le variabili: <br />
                      <code className="text-xs bg-muted p-1 rounded">{'{'}ordinePF{'}'}</code>, 
                      <code className="text-xs bg-muted p-1 rounded mx-1">{'{'}details{'}'}</code> (Codice Articolo), 
                      <code className="text-xs bg-muted p-1 rounded mx-1">{'{'}qta{'}'}</code>, 
                      <code className="text-xs bg-muted p-1 rounded">{'{'}numeroODLInterno{'}'}</code>
                    </p>
                    <Input 
                        value={settings.jobOrderQrCodeRule || '{ordinePF}@{details}@{qta}'} 
                        onChange={(e) => setSettings({ ...settings, jobOrderQrCodeRule: e.target.value })} 
                        placeholder="Es. {ordinePF}@{details}@{qta}" 
                        className="font-mono"
                    />
                    <p className="text-xs text-muted-foreground mt-2">
                      Esempio Risultato: {
                        (settings.jobOrderQrCodeRule || '{ordinePF}@{details}@{qta}')
                        .replace('{ordinePF}', 'COM001')
                        .replace('{details}', 'ART123')
                        .replace('{qta}', '100')
                        .replace('{numeroODLInterno}', '0001-26')
                      }
                    </p>
                  </div>
                </CardContent>
              </Card>
            </TabsContent>

          </Tabs>
        </div>
      </AppShell>
    </AdminAuthGuard>
  );
}

"use client";

import React, { useState, useEffect } from 'react';
import * as z from 'zod';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import AdminAuthGuard from '@/components/AdminAuthGuard';
import AppShell from '@/components/layout/AppShell';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { useToast } from '@/hooks/use-toast';
import { Timer, Save, Loader2, AlertCircle } from 'lucide-react';
import { getTimeTrackingSettings, saveTimeTrackingSettings, type TimeTrackingSettings } from './actions';
import { useAuth } from '@/components/auth/AuthProvider';
import { Skeleton } from '@/components/ui/skeleton';
import { Form, FormControl, FormDescription, FormField, FormItem, FormLabel, FormMessage } from '@/components/ui/form';
import { Input } from '@/components/ui/input';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';

const settingsSchema = z.object({
  minimumPhaseDurationSeconds: z.coerce
    .number()
    .int("Il valore deve essere un numero intero.")
    .min(0, "Il valore non può essere negativo.")
    .max(300, "Il valore non può superare 300 secondi."),
});

type SettingsFormValues = z.infer<typeof settingsSchema>;

export default function TimeTrackingSettingsPage() {
  const [settings, setSettings] = useState<TimeTrackingSettings>({ 
      minimumPhaseDurationSeconds: 10,
  });
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const { user } = useAuth();
  const { toast } = useToast();

  const form = useForm<SettingsFormValues>({
    resolver: zodResolver(settingsSchema),
    defaultValues: {
      minimumPhaseDurationSeconds: 10,
    },
  });

  const fetchSettings = async () => {
    setIsLoading(true);
    try {
        const data = await getTimeTrackingSettings();
        setSettings(data);
        form.reset(data);
    } catch (error) {
        toast({
            variant: "destructive",
            title: "Errore",
            description: "Impossibile caricare le impostazioni.",
        });
    }
    setIsLoading(false);
  };

  useEffect(() => {
    fetchSettings();
     // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const onSubmit = async (values: SettingsFormValues) => {
    if (!user) return;
    setIsSaving(true);
    const result = await saveTimeTrackingSettings(values, user.uid);
    toast({
      title: result.success ? "Impostazioni Salvate" : "Errore",
      description: result.message,
      variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
      await fetchSettings();
    }
    setIsSaving(false);
  };

  return (
    <AdminAuthGuard>
      <AppShell>
        <div className="space-y-8 max-w-4xl mx-auto">
          <header className="space-y-2">
            <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
              <Timer className="h-8 w-8 text-primary" />
              Gestione Rilevazione Tempi
            </h1>
            <p className="text-muted-foreground">
              Definisci le regole per la validazione e l'analisi dei tempi di produzione.
            </p>
          </header>

          <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)}>
              <Card>
                <CardHeader>
                  <CardTitle>Regole di Validazione Automatica</CardTitle>
                  <CardDescription>
                    Imposta i parametri usati per determinare se i dati cronometrati sono affidabili.
                  </CardDescription>
                </CardHeader>
                <CardContent className="space-y-4">
                  {isLoading ? (
                    <div className="space-y-2">
                      <Skeleton className="h-10 w-full" />
                    </div>
                  ) : (
                    <FormField
                      control={form.control}
                      name="minimumPhaseDurationSeconds"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Soglia minima di durata fase (in secondi)</FormLabel>
                          <FormControl>
                            <Input type="number" placeholder="Es. 10" {...field} />
                          </FormControl>
                          <FormDescription>
                            Una fase completata in meno di questo tempo renderà il calcolo totale per quella commessa "non affidabile".
                          </FormDescription>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  )}
                </CardContent>
                <CardFooter>
                  <Button type="submit" disabled={isSaving || isLoading}>
                    {isSaving ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <Save className="mr-2 h-4 w-4" />}
                    Salva Impostazioni
                  </Button>
                </CardFooter>
              </Card>
            </form>
          </Form>
          
           <Alert variant="default" className="border-blue-500/50 bg-blue-500/10 text-blue-900 dark:text-blue-200">
             <AlertCircle className="h-5 w-5 text-blue-600 dark:text-blue-400" />
            <AlertTitle className="text-blue-800 dark:text-blue-300">Come funziona l'affidabilità?</AlertTitle>
            <AlertDescription>
             Un tempo di produzione per un articolo è considerato "affidabile" solo se tutte le sue fasi sono state completate organicamente, senza forzature manuali e rispettando la soglia di tempo minima impostata sopra.
            </AlertDescription>
          </Alert>
        </div>
      </AppShell>
    </AdminAuthGuard>
  );
}

"use client";

import React, { useState, useEffect } from 'react';
import * as z from 'zod';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { useToast } from '@/hooks/use-toast';
import * as XLSX from 'xlsx';

import { type WorkPhaseTemplate, RawMaterialType, type Department } from '@/types';
import { getWorkPhaseTemplates, saveWorkPhaseTemplate, deleteWorkPhaseTemplate, getDepartments, deleteSelectedWorkPhaseTemplates } from './actions';


import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle, CardFooter } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Checkbox } from '@/components/ui/checkbox';
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from "@/components/ui/alert-dialog";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage, FormDescription } from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Textarea } from '@/components/ui/textarea';
import { Badge } from '@/components/ui/badge';
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { Switch } from '@/components/ui/switch';
import { Workflow, PlusCircle, Edit, Trash2, Download, Save, Loader2, ListOrdered, Check, X, Timer } from 'lucide-react';
import AppShell from '@/components/layout/AppShell';
import AdminAuthGuard from '@/components/AdminAuthGuard';

const materialTypes: RawMaterialType[] = ['BOB', 'TUBI', 'PF3V0', 'GUAINA'];

// Base schema without department enum
const workPhaseSchema = z.object({
  id: z.string().optional(),
  name: z.string().min(3, 'Il nome deve avere almeno 3 caratteri.'),
  description: z.string().min(10, 'La descrizione deve avere almeno 10 caratteri.'),
  departmentCodes: z.array(z.string()).min(1, 'Selezionare almeno un reparto.'),
  type: z.enum(['preparation', 'production', 'quality', 'packaging'], { required_error: 'Specificare il tipo di fase' }),
  tracksTime: z.boolean().default(true).optional(),
  requiresMaterialScan: z.boolean().default(false).optional(),
  requiresMaterialSearch: z.boolean().default(false).optional(),
  requiresMaterialAssociation: z.boolean().default(false).optional(),
  allowedMaterialTypes: z.array(z.string()).optional(),
  isIndependent: z.boolean().default(false).optional(),
});


type WorkPhaseFormValues = z.infer<typeof workPhaseSchema>;

export default function WorkPhaseManagementClientPage() {
  const [phases, setPhases] = useState<WorkPhaseTemplate[]>([]);
  const [departments, setDepartments] = useState<Department[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingPhase, setEditingPhase] = useState<WorkPhaseTemplate | null>(null);
  const [selectedRows, setSelectedRows] = useState<string[]>([]);
  const [isPending, setIsPending] = useState(false);


  const { toast } = useToast();

  const form = useForm<WorkPhaseFormValues>({
    resolver: zodResolver(workPhaseSchema),
    defaultValues: { id: undefined, name: "", description: "", departmentCodes: [], type: 'production', tracksTime: true, requiresMaterialScan: false, requiresMaterialSearch: false, requiresMaterialAssociation: false, allowedMaterialTypes: [], isIndependent: false },
  });
  
  const fetchAllData = async () => {
    setIsLoading(true);
    const [phasesData, departmentsData] = await Promise.all([
      getWorkPhaseTemplates(),
      getDepartments(),
    ]);
    setPhases(phasesData);
    setDepartments(departmentsData);
    setIsLoading(false);
  };

  useEffect(() => {
    fetchAllData();
  }, []);

  const handleOpenDialog = (phase: WorkPhaseTemplate | null = null) => {
    setEditingPhase(phase);
    if (phase) {
      form.reset({
        id: phase.id,
        name: phase.name,
        description: phase.description,
        departmentCodes: phase.departmentCodes || [],
        type: phase.type || 'production',
        tracksTime: phase.tracksTime !== false,
        requiresMaterialScan: phase.requiresMaterialScan || false,
        requiresMaterialSearch: phase.requiresMaterialSearch || false,
        requiresMaterialAssociation: phase.requiresMaterialAssociation || false,
        allowedMaterialTypes: phase.allowedMaterialTypes || [],
        isIndependent: phase.isIndependent || false,
      });
    } else {
      form.reset({ id: undefined, name: "", description: "", departmentCodes: [], type: 'production', tracksTime: true, requiresMaterialScan: false, requiresMaterialSearch: false, requiresMaterialAssociation: false, allowedMaterialTypes: [], isIndependent: false });
    }
    setIsDialogOpen(true);
  };

  const handleCloseDialog = () => {
    setIsDialogOpen(false);
    setEditingPhase(null);
    form.reset();
  }

  const onSubmit = async (values: WorkPhaseFormValues) => {
    const formData = new FormData();
    if (values.id) formData.append('id', values.id);
    formData.append('name', values.name);
    formData.append('description', values.description);
    values.departmentCodes.forEach(code => formData.append('departmentCodes', code));
    formData.append('type', values.type);
    if (values.tracksTime) formData.append('tracksTime', 'on');
    if (values.type !== 'quality') {
        if (values.requiresMaterialScan) formData.append('requiresMaterialScan', 'on');
        if (values.requiresMaterialSearch) formData.append('requiresMaterialSearch', 'on');
        if (values.requiresMaterialAssociation) formData.append('requiresMaterialAssociation', 'on');
    }
    if (values.isIndependent) formData.append('isIndependent', 'on');
    (values.allowedMaterialTypes || []).forEach(type => formData.append('allowedMaterialTypes', type));


    setIsPending(true);
    const result = await saveWorkPhaseTemplate(formData);
    toast({
        title: result.success ? "Successo" : "Errore",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });

    if (result.success) {
        await fetchAllData();
        handleCloseDialog();
    }
    setIsPending(false);
  };

  const handleDelete = async (id: string) => {
    setIsPending(true);
    const result = await deleteWorkPhaseTemplate(id);
    toast({
        title: result.success ? "Successo" : "Errore",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });
    if (result.success) await fetchAllData();
    setIsPending(false);
  };

  const handleDeleteSelected = async () => {
    setIsPending(true);
    const result = await deleteSelectedWorkPhaseTemplates(selectedRows);
    toast({
        title: result.success ? "Successo" : "Errore",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
        await fetchAllData();
        setSelectedRows([]);
    }
    setIsPending(false);
  };


  
  const handleSelectAll = (checked: boolean | 'indeterminate') => {
    setSelectedRows(checked === true ? phases.map(p => p.id) : []);
  };
  
  const handleSelectRow = (id: string) => {
    setSelectedRows(prev => prev.includes(id) ? prev.filter(rowId => rowId !== id) : [...prev, id]);
  };

  const handleExport = () => {
    const departmentNameMap = new Map(departments.map(d => [d.code, d.name]));
    const dataToExport = phases.map(phase => ({
        'Tipo': phase.type === 'production' ? 'Produzione' : 'Preparazione',

        'Traccia Tempo': phase.tracksTime ? 'Sì' : 'No',
        'Richiede Scansione Materiale': phase.requiresMaterialScan ? 'Sì' : 'No',
        'Richiede Associazione Materiale': phase.requiresMaterialAssociation ? 'Sì' : 'No',
        'Nome Fase': phase.name,
        'Descrizione': phase.description,
        'Reparti': (phase.departmentCodes || []).map(code => departmentNameMap.get(code) || code).join(', '),
    }));
    const ws = XLSX.utils.json_to_sheet(dataToExport);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Fasi Lavorazione");
    XLSX.writeFile(wb, "fasi_lavorazione.xlsx");
  };
  
  const renderLoading = () => (
      <TableRow>
          <TableCell colSpan={10} className="h-24 text-center">
              <div className="flex items-center justify-center gap-2 text-muted-foreground">
                  <Loader2 className="h-5 w-5 animate-spin" />
                  <span>Caricamento fasi...</span>
              </div>
          </TableCell>
      </TableRow>
  );

  return (
    <AdminAuthGuard>
        <AppShell>
            <div className="space-y-6">
            <div className="flex justify-between items-center">
                <header>
                    <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
                    <Workflow className="h-8 w-8 text-primary" />
                    Gestione Fasi di Lavorazione
                    </h1>
                    <p className="text-muted-foreground mt-2">
                    Definisci le fasi "modello" e le loro proprietà per i cicli di lavorazione delle commesse.

                    </p>
                </header>
                <div className="flex items-center gap-2">
                    <Button onClick={handleExport} variant="outline" disabled={isLoading || phases.length === 0}>
                        <Download className="mr-2 h-4 w-4" />
                        Esporta
                    </Button>
                    <Button onClick={() => handleOpenDialog()} disabled={isLoading}>
                    <PlusCircle className="mr-2 h-4 w-4" />
                    Aggiungi
                    </Button>
                </div>
            </div>

            <Card>
                <CardHeader>
                <div className="flex justify-between items-center gap-4 flex-wrap">
                    <div>
                    <CardTitle>Elenco Fasi Standard</CardTitle>
                    <CardDescription>Queste sono le fasi disponibili per la configurazione dei cicli di lavoro.</CardDescription>
                    </div>
                    <div className="flex items-center gap-2">

                    {selectedRows.length > 0 && (
                        <AlertDialog>
                            <AlertDialogTrigger asChild>
                            <Button variant="destructive" disabled={isPending}>
                                {isPending ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <Trash2 className="mr-2 h-4 w-4" />}
                                Elimina ({selectedRows.length})
                            </Button>
                            </AlertDialogTrigger>
                            <AlertDialogContent>
                                <AlertDialogHeader>
                                    <AlertDialogTitle>Sei sicuro?</AlertDialogTitle>
                                    <AlertDialogDescription>
                                        Questa azione non può essere annullata. Verranno eliminate definitivamente {selectedRows.length} fasi.
                                    </AlertDialogDescription>
                                </AlertDialogHeader>
                                <AlertDialogFooter>
                                    <AlertDialogCancel>Annulla</AlertDialogCancel>
                                    <AlertDialogAction onClick={handleDeleteSelected}>Continua</AlertDialogAction>
                                </AlertDialogFooter>
                            </AlertDialogContent>
                        </AlertDialog>
                    )}
                    </div>
                </div>
                </CardHeader>
                <CardContent>
                <div className="overflow-x-auto">
                    <Table>
                    <TableHeader>
                        <TableRow>
                        <TableHead padding="checkbox">
                            <Checkbox
                                checked={!isLoading && selectedRows.length > 0 && selectedRows.length === phases.length ? true : !isLoading && selectedRows.length > 0 ? 'indeterminate' : false}
                                onCheckedChange={handleSelectAll}
                                aria-label="Seleziona tutte"
                                disabled={isLoading}
                            />
                        </TableHead>
                        <TableHead>Nome Fase</TableHead>

                        <TableHead>Tipo</TableHead>
                        <TableHead>Traccia Tempo</TableHead>
                        <TableHead>Scansione Mat.</TableHead>
                        <TableHead>Associa Mat.</TableHead>
                        <TableHead>Ricerca Mat.</TableHead>
                        <TableHead>Descrizione</TableHead>
                        <TableHead>Reparti</TableHead>
                        <TableHead className="text-right">Azioni</TableHead>
                        </TableRow>
                    </TableHeader>
                    <TableBody>
                        {isLoading ? renderLoading() : phases.length > 0 ? (
                        phases.map((phase) => (
                            <TableRow key={phase.id} data-state={selectedRows.includes(phase.id) && "selected"}>
                            <TableCell padding="checkbox">
                                <Checkbox
                                    checked={selectedRows.includes(phase.id)}
                                    onCheckedChange={() => handleSelectRow(phase.id)}
                                    aria-label={`Seleziona la fase ${phase.name}`}
                                />
                            </TableCell>

                            <TableCell className="font-medium">{phase.name}</TableCell>
                            <TableCell>
                                <Badge variant={phase.type === 'production' ? 'default' : phase.type === 'quality' ? 'secondary' : phase.type === 'packaging' ? 'outline' : 'destructive'}>
                                {phase.type === 'production' ? 'Produzione' : phase.type === 'quality' ? 'Qualità' : phase.type === 'packaging' ? 'Packaging' : 'Preparazione'}
                                </Badge>
                            </TableCell>
                            <TableCell className="text-center">
                                {phase.tracksTime !== false ? <Check className="h-5 w-5 text-green-500" /> : <X className="h-5 w-5 text-muted-foreground" />}
                            </TableCell>
                             <TableCell className="text-center">
                                {phase.requiresMaterialScan ? <Check className="h-5 w-5 text-green-500" /> : <X className="h-5 w-5 text-muted-foreground" />}
                            </TableCell>
                            <TableCell className="text-center">
                                {phase.requiresMaterialAssociation ? <Check className="h-5 w-5 text-green-500" /> : <X className="h-5 w-5 text-muted-foreground" />}
                            </TableCell>
                             <TableCell className="text-center">
                                {phase.requiresMaterialSearch ? <Check className="h-5 w-5 text-green-500" /> : <X className="h-5 w-5 text-muted-foreground" />}
                            </TableCell>
                            <TableCell className="max-w-sm truncate">{phase.description}</TableCell>
                            <TableCell>
                                <div className="flex flex-wrap gap-1">
                                    {(phase.departmentCodes || []).map(code => (
                                        <Badge key={code} variant="secondary">{(departments.find(d => d.code === code))?.name || code}</Badge>
                                    ))}
                                </div>
                            </TableCell>
                            <TableCell className="text-right space-x-2">
                                <Button variant="outline" size="icon" onClick={() => handleOpenDialog(phase)}>
                                <Edit className="h-4 w-4" />
                                </Button>
                                <AlertDialog>
                                <AlertDialogTrigger asChild>
                                    <Button variant="destructive" size="icon">
                                    <Trash2 className="h-4 w-4" />
                                    </Button>
                                </AlertDialogTrigger>
                                <AlertDialogContent>
                                    <AlertDialogHeader>
                                    <AlertDialogTitle>Sei sicuro?</AlertDialogTitle>
                                    <AlertDialogDescription>
                                        Questa azione non può essere annullata. La fase verrà eliminata.
                                    </AlertDialogDescription>
                                    </AlertDialogHeader>
                                    <AlertDialogFooter>
                                    <AlertDialogCancel>Annulla</AlertDialogCancel>
                                    <AlertDialogAction onClick={() => handleDelete(phase.id)}>Continua</AlertDialogAction>
                                    </AlertDialogFooter>
                                </AlertDialogContent>
                                </AlertDialog>
                            </TableCell>
                            </TableRow>
                        ))
                        ) : (
                        <TableRow>
                            <TableCell colSpan={10} className="text-center h-24">Nessuna fase definita.</TableCell>
                        </TableRow>
                        )}
                    </TableBody>
                    </Table>
                </div>
                </CardContent>
            </Card>
            

            <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
            <DialogContent className="sm:max-w-lg" onInteractOutside={(e) => {if (!isPending) e.preventDefault();}} onEscapeKeyDown={(e) => {if (!isPending) handleCloseDialog();}}>
                <DialogHeader>
                <DialogTitle>{editingPhase ? "Modifica Fase" : "Aggiungi Nuova Fase"}</DialogTitle>
                <DialogDescription>
                    {editingPhase ? "Modifica i dettagli della fase." : "Compila i campi per aggiungere una nuova fase standard."}
                </DialogDescription>
                </DialogHeader>
                <Form {...form}>
                <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4 py-4 max-h-[70vh] overflow-y-auto pr-4">
                    <FormField control={form.control} name="name" render={({ field }) => (
                    <FormItem>
                        <FormLabel>Nome Fase</FormLabel>
                        <FormControl><Input placeholder="Es. Saldatura Manuale" {...field} /></FormControl>
                        <FormMessage />
                    </FormItem>
                    )} />
                    <FormField control={form.control} name="description" render={({ field }) => (
                    <FormItem>
                        <FormLabel>Descrizione</FormLabel>
                        <FormControl><Textarea placeholder="Descrivi lo scopo e le attività principali di questa fase." {...field} /></FormControl>
                        <FormMessage />
                    </FormItem>
                    )} />
                    <FormField
                        control={form.control}
                        name="type"
                        render={({ field }) => (
                        <FormItem className="space-y-3">
                            <FormLabel>Tipo di Fase</FormLabel>
                            <FormControl>
                            <RadioGroup
                                onValueChange={(value) => {
                                  field.onChange(value);
                                  const isTimeTracked = value === 'preparation' || value === 'production';
                                  form.setValue('tracksTime', isTimeTracked);
                                }}
                                defaultValue={field.value}
                                className="flex flex-col space-y-1"
                            >
                                <FormItem className="flex items-center space-x-3 space-y-0">
                                    <FormControl><RadioGroupItem value="preparation" /></FormControl>
                                    <FormLabel className="font-normal">Preparazione</FormLabel>
                                </FormItem>
                                <FormItem className="flex items-center space-x-3 space-y-0">
                                    <FormControl><RadioGroupItem value="production" /></FormControl>
                                    <FormLabel className="font-normal">Produzione</FormLabel>
                                </FormItem>
                                <FormItem className="flex items-center space-x-3 space-y-0">
                                    <FormControl><RadioGroupItem value="quality" /></FormControl>
                                    <FormLabel className="font-normal">Controllo Qualità</FormLabel>
                                </FormItem>
                                <FormItem className="flex items-center space-x-3 space-y-0">
                                    <FormControl><RadioGroupItem value="packaging" /></FormControl>
                                    <FormLabel className="font-normal">Packaging</FormLabel>
                                </FormItem>
                            </RadioGroup>
                            </FormControl>
                            <FormMessage />
                        </FormItem>
                        )}
                    />
                    <FormField
                      control={form.control}
                      name="tracksTime"
                      render={({ field }) => (
                      <FormItem className="flex flex-row items-center justify-between rounded-lg border p-4">
                          <div className="space-y-0.5">
                          <FormLabel className="text-base flex items-center gap-2">
                              <Timer className="h-4 w-4" />
                              Abilita Conteggio Tempo
                          </FormLabel>
                          <FormDescription>
                              Se attivo, il tempo speso in questa fase verrà conteggiato.
                          </FormDescription>
                          </div>
                          <FormControl>
                          <Switch
                              checked={field.value}
                              onCheckedChange={field.onChange}
                          />
                          </FormControl>
                      </FormItem>
                      )}
                    />
                     <FormField
                      control={form.control}
                      name="isIndependent"
                      render={({ field }) => (
                      <FormItem className="flex flex-row items-center justify-between rounded-lg border p-4">
                          <div className="space-y-0.5">
                          <FormLabel className="text-base">
                              Lavorazione Indipendente
                          </FormLabel>
                          <FormDescription>
                            Se attivo, la fase non seguirà la sequenza e sarà avviabile in qualsiasi momento.
                          </FormDescription>
                          </div>
                          <FormControl>
                          <Switch
                              checked={field.value}
                              onCheckedChange={field.onChange}
                          />
                          </FormControl>
                      </FormItem>
                      )}
                    />
                    {form.watch('type') === 'preparation' && (
                    <div className="space-y-4">
                        <FormField
                        control={form.control}
                        name="requiresMaterialScan"
                        render={({ field }) => (
                        <FormItem className="flex flex-row items-center justify-between rounded-lg border p-4">
                            <div className="space-y-0.5">
                            <FormLabel className="text-base">
                                Richiede Scansione Materiale
                            </FormLabel>
                            <FormDescription>
                                Se attiva, l'operatore dovrà scansionare un materiale per avviare questa fase.
                            </FormDescription>
                            </div>
                            <FormControl>
                            <Switch
                                checked={field.value}
                                onCheckedChange={field.onChange}
                            />
                            </FormControl>
                        </FormItem>
                        )}
                        />
                        <FormField
                        control={form.control}
                        name="requiresMaterialSearch"
                        render={({ field }) => (
                        <FormItem className="flex flex-row items-center justify-between rounded-lg border p-4">
                            <div className="space-y-0.5">
                            <FormLabel className="text-base">
                                Richiede Ricerca Materiale
                            </FormLabel>
                            <FormDescription>
                                Se attiva, l'operatore cercherà il materiale manualmente.
                            </FormDescription>
                            </div>
                            <FormControl>
                            <Switch
                                checked={field.value}
                                onCheckedChange={field.onChange}
                            />
                            </FormControl>
                        </FormItem>
                        )}
                        />
                         <FormField
                        control={form.control}
                        name="requiresMaterialAssociation"
                        render={({ field }) => (
                        <FormItem className="flex flex-row items-center justify-between rounded-lg border p-4">
                            <div className="space-y-0.5">
                            <FormLabel className="text-base">
                                Associazione Materiale Facoltativa
                            </FormLabel>
                            <FormDescription>
                                Se attiva, mostra il pulsante "Associa Materiale".
                            </FormDescription>
                            </div>
                            <FormControl>
                            <Switch
                                checked={field.value}
                                onCheckedChange={field.onChange}
                            />
                            </FormControl>
                        </FormItem>
                        )}
                        />
                    {(form.watch('requiresMaterialScan') || form.watch('requiresMaterialSearch')) && (
                        <FormField
                            control={form.control}
                            name="allowedMaterialTypes"
                            render={({ field }) => (
                                <FormItem>
                                    <div className="mb-4">
                                        <FormLabel>Tipi di Materiale Ammessi</FormLabel>
                                        <FormDescription>
                                            Seleziona quali tipi di materiale sono permessi per questa fase.
                                        </FormDescription>
                                    </div>
                                    <div className="grid grid-cols-2 gap-2 rounded-lg border p-4">
                                        {materialTypes.map((type) => (
                                            <FormField
                                                key={type}
                                                control={form.control}
                                                name="allowedMaterialTypes"
                                                render={({ field }) => {
                                                    return (
                                                        <FormItem key={type} className="flex flex-row items-start space-x-3 space-y-0">
                                                            <FormControl>
                                                                <Checkbox
                                                                    checked={field.value?.includes(type)}
                                                                    onCheckedChange={(checked) => {
                                                                        return checked
                                                                            ? field.onChange([...(field.value || []), type])
                                                                            : field.onChange(
                                                                                    (field.value || []).filter(
                                                                                        (value) => value !== type
                                                                                    )
                                                                                )
                                                                    }}
                                                                />
                                                            </FormControl>
                                                            <FormLabel className="font-normal">{type}</FormLabel>
                                                        </FormItem>
                                                    )
                                                }}
                                            />
                                        ))}
                                    </div>
                                    <FormMessage />
                                </FormItem>
                            )}
                        />
                    )}
                    </div>
                    )}
                    <FormField
                      control={form.control}
                      name="departmentCodes"
                      render={() => (
                        <FormItem>
                          <div className="mb-4">
                            <FormLabel>Reparti di Competenza</FormLabel>
                            <FormDescription>
                              Seleziona uno o più reparti per questa fase.
                            </FormDescription>
                          </div>
                          <div className="grid grid-cols-2 gap-2 rounded-lg border p-4">
                            {departments
                              .filter((d: Department) => {
                                const phaseType = form.watch('type');
                                if (phaseType === 'preparation') return d.macroAreas?.includes('PREPARAZIONE');
                                if (phaseType === 'production') return d.macroAreas?.includes('PRODUZIONE');
                                if (phaseType === 'quality' || phaseType === 'packaging') return d.macroAreas?.includes('QLTY_PACK');
                                return false;
                              })
                              .map((dept: Department) => (
                                <FormField
                                  key={dept.id}
                                  control={form.control}
                                  name="departmentCodes"
                                  render={({ field }) => (
                                    <FormItem
                                      key={dept.id}
                                      className="flex flex-row items-center space-x-3 space-y-0"
                                    >
                                      <FormControl>
                                        <Checkbox
                                          checked={field.value?.includes(dept.code)}
                                          onCheckedChange={(checked) => {
                                            const currentValue = field.value || [];
                                            const newValue = checked
                                              ? [...currentValue, dept.code]
                                              : currentValue.filter((value) => value !== dept.code);
                                            field.onChange(newValue);
                                          }}
                                        />
                                      </FormControl>
                                      <FormLabel className="font-normal text-sm">
                                        {dept.name}
                                      </FormLabel>
                                    </FormItem>
                                  )}
                                />
                              ))}
                          </div>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                    <DialogFooter>
                    <Button type="button" variant="outline" onClick={handleCloseDialog} disabled={isPending}>Annulla</Button>
                    <Button type="submit" disabled={isPending}>
                        {isPending ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : null}
                        {editingPhase ? "Salva Modifiche" : "Aggiungi Fase"}
                    </Button>
                    </DialogFooter>
                </form>
                </Form>
            </DialogContent>
            </Dialog>
        </div>
    </AppShell>
  </AdminAuthGuard>
  );
}

"use client";

import React, { useState, useEffect } from 'react';
import { useForm, useFieldArray } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import AdminAuthGuard from '@/components/AdminAuthGuard';
import AppShell from '@/components/layout/AppShell';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { useToast } from '@/hooks/use-toast';
import { Clock, Save, Loader2, Plus, Trash2, CalendarDays, Coffee, Percent, Calculator } from 'lucide-react';
import { getWorkingHoursConfig, saveWorkingHoursConfig } from './actions';
import { useAuth } from '@/components/auth/AuthProvider';
import { Skeleton } from '@/components/ui/skeleton';
import { Form, FormControl, FormDescription, FormField, FormItem, FormLabel, FormMessage } from '@/components/ui/form';
import { Input } from '@/components/ui/input';
import { Checkbox } from '@/components/ui/checkbox';
import { Separator } from '@/components/ui/separator';
import { Badge } from '@/components/ui/badge';

const shiftSchema = z.object({
  id: z.string(),
  name: z.string().min(1, "Il nome del turno è obbligatorio."),
  startTime: z.string().regex(/^([0-1]?[0-9]|2[0-3]):[0-5][0-9]$/, "Formato HH:mm richiesto."),
  endTime: z.string().regex(/^([0-1]?[0-9]|2[0-3]):[0-5][0-9]$/, "Formato HH:mm richiesto."),
  breakMinutes: z.coerce.number().min(0, "La pausa non può essere negativa.").default(0),
});

const workingHoursSchema = z.object({
  workingDays: z.array(z.number()).min(1, "Selezionare almeno un giorno lavorativo."),
  shifts: z.array(shiftSchema).min(1, "Aggiungere almeno un turno."),
  efficiencyPercentage: z.coerce.number().min(1, "L'efficienza deve essere almeno 1%").max(100, "L'efficienza non può superare 100%").default(95),
});

type WorkingHoursValues = z.infer<typeof workingHoursSchema>;

const DAYS = [
  { id: 1, label: "Lunedì" },
  { id: 2, label: "Martedì" },
  { id: 3, label: "Mercoledì" },
  { id: 4, label: "Giovedì" },
  { id: 5, label: "Venerdì" },
  { id: 6, label: "Sabato" },
  { id: 7, label: "Domenica" },
];

export default function WorkingHoursPage() {
  const { user } = useAuth();
  const { toast } = useToast();
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);

  const form = useForm<WorkingHoursValues>({
    resolver: zodResolver(workingHoursSchema),
    defaultValues: {
      workingDays: [1, 2, 3, 4, 5],
      shifts: [{ id: 'shift-1', name: 'Turno Centrale', startTime: '08:00', endTime: '17:00', breakMinutes: 60 }],
      efficiencyPercentage: 95,
    },
  });

  const { fields, append, remove } = useFieldArray({
    control: form.control,
    name: "shifts",
  });

  useEffect(() => {
    async function loadConfig() {
      setIsLoading(true);
      const config = await getWorkingHoursConfig();
      form.reset(config);
      setIsLoading(false);
    }
    loadConfig();
  }, [form]);

  const onSubmit = async (values: WorkingHoursValues) => {
    if (!user) return;
    setIsSaving(true);
    const result = await saveWorkingHoursConfig(values, user.uid);
    toast({
      title: result.success ? "Successo" : "Errore",
      description: result.message,
      variant: result.success ? "default" : "destructive",
    });
    setIsSaving(false);
  };

  const calculateDetailedHours = (start: string, end: string, breakMins: number, efficiency: number) => {
    try {
      const [startH, startM] = start.split(':').map(Number);
      const [endH, endM] = end.split(':').map(Number);
      const totalMinutes = (endH * 60 + endM) - (startH * 60 + startM);
      if (totalMinutes <= 0) return { total: 0, net: 0, effective: 0 };
      
      const total = totalMinutes / 60;
      const net = Math.max(0, (totalMinutes - breakMins) / 60);
      const effective = net * (efficiency / 100);
      
      return { 
        total: total.toFixed(2), 
        net: net.toFixed(2), 
        effective: effective.toFixed(2) 
      };
    } catch {
      return { total: 0, net: 0, effective: 0 };
    }
  };

  if (isLoading) {
    return (
      <AdminAuthGuard>
        <AppShell>
          <div className="space-y-6 max-w-3xl mx-auto">
            <Skeleton className="h-10 w-64" />
            <Card><CardContent className="p-6"><Skeleton className="h-64 w-full" /></CardContent></Card>
          </div>
        </AppShell>
      </AdminAuthGuard>
    );
  }

  const efficiency = form.watch('efficiencyPercentage') || 95;

  return (
    <AdminAuthGuard>
      <AppShell>
        <div className="space-y-8 max-w-3xl mx-auto">
          <header className="space-y-2">
            <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
              <Clock className="h-8 w-8 text-primary" />
              Gestione Orario Lavorativo
            </h1>
            <p className="text-muted-foreground">
              Configura i giorni lavorativi, i turni e l'efficienza stimata per la pianificazione.
            </p>
          </header>

          <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <Card className="md:col-span-2">
                    <CardHeader>
                    <CardTitle className="flex items-center gap-2">
                        <CalendarDays className="h-5 w-5 text-primary" />
                        Settimana Lavorativa
                    </CardTitle>
                    <CardDescription>Seleziona i giorni in cui l'azienda è operativa.</CardDescription>
                    </CardHeader>
                    <CardContent>
                    <FormField
                        control={form.control}
                        name="workingDays"
                        render={() => (
                        <FormItem>
                            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 pt-2">
                            {DAYS.map((day) => (
                                <FormField
                                key={day.id}
                                control={form.control}
                                name="workingDays"
                                render={({ field }) => {
                                    return (
                                    <FormItem
                                        key={day.id}
                                        className="flex flex-row items-start space-x-3 space-y-0"
                                    >
                                        <FormControl>
                                        <Checkbox
                                            checked={field.value?.includes(day.id)}
                                            onCheckedChange={(checked) => {
                                            return checked
                                                ? field.onChange([...field.value, day.id])
                                                : field.onChange(
                                                    field.value?.filter(
                                                    (value) => value !== day.id
                                                    )
                                                )
                                            }}
                                        />
                                        </FormControl>
                                        <FormLabel className="text-sm font-normal">
                                        {day.label}
                                        </FormLabel>
                                    </FormItem>
                                    )
                                }}
                                />
                            ))}
                            </div>
                            <FormMessage />
                        </FormItem>
                        )}
                    />
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <Percent className="h-5 w-5 text-primary" />
                            Efficienza
                        </CardTitle>
                        <CardDescription>Percentuale di lavoro effettivo.</CardDescription>
                    </CardHeader>
                    <CardContent>
                        <FormField
                            control={form.control}
                            name="efficiencyPercentage"
                            render={({ field }) => (
                                <FormItem>
                                    <FormLabel>Indice Efficienza (%)</FormLabel>
                                    <FormControl>
                                        <div className="relative">
                                            <Input type="number" {...field} className="pr-8" />
                                            <span className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground">%</span>
                                        </div>
                                    </FormControl>
                                    <FormDescription className="text-[10px] leading-tight">
                                        Considera pause fisiologiche e tempi morti tecnici.
                                    </FormDescription>
                                    <FormMessage />
                                </FormItem>
                            )}
                        />
                    </CardContent>
                </Card>
              </div>

              <Card>
                <CardHeader className="flex flex-row items-center justify-between">
                  <div className="space-y-1">
                    <CardTitle className="flex items-center gap-2">
                      <Clock className="h-5 w-5 text-primary" />
                      Turni Giornalieri
                    </CardTitle>
                    <CardDescription>Definisci gli orari e le pause di attività.</CardDescription>
                  </div>
                  <Button
                    type="button"
                    variant="outline"
                    size="sm"
                    onClick={() => append({ id: `shift-${Date.now()}`, name: '', startTime: '08:00', endTime: '17:00', breakMinutes: 60 })}
                  >
                    <Plus className="h-4 w-4 mr-2" /> Aggiungi Turno
                  </Button>
                </CardHeader>
                <CardContent className="space-y-4">
                  {fields.map((field, index) => {
                    const stats = calculateDetailedHours(
                        form.watch(`shifts.${index}.startTime`),
                        form.watch(`shifts.${index}.endTime`),
                        form.watch(`shifts.${index}.breakMinutes`),
                        efficiency
                    );

                    return (
                    <div key={field.id} className="space-y-4 p-4 border rounded-lg bg-muted/20 relative">
                      <div className="grid grid-cols-1 sm:grid-cols-4 gap-4">
                        <FormField
                          control={form.control}
                          name={`shifts.${index}.name`}
                          render={({ field }) => (
                            <FormItem className="sm:col-span-1">
                              <FormLabel>Nome Turno</FormLabel>
                              <FormControl><Input placeholder="Es. Turno Centrale" {...field} /></FormControl>
                              <FormMessage />
                            </FormItem>
                          )}
                        />
                        <FormField
                          control={form.control}
                          name={`shifts.${index}.startTime`}
                          render={({ field }) => (
                            <FormItem>
                              <FormLabel>Inizio</FormLabel>
                              <FormControl><Input type="time" {...field} /></FormControl>
                              <FormMessage />
                            </FormItem>
                          )}
                        />
                        <FormField
                          control={form.control}
                          name={`shifts.${index}.endTime`}
                          render={({ field }) => (
                            <FormItem>
                              <FormLabel>Fine</FormLabel>
                              <FormControl><Input type="time" {...field} /></FormControl>
                              <FormMessage />
                            </FormItem>
                          )}
                        />
                        <FormField
                          control={form.control}
                          name={`shifts.${index}.breakMinutes`}
                          render={({ field }) => (
                            <FormItem>
                              <FormLabel className="flex items-center gap-2"><Coffee className="h-3 w-3" />Pausa (min)</FormLabel>
                              <FormControl><Input type="number" {...field} /></FormControl>
                              <FormMessage />
                            </FormItem>
                          )}
                        />
                      </div>
                      
                      <Separator className="bg-border/50" />

                      <div className="flex flex-wrap justify-between items-center gap-4">
                        <div className="flex gap-4">
                            <div className="flex flex-col">
                                <span className="text-[10px] uppercase font-bold text-muted-foreground">Ore Totali</span>
                                <Badge variant="secondary" className="font-mono text-sm w-fit">{stats.total} h</Badge>
                            </div>
                            <div className="flex flex-col">
                                <span className="text-[10px] uppercase font-bold text-muted-foreground">Ore Nette</span>
                                <Badge variant="outline" className="font-mono text-sm w-fit border-blue-500/50 text-blue-600">{stats.net} h</Badge>
                            </div>
                            <div className="flex flex-col">
                                <span className="text-[10px] uppercase font-bold text-primary">Capacità Reale (Effettiva)</span>
                                <Badge variant="default" className="font-mono text-base w-fit bg-green-600 hover:bg-green-600">
                                    <Calculator className="h-3 w-3 mr-1.5" />
                                    {stats.effective} h
                                </Badge>
                            </div>
                        </div>
                        {fields.length > 1 && (
                          <Button
                            type="button"
                            variant="ghost"
                            size="sm"
                            className="text-destructive hover:text-destructive hover:bg-destructive/10"
                            onClick={() => remove(index)}
                          >
                            <Trash2 className="h-4 w-4 mr-2" /> Rimuovi Turno
                          </Button>
                        )}
                      </div>
                    </div>
                  )})}
                </CardContent>
                <CardFooter className="border-t pt-6">
                  <Button type="submit" className="w-full sm:w-auto" disabled={isSaving}>
                    {isSaving ? <Loader2 className="h-4 w-4 mr-2 animate-spin" /> : <Save className="h-4 w-4 mr-2" />}
                    Salva Configurazione
                  </Button>
                </CardFooter>
              </Card>
            </form>
          </Form>
        </div>
      </AppShell>
    </AdminAuthGuard>
  );
}

"use client";

import React from 'react';
import AuthGuard from '@/components/AuthGuard';
import AppShell from '@/components/layout/AppShell';
import { Users, ScanLine, AlertTriangle, Clock, PackagePlus, SearchCheck, Warehouse, MinusSquare, Truck, LayoutGrid } from 'lucide-react';
import DashboardItem from '@/components/dashboard/DashboardItem';
import { useAuth } from '@/components/auth/AuthProvider';
import { Button } from '@/components/ui/button';
import Link from 'next/link';


export default function DashboardPage() {
  const { operator } = useAuth();

  const checkAccess = (keywords: string[]) => {
    if (!operator) return false;
    if (operator.role === 'supervisor' || operator.role === 'admin') return true;
    
    const reparti = Array.isArray(operator.reparto) ? operator.reparto : [operator.reparto];
    return reparti.some(r => {
      const upperR = String(r || '').toUpperCase();
      return keywords.some(k => upperR.includes(k.toUpperCase()));
    });
  };

  const hasMagAccess = checkAccess(['MAG', 'MAGAZZINO', 'COLLAUDO']);
  const hasPackingAccess = checkAccess(['MAG', 'MAGAZZINO', 'COLLAUDO', 'QUALIT', 'QLTY', 'IMBALLO', 'PACK']);


  return (
    <AuthGuard>
      <AppShell>
        <div className="space-y-8">
          <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
            <div className="space-y-1">
              <h1 className="text-3xl font-bold font-headline tracking-tight uppercase">Dashboard Operatore</h1>
              <p className="text-muted-foreground text-sm font-medium">
                Seleziona un'opzione qui sotto per accedere alle funzioni di ProdFastXcan.
              </p>
            </div>
            
            {operator?.role === 'supervisor' && (
              <Button asChild variant="outline" className="border-primary text-primary hover:bg-primary/10 font-bold uppercase text-[10px] h-9 gap-2 shadow-sm">
                <Link href="/supervisor/dashboard">
                  <LayoutGrid className="h-4 w-4" />
                  Torna alla Gestione
                </Link>
              </Button>
            )}
          </header>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            <DashboardItem
              title="Scansione Commessa PF"
              description="Scansiona un QR code della commessa per iniziare o continuare il lavoro."
              icon={ScanLine}
              href="/scan-job"
            />
            {hasMagAccess && (
              <>
                 <DashboardItem
                  title="Carico Merce"
                  description="Modalità inventario per registrare rapidamente materiale in ingresso."
                  icon={PackagePlus}
                  href="/material-loading"
                />
                 <DashboardItem
                  title="Verifica Materiale"
                  description="Cerca un materiale per vederne i dettagli e lo stock attuale."
                  icon={SearchCheck}
                  href="/material-check"
                />
              </>
            )}
             {(operator?.canAccessInventory || operator?.role === 'admin' || operator?.role === 'supervisor') && (
                <DashboardItem
                  title="Inventario"
                  description="Gestisci l'inventario delle materie prime."
                  icon={Warehouse}
                  href="/inventory"
                />
            )}
             {(operator?.canAccessMaterialWithdrawal || operator?.role === 'admin' || operator?.role === 'supervisor') && (
                <DashboardItem
                  title="Scarico Materiale"
                  description="Registra uno scarico manuale di materiale per la produzione"
                  icon={MinusSquare}
                  href="/manual-withdrawal"
                />
            )}
            <DashboardItem
              title="Dati Operatore"
              description="Visualizza e gestisci le informazioni del tuo profilo utente."
              icon={Users}
              href="/operator"
            />
            <DashboardItem
              title="Timbratrice"
              description="Registra l'orario di ingresso o di uscita dal turno di lavoro."
              icon={Clock}
              className="opacity-50 cursor-not-allowed"
            />
            {hasPackingAccess && (
                <DashboardItem
                  title="Packing List"
                  description="Gestisci l'imballaggio e la spedizione delle commesse completate."
                  icon={Truck}
                  href="/operator/packing"
                />
            )}
            <DashboardItem
              title="Segnala Problema"
              description="Segnala eventuali problemi riscontrati durante la produzione."
              icon={AlertTriangle}
              href="/report-problem"
            />
          </div>
        </div>
      </AppShell>
    </AuthGuard>
  );
}

"use client";

import React, { useState, useEffect, useRef, useCallback } from 'react';
import Image from 'next/image';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';

import { login } from '@/lib/auth';
import { useAuth } from '@/components/auth/AuthProvider';
import { useCameraStream } from '@/hooks/use-camera-stream';

import { useToast } from '@/hooks/use-toast';
import { cn } from '@/lib/utils';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card';
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from '@/components/ui/form';
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip";
import { QrCode, Lock, LogIn, User, Loader2, KeyRound, AlertTriangle, Clock, ScanLine, Download, PackagePlus, Camera, TestTube } from 'lucide-react';


// Add type for the install prompt event
interface BeforeInstallPromptEvent extends Event {
    readonly platforms: Array<string>;
    readonly userChoice: Promise<{
        outcome: 'accepted' | 'dismissed';
        platform: string;
    }>;
    prompt(): Promise<void>;
}


const manualLoginSchema = z.object({
  username: z.string().min(1, { message: "Il nome utente è obbligatorio." }),
  password: z.string().min(1, { message: "La password è obbligatoria." }),
});

type LoginStep = 'initial' | 'camera' | 'logging_in' | 'manual_login';

export default function LoginForm() {
    const [step, setStep] = useState<LoginStep>('initial');
    const [isScanning, setIsScanning] = useState(false);
    const videoRef = useRef<HTMLVideoElement>(null);
    const { hasPermission: hasCameraPermission } = useCameraStream(step === 'camera', videoRef);

    const { toast } = useToast();
    const { user, operator, loading: authLoading } = useAuth();

    const manualForm = useForm<z.infer<typeof manualLoginSchema>>({
        resolver: zodResolver(manualLoginSchema),
        defaultValues: { username: "", password: "" },
    });

    const performLogin = useCallback(async (username: string, password_used: string) => {
        setStep('logging_in');
        try {
            await login(username, password_used);
            // On success, the AuthProvider's onAuthStateChanged listener will handle the redirect.
        } catch (error) {
            localStorage.removeItem('login_redirect_path');
            const errorMessage = error instanceof Error ? error.message : "Credenziali non valide o utente non trovato.";
            toast({
                title: "Accesso Fallito",
                description: errorMessage,
                variant: "destructive",
            });
            setStep('manual_login');
        }
    }, [toast]);
    
    const handleQrLoginClick = (targetPath: string | null) => {
      if (targetPath) {
        localStorage.setItem('login_redirect_path', targetPath);
      } else {
        localStorage.removeItem('login_redirect_path');
      }
      setStep('camera');
    };
    
    const triggerScan = async () => {
        if (typeof window === 'undefined' || !('BarcodeDetector' in window)) {
          toast({ variant: 'destructive', title: 'Funzionalità non Supportata', description: 'Il tuo browser non supporta la scansione dei codici a barre.' });
          return;
        }

        if (!videoRef.current || videoRef.current.paused || videoRef.current.readyState < 2) {
            toast({ variant: 'destructive', title: 'Fotocamera non Pronta', description: 'Attendere che il video sia attivo.' });
            return;
        }

        setIsScanning(true);
        toast({ title: 'Scansione...', description: 'Alla ricerca di un codice nel frame.' });
        
        try {
            const barcodeDetector = new (window as any).BarcodeDetector({ formats: ['qr_code'] });
            const barcodes = await barcodeDetector.detect(videoRef.current);

            if (barcodes.length > 0) {
                setStep('initial'); // Stop the camera
                const [username, password] = barcodes[0].rawValue.split('@');
                if (username && password) {
                     performLogin(username, password);
                } else {
                    toast({
                        variant: 'destructive',
                        title: 'Dati QR non Validi',
                        description: 'Il formato del QR code per il login non è corretto.',
                    });
                    setStep('initial');
                }
            } else {
                toast({ variant: 'destructive', title: 'Nessun Codice Trovato', description: 'Assicurati che il codice sia ben visibile e riprova.' });
            }
        } catch (error) {
            toast({ variant: 'destructive', title: 'Errore di Scansione', description: 'Impossibile processare l\'immagine.' });
        } finally {
            setIsScanning(false);
        }
    };


    const onManualSubmit = (values: z.infer<typeof manualLoginSchema>) => {
        localStorage.removeItem('login_redirect_path');
        performLogin(values.username, values.password);
    };

    const [installPrompt, setInstallPrompt] = useState<BeforeInstallPromptEvent | null>(null);

    useEffect(() => {
        const handleBeforeInstallPrompt = (e: Event) => {
            e.preventDefault();
            setInstallPrompt(e as BeforeInstallPromptEvent);
        };

        window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
        return () => window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    }, []);

    const handleInstallClick = async () => {
        if (!installPrompt) return;
        await installPrompt.prompt();
        const { outcome } = await installPrompt.userChoice;
        if (outcome === 'accepted') {
            setInstallPrompt(null);
        }
    };

    const renderStep = () => {
        switch (step) {
            case 'initial':
                return (
                    <>
                        <CardHeader className="items-center text-center">
                            <Image src="/logo.png" alt="PFXcan Logo" width={150} height={100} unoptimized={true} priority={true} />
                            <CardTitle className="text-2xl font-headline">Benvenuto in PFXcan</CardTitle>
                             <CardDescription className="text-muted-foreground">Seleziona una modalità di accesso.</CardDescription>
                        </CardHeader>
                        <CardContent className="flex flex-col gap-4">
                            <Button onClick={() => handleQrLoginClick(null)} size="lg" className="h-14 text-lg">
                               <QrCode className="mr-3 h-6 w-6" />
                                Accesso Standard (QR)
                            </Button>

                             <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                                <Button variant="secondary" className="h-20 flex-col gap-1 text-secondary-foreground opacity-50 cursor-not-allowed" disabled>
                                    <Clock className="h-6 w-6" />
                                    Timbratura
                                </Button>
                                <Button onClick={() => handleQrLoginClick('/scan-job')} className="h-20 flex-col gap-1 bg-green-600 text-white hover:bg-green-700">
                                    <ScanLine className="h-6 w-6" />
                                    Produzione
                                </Button>
                                 <Button onClick={() => handleQrLoginClick('/material-loading')} className="h-20 flex-col gap-1 bg-amber-500 text-white hover:bg-amber-600">
                                    <PackagePlus className="h-6 w-6" />
                                    Carico Merce
                                </Button>
                            </div>
                            
                            <div className="relative flex py-2 items-center">
                                <div className="flex-grow border-t border-muted-foreground/20"></div>
                                <span className="flex-shrink mx-4 text-xs text-muted-foreground">OPPURE</span>
                                <div className="flex-grow border-t border-muted-foreground/20"></div>
                            </div>

                            <Button onClick={() => setStep('manual_login')} variant="outline">
                                <KeyRound className="mr-2 h-4 w-4" />
                                Accedi con Password
                            </Button>

                            {installPrompt && (
                                <Button 
                                    onClick={handleInstallClick} 
                                    variant="default" 
                                    className="mt-2 bg-blue-600 hover:bg-blue-700 text-white animate-pulse"
                                >
                                    <Download className="mr-2 h-4 w-4" />
                                    Installa l'App sul dispositivo
                                </Button>
                            )}
                        </CardContent>
                    </>
                );
            case 'camera':
                return (
                    <div>
                         <CardHeader>
                            <CardTitle className="text-center font-headline">Scansione QR Code</CardTitle>
                            <CardDescription className="text-center">Inquadra il QR code e premi il pulsante per scansionare.</CardDescription>
                        </CardHeader>
                        <CardContent className="relative grid place-items-center aspect-square bg-black rounded-lg overflow-hidden">
                             <video ref={videoRef} className="w-full h-full object-cover" autoPlay muted playsInline />
                             <div className="absolute inset-0 grid place-items-center pointer-events-none">
                                <div className="w-2/3 h-2/3 relative">
                                    <div className="absolute top-0 left-0 w-8 h-8 border-t-4 border-l-4 border-primary rounded-tl-lg"></div>
                                    <div className="absolute top-0 right-0 w-8 h-8 border-t-4 border-r-4 border-primary rounded-tr-lg"></div>
                                    <div className="absolute bottom-0 left-0 w-8 h-8 border-b-4 border-l-4 border-primary rounded-bl-lg"></div>
                                    <div className="absolute bottom-0 right-0 w-8 h-8 border-b-4 border-r-4 border-primary rounded-br-lg"></div>
                                    <div className="absolute w-full top-1/2 -translate-y-1/2 h-0.5 bg-red-500/80 shadow-[0_0_4px_1px_#ef4444]"></div>
                                </div>
                             </div>
                             {hasCameraPermission === false && (
                                <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center text-center p-4">
                                    <AlertTriangle className="h-12 w-12 text-destructive mb-4" />
                                    <p className="text-destructive-foreground font-semibold">Accesso alla fotocamera negato</p>
                                    <p className="text-sm text-muted-foreground mt-2">Controlla i permessi del browser per continuare.</p>
                                </div>
                            )}
                        </CardContent>
                        <CardFooter className="pt-6 flex flex-col gap-2">
                             <Button onClick={triggerScan} disabled={isScanning || !hasCameraPermission} className="w-full h-14">
                                {isScanning ? <Loader2 className="h-6 w-6 animate-spin" /> : <Camera className="h-6 w-6" />}
                                <span className="ml-2 text-lg">{isScanning ? 'Scansionando...' : 'Scansiona'}</span>
                             </Button>
                            <Button variant="outline" className="w-full" onClick={() => setStep('initial')}>Annulla</Button>
                        </CardFooter>
                    </div>
                );
            case 'manual_login':
                 return (
                     <div>
                        <Form {...manualForm}>
                            <form onSubmit={manualForm.handleSubmit(onManualSubmit)}>
                                 <CardHeader className="items-center text-center">
                                    <Image src="/logo.png" alt="PFXcan Logo" width={120} height={80} unoptimized={true} />
                                    <CardTitle>Accesso Manuale</CardTitle>
                                    <CardDescription className="text-muted-foreground">Inserisci le tue credenziali.</CardDescription>
                                 </CardHeader>
                                <CardContent className="space-y-6">
                                    <FormField control={manualForm.control} name="username" render={({ field }) => ( <FormItem> <FormLabel className="flex items-center"><User className="mr-2 h-5 w-5" />Nome Utente</FormLabel> <FormControl><Input placeholder="Es. Daniel" {...field} /></FormControl> <FormMessage /> </FormItem> )} />
                                    <FormField control={manualForm.control} name="password" render={({ field }) => ( <FormItem> <FormLabel className="flex items-center"><Lock className="mr-2 h-5 w-5" />Password</FormLabel> <FormControl><Input type="password" placeholder="••••••••" {...field} /></FormControl> <FormMessage /> </FormItem> )} />
                                </CardContent>
                                <CardFooter className="flex-col gap-4">
                                    <Button type="submit" className="w-full" disabled={authLoading}>
                                        {authLoading ? <Loader2 className="mr-2 h-5 w-5 animate-spin" /> : <LogIn className="mr-2 h-5 w-5" />}
                                        {authLoading ? "Verifica..." : "Accedi"}
                                    </Button>
                                    <Button variant="link" size="sm" onClick={() => setStep('initial')}>Torna all'accesso rapido</Button>
                                </CardFooter>
                            </form>
                        </Form>
                     </div>
                 );
            case 'logging_in':
                return (
                     <div className="flex flex-col items-center justify-center p-12 gap-4 aspect-video">
                        <Loader2 className="h-16 w-16 animate-spin text-primary" />
                        <p className="text-xl font-semibold">Accesso in corso...</p>
                    </div>
                );
        }
    };

    return (
        <>
            <Card className="w-full max-w-md shadow-xl border-border/50 bg-card overflow-hidden">
                {renderStep()}
            </Card>
        </>
    );
}

"use client";

import React, { useState, useRef, useCallback, useEffect, useMemo } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { useRouter } from 'next/navigation';
import { format } from 'date-fns';

import AuthGuard from '@/components/AuthGuard';
import AppShell from '@/components/layout/AppShell';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle, CardFooter } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Switch } from '@/components/ui/switch';
import { useToast } from "@/hooks/use-toast";
import { useAuth } from '@/components/auth/AuthProvider';
import { getRawMaterialByCode } from '@/app/scan-job/actions';
import { getPackagingItems, registerInventoryBatch } from './actions';
import type { RawMaterial, Packaging } from '@/types';
import { Warehouse, QrCode, Loader2, Camera, AlertTriangle, ArrowLeft, Weight, Archive, Send, Check } from 'lucide-react';
import { cn } from '@/lib/utils';
import { Alert, AlertTitle, AlertDescription } from '@/components/ui/alert';
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { useCameraStream } from '@/hooks/use-camera-stream';
import { formatDisplayStock } from '@/lib/utils';

const inventoryFormSchema = z.object({
  materialId: z.string().min(1),
  lotto: z.string().optional(),
  inputQuantity: z.coerce.number().positive("La quantità deve essere un numero positivo."),
  packagingId: z.string().optional(),
  operatorId: z.string(),
  operatorName: z.string(),
  inputUnit: z.enum(['n', 'mt', 'kg']),
});
type InventoryFormValues = z.infer<typeof inventoryFormSchema>;

type Step = 'scan_material' | 'form' | 'saving' | 'success';

export default function InventoryPage() {
  const { operator, loading: authLoading } = useAuth();
  const router = useRouter();
  const { toast } = useToast();

  const [step, setStep] = useState<Step>('scan_material');
  const [scannedMaterial, setScannedMaterial] = useState<RawMaterial | null>(null);
  const [packagingItems, setPackagingItems] = useState<Packaging[]>([]);
  const [isCapturing, setIsCapturing] = useState(false);
  const [isLottoScanOpen, setIsLottoScanOpen] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const { hasPermission: hasCameraPermission } = useCameraStream(step === 'scan_material' || isLottoScanOpen, videoRef);

  const form = useForm<InventoryFormValues>({
    resolver: zodResolver(inventoryFormSchema),
  });

  const selectedPackagingId = form.watch('packagingId');
  const enteredQuantity = form.watch('inputQuantity') || 0;
  const inputUnit = form.watch('inputUnit');

  const calculatedNetWeight = useMemo(() => {
    if (!scannedMaterial || !enteredQuantity) return 0;

    const selectedTara = packagingItems.find(p => p.id === selectedPackagingId)?.weightKg || 0;

    if (inputUnit === 'kg') {
      return (enteredQuantity || 0) - selectedTara;
    }

    const factor = (inputUnit === 'mt')
      ? (scannedMaterial.rapportoKgMt || scannedMaterial.conversionFactor || 0)
      : (scannedMaterial.conversionFactor || 0);

    return (enteredQuantity * factor);
  }, [scannedMaterial, enteredQuantity, inputUnit, packagingItems, selectedPackagingId]);

  useEffect(() => {
    if (!authLoading && operator && !operator.canAccessInventory && operator.role !== 'admin' && operator.role !== 'supervisor') {
      toast({
        variant: "destructive",
        title: "Accesso Negato",
        description: "Non hai i permessi per accedere alla pagina Inventario."
      });
      router.replace('/dashboard');
    }
  }, [operator, authLoading, router, toast]);

  useEffect(() => {
    getPackagingItems().then(setPackagingItems);
  }, []);

  const handleMaterialScanned = useCallback(async (code: string) => {
    setIsLottoScanOpen(false);
    const result = await getRawMaterialByCode(code.trim());
    if ('error' in result) {
      toast({ variant: 'destructive', title: result.title || "Errore", description: result.error });
      setStep('scan_material');
    } else {
      setScannedMaterial(result);
      if (operator) {
        form.reset({
          materialId: result.id,
          lotto: '',
          packagingId: 'none',
          operatorId: operator.id,
          operatorName: operator.nome,
          inputUnit: result.unitOfMeasure,
          inputQuantity: undefined,
        });
      }
      setStep('form');
    }
  }, [toast, form, operator]);

  const handleLottoScanned = useCallback((code: string) => {
    form.setValue('lotto', code.trim());
    setIsLottoScanOpen(false);
    toast({ title: "Lotto Scansionato", description: `Lotto "${code.trim()}" inserito.` });
  }, [form, toast]);

  const triggerScan = async (onScan: (code: string) => void) => {
    if (!videoRef.current || videoRef.current.paused || videoRef.current.readyState < 2) {
      toast({ variant: 'destructive', title: 'Fotocamera non pronta.' });
      return;
    }
    if (!('BarcodeDetector' in window)) {
      toast({ variant: 'destructive', title: 'Funzionalità non supportata.' });
      return;
    }

    setIsCapturing(true);
    try {
      const barcodeDetector = new (window as any).BarcodeDetector({ formats: ['qr_code', 'code_128', 'ean_13', 'code_39'] });
      const barcodes = await barcodeDetector.detect(videoRef.current);
      if (barcodes.length > 0) {
        onScan(barcodes[0].rawValue);
      } else {
        toast({ variant: 'destructive', title: 'Nessun codice trovato.' });
      }
    } catch (error) {
      toast({ variant: 'destructive', title: 'Errore durante la scansione.' });
    } finally {
      setIsCapturing(false);
    }
  };

  const onSubmit = async (values: InventoryFormValues) => {
    if (!operator || !scannedMaterial) {
      toast({ variant: "destructive", title: "Errore", description: "Dati operatore o materiale mancanti." });
      return;
    }

    setStep('saving');
    const formData = new FormData();
    Object.entries(values).forEach(([key, value]) => {
      if (value !== undefined) formData.append(key, String(value));
    });

    const result = await registerInventoryBatch(formData);

    toast({
      title: result.success ? "Inventario Registrato" : "Operazione Fallita",
      description: result.message,
      variant: result.success ? "default" : "destructive",
    });

    if (result.success) {
      setStep('success');
    } else {
      setStep('form');
    }
  };

  const resetFlow = () => {
    setScannedMaterial(null);
    form.reset();
    setStep('scan_material');
  };

  if (authLoading || !operator) {
    return <AppShell><div className="flex items-center justify-center h-full"><Loader2 className="h-12 w-12 animate-spin text-primary" /></div></AppShell>;
  }

  return (
    <AuthGuard>
      <AppShell>
        <div className="space-y-8 max-w-2xl mx-auto">
          <header className="space-y-2">
            <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
              <Warehouse className="h-8 w-8 text-primary" />
              Registrazione Inventario
            </h1>
            <p className="text-muted-foreground">
              Scansiona un materiale e registra il peso per aggiornare l'inventario.
            </p>
          </header>

          <Card>
            {step === 'scan_material' && (
              <>
                <CardHeader>
                  <CardTitle>1. Scansione Materia Prima</CardTitle>
                  <CardDescription>Inquadra il codice a barre o QR code del materiale da inventariare.</CardDescription>
                </CardHeader>
                <CardContent>
                  <div className="relative grid place-items-center aspect-video bg-black rounded-lg overflow-hidden">
                    <video ref={videoRef} className="w-full h-full object-cover" autoPlay muted playsInline />
                    {hasCameraPermission === false && (
                      <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center text-center p-4">
                        <Alert variant="destructive">
                          <AlertTriangle className="h-4 w-4" />
                          <AlertTitle>Accesso Fotocamera Negato</AlertTitle>
                          <AlertDescription>Controlla i permessi del browser per continuare.</AlertDescription>
                        </Alert>
                      </div>
                    )}
                    {hasCameraPermission && (
                      <div className="absolute inset-0 grid place-items-center pointer-events-none">
                        <div className="w-5/6 h-2/5 relative">
                          <div className="absolute top-0 left-0 w-8 h-8 border-t-4 border-l-4 border-primary rounded-tl-lg"></div>
                          <div className="absolute top-0 right-0 w-8 h-8 border-t-4 border-r-4 border-primary rounded-tr-lg"></div>
                          <div className="absolute bottom-0 left-0 w-8 h-8 border-b-4 border-l-4 border-primary rounded-bl-lg"></div>
                          <div className="absolute bottom-0 right-0 w-8 h-8 border-b-4 border-r-4 border-primary rounded-br-lg"></div>
                          <div className="absolute w-full top-1/2 -translate-y-1/2 h-0.5 bg-red-500/80 shadow-[0_0_4px_1px_#ef4444]"></div>
                        </div>
                      </div>
                    )}
                  </div>
                </CardContent>
                <CardFooter>
                  <Button onClick={() => triggerScan(handleMaterialScanned)} disabled={isCapturing || !hasCameraPermission} className="w-full h-12">
                    {isCapturing ? <Loader2 className="h-5 w-5 animate-spin" /> : <Camera className="h-5 w-5" />}
                    <span className="ml-2">{isCapturing ? 'Scansionando...' : 'Scansiona Materiale'}</span>
                  </Button>
                </CardFooter>
              </>
            )}

            {step === 'form' && scannedMaterial && (
              <Form {...form}>
                <form onSubmit={form.handleSubmit(onSubmit)}>
                  <CardHeader>
                    <CardTitle>2. Inserimento Dati</CardTitle>
                    <CardDescription>
                      Inserisci i dati per il materiale: <span className="font-bold text-primary">{scannedMaterial.code}</span>
                    </CardDescription>
                  </CardHeader>
                  <CardContent className="space-y-6">
                    <FormField
                      control={form.control}
                      name="lotto"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Numero Lotto (Opzionale)</FormLabel>
                          <div className="flex items-center gap-2">
                            <FormControl>
                              <Input placeholder="Scansiona o digita il lotto" {...field} />
                            </FormControl>
                            <Button type="button" variant="outline" size="icon" onClick={() => setIsLottoScanOpen(true)}>
                              <QrCode className="h-5 w-5" />
                            </Button>
                          </div>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={form.control}
                      name="inputUnit"
                      render={({ field }) => (
                        <FormItem>
                          <div className="flex items-center space-x-2 rounded-lg border p-3 justify-center">
                            <Label htmlFor="unit-switch">{scannedMaterial.unitOfMeasure.toUpperCase()}</Label>
                            <Switch
                              id="unit-switch"
                              checked={field.value === 'kg'}
                              onCheckedChange={(checked) => field.onChange(checked ? 'kg' : scannedMaterial.unitOfMeasure)}
                            />
                            <Label htmlFor="unit-switch">KG</Label>
                          </div>
                        </FormItem>
                      )}
                    />

                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                      <FormField control={form.control} name="inputQuantity" render={({ field }) => (
                        <FormItem>
                          <FormLabel className="flex items-center"><Weight className="mr-2 h-4 w-4" />
                            {inputUnit === 'kg' ? 'Quantità Lorda (KG)' : `Quantità Inserita (${scannedMaterial.unitOfMeasure.toUpperCase()})`}
                          </FormLabel>
                          <FormControl><Input type="number" step="any" placeholder="Es. 15.5" {...field} value={field.value ?? ''} /></FormControl>
                          <FormMessage />
                        </FormItem>
                      )} />
                      <FormField control={form.control} name="packagingId" render={({ field }) => (
                        <FormItem>
                          <FormLabel className="flex items-center"><Archive className="mr-2 h-4 w-4" />Tara (Imballo)</FormLabel>
                          <Select onValueChange={field.onChange} defaultValue={field.value}>
                            <FormControl><SelectTrigger><SelectValue placeholder="Nessuna" /></SelectTrigger></FormControl>
                            <SelectContent>
                              <SelectItem value="none">Nessuna Tara (0.00 kg)</SelectItem>
                              {packagingItems.map(item => (
                                <SelectItem key={item.id} value={item.id}>{item.name} ({item.weightKg.toFixed(3)} kg)</SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                          <FormMessage />
                        </FormItem>
                      )} />
                    </div>

                    <div className="p-4 rounded-lg border bg-muted">
                      <Label className="text-muted-foreground">Peso Netto Calcolato (KG)</Label>
                      <p className="text-2xl font-bold text-primary">{calculatedNetWeight >= 0 ? formatDisplayStock(calculatedNetWeight, 'kg') : '---'}</p>
                    </div>

                  </CardContent>
                  <CardFooter className="justify-between">
                    <Button type="button" variant="outline" onClick={resetFlow}><ArrowLeft className="mr-2 h-4 w-4" />Annulla</Button>
                    <Button type="submit" disabled={calculatedNetWeight < 0 || form.formState.isSubmitting}>
                      {form.formState.isSubmitting ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Send className="mr-2 h-4 w-4" />}
                      Salva Registrazione
                    </Button>
                  </CardFooter>
                </form>
              </Form>
            )}

            {step === 'saving' && (
              <CardContent className="flex flex-col items-center justify-center py-16 gap-4">
                <Loader2 className="h-16 w-16 animate-spin text-primary" />
                <p className="text-muted-foreground">Salvataggio in corso...</p>
              </CardContent>
            )}

            {step === 'success' && (
              <CardContent className="flex flex-col items-center justify-center py-16 gap-4">
                <div className="bg-green-100 p-4 rounded-full"><Check className="h-12 w-12 text-green-600" /></div>
                <CardTitle>Inventario Registrato</CardTitle>
                <CardDescription>La registrazione è stata inviata per l'approvazione.</CardDescription>
                <Button onClick={resetFlow} className="mt-4">Registra Altro</Button>
              </CardContent>
            )}
          </Card>
        </div>

        <Dialog open={isLottoScanOpen} onOpenChange={setIsLottoScanOpen}>
          <DialogContent>
            <DialogHeader><DialogTitle>Scansiona Codice Lotto</DialogTitle></DialogHeader>
            <div className="relative grid place-items-center aspect-video bg-black rounded-lg overflow-hidden my-4">
              <video ref={videoRef} className="w-full h-full object-cover" autoPlay muted playsInline />
              <div className="absolute inset-0 grid place-items-center pointer-events-none">
                <div className="w-5/6 h-2/5 relative">
                  <div className="absolute top-0 left-0 w-8 h-8 border-t-4 border-l-4 border-primary rounded-tl-lg"></div>
                  <div className="absolute top-0 right-0 w-8 h-8 border-t-4 border-r-4 border-primary rounded-tr-lg"></div>
                  <div className="absolute bottom-0 left-0 w-8 h-8 border-b-4 border-l-4 border-primary rounded-bl-lg"></div>
                  <div className="absolute bottom-0 right-0 w-8 h-8 border-b-4 border-r-4 border-primary rounded-br-lg"></div>
                  <div className="absolute w-full top-1/2 -translate-y-1/2 h-0.5 bg-red-500/80 shadow-[0_0_4px_1px_#ef4444]"></div>
                </div>
              </div>
            </div>
            <DialogFooter>
              <Button onClick={() => triggerScan(handleLottoScanned)} disabled={isCapturing || !hasCameraPermission} className="w-full">
                {isCapturing ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Camera className="mr-2 h-4 w-4" />}
                {isCapturing ? 'Scansionando...' : 'Scansiona Lotto'}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </AppShell>
    </AuthGuard>
  );
}

"use client";

import React, { useState, useRef, useCallback, useEffect, useMemo } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { useRouter } from 'next/navigation';

import AuthGuard from '@/components/AuthGuard';
import AppShell from '@/components/layout/AppShell';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';

import { Card, CardContent, CardDescription, CardHeader, CardTitle, CardFooter } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { useToast } from "@/hooks/use-toast";
import { useAuth } from '@/components/auth/AuthProvider';
import { logManualWithdrawal } from './actions';
import { useActiveMaterialSession } from '@/contexts/ActiveMaterialSessionProvider';
import { closeMaterialSessionAndUpdateStock, getRawMaterialByCode, findLastWeightForLotto } from '@/app/scan-job/actions';
import { getLotInfoForMaterial, type LotInfo } from '@/app/admin/raw-material-management/actions';
import type { RawMaterial, ActiveMaterialSessionData } from '@/types';

import { MinusSquare, QrCode, Loader2, Camera, AlertTriangle, ArrowLeft, Send, Barcode, Package, Search, Boxes, Info, PlayCircle, Weight, X, Lock } from 'lucide-react';


import { useCameraStream } from '@/hooks/use-camera-stream';
import { useBatchSelection } from '@/hooks/useBatchSelection';
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";

import { 
  Select, 
  SelectContent, 
  SelectItem, 
  SelectTrigger, 
  SelectValue 
} from "@/components/ui/select";
import { getGlobalSettings } from '@/lib/settings-actions';
import { Switch } from '@/components/ui/switch';
import { formatDisplayStock } from '@/lib/utils';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { ScrollArea } from '@/components/ui/scroll-area';
import { cn } from '@/lib/utils';

const withdrawalFormSchema = z.object({
  materialId: z.string().min(1, "ID Materiale mancante."),
  lotto: z.string().optional(),
  quantity: z.coerce.number().optional(),
  notes: z.string().optional(),
  jobOrderPFs: z.array(z.string()).default([]),
  packagingId: z.string().optional(),
});

type WithdrawalFormValues = z.infer<typeof withdrawalFormSchema>;

type ScanType = 'material' | 'lotto' | null;

export default function ManualWithdrawalPage() {
  const { operator, loading: authLoading } = useAuth();
  const router = useRouter();
  const { toast } = useToast();

  const [scannedMaterial, setScannedMaterial] = useState<RawMaterial | null>(null);
  const [allLots, setAllLots] = useState<LotInfo[]>([]);
  const [isCapturing, setIsCapturing] = useState(false);
  const [flash, setFlash] = useState(false);
  const [scanType, setScanType] = useState<ScanType>(null);
  const [jobScannerOpen, setJobScannerOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [inputUnit, setInputUnit] = useState<'primary' | 'kg'>('primary');
  const [useSession, setUseSession] = useState(false);


  const { activeSessions, startSession, closeSession, getSessionByMaterialId } = useActiveMaterialSession();


  const videoRef = useRef<HTMLVideoElement>(null);
  const { hasPermission } = useCameraStream(!!scanType, videoRef);

  const form = useForm<WithdrawalFormValues>({
    resolver: zodResolver(withdrawalFormSchema),
    defaultValues: {
      lotto: '',
      notes: '',
      jobOrderPFs: [],
      packagingId: 'none'
    }
  });

  const lottoValue = form.watch('lotto');
  const packagingIdValue = form.watch('packagingId');

  const {
      isLoading: isLoadingLots,
      lotAvailability,
      isFixedTare,
      calculatedNet,
      batchMetadata
  } = useBatchSelection({
      form,
      materialId: scannedMaterial?.id,
      quantityFieldName: 'quantity',
      packagingFieldName: 'packagingId'
  });


  useEffect(() => {
    if (!authLoading && operator && !operator.canAccessMaterialWithdrawal && operator.role !== 'admin' && operator.role !== 'supervisor') {
      toast({
        variant: "destructive",
        title: "Accesso Negato",
        description: "Non hai i permessi per accedere allo scarico manuale.",
      });
      router.replace('/dashboard');
    }
  }, [operator, authLoading, router, toast]);

  const handleScan = useCallback(async (code: string) => {
    setIsCapturing(true);
    if (scanType === 'material') {
      const result = await getRawMaterialByCode(code.trim());
      if ('error' in result) {
        toast({ variant: 'destructive', title: result.title, description: result.error });
      } else {
        setScannedMaterial(result);
        form.setValue('materialId', result.id);
        toast({ title: "Materiale Trovato", description: result.code });
      }
    } else if (scanType === 'lotto') {
        const lottoData = await findLastWeightForLotto(scannedMaterial?.id, code.trim());
        if (lottoData?.material) {
            setScannedMaterial(lottoData.material);
            form.setValue('materialId', lottoData.material.id);
            form.setValue('lotto', code.trim());
            toast({ title: "Lotto Riconosciuto", description: `Materiale: ${lottoData.material.code}, Lotto: ${code.trim()}` });
        } else {
            form.setValue('lotto', code.trim());
            toast({ title: 'Lotto Nuovo', description: 'Nessuno storico trovato per questo lotto.' });
        }
    }

    setScanType(null);
    setIsCapturing(false);
  }, [scanType, form, toast]);

  const handleJobScanManual = useCallback(async () => {
    if (!jobVideoRef.current || jobVideoRef.current.paused || jobVideoRef.current.readyState < 2) return;
    if (!('BarcodeDetector' in window)) return;

    setIsCapturing(true);
    try {
      const barcodeDetector = new (window as any).BarcodeDetector({ formats: ['qr_code', 'code_128', 'ean_13', 'code_39'] });
      const barcodes = await barcodeDetector.detect(jobVideoRef.current);
      if (barcodes.length > 0) {
        const rawCode = barcodes[0].rawValue.trim();
        const code = rawCode.includes('@') ? rawCode.split('@')[0].trim() : rawCode;
        
        if (code) {
            const currentJobs = form.getValues('jobOrderPFs') || [];
            if (!currentJobs.includes(code)) {
                form.setValue('jobOrderPFs', [...currentJobs, code]);
                setFlash(true);
                setTimeout(() => setFlash(false), 500);
                toast({ title: "Commessa Aggiunta", description: code });
            } else {
                toast({ variant: 'destructive', title: "Già in lista", description: code });
            }
        }
      } else {
        toast({ variant: 'destructive', title: "Nessun QR", description: "Inquadra meglio il codice." });
      }
    } catch (error) {
      console.error("Job scan error:", error);
    } finally {
      setIsCapturing(false);
    }
  }, [form, toast]);


  const triggerScan = async () => {
    if (!videoRef.current || videoRef.current.paused || videoRef.current.readyState < 2) {
      toast({ variant: 'destructive', title: 'Fotocamera non pronta.' });
      return;
    }
    if (!('BarcodeDetector' in window)) {
      toast({ variant: 'destructive', title: 'Funzionalità non supportata.' });
      return;
    }

    setIsCapturing(true);
    try {
      const barcodeDetector = new (window as any).BarcodeDetector({ formats: ['qr_code', 'code_128', 'ean_13', 'code_39'] });
      const barcodes = await barcodeDetector.detect(videoRef.current);
      if (barcodes.length > 0) {
        setFlash(true);
        setTimeout(() => setFlash(false), 500);
        await handleScan(barcodes[0].rawValue);
      } else {
        toast({ variant: 'destructive', title: 'Nessun codice trovato.' });
      }
    } catch (error) {
      toast({ variant: 'destructive', title: 'Errore durante la scansione.' });
    } finally {
      setIsCapturing(false);
    }
  };

  const onSubmit = async (values: WithdrawalFormValues, isFinished: boolean = false) => {
    if (!operator || !scannedMaterial) return;
    setIsSubmitting(true);

    if (useSession) {
      const initialGross = values.quantity || 0;
      const initialTare = packagingItems.find(p => p.id === packagingIdValue)?.weightKg || 0;
      const initialNet = Math.max(0, initialGross - initialTare);

      // START INDEPENDENT SESSION
      const sessionResult = await startSession({
        materialId: scannedMaterial.id,
        materialCode: scannedMaterial.code,
        lotto: values.lotto || null,
        linkedJobOrderIds: values.jobOrderPFs || [],
        grossOpeningWeight: initialGross,
        netOpeningWeight: initialNet,
        packagingId: packagingIdValue,
        tareWeight: initialTare
      }, scannedMaterial.type);

      if (sessionResult.success) {
        toast({ title: "Sessione Indipendente Avviata", description: "La bobina è ora attiva. Monitorala dalla barra superiore (3 Cubi)." });
        resetFlow();
      } else {
        toast({ variant: 'destructive', title: 'Errore', description: sessionResult.message });
      }
      setIsSubmitting(false);
      return;
    }

    let finalQty = values.quantity || 0;
    let finalUnit = scannedMaterial.unitOfMeasure;

    if (isKgMode && lotAvailability) {
      // In SCALE mode, effectiveNet is what is LEFT on the scale.
      // The withdrawal is the DIFFERENCE.
      const currentAvail = lotAvailability.available;
      const remaining = effectiveNet;
      const consumed = Math.max(0, currentAvail - remaining);
      
      finalQty = consumed;
      finalUnit = scannedMaterial.unitOfMeasure; // USE BASE UOM (n, mt), NOT kg
      
      if (consumed <= 0.001 && !isFinished) {
          toast({ 
              variant: 'destructive', 
              title: "Nessun prelievo rilevato", 
              description: "Il peso sulla bilancia indica che non è stato prelevato materiale (o il peso è superiore alla giacenza)." 
          });
          setIsSubmitting(false);
          return;
      }
    }

    const result = await logManualWithdrawal({
      ...values,
      quantity: finalQty,
      operatorId: operator.id,
      operatorName: operator.nome,
      unit: finalUnit as any,
      isFinished: isFinished
    });

    toast({
      title: result.success ? (isFinished ? "Materiale Finito" : "Scarico Registrato") : "Errore",
      description: result.message,
      variant: result.success ? "default" : "destructive",
    });

    if (result.success) {
      resetFlow();
    }
    setIsSubmitting(false);
  };

  const resetFlow = () => {
    setScannedMaterial(null);
    setAllLots([]);
    form.reset({
      lotto: '',
      notes: '',
      jobOrderPFs: [],
      quantity: undefined,
      packagingId: 'none'
    });
  };


  const [packagingItems, setPackagingItems] = useState<any[]>([]);

  useEffect(() => {
     if (scannedMaterial) {
        getLotInfoForMaterial(scannedMaterial.id).then(setAllLots);
     }
  }, [scannedMaterial]);


  useEffect(() => {
    import('../inventory/actions').then(m => m.getPackagingItems().then(setPackagingItems));
  }, []);

  const renderScanView = () => (
    <DialogContent className="max-w-md p-0 overflow-hidden border-2 border-primary/20 bg-slate-900 text-white">
      <DialogHeader className="p-6 pb-2 border-b border-slate-800 bg-slate-950/50">
        <DialogTitle className="text-lg font-black uppercase tracking-tight text-white flex items-center gap-2">
            <Camera className="h-5 w-5 text-primary" /> Scansione {scanType === 'material' ? 'Materiale' : 'Lotto'}
        </DialogTitle>
        <DialogDescription className="text-[10px] font-bold uppercase text-slate-500">Inquadra e premi SPARA</DialogDescription>
      </DialogHeader>
      <div className="p-6 pt-0">
        <div className="relative aspect-video bg-black rounded-2xl overflow-hidden my-4 border-4 border-slate-700 shadow-inner group">
            <video ref={videoRef} className="w-full h-full object-cover" autoPlay muted playsInline />
            
            {/* Flash Effect */}
            <div className={cn(
                "absolute inset-0 bg-green-500/40 transition-opacity duration-300 pointer-events-none",
                flash ? "opacity-100" : "opacity-0"
            )} />

            {!hasPermission && (
                <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center text-center p-4">
                    <AlertTriangle className="h-12 w-12 text-destructive mb-4" />
                    <p className="text-white font-semibold">Accesso Fotocamera Negato</p>
                </div>
            )}

            {/* SPARA BUTTON Overlay */}
            <div className="absolute inset-x-0 bottom-4 flex justify-center">
                <Button 
                    onClick={triggerScan}
                    disabled={isCapturing || !hasPermission}
                    className="h-16 w-16 rounded-full bg-white/20 hover:bg-white/40 border-4 border-white shadow-2xl transition-all active:scale-90"
                >
                    <div className="h-10 w-10 rounded-full bg-red-600 group-hover:bg-red-500 shadow-inner" />
                </Button>
            </div>
            <div className="absolute bottom-2 w-full text-center">
                <span className="text-[10px] font-black uppercase text-white shadow-black drop-shadow-md">Tasto SPARA</span>
            </div>
        </div>
        <div className="flex flex-col gap-2">
             <Button variant="outline" onClick={() => setScanType(null)} className="w-full h-12 border-slate-700 text-slate-300 uppercase font-black text-xs tracking-widest">Annulla</Button>
        </div>
      </div>
    </DialogContent>
  );
  
  const jobVideoRef = useRef<HTMLVideoElement>(null);
  const { hasPermission: hasJobPermission } = useCameraStream(jobScannerOpen, jobVideoRef);


  const renderJobScannerView = () => (
    <DialogContent className="max-w-md p-0 overflow-hidden border-2 border-primary/20 shadow-2xl bg-slate-900 text-white">
      <DialogHeader className="p-6 pb-2 border-b border-slate-800 bg-slate-950/50">
        <DialogTitle className="text-lg font-black uppercase tracking-tight flex items-center gap-2 text-white">
            <Camera className="h-5 w-5 text-primary" /> Scanner Commesse
        </DialogTitle>
        <DialogDescription className="text-[10px] font-bold uppercase text-slate-500 italic">Inquadra e premi SPARA (Scansione Multipla)</DialogDescription>
      </DialogHeader>
      <div className="p-6 pt-0 space-y-4">
        <div className="relative aspect-video bg-black rounded-2xl overflow-hidden my-4 border-4 border-slate-700 shadow-inner group">
            <video ref={jobVideoRef} className="w-full h-full object-cover" autoPlay muted playsInline />
            
            {/* Flash Effect */}
            <div className={cn(
                "absolute inset-0 bg-green-500/40 transition-opacity duration-300 pointer-events-none",
                flash ? "opacity-100" : "opacity-0"
            )} />

            {!hasJobPermission && (
                <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center text-center p-4">
                    <AlertTriangle className="h-12 w-12 text-destructive mb-4" />
                    <p className="text-white font-semibold">Accesso Fotocamera Negato</p>
                </div>
            )}

            {/* SPARA BUTTON Overlay */}
            <div className="absolute inset-x-0 bottom-4 flex justify-center">
                <Button 
                    onClick={handleJobScanManual}
                    disabled={isCapturing || !hasJobPermission}
                    className="h-16 w-16 rounded-full bg-white/20 hover:bg-white/40 border-4 border-white shadow-2xl transition-all active:scale-90"
                >
                    <div className="h-10 w-10 rounded-full bg-red-600 group-hover:bg-red-500 shadow-inner" />
                </Button>
            </div>
            <div className="absolute bottom-2 w-full text-center">
                <span className="text-[10px] font-black uppercase text-white shadow-black drop-shadow-md">Tasto SPARA</span>
            </div>
        </div>

        <div className="space-y-4">
            <div className="bg-slate-950/50 p-4 rounded-xl space-y-2 border border-slate-800">
                <div className="flex items-center justify-between text-[10px] font-black uppercase text-slate-500">
                    <span>Sala d'attesa</span>
                    <Badge variant="outline" className="h-4 px-1 text-[8px] bg-primary/10 border-primary/20 text-primary">{(form.watch('jobOrderPFs') || []).length}</Badge>
                </div>
                <ScrollArea className="h-24 pr-2">
                    <div className="flex flex-wrap gap-1.5">
                        {(form.watch('jobOrderPFs') || []).map((pf, i) => (
                            <Badge key={pf+i} variant="secondary" className="bg-slate-800 border-slate-700 font-mono font-bold text-[9px] h-6 text-slate-100 flex items-center gap-1 group">
                                {pf}
                                <button
                                    onClick={(e) => {
                                        e.preventDefault();
                                        const current = form.getValues('jobOrderPFs');
                                        form.setValue('jobOrderPFs', current.filter((_, idx) => idx !== i));
                                    }}
                                    className="hover:text-destructive transition-colors"
                                >
                                    <X className="h-3 w-3" />
                                </button>
                            </Badge>
                        ))}
                        {(form.watch('jobOrderPFs') || []).length === 0 && (
                            <div className="w-full flex flex-col items-center justify-center py-4 opacity-20">
                                <Boxes className="h-6 w-6 mb-1" />
                                <span className="text-[9px] uppercase font-black mt-1 tracking-widest">Nessun Codice</span>
                            </div>
                        )}
                    </div>
                </ScrollArea>
            </div>
            <Button onClick={() => setJobScannerOpen(false)} className="w-full h-14 text-lg font-black uppercase tracking-tight rounded-2xl shadow-xl shadow-primary/20 transition-all active:scale-95">
                Concludi ed Esci
            </Button>
        </div>
      </div>
    </DialogContent>
  );

  const isKgMode = scannedMaterial?.unitOfMeasure === 'kg' || inputUnit === 'kg';
  const selectedPackaging = packagingItems.find(p => p.id === packagingIdValue);
  const tareWeight = selectedPackaging?.weightKg || 0;
  // Use calculated net from hook
  const effectiveNet = calculatedNet > 0 ? calculatedNet : (lotAvailability?.available || 0);
  const expectedGross = effectiveNet + tareWeight;



  if (authLoading || !operator) {
    return <AppShell><div className="flex items-center justify-center h-full"><Loader2 className="h-12 w-12 animate-spin text-primary" /></div></AppShell>;
  }

  return (
    <AuthGuard>
      <AppShell>
        <div className="space-y-6 max-w-3xl mx-auto pb-20">
          <header className="space-y-2 text-center sm:text-left">
            <div className="inline-flex items-center justify-center sm:justify-start gap-3">
                <div className="p-3 bg-primary/10 rounded-2xl border-2 border-primary/20">
                    <MinusSquare className="h-6 w-6 text-primary" />
                </div>
                <div>
                    <h1 className="text-2xl font-black font-headline tracking-tighter uppercase leading-none">
                      Scarico Manuale
                    </h1>
                    <p className="text-xs text-muted-foreground font-bold uppercase tracking-widest mt-1">
                      Gestione prelievi liberi o campionature
                    </p>
                </div>
            </div>
          </header>

          <Form {...form}>
            <form id="withdrawal-form" onSubmit={form.handleSubmit((v) => onSubmit(v, false))} className="space-y-6">
              <Card className="border-2 shadow-xl overflow-hidden rounded-3xl">
                <CardContent className="p-0">
                  {scannedMaterial ? (
                    <div className="animate-in fade-in zoom-in-95 duration-300">
                      <div className="p-6 bg-muted/30 border-b space-y-4">
                        <div className="text-center space-y-1">
                          <p className="font-black text-2xl tracking-tighter leading-none">{scannedMaterial.code}</p>
                          <p className="text-[10px] text-muted-foreground uppercase font-black tracking-[0.2em]">{scannedMaterial.description}</p>
                        </div>

                        <div className="grid grid-cols-1 xs:grid-cols-2 gap-3">
                          <div className="p-3 rounded-2xl bg-background border-2 border-primary/5 flex flex-col items-center justify-center text-center shadow-sm">
                            <Label className="text-[8px] uppercase font-black text-muted-foreground mb-1">Totale Magazzino</Label>
                            <p className="text-lg font-black text-primary leading-tight">
                              {formatDisplayStock(scannedMaterial.currentStockUnits, scannedMaterial.unitOfMeasure)} <span className="text-[10px] opacity-70">{scannedMaterial.unitOfMeasure.toUpperCase()}</span>
                            </p>
                            <p className="text-[9px] font-bold text-muted-foreground mt-1">
                              ({formatDisplayStock(scannedMaterial.currentWeightKg, 'kg')} KG)
                            </p>
                          </div>

                          <div className={cn(
                            "p-3 rounded-2xl border-2 flex flex-col items-center justify-center text-center transition-all shadow-sm",
                            lotAvailability ? "bg-primary border-primary text-primary-foreground shadow-primary/20" : "bg-muted/50 border-dashed border-muted-foreground/30 opacity-70"
                          )}>
                            <Label className={cn("text-[8px] uppercase font-black mb-1", lotAvailability ? "text-primary-foreground/70" : "text-muted-foreground")}>In Uso (LOTTO)</Label>
                            {lotAvailability ? (
                              <>
                                <p className="text-lg font-black leading-tight">
                                  {formatDisplayStock(lotAvailability.available, scannedMaterial.unitOfMeasure)} <span className="text-[10px] opacity-70">{scannedMaterial.unitOfMeasure.toUpperCase()}</span>
                                </p>
                                <p className="text-[9px] font-mono font-bold tracking-tight">{lotAvailability.lotto}</p>
                              </>
                            ) : (
                              <p className="text-[11px] font-black uppercase text-muted-foreground italic">Seleziona Lotto</p>
                            )}
                          </div>
                        </div>

                        {/* Transparency Panel */}
                        {isKgMode && lotAvailability && (
                            <div className="p-4 bg-orange-500/10 border-2 border-orange-500/20 rounded-2xl space-y-3 animate-in slide-in-from-top-4">
                                <div className="flex justify-between items-center text-[10px] uppercase font-black text-orange-800/80">
                                    <span className="flex items-center gap-2"><Info className="h-3 w-3" /> Trasparenza Bilancia</span>
                                    <span>3 Decimali</span>
                                </div>
                                <div className="grid grid-cols-1 xs:grid-cols-3 gap-3 text-center">
                                    <div className="space-y-1">
                                        <p className="text-[9px] font-bold text-muted-foreground uppercase leading-none">Netto Ricalcolato</p>
                                        <p className="text-md font-black">{effectiveNet.toFixed(3)}</p>
                                    </div>
                                    <div className="space-y-1">
                                        <p className="text-[9px] font-bold text-muted-foreground uppercase leading-none">Tara ({packagingIdValue === 'none' ? '0' : 'Attiva'})</p>
                                        <p className={cn("text-md font-black", isFixedTare ? "text-primary" : "text-orange-600")}>
                                            {isFixedTare && <Lock className="inline-block h-3 w-3 mr-1 mb-1" />}
                                            +{tareWeight.toFixed(3)}
                                        </p>
                                    </div>
                                    <div className="bg-orange-500/10 rounded-xl py-2 space-y-1 border border-orange-500/20">
                                        <p className="text-[9px] font-bold text-orange-800 uppercase leading-none">Lordo (Input)</p>
                                        <p className="text-md font-black text-orange-800">{(Number(form.watch('quantity')) || 0).toFixed(3)}</p>
                                    </div>
                                </div>

                            </div>
                        )}
                      </div>

                      <div className="p-6 space-y-6">
                        <div className="space-y-3">
                          <div className="flex items-center justify-between px-1">
                            <h4 className="font-black text-[10px] uppercase tracking-widest text-muted-foreground flex items-center gap-2">
                                <Boxes className="h-3 w-3" /> Lotti Disponibili (FIFO)
                            </h4>
                            {isLoadingLots && <Loader2 className="h-3 w-3 animate-spin text-primary" />}
                          </div>
                          <ScrollArea className="h-36 border-2 rounded-2xl bg-muted/20 border-muted p-1">
                              <div className="grid grid-cols-1 gap-1">
                                  {allLots.length > 0 ? allLots.map(lot => (
                                      <Button 
                                        key={lot.lotto}
                                        type="button"
                                        variant={lot.lotto === lottoValue ? "default" : "ghost"}
                                        className={cn(
                                            "justify-between h-10 px-4 rounded-xl border-transparent",
                                            lot.lotto === lottoValue && "border-primary shadow-md"
                                        )}
                                        onClick={() => {
                                          form.setValue('lotto', lot.lotto);
                                        }}

                                      >
                                          <div className="flex items-center gap-2">
                                              <Barcode className="h-4 w-4 opacity-50" />
                                              <span className="font-mono font-bold text-xs">{lot.lotto}</span>
                                          </div>
                                          <div className="text-xs font-black">
                                              {formatDisplayStock(lot.available, scannedMaterial.unitOfMeasure)}
                                          </div>
                                      </Button>
                                  )) : !isLoadingLots && (
                                      <div className="flex flex-col items-center justify-center h-24 text-center">
                                          <Package className="h-8 w-8 text-muted-foreground/30 mb-2" />
                                          <p className="text-[10px] text-muted-foreground font-bold uppercase">Nessun lotto attivo</p>
                                      </div>
                                  )}
                              </div>
                          </ScrollArea>
                        </div>

                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                            <FormField
                              control={form.control}
                              name="lotto"
                              render={({ field }) => (
                                <FormItem className="space-y-1">
                                  <FormLabel className="font-black text-[10px] uppercase text-muted-foreground ml-1">Codice Lotto</FormLabel>
                                  <FormControl>
                                      <div className="relative">
                                          <Barcode className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                                          <Input placeholder="Scansiona o digita..." {...field} value={field.value ?? ''} className="font-mono font-black pl-10 h-11 rounded-xl bg-muted/10 border-2" />
                                      </div>
                                  </FormControl>
                                  <FormMessage />
                                </FormItem>
                              )}
                            />

                            <FormField
                                control={form.control}
                                name="packagingId"
                                render={({ field }) => (
                                    <FormItem className="space-y-1">
                                        <FormLabel className="font-black text-[10px] uppercase text-muted-foreground ml-1 flex items-center justify-between">
                                            <span>Tara Imballo / Bobina</span>
                                            {isFixedTare && <Badge variant="outline" className="text-[7px] h-3 px-1 border-primary text-primary font-black"><Lock className="h-2 w-2 mr-0.5" /> CERTIFICATA</Badge>}
                                        </FormLabel>
                                        <Select onValueChange={(val) => field.onChange(val || 'none')} value={field.value || 'none'} disabled={isFixedTare}>
                                            <FormControl>
                                                <SelectTrigger className={cn("h-11 rounded-xl bg-muted/10 border-2 font-bold text-xs", isFixedTare && "bg-primary/5 border-primary/20")}>
                                                    <SelectValue placeholder="Seleziona..." />
                                                </SelectTrigger>
                                            </FormControl>
                                            <SelectContent>
                                                <SelectItem value="none" className="text-xs font-bold">Nessuna Tara (0.00 kg)</SelectItem>
                                                {packagingItems.filter(p => !scannedMaterial || (p.associatedTypes && p.associatedTypes.includes(scannedMaterial.type))).map(item => (
                                                    <SelectItem key={item.id} value={item.id} className="text-xs font-bold">{item.name} ({item.weightKg.toFixed(3)} kg)</SelectItem>
                                                ))}
                                            </SelectContent>
                                        </Select>
                                    </FormItem>
                                )}
                            />

                        </div>

                        <div className="space-y-4 pt-2">
                             <div className="flex items-center justify-between p-4 border-2 rounded-2xl bg-primary/5 border-primary/10">
                                <div className="space-y-0.5">
                                    <Label className="text-sm font-black uppercase tracking-tight">Modalità Sessione</Label>
                                    <p className="text-[10px] text-muted-foreground font-bold uppercase">Apri una sessione per pesate multiple</p>
                                </div>
                                <Switch
                                    checked={useSession}
                                    onCheckedChange={setUseSession}
                                    className="data-[state=checked]:bg-primary"
                                />
                            </div>

                            {scannedMaterial.unitOfMeasure !== 'kg' && (
                                <div className="flex items-center space-x-4 rounded-2xl border-2 p-2 justify-center bg-muted/10 border-muted">
                                    <Label htmlFor="unit-switch" className="text-[10px] font-black uppercase">{scannedMaterial.unitOfMeasure}</Label>
                                    <Switch
                                        id="unit-switch"
                                        checked={inputUnit === 'kg'}
                                        onCheckedChange={(checked) => setInputUnit(checked ? 'kg' : 'primary')}
                                    />
                                    <Label htmlFor="unit-switch" className="text-[10px] font-black uppercase text-orange-600">KG (Bilancia)</Label>
                                </div>
                            )}

                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                <FormField
                                  control={form.control}
                                  name="jobOrderPFs"
                                  render={({ field }) => (
                                    <FormItem className="space-y-1">
                                      <FormLabel className="font-black text-[10px] uppercase text-muted-foreground ml-1 flex justify-between items-center">
                                          <span>Commesse Collegate ({field.value?.length || 0})</span>
                                          <Button 
                                            type="button" 
                                            variant="outline" 
                                            size="sm" 
                                            className="h-7 text-[9px] font-black uppercase px-2 border-primary/30 text-primary"
                                            onClick={() => setJobScannerOpen(true)}
                                          >
                                              <Camera className="mr-1 h-3 w-3" /> Scanner QR
                                          </Button>
                                      </FormLabel>
                                      <FormControl>
                                          <div className="space-y-2">
                                              <div className="flex flex-wrap gap-1.5 p-3 rounded-xl bg-muted/10 border-2 border-dashed border-muted min-h-[44px]">
                                                  {field.value?.map((pf, idx) => (
                                                      <Badge key={idx} variant="secondary" className="pl-2 pr-1 h-7 font-mono font-bold text-[10px] flex items-center gap-1 group">
                                                          {pf}
                                                          <button 
                                                            type="button"
                                                            onClick={() => field.onChange(field.value.filter((_, i) => i !== idx))}
                                                            className="hover:bg-destructive/20 p-0.5 rounded-full transition-colors"
                                                          >
                                                              <X className="h-3 w-3" />
                                                          </button>
                                                      </Badge>
                                                  ))}
                                                  {(!field.value || field.value.length === 0) && (
                                                      <span className="text-[10px] text-muted-foreground font-bold italic opacity-50 flex items-center gap-2">
                                                          <Package className="h-3 w-3" /> Nessuna commessa...
                                                      </span>
                                                  )}
                                              </div>
                                              <div className="relative">
                                                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                                                  <Input 
                                                    placeholder="Aggiungi manualmente..." 
                                                    className="pl-10 h-10 rounded-xl bg-muted/5 border-2 text-xs" 
                                                    onKeyDown={(e) => {
                                                        if (e.key === 'Enter') {
                                                            e.preventDefault();
                                                            const rawVal = e.currentTarget.value.trim();
                                                            const val = rawVal.includes('@') ? rawVal.split('@')[0].trim() : rawVal;
                                                            
                                                            if (val && !field.value.includes(val)) {
                                                                field.onChange([...field.value, val]);
                                                                e.currentTarget.value = '';
                                                            }
                                                        }
                                                    }}
                                                  />
                                              </div>
                                          </div>
                                      </FormControl>
                                    </FormItem>
                                  )}
                                />

                                <FormField
                                  control={form.control}
                                  name="quantity"
                                  render={({ field }) => (
                                    <FormItem className="space-y-1">
                                      <FormLabel className="text-primary font-black uppercase text-[10px] ml-1">
                                        {isKgMode ? 'PESO LORDO (Sulla Bilancia)' : `QUANTITÀ NETTA (${scannedMaterial.unitOfMeasure.toUpperCase()})`}
                                      </FormLabel>
                                      <FormControl>
                                          <div className="relative">
                                              <Weight className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-muted-foreground" />
                                              <Input 
                                                type="number" 
                                                step="0.001" 
                                                {...field} 
                                                value={field.value ?? ''} 
                                                className="pl-10 h-14 text-2xl font-black font-mono border-2 border-primary/30 rounded-2xl focus:border-primary transition-all shadow-sm" 
                                              />
                                          </div>
                                      </FormControl>
                                      {isKgMode && (
                                          <p className="text-[9px] text-muted-foreground italic font-black uppercase text-right">
                                              L'app considererà una tara di {tareWeight.toFixed(3)}kg
                                          </p>
                                      )}
                                      <FormMessage />
                                    </FormItem>
                                  )}
                                />
                            </div>

                            <FormField
                              control={form.control}
                              name="notes"
                              render={({ field }) => (
                                <FormItem className="space-y-1">
                                  <FormLabel className="font-black text-[10px] uppercase text-muted-foreground ml-1">Note / Causale</FormLabel>
                                  <FormControl><Input placeholder="Es. Sgrido finale o campionatura..." {...field} value={field.value ?? ''} className="h-11 rounded-xl bg-muted/10 border-2" /></FormControl>
                                </FormItem>
                              )}
                            />
                        </div>
                      </div>
                    </div>
                  ) : (
                    <div className="p-12 text-center space-y-6">
                      <div className="mx-auto w-24 h-24 bg-muted/30 rounded-3xl border-2 border-dashed border-muted-foreground/30 flex items-center justify-center animate-pulse">
                          <QrCode className="h-10 w-10 text-muted-foreground" />
                      </div>
                      <div className="space-y-2">
                          <h3 className="text-xl font-black uppercase tracking-tight">Inizia la procedura</h3>
                          <p className="text-sm text-muted-foreground font-bold uppercase tracking-widest max-w-[280px] mx-auto">
                            Scansiona il materiale o inserisci il lotto per sbloccare la registrazione.
                          </p>
                      </div>
                      <div className="flex flex-col gap-3 max-w-sm mx-auto w-full">
                        <Button type="button" onClick={() => setScanType('material')} className="h-16 rounded-2xl shadow-lg hover:shadow-primary/20 transition-all font-black uppercase text-xs tracking-widest w-full">
                          <QrCode className="mr-2 h-6 w-6" /> Scansiona Materiale
                        </Button>
                        <Button type="button" onClick={() => setScanType('lotto')} className="h-16 rounded-2xl shadow-lg border-2 font-black uppercase text-xs tracking-widest w-full" variant="secondary">
                          <Barcode className="mr-2 h-6 w-6" /> Inserisci Lotto
                        </Button>
                      </div>
                    </div>
                  )}
                </CardContent>
                
                {scannedMaterial && (
                    <CardFooter className="p-6 bg-muted/10 border-t flex flex-col gap-3">
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 w-full">
                            <Button 
                                type="submit" 
                                disabled={isSubmitting} 
                                className="w-full h-16 text-xl font-black uppercase tracking-tighter rounded-2xl shadow-xl shadow-primary/20"
                            >
                                {isSubmitting ? <Loader2 className="mr-2 h-6 w-6 animate-spin" /> : (useSession ? <PlayCircle className="mr-2 h-6 w-6" /> : <Send className="mr-2 h-6 w-6" />)}
                                {useSession ? 'Avvia Sessione' : 'Registra Scarico'}
                            </Button>
                            
                            {!useSession && lotAvailability && (
                                <Button 
                                    type="button" 
                                    variant="outline"
                                    onClick={() => onSubmit(form.getValues(), true)}
                                    disabled={isSubmitting}
                                    className="w-full h-16 text-xl font-black uppercase tracking-tighter rounded-2xl border-2 border-red-600 bg-red-600/10 text-red-500 hover:bg-red-600 hover:text-white transition-all shadow-[0_0_15px_rgba(220,38,38,0.2)]"
                                >
                                    <X className="mr-2 h-6 w-6" /> Materiale Finito
                                </Button>
                            )}
                        </div>
                        <Button type="button" variant="ghost" onClick={resetFlow} className="text-muted-foreground uppercase font-black text-xs h-10 w-full rounded-xl">
                            Annulla tutto
                        </Button>
                    </CardFooter>
                )}
              </Card>
            </form>
          </Form>

          {activeSessions.length > 0 && (
              <div className="space-y-6 pt-10">
                  <h3 className="font-black text-xl uppercase tracking-tighter flex items-center gap-3">
                    <Info className="h-6 w-6 text-primary" /> Sessioni Attive (Officina & Magazzino)
                  </h3>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                      {activeSessions.map((s, idx) => (
                          <Card key={idx} className="border-2 border-primary/20 bg-primary/5 rounded-3xl overflow-hidden group shadow-md hover:shadow-lg transition-all">
                              <CardHeader className="py-4 bg-muted/20 border-b">
                                  <div className="flex justify-between items-start">
                                      <div>
                                          <CardTitle className="text-xl font-black tracking-tighter leading-none">{s.materialCode}</CardTitle>
                                          <CardDescription className="text-[9px] font-black uppercase text-muted-foreground tracking-widest mt-1">Lotto: {s.lotto || 'N/D'}</CardDescription>
                                      </div>
                                      <Badge variant="outline" className="bg-primary/10 border-primary/30 text-primary font-black text-[10px]">ATTIVA</Badge>
                                  </div>
                              </CardHeader>
                              <CardContent className="py-4 space-y-2">
                                  <div className="flex justify-between text-xs font-bold uppercase border-b pb-2">
                                      <span className="text-muted-foreground">Peso Apertura</span>
                                      <span className="text-primary">{formatDisplayStock(s.netOpeningWeight, 'kg')} KG</span>
                                  </div>
                                  {s.linkedJobOrderPFs && s.linkedJobOrderPFs.length > 0 && (
                                    <div className="space-y-1">
                                        <p className="text-[9px] font-black uppercase text-muted-foreground">Commesse Collegate:</p>
                                        <div className="flex flex-wrap gap-1">
                                            {s.linkedJobOrderPFs.map(pf => (
                                                <Badge key={pf} variant="secondary" className="text-[8px] px-1.5 h-4">{pf}</Badge>
                                            ))}
                                        </div>
                                    </div>
                                  )}
                              </CardContent>
                              <CardFooter className="py-4 border-t bg-background">
                                  <Button 
                                    variant="destructive" 
                                    size="lg" 
                                    className="w-full font-black uppercase tracking-tight rounded-xl h-12"
                                    onClick={() => {
                                        const event = new CustomEvent('close-material-session', { detail: s });
                                        window.dispatchEvent(event);
                                        toast({ title: "Chiusura in corso", description: "Completa i dati nella barra superiore." });
                                    }}
                                  >
                                      <Package className="mr-2 h-4 w-4" /> Chiudi Sessione
                                  </Button>
                              </CardFooter>
                          </Card>
                      ))}
                  </div>
              </div>
          )}
        </div>

        <Dialog open={!!scanType} onOpenChange={(open) => !open && setScanType(null)}>
          {renderScanView()}
        </Dialog>

        <Dialog open={jobScannerOpen} onOpenChange={setJobScannerOpen}>
          {renderJobScannerView()}
        </Dialog>

      </AppShell>
    </AuthGuard>
  );
}

"use client";

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { format, parseISO } from 'date-fns';
import { it } from 'date-fns/locale';

import AuthGuard from '@/components/AuthGuard';
import AppShell from '@/components/layout/AppShell';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle, CardFooter } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle, DialogClose } from '@/components/ui/dialog';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge as UiBadge } from '@/components/ui/badge';
import { ScrollArea } from '@/components/ui/scroll-area';
import { useToast } from "@/hooks/use-toast";
import { useAuth } from '@/components/auth/AuthProvider';
import { useMasterData } from '@/contexts/MasterDataProvider';

import { getRawMaterialByCode, findLastWeightForLotto } from '@/app/scan-job/actions';
import { getMaterialWithdrawalsForMaterial, getLotInfoForMaterial, type LotInfo } from '@/app/admin/raw-material-management/actions';
import type { RawMaterial } from '@/types';
import { db } from '@/lib/firebase';
import { collection, getDocs } from 'firebase/firestore';
import { QrCode, AlertTriangle, SearchCheck, Send, Loader2, Keyboard, History, ArrowUpCircle, ArrowDownCircle, Camera, Barcode, Package, Info, Boxes } from 'lucide-react';
import { cn } from '@/lib/utils';
import { formatDisplayStock } from '@/lib/utils';
import { Separator } from '@/components/ui/separator';

type Movement = {
  type: 'Carico' | 'Scarico';
  date: string;
  description: string;
  quantity: number;
  unit: string;
  id: string;
};

type Step = 'initial' | 'scanning_material' | 'scanning_lotto' | 'manual_input' | 'result';

export default function MaterialCheckPage() {
    const { operator, loading: authLoading } = useAuth();
    const router = useRouter();
    const { toast } = useToast();

    const { rawMaterialsMap, isLoading: isMasterLoading } = useMasterData();

    const [step, setStep] = useState<Step>('initial');
    const [foundMaterial, setFoundMaterial] = useState<RawMaterial | null>(null);
    const [foundLotInfo, setFoundLotInfo] = useState<LotInfo | null>(null);
    const [allLots, setAllLots] = useState<LotInfo[]>([]);
    const [manualCode, setManualCode] = useState('');
    const [isSearching, setIsSearching] = useState(false);
    const [isCapturing, setIsCapturing] = useState(false);
    
    const [isHistoryDialogOpen, setIsHistoryDialogOpen] = useState(false);
    const [materialMovements, setMaterialMovements] = useState<Movement[]>([]);

    const videoRef = useRef<HTMLVideoElement>(null);
    const streamRef = useRef<MediaStream | null>(null);
    const [hasCameraPermission, setHasCameraPermission] = useState(true);

    useEffect(() => {
        if (!authLoading && operator) {
            const allowedAccessReparti = ['MAG', 'Collaudo'];
            const hasAccess = operator.role === 'admin' || 
                              operator.role === 'supervisor' || 
                              (Array.isArray(operator.reparto) 
                                ? operator.reparto.some(r => allowedAccessReparti.includes(r))
                                : allowedAccessReparti.includes(operator.reparto));
            
            if (!hasAccess) {
                toast({ variant: 'destructive', title: 'Accesso Negato', description: 'Non hai i permessi per accedere a questa pagina.' });
                router.replace('/dashboard');
            }
        }
    }, [operator, authLoading, router, toast]);

    const stopCamera = useCallback(() => {
        if (streamRef.current) {
            streamRef.current.getTracks().forEach(track => track.stop());
            streamRef.current = null;
        }
        setIsCapturing(false);
    }, []);

    if (authLoading || isMasterLoading) {
        return (
            <div className="flex h-screen items-center justify-center">
                <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
        );
    }
    
    const fetchMaterialDetails = async (material: RawMaterial, specificLotto?: string) => {
        try {
            const lots = await getLotInfoForMaterial(material.id);
            setAllLots(lots);
            if (specificLotto) {
                const matched = lots.find(l => l.lotto === specificLotto);
                setFoundLotInfo(matched || null);
            }
        } catch (e) {
            console.error("Error fetching lots:", e);
        }
    };

    const handleCodeSubmit = useCallback(async (code: string) => {
        stopCamera();
        const trimmedCode = code.trim();
        if (!trimmedCode) {
            toast({ variant: 'destructive', title: "Codice Vuoto", description: "Inserisci un codice valido." });
            return;
        }
        setIsSearching(true);
        
        if (step === 'scanning_lotto') {
            const lottoData = await findLastWeightForLotto(undefined, trimmedCode);
            if (lottoData?.material) {
                setFoundMaterial(lottoData.material);
                await fetchMaterialDetails(lottoData.material, trimmedCode);
                setStep('result');
            } else {
                toast({ variant: 'destructive', title: 'Lotto non trovato', description: 'Nessuna corrispondenza trovata per questo lotto.' });
                setStep('initial');
            }
        } else {
            // Check cache first
            const cachedMat = rawMaterialsMap.get(trimmedCode.toUpperCase());
            if (cachedMat) {
                setFoundMaterial(cachedMat);
                await fetchMaterialDetails(cachedMat);
                setStep('result');
            } else {
                // Fallback to server if not in cache (could be a very new material)
                const result = await getRawMaterialByCode(trimmedCode);
                if ('error' in result) {
                    toast({ variant: 'destructive', title: result.title || "Errore", description: result.error });
                    setStep('initial');
                } else {
                    setFoundMaterial(result);
                    await fetchMaterialDetails(result);
                    setStep('result');
                }
            }
        }
        setIsSearching(false);
    }, [stopCamera, toast, step]);

    useEffect(() => {
        if (step !== 'scanning_material' && step !== 'scanning_lotto') {
            stopCamera();
            return;
        }

        const startCamera = async () => {
            setHasCameraPermission(true);
            try {
                const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
                streamRef.current = stream;
                if (videoRef.current) {
                    videoRef.current.srcObject = stream;
                    await videoRef.current.play();
                }
            } catch (err) {
                setHasCameraPermission(false);
                toast({ variant: "destructive", title: "Errore Fotocamera", description: "Accesso negato o non disponibile." });
                stopCamera(); 
            }
        };

        startCamera();
        return () => { stopCamera(); };
    }, [step, stopCamera, toast]);
    
     const triggerScan = async () => {
        if (!videoRef.current || videoRef.current.paused || videoRef.current.readyState < 2) {
            toast({ variant: 'destructive', title: 'Fotocamera non pronta.' });
            return;
        }
        if (!('BarcodeDetector' in window)) {
            toast({ variant: 'destructive', title: 'Funzionalità non supportata.' });
            return;
        }

        setIsCapturing(true);
        try {
            const barcodeDetector = new (window as any).BarcodeDetector({ formats: ['qr_code', 'code_128', 'ean_13', 'code_39'] });
            const barcodes = await barcodeDetector.detect(videoRef.current);
            if (barcodes.length > 0) {
                handleCodeSubmit(barcodes[0].rawValue);
            } else {
                toast({ variant: 'destructive', title: 'Nessun codice trovato.' });
            }
        } catch (error) {
            toast({ variant: 'destructive', title: 'Errore durante la scansione.' });
        } finally {
            setIsCapturing(false);
        }
    };
    
    const resetFlow = () => {
        setFoundMaterial(null);
        setFoundLotInfo(null);
        setAllLots([]);
        setManualCode('');
        setStep('initial');
    };

    const handleOpenHistoryDialog = async () => {
        if (!foundMaterial) return;
        setIsHistoryDialogOpen(true);
        const withdrawals = await getMaterialWithdrawalsForMaterial(foundMaterial.id);
        const combinedMovements: Movement[] = [
            ...(foundMaterial.batches || []).map(b => ({
                type: 'Carico' as const,
                date: b.date,
                description: `Lotto: ${b.lotto || 'N/D'} - DDT: ${b.ddt}`,
                quantity: b.netQuantity,
                unit: foundMaterial.unitOfMeasure.toUpperCase(),
                id: b.id
            })),
            ...withdrawals.map(w => ({
                type: 'Scarico' as const,
                date: w.withdrawalDate.toISOString(),
                description: `Commesse: ${w.jobOrderPFs.join(', ')}`,
                quantity: -w.consumedWeight,
                unit: 'KG',
                id: w.id
            }))
        ];
        combinedMovements.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
        setMaterialMovements(combinedMovements);
    };

    if (authLoading || !operator) {
        return <AppShell><div className="flex items-center justify-center h-full"><Loader2 className="h-12 w-12 animate-spin text-primary" /></div></AppShell>;
    }
    
    return (
        <AuthGuard>
            <AppShell>
                <div className="space-y-6 max-w-2xl mx-auto">
                    {step === 'initial' && (
                         <Card>
                            <CardHeader>
                                <CardTitle className="flex items-center gap-3"><SearchCheck className="h-7 w-7 text-primary" /> Verifica Materiale</CardTitle>
                                <CardDescription>Cerca una materia prima per codice o lotto per visualizzare stock e dettagli.</CardDescription>
                            </CardHeader>
                            <CardContent className="grid grid-cols-1 gap-4 pt-4">
                                <Button onClick={() => setStep('scanning_material')} className="h-16 text-lg" variant="default">
                                    <QrCode className="mr-2 h-6 w-6" />
                                    Scansione Materiale
                                </Button>
                                <Button onClick={() => setStep('scanning_lotto')} className="h-16 text-lg" variant="secondary">
                                    <Barcode className="mr-2 h-6 w-6" />
                                    Scansione Lotto
                                </Button>
                                <Separator className="my-2" />
                                <Button onClick={() => setStep('manual_input')} variant="outline">
                                    <Keyboard className="mr-2 h-5 w-5" />
                                    Inserimento Manuale
                                </Button>
                            </CardContent>
                        </Card>
                    )}

                     {step === 'manual_input' && (
                        <Card>
                            <CardHeader>
                                <CardTitle>Ricerca Manuale</CardTitle>
                                <CardDescription>Inserisci il codice della materia prima.</CardDescription>
                            </CardHeader>
                            <CardContent className="space-y-4">
                                <div className="space-y-2">
                                    <Label htmlFor="manualCode">Codice Materiale</Label>
                                    <div className="flex items-center gap-2">
                                        <Input
                                            id="manualCode"
                                            value={manualCode}
                                            onChange={(e) => setManualCode(e.target.value)}
                                            placeholder="Es. BOB-123"
                                            autoFocus
                                        />
                                        <Button onClick={() => handleCodeSubmit(manualCode)} disabled={!manualCode || isSearching}>
                                            {isSearching ? <Loader2 className="h-4 w-4 animate-spin" /> : <Send className="h-4 w-4" />}
                                        </Button>
                                    </div>
                                </div>
                            </CardContent>
                            <CardFooter>
                                <Button variant="outline" onClick={() => setStep('initial')} className="w-full">Annulla</Button>
                            </CardFooter>
                        </Card>
                    )}

                    {(step === 'scanning_material' || step === 'scanning_lotto') && (
                        <Card>
                            <CardHeader>
                                <CardTitle className="text-center">Inquadra il Codice {step === 'scanning_lotto' ? 'Lotto' : 'Materiale'}</CardTitle>
                            </CardHeader>
                            <CardContent className="relative grid place-items-center aspect-video bg-black rounded-lg overflow-hidden">
                                <video ref={videoRef} className="w-full h-full object-cover" autoPlay muted playsInline />
                                {!hasCameraPermission && (
                                    <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center text-center p-4">
                                        <AlertTriangle className="h-12 w-12 text-destructive mb-4" />
                                        <p className="text-white font-semibold">Accesso fotocamera negato</p>
                                    </div>
                                )}
                                <div className="absolute inset-0 grid place-items-center pointer-events-none">
                                    <div className="w-5/6 h-2/5 border-2 border-primary/50 rounded-lg relative">
                                        <div className="absolute w-full top-1/2 -translate-y-1/2 h-0.5 bg-red-500/80 shadow-[0_0_4px_1px_#ef4444]"></div>
                                    </div>
                                </div>
                            </CardContent>
                            <CardFooter className="flex-col gap-2">
                                <Button onClick={triggerScan} disabled={isCapturing || !hasCameraPermission} className="w-full h-12">
                                    {isCapturing ? <Loader2 className="h-5 w-5 animate-spin"/> : <Camera className="mr-2 h-5 w-5" />}
                                    <span className="ml-2">Scansiona Ora</span>
                                </Button>
                                <Button variant="outline" className="w-full" onClick={() => setStep('initial')}>Annulla</Button>
                            </CardFooter>
                        </Card>
                    )}

                    {step === 'result' && foundMaterial && (
                        <div className="space-y-4">
                            <Card className="border-primary/20 shadow-md">
                                <CardHeader className="bg-muted/30 pb-4">
                                    <div className="flex justify-between items-start">
                                        <div>
                                            <CardTitle className="text-2xl font-bold">{foundMaterial.code}</CardTitle>
                                            <CardDescription className="text-foreground/70">{foundMaterial.description}</CardDescription>
                                        </div>
                                        <UiBadge variant="outline">{foundMaterial.type}</UiBadge>
                                    </div>
                                </CardHeader>
                                <CardContent className="pt-6 space-y-6">
                                    {foundLotInfo && (
                                        <Alert className="bg-primary/5 border-primary/20">
                                            <Info className="h-4 w-4 text-primary" />
                                            <AlertTitle className="font-bold text-primary">Lotto Selezionato: {foundLotInfo.lotto}</AlertTitle>
                                            <AlertDescription className="text-base font-semibold">
                                                Disponibilità: {formatDisplayStock(foundLotInfo.available, foundMaterial.unitOfMeasure)} {foundMaterial.unitOfMeasure.toUpperCase()}
                                            </AlertDescription>
                                        </Alert>
                                    )}

                                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                        <div className="p-4 rounded-lg border bg-background text-center space-y-1">
                                            <Label className="text-muted-foreground uppercase text-[10px] font-bold tracking-wider">Stock Totale ({foundMaterial.unitOfMeasure.toUpperCase()})</Label>
                                            <p className="text-2xl font-black text-primary">{formatDisplayStock(foundMaterial.currentStockUnits, foundMaterial.unitOfMeasure)}</p>
                                        </div>
                                        <div className="p-4 rounded-lg border bg-background text-center space-y-1">
                                            <Label className="text-muted-foreground uppercase text-[10px] font-bold tracking-wider">Peso Netto Totale (KG)</Label>
                                            <p className="text-2xl font-black text-primary">{formatDisplayStock(foundMaterial.currentWeightKg, 'kg')}</p>
                                        </div>
                                    </div>

                                    <div className="space-y-3">
                                        <h4 className="font-bold flex items-center gap-2"><Boxes className="h-4 w-4 text-muted-foreground" /> Breakdown Lotti Disponibili</h4>
                                        <ScrollArea className="h-48 border rounded-md">
                                            <Table>
                                                <TableHeader className="bg-muted/50">
                                                    <TableRow>
                                                        <TableHead>Lotto</TableHead>
                                                        <TableHead className="text-right">Residuo ({foundMaterial.unitOfMeasure.toUpperCase()})</TableHead>
                                                    </TableRow>
                                                </TableHeader>
                                                <TableBody>
                                                    {allLots.length > 0 ? allLots.map(lot => (
                                                        <TableRow key={lot.lotto} className={cn(lot.lotto === foundLotInfo?.lotto && "bg-primary/5")}>
                                                            <TableCell className="font-mono font-bold">{lot.lotto}</TableCell>
                                                            <TableCell className="text-right font-semibold">{formatDisplayStock(lot.available, foundMaterial.unitOfMeasure)}</TableCell>
                                                        </TableRow>
                                                    )) : (
                                                        <TableRow><TableCell colSpan={2} className="text-center py-4 text-muted-foreground italic">Nessun lotto con stock positivo.</TableCell></TableRow>
                                                    )}
                                                </TableBody>
                                            </Table>
                                        </ScrollArea>
                                    </div>
                                </CardContent>
                                <CardFooter className="bg-muted/30 pt-6 flex flex-col sm:flex-row gap-2">
                                    <Button onClick={handleOpenHistoryDialog} variant="secondary" className="flex-1">
                                        <History className="mr-2 h-4 w-4" />
                                        Storico Movimenti
                                    </Button>
                                    <Button onClick={resetFlow} className="flex-1">Nuova Ricerca</Button>
                                </CardFooter>
                            </Card>
                        </div>
                    )}
                </div>

                <Dialog open={isHistoryDialogOpen} onOpenChange={setIsHistoryDialogOpen}>
                    <DialogContent className="sm:max-w-4xl">
                        <DialogHeader>
                            <DialogTitle>Storico Movimenti: {foundMaterial?.code}</DialogTitle>
                        </DialogHeader>
                        <ScrollArea className="max-h-[60vh]">
                            <Table>
                                <TableHeader>
                                    <TableRow>
                                        <TableHead>Data</TableHead>
                                        <TableHead>Tipo</TableHead>
                                        <TableHead>Descrizione</TableHead>
                                        <TableHead className="text-right">Quantità</TableHead>
                                    </TableRow>
                                </TableHeader>
                                <TableBody>
                                    {materialMovements.map((mov, idx) => (
                                        <TableRow key={idx}>
                                            <TableCell>{format(parseISO(mov.date), 'dd/MM/yyyy HH:mm', { locale: it })}</TableCell>
                                            <TableCell>
                                                <UiBadge variant={mov.type === 'Carico' ? 'default' : 'destructive'}>{mov.type}</UiBadge>
                                            </TableCell>
                                            <TableCell className="text-xs truncate max-w-sm">{mov.description}</TableCell>
                                            <TableCell className={cn("text-right font-mono font-bold", mov.type === 'Carico' ? 'text-green-600' : 'text-destructive')}>
                                                {formatDisplayStock(mov.quantity, mov.unit.toLowerCase() as any)} {mov.unit}
                                            </TableCell>
                                        </TableRow>
                                    ))}
                                </TableBody>
                            </Table>
                        </ScrollArea>
                        <DialogFooter>
                            <DialogClose asChild><Button variant="outline">Chiudi</Button></DialogClose>
                        </DialogFooter>
                    </DialogContent>
                </Dialog>
            </AppShell>
        </AuthGuard>
    );
}

"use client";

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { useRouter } from 'next/navigation';
import { format } from 'date-fns';

import AuthGuard from '@/components/AuthGuard';
import AppShell from '@/components/layout/AppShell';
import OperatorNavMenu from '@/components/operator/OperatorNavMenu';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle, CardFooter } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Switch } from '@/components/ui/switch';
import { useToast } from "@/hooks/use-toast";
import { useAuth } from '@/components/auth/AuthProvider';
import { addBatchToRawMaterial, reportNonConformity, getPackagingItems, getOpenPurchaseOrdersForMaterial } from './actions';
import { getRawMaterialByCode } from '@/app/scan-job/actions';
import { calculateInventoryMovement } from '@/lib/inventory-utils';
import type { RawMaterial, Packaging, PurchaseOrder } from '@/types';
import { QrCode, AlertTriangle, Boxes, Send, Loader2, Package, Barcode, PlayCircle, Weight, Check, X, ArrowLeft, ThumbsDown, ThumbsUp, MessageSquare, Camera, Archive, TestTube, Truck, ClipboardList, Calendar } from 'lucide-react';
import { useCameraStream } from '@/hooks/use-camera-stream';
import { cn } from '@/lib/utils';
import { Badge } from '@/components/ui/badge';

const batchFormSchema = z.object({
  materialId: z.string().min(1),
  lotto: z.string().min(1, "Il lotto è obbligatorio."),
  date: z.string().refine((val) => !isNaN(Date.parse(val)), { message: "Data non valida"}),
  ddt: z.string().optional(),
  quantity: z.coerce.number().positive("La quantità deve essere un numero positivo."),
  packagingId: z.string().optional(),
  unit: z.enum(['n', 'kg', 'mt']),
  purchaseOrderId: z.string().optional(),
});
type BatchFormValues = z.infer<typeof batchFormSchema>;

const ncReportFormSchema = z.object({
    quantity: z.coerce.number().positive("La quantità è obbligatoria."),
    reason: z.string(),
    notes: z.string().optional(),
});
type NcReportFormValues = z.infer<typeof ncReportFormSchema>;

type Step = 'scan_material' | 'select_order' | 'validate' | 'scan_lotto' | 'enter_quantity' | 'saving' | 'success';

// New isolated component for scanning UI
const ScanUI = ({ title, onScan, onCancel }: { title: string, onScan: (code: string) => void, onCancel: () => void }) => {
    const videoRef = useRef<HTMLVideoElement>(null);
    const { hasPermission } = useCameraStream(true, videoRef);
    const [isCapturing, setIsCapturing] = useState(false);
    const { toast } = useToast();

    const triggerScan = async () => {
        if (!videoRef.current || videoRef.current.readyState < 2) {
            toast({ variant: 'destructive', title: 'Fotocamera non pronta.' });
            return;
        }
        if (!('BarcodeDetector' in window)) {
            toast({ variant: 'destructive', title: 'Funzionalità non supportata.' });
            return;
        }

        setIsCapturing(true);
        try {
            const barcodeDetector = new (window as any).BarcodeDetector({ formats: ['qr_code', 'code_128', 'ean_13'] });
            const barcodes = await barcodeDetector.detect(videoRef.current);
            if (barcodes.length > 0) {
                onScan(barcodes[0].rawValue);
            } else {
                toast({ variant: 'destructive', title: 'Nessun codice trovato.' });
            }
        } catch (error) {
            toast({ variant: 'destructive', title: 'Errore durante la scansione.' });
        } finally {
            setIsCapturing(false);
        }
    };

    return (
        <div className="text-center space-y-4">
            <h3 className="text-xl font-semibold">{title}</h3>
            <div className="relative grid place-items-center aspect-video bg-black rounded-lg overflow-hidden">
                <video ref={videoRef} className="w-full h-full object-cover" autoPlay muted playsInline />
                {hasPermission === false ? (
                     <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center text-center p-4">
                        <AlertTriangle className="h-12 w-12 text-destructive mb-4" />
                        <p className="text-destructive-foreground font-semibold">Accesso alla fotocamera negato</p>
                        <p className="text-sm text-muted-foreground mt-2">Controlla i permessi del browser per continuare.</p>
                    </div>
                ) : (
                    <div className="absolute inset-0 grid place-items-center pointer-events-none">
                        <div className="w-5/6 h-2/5 relative">
                            <div className="absolute top-0 left-0 w-8 h-8 border-t-4 border-l-4 border-primary rounded-tl-lg"></div>
                            <div className="absolute top-0 right-0 w-8 h-8 border-t-4 border-r-4 border-primary rounded-tr-lg"></div>
                            <div className="absolute bottom-0 left-0 w-8 h-8 border-b-4 border-l-4 border-primary rounded-bl-lg"></div>
                            <div className="absolute bottom-0 right-0 w-8 h-8 border-b-4 border-r-4 border-primary rounded-br-lg"></div>
                            <div className="absolute w-full top-1/2 -translate-y-1/2 h-0.5 bg-red-500/80 shadow-[0_0_4px_1px_#ef4444]"></div>
                        </div>
                    </div>
                )}
            </div>
            <div className="flex flex-col gap-2">
                <Button onClick={triggerScan} disabled={isCapturing || !hasPermission} className="w-full h-12">
                    {isCapturing ? <Loader2 className="h-5 w-5 animate-spin" /> : <Camera className="h-5 w-5" />}
                    <span className="ml-2">{isCapturing ? 'Scansionando...' : 'Scansiona Ora'}</span>
                </Button>
                <Button variant="outline" onClick={onCancel}>Annulla</Button>
            </div>
        </div>
    );
};


export default function MaterialLoadingPage() {
    const { operator, loading: authLoading } = useAuth();
    const router = useRouter();
    const { toast } = useToast();

    const [step, setStep] = useState<Step>('scan_material');
    const [scannedMaterial, setScannedMaterial] = useState<RawMaterial | null>(null);
    const [openOrders, setOpenOrders] = useState<PurchaseOrder[]>([]);
    const [selectedOrder, setSelectedOrder] = useState<PurchaseOrder | null>(null);
    const [scannedLotto, setScannedLotto] = useState<string | null>(null);
    const [packagingItems, setPackagingItems] = useState<Packaging[]>([]);
    const [showNCReport, setShowNCReport] = useState(false);
    const [inputUnit, setInputUnit] = useState<'primary' | 'kg'>('primary');
    const [isLoadingOrders, setIsLoadingOrders] = useState(false);
    
    useEffect(() => {
        if (!authLoading && operator) {
            const allowedAccessReparti = ['MAG', 'Collaudo'];
            const hasAccess = operator.role === 'admin' || 
                              operator.role === 'supervisor' || 
                              (Array.isArray(operator.reparto) 
                                ? operator.reparto.some(r => allowedAccessReparti.includes(r)) 
                                : allowedAccessReparti.includes(operator.reparto));
            
            if (!hasAccess) {
                toast({ variant: 'destructive', title: 'Accesso Negato', description: 'Non hai i permessi per accedere a questa pagina.' });
                router.replace('/dashboard');
            }
        }
    }, [operator, authLoading, router, toast]);
    
    useEffect(() => {
        if (scannedMaterial) {
            setInputUnit('primary'); 
        }
    }, [scannedMaterial]);

    useEffect(() => {
        if (step === 'enter_quantity') {
            getPackagingItems().then(setPackagingItems);
        }
    }, [step]);

    const form = useForm<BatchFormValues>({
        resolver: zodResolver(batchFormSchema),
        defaultValues: { date: format(new Date(), 'yyyy-MM-dd'), ddt: 'CARICO_RAPIDO' },
    });
    
    const ncForm = useForm<NcReportFormValues>();

    const selectedPackagingId = form.watch('packagingId');
    const enteredQuantity = form.watch('quantity');
    
    const calculatedGrossWeight = React.useMemo(() => {
        if (!scannedMaterial || !enteredQuantity) return 0;
        
        const numEnteredQuantity = parseFloat(String(enteredQuantity));
        if (isNaN(numEnteredQuantity) || numEnteredQuantity <= 0) return 0;

        const selectedTara = packagingItems.find(p => p.id === selectedPackagingId)?.weightKg || 0;
        
        // Use the centralized logic to determine Net Weight in KG
        const { weightToChange: netWeightKg } = calculateInventoryMovement(
            scannedMaterial,
            { defaultUnit: scannedMaterial.unitOfMeasure, hasConversion: true },
            numEnteredQuantity,
            (inputUnit === 'kg' ? 'kg' : scannedMaterial.unitOfMeasure) as any,
            true // isAddition
        );

        // Lordo (KG) = Netto (KG) + Tara (KG)
        return Number((netWeightKg + selectedTara).toFixed(3));
    }, [enteredQuantity, packagingItems, selectedPackagingId, scannedMaterial, inputUnit]);

    
    const handleMaterialScanned = useCallback(async (code: string) => {
        const result = await getRawMaterialByCode(code.trim());
        if ('error' in result) {
            toast({ variant: 'destructive', title: result.title || "Errore", description: result.error });
        } else {
            setScannedMaterial(result);
            form.setValue('materialId', result.id);
            form.setValue('unit', result.unitOfMeasure);
            setInputUnit('primary');
            
            // Fetch open orders for this material
            setIsLoadingOrders(true);
            setStep('select_order');
            try {
                const orders = await getOpenPurchaseOrdersForMaterial(result.code);
                setOpenOrders(orders);
            } catch (error) {
                console.error("Search error:", error);
                toast({ variant: 'destructive', title: "Errore di Ricerca", description: "Si è verificato un problema durante la ricerca degli ordini." });
            } finally {
                setIsLoadingOrders(false);
            }
        }
    }, [toast, form]);

    const handleSelectOrder = (order: PurchaseOrder | null) => {
        setSelectedOrder(order);
        if (order) {
            form.setValue('purchaseOrderId', order.id);
            form.setValue('ddt', order.orderNumber);
            // Propose remaining quantity
            const remaining = order.quantity - (order.receivedQuantity || 0);
            form.setValue('quantity', remaining > 0 ? remaining : 0);
        } else {
            form.setValue('purchaseOrderId', undefined);
            form.setValue('quantity', 0);
        }
        setStep('validate');
    };

    const handleLottoScanned = (code: string) => {
        setScannedLotto(code.trim());
        form.setValue('lotto', code.trim());
        setStep('enter_quantity');
    };

    async function onFinalSubmit(values: BatchFormValues) {
        setStep('saving');
        const formData = new FormData();
        Object.entries(values).forEach(([key, value]) => {
          if (value !== undefined) formData.append(key, String(value));
        });

        const finalUnit = inputUnit === 'primary' ? scannedMaterial?.unitOfMeasure : 'kg';
        formData.set('unit', finalUnit || 'n');
        
        // Pass trace weights to action
        const packaging = packagingItems.find(p => p.id === values.packagingId);
        const tareWeight = packaging?.weightKg || 0;
        formData.set('tareWeight', String(tareWeight));
        formData.set('tareName', packaging?.name || 'Nessuna Tara');
        formData.set('grossWeight', String(calculatedGrossWeight));
        formData.set('netWeightKg', String(calculatedGrossWeight - tareWeight));


        const result = await addBatchToRawMaterial(formData);
        toast({
            title: result.success ? "Carico Registrato" : "Errore",
            description: result.message,
            variant: result.success ? "default" : "destructive",
        });

        if (result.success) {
            setStep('success');
        } else {
            setStep('enter_quantity'); 
        }
    };
    
    const handleNonConformityReport = async (values: NcReportFormValues) => {
        if (!scannedMaterial || !operator) return;

        const result = await reportNonConformity({
            materialId: scannedMaterial.id,
            materialCode: scannedMaterial.code,
            lotto: scannedLotto || 'NC_DA_CONVALIDA',
            quantity: values.quantity,
            reason: values.reason,
            notes: values.notes,
            operatorId: operator.id,
            operatorName: operator.nome,
        });

        if (result.success) {
            toast({
                title: "Segnalazione Inviata",
                description: `La NC è stata registrata e il materiale è in attesa di revisione.`,
            });
            resetFlow();
        } else {
             toast({
                variant: "destructive",
                title: "Errore Segnalazione",
                description: result.message,
            });
        }
    };

    const resetFlow = () => {
        setScannedMaterial(null);
        setScannedLotto(null);
        setSelectedOrder(null);
        setOpenOrders([]);
        setShowNCReport(false);
        ncForm.reset();
        form.reset({ date: format(new Date(), 'yyyy-MM-dd'), ddt: 'CARICO_RAPIDO' });
        setStep('scan_material');
    };

    if (authLoading || !operator) {
        return <AppShell><div className="flex items-center justify-center h-full"><Loader2 className="h-12 w-12 animate-spin text-primary" /></div></AppShell>;
    }
    
    const filteredPackagingItems = scannedMaterial
        ? packagingItems.filter(item => item.associatedTypes?.includes(scannedMaterial.type))
        : [];
    
    return (
        <AuthGuard>
            <AppShell>
                <div className="space-y-6 max-w-xl mx-auto">
                    <OperatorNavMenu />
                     <Card>
                        <CardHeader>
                            <CardTitle className="flex items-center gap-3"><Package className="h-7 w-7 text-primary" /> Carico Merce Rapido</CardTitle>
                            <CardDescription>Segui i passaggi per registrare un nuovo lotto di materiale in ingresso.</CardDescription>
                        </CardHeader>
                        
                        <CardContent>
                            <ol className="relative flex items-center justify-between w-full text-sm font-medium text-center text-gray-500 dark:text-gray-400">
                                {['Materiale', 'Ordine', 'Convalida', 'Lotto', 'Q.tà'].map((title, index) => {
                                    const stepNames: Step[] = ['scan_material', 'select_order', 'validate', 'scan_lotto', 'enter_quantity', 'saving', 'success'];
                                    const stepIndex = stepNames.indexOf(step);
                                    const isCompleted = stepIndex > index || step === 'saving' || step === 'success';
                                    const isActive = stepIndex === index;

                                    return (
                                        <li key={title} className={`flex items-center ${index < 4 ? 'w-full' : ''} ${isCompleted ? 'text-primary dark:text-primary after:border-primary dark:after:border-primary' : ''} after:content-[''] after:w-full after:h-1 after:border-b after:border-gray-200 after:border-1 after:inline-block dark:after:border-gray-700`}>
                                            <span className={`flex items-center justify-center w-8 h-8 sm:w-10 sm:h-10 ${isActive || isCompleted ? 'bg-primary/20' : 'bg-muted'} rounded-full shrink-0`}>
                                                {isCompleted ? <Check className="w-4 h-4 sm:w-5 sm:h-5 text-primary" /> : <span className={`${isActive ? 'text-primary' : 'text-muted-foreground'}`}>{index + 1}</span>}
                                            </span>
                                        </li>
                                    );
                                })}
                            </ol>
                            
                            <div className="mt-8">
                                {step === 'scan_material' && (
                                    <ScanUI title="1. Scansiona il Codice Materiale" onScan={handleMaterialScanned} onCancel={resetFlow} />
                                )}

                                {step === 'select_order' && (
                                    <div className="space-y-4">
                                        <h3 className="text-xl font-semibold text-center">2. Seleziona Ordine Fornitore</h3>
                                        <p className="text-center text-sm text-muted-foreground">Materiale: <span className="font-bold">{scannedMaterial?.code}</span></p>
                                        
                                        {isLoadingOrders ? (
                                            <div className="py-10 text-center"><Loader2 className="h-10 w-10 animate-spin mx-auto text-primary"/></div>
                                        ) : (
                                            <div className="space-y-2">
                                                {openOrders.length > 0 ? (
                                                    openOrders.map(order => {
                                                        const remaining = order.quantity - (order.receivedQuantity || 0);
                                                        return (
                                                            <Button 
                                                                key={order.id} 
                                                                variant="outline" 
                                                                className="w-full h-auto p-4 flex flex-col items-start gap-1 text-left hover:border-primary"
                                                                onClick={() => handleSelectOrder(order)}
                                                            >
                                                                <div className="flex justify-between w-full font-bold">
                                                                    <span>Ordine: {order.orderNumber}</span>
                                                                    <Badge variant="secondary">{format(new Date(order.expectedDeliveryDate), 'dd/MM/yyyy')}</Badge>
                                                                </div>
                                                                <div className="text-sm text-muted-foreground flex justify-between w-full">
                                                                    <span>Fornitore: {order.supplierName || 'N/D'}</span>
                                                                    <span className="text-primary font-semibold">Residuo: {remaining} {order.unitOfMeasure.toUpperCase()}</span>
                                                                </div>
                                                            </Button>
                                                        );
                                                    })
                                                ) : (
                                                    <Alert>
                                                        <AlertTriangle className="h-4 w-4" />
                                                        <AlertTitle>Nessun Ordine Trovato</AlertTitle>
                                                        <AlertDescription>Non ci sono ordini pendenti per questo materiale. Puoi procedere con un carico libero.</AlertDescription>
                                                    </Alert>
                                                )}
                                                <Button variant="ghost" className="w-full mt-4" onClick={() => handleSelectOrder(null)}>
                                                    Procedi senza ordine (Carico Libero)
                                                </Button>
                                            </div>
                                        )}
                                    </div>
                                )}

                                {step === 'validate' && (
                                     <div className="text-center space-y-4">
                                        <h3 className="text-xl font-semibold">3. Convalida / Segnala Merce</h3>
                                        <p className="text-muted-foreground">Il materiale ricevuto è conforme?</p>
                                        <div className="flex justify-center gap-4 pt-4">
                                            <Button onClick={() => setStep('scan_lotto')} className="h-24 w-32 flex-col gap-2 bg-green-600 hover:bg-green-700 text-lg">
                                                <ThumbsUp className="h-8 w-8" />
                                                OK
                                            </Button>
                                            <Button onClick={() => setShowNCReport(true)} variant="destructive" className="h-24 w-32 flex-col gap-2 text-lg">
                                                <ThumbsDown className="h-8 w-8" />
                                                NC
                                            </Button>
                                        </div>
                                        
                                        {showNCReport && (
                                            <Card className="mt-6 text-left p-4 border-destructive">
                                            <Form {...ncForm}>
                                              <form onSubmit={ncForm.handleSubmit(handleNonConformityReport)} className="space-y-4">
                                                <CardHeader className="p-2">
                                                  <CardTitle className="text-base">Segnala Non Conformità</CardTitle>
                                                  <CardDescription>Specifica il problema e la quantità.</CardDescription>
                                                </CardHeader>
                                                <CardContent className="p-2 space-y-4">
                                                  <FormField
                                                      control={ncForm.control}
                                                      name="reason"
                                                      render={({ field }) => (
                                                          <FormItem>
                                                              <FormLabel>Motivo della Non Conformità</FormLabel>
                                                              <div className="grid grid-cols-1 sm:grid-cols-3 gap-2">
                                                                  <Button type="button" variant={field.value === 'Codifica Errata' ? 'default' : 'outline'} onClick={() => field.onChange('Codifica Errata')}>Codifica Errata</Button>
                                                                  <Button type="button" variant={field.value === 'Dimensioni Errate' ? 'default' : 'outline'} onClick={() => field.onChange('Dimensioni Errate')}>Dimensioni Errate</Button>
                                                                  <Button type="button" variant={field.value === 'Altro' ? 'default' : 'outline'} onClick={() => field.onChange('Altro')}>Altro</Button>
                                                              </div>
                                                              <FormMessage />
                                                          </FormItem>
                                                      )}
                                                  />

                                                  <FormField
                                                      control={ncForm.control}
                                                      name="quantity"
                                                      render={({ field }) => (
                                                          <FormItem>
                                                              <FormLabel>Quantità NC ({scannedMaterial?.unitOfMeasure.toUpperCase()})</FormLabel>
                                                              <FormControl><Input type="number" step="any" placeholder="Es. 10.5" {...field} value={field.value ?? ''} /></FormControl>
                                                              <FormMessage />
                                                          </FormItem>
                                                      )}
                                                  />

                                                  <FormField
                                                      control={ncForm.control}
                                                      name="notes"
                                                      render={({ field }) => (
                                                          <FormItem>
                                                              <FormLabel>Note Aggiuntive (Opzionale)</FormLabel>
                                                              <FormControl><Input placeholder="Aggiungi dettagli..." {...field} /></FormControl>
                                                              <FormMessage />
                                                          </FormItem>
                                                      )}
                                                  />
                                                </CardContent>
                                                <CardFooter className="p-2">
                                                  <Button type="submit" className="w-full" variant="destructive" disabled={ncForm.formState.isSubmitting}>
                                                    {ncForm.formState.isSubmitting ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <Send className="mr-2 h-4 w-4" />}
                                                    Invia Segnalazione
                                                  </Button>
                                                </CardFooter>
                                              </form>
                                            </Form>
                                          </Card>
                                        )}
                                    </div>
                                )}

                                {step === 'scan_lotto' && (
                                    <ScanUI title="4. Scansiona il Codice del Lotto" onScan={handleLottoScanned} onCancel={resetFlow} />
                                )}

                                {step === 'enter_quantity' && scannedMaterial && (
                                    <div>
                                        <h3 className="text-xl font-semibold text-center mb-4">5. Inserisci Quantità Ricevuta</h3>
                                         <Form {...form}>
                                            <form onSubmit={form.handleSubmit(onFinalSubmit)} className="space-y-6 text-left">
                                                <div className="p-3 bg-muted rounded-md text-sm space-y-1">
                                                    <p>Materiale: <span className="font-bold">{scannedMaterial?.code}</span></p>
                                                    <p>Lotto: <span className="font-bold">{scannedLotto}</span></p>
                                                    {selectedOrder && (
                                                        <p className="text-primary font-semibold flex items-center gap-2"><Truck className="h-4 w-4"/> Ordine: {selectedOrder.orderNumber}</p>
                                                    )}
                                                </div>
                                                
                                                {scannedMaterial.unitOfMeasure !== 'kg' && (
                                                    <div className="flex items-center space-x-2 rounded-lg border p-3 justify-center">
                                                        <Label htmlFor="unit-switch">{scannedMaterial.unitOfMeasure.toUpperCase()}</Label>
                                                        <Switch
                                                        id="unit-switch"
                                                        checked={inputUnit === 'kg'}
                                                        onCheckedChange={(checked) => setInputUnit(checked ? 'kg' : 'primary')}
                                                        />
                                                        <Label htmlFor="unit-switch">KG</Label>
                                                    </div>
                                                )}

                                                 <FormField control={form.control} name="quantity" render={({ field }) => (
                                                    <FormItem>
                                                        <FormLabel>
                                                            {inputUnit === 'kg' ? 'Quantità Netta (KG)' : `Quantità Netta (${scannedMaterial?.unitOfMeasure.toUpperCase()})`}
                                                        </FormLabel>
                                                        <FormControl><Input type="number" step="any" placeholder="Es. 500" {...field} value={field.value ?? ''} autoFocus /></FormControl>
                                                        <FormMessage />
                                                        {selectedOrder && inputUnit === 'primary' && (
                                                            <p className="text-xs text-muted-foreground italic">Quantità proposta basata sul residuo dell'ordine.</p>
                                                        )}
                                                    </FormItem>
                                                )} />

                                                <FormField
                                                  control={form.control}
                                                  name="packagingId"
                                                  render={({ field }) => (
                                                    <FormItem>
                                                      <FormLabel className="flex items-center"><Archive className="mr-2 h-4 w-4" />Imballo (Tara)</FormLabel>
                                                      <Select onValueChange={field.onChange} defaultValue={field.value}>
                                                        <FormControl><SelectTrigger><SelectValue placeholder="Seleziona un imballo..." /></SelectTrigger></FormControl>
                                                        <SelectContent>
                                                            <SelectItem value="none">Nessuna Tara (0.00 kg)</SelectItem>
                                                            {filteredPackagingItems.map(item => (
                                                                <SelectItem key={item.id} value={item.id}>
                                                                    {item.name} ({item.weightKg} kg)
                                                                </SelectItem>
                                                            ))}
                                                        </SelectContent>
                                                      </Select>
                                                      <FormMessage />
                                                    </FormItem>
                                                  )}
                                                />
                                                <div className="p-4 rounded-lg border bg-muted">
                                                    <Label className="text-muted-foreground">Peso Lordo Calcolato (KG)</Label>
                                                    <p className="text-2xl font-bold text-primary">{calculatedGrossWeight > 0 ? calculatedGrossWeight.toFixed(3) : '---'}</p>
                                                </div>
                                                
                                                <Button type="submit" className="w-full h-12 text-lg">Registra Carico</Button>
                                            </form>
                                        </Form>
                                    </div>
                                )}
                                {step === 'saving' && (
                                    <div className="text-center py-8">
                                        <Loader2 className="h-12 w-12 animate-spin text-primary mx-auto" />
                                        <p className="mt-4 text-muted-foreground">Registrazione in corso...</p>
                                    </div>
                                )}
                                  {step === 'success' && (
                                    <div className="text-center py-8 space-y-4">
                                        <Check className="h-16 w-16 text-green-500 bg-green-500/10 rounded-full p-2 mx-auto" />
                                        <h3 className="text-xl font-semibold">Carico Registrato con Successo!</h3>
                                        <p className="text-sm text-muted-foreground">Lo stock è stato aggiornato e l'ordine è stato processato.</p>
                                        <Button onClick={resetFlow} className="w-full h-12 text-lg">Carica un Altro Materiale</Button>
                                    </div>
                                 )}
                            </div>
                        </CardContent>

                        <CardFooter className="flex-col gap-4">
                           {step !== 'success' && step !== 'scan_material' && (
                            <div className="w-full flex justify-between items-center">
                                <Button variant="ghost" onClick={resetFlow}><ArrowLeft className="mr-2 h-4 w-4"/>Ricomincia</Button>
                            </div>
                           )}
                        </CardFooter>
                     </Card>
                </div>
            </AppShell>
        </AuthGuard>
    );
}

"use client";

import React, { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Checkbox } from '@/components/ui/checkbox';
import { Label } from '@/components/ui/label';
import { FileLock, Check, Loader2 } from 'lucide-react';
import { type Operator } from '@/types';
import { useAuth } from '@/components/auth/AuthProvider';
import { useToast } from "@/hooks/use-toast";
import { signPrivacyPolicy, getPrivacyPolicyContent } from './actions';
import { Skeleton } from '@/components/ui/skeleton';

interface PrivacyFormProps {
    operator: Operator;
}

export default function PrivacyForm({ operator }: PrivacyFormProps) {
    const { refetchOperator } = useAuth();
    const [privacyAccepted, setPrivacyAccepted] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [policyContent, setPolicyContent] = useState('');
    const [isLoadingPolicy, setIsLoadingPolicy] = useState(true);
    const { toast } = useToast();
    const router = useRouter();

    const isSigned = !!operator.privacySigned;

    useEffect(() => {
        setPrivacyAccepted(isSigned);
    }, [isSigned]);

    useEffect(() => {
        async function fetchPolicy() {
            try {
                const content = await getPrivacyPolicyContent();
                setPolicyContent(content);
            } catch (error) {
                toast({
                    variant: "destructive",
                    title: "Errore",
                    description: "Impossibile caricare l'informativa sulla privacy.",
                });
            } finally {
                setIsLoadingPolicy(false);
            }
        }
        fetchPolicy();
    }, [toast]);
  
    const handleSaveSignature = async () => {
        if (!operator) {
            toast({
                variant: "destructive",
                title: "Errore",
                description: "Dati operatore non trovati. Impossibile salvare la firma.",
            });
            return;
        }

        setIsSubmitting(true);
        const result = await signPrivacyPolicy(operator.id);

        if (result.success) {
            toast({
                title: "Firma Salvata",
                description: "Grazie per aver accettato. Verrai reindirizzato alla dashboard.",
            });
            await refetchOperator();
            router.push('/dashboard');
        } else {
            toast({
                variant: "destructive",
                title: "Errore",
                description: result.message,
            });
        }
        setIsSubmitting(false);
    };

    return (
        <Card className="shadow-lg">
            <CardHeader>
              <div className="flex items-center space-x-3">
                <FileLock className="h-8 w-8 text-primary" />
                <div>
                  <CardTitle className="text-xl font-headline mb-1">Informativa sulla Privacy e Riservatezza</CardTitle>
                  <CardDescription>
                    {isSigned 
                      ? "Hai già accettato l'informativa." 
                      : "Presa visione obbligatoria per l'utilizzo dell'applicazione."
                    }
                  </CardDescription>
                </div>
              </div>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="p-4 border rounded-md bg-background/50 text-sm text-muted-foreground space-y-3 prose dark:prose-invert max-w-none">
                {isLoadingPolicy ? (
                    <div className="space-y-2">
                        <Skeleton className="h-6 w-3/4" />
                        <Skeleton className="h-4 w-full" />
                        <Skeleton className="h-4 w-full" />
                        <Skeleton className="h-4 w-5/6" />
                    </div>
                ) : (
                    <div dangerouslySetInnerHTML={{ __html: policyContent }} />
                )}
              </div>
              <div className="flex items-center space-x-2 pt-4">
                 <Checkbox 
                    id="privacy" 
                    checked={privacyAccepted} 
                    onCheckedChange={(checked) => setPrivacyAccepted(checked as boolean)}
                    disabled={isSigned}
                />
                <Label htmlFor="privacy" className="text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70">
                  Dichiaro di aver letto e compreso l'informativa sulla privacy.
                </Label>
              </div>
            </CardContent>
            <CardFooter>
               {isSigned ? (
                <div className="w-full text-center text-green-500 font-semibold flex items-center justify-center">
                    <Check className="mr-2 h-5 w-5"/>
                    Informativa accettata e firmata.
                </div>
               ) : (
                <Button 
                    className="w-full"
                    onClick={handleSaveSignature}
                    disabled={!privacyAccepted || isSubmitting || isLoadingPolicy}
                >
                    {isSubmitting ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : null}
                    Salva Firma e Accetta
                </Button>
               )}
            </CardFooter>
        </Card>
    );
}

"use client";

import React, { useState, useMemo, useRef } from 'react';
import { JobOrder, Article } from '@/types';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle, CardFooter } from '@/components/ui/card';
import { Checkbox } from '@/components/ui/checkbox';
import { Label } from '@/components/ui/label';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Separator } from '@/components/ui/separator';
import { ScrollArea } from '@/components/ui/scroll-area';
import { 
    Package, Ship, CheckCircle2, ChevronRight, 
    ChevronLeft, Scale, Printer, Loader2, Info, AlertTriangle, Boxes,
    Building2, ListTodo, Box
} from 'lucide-react';
import { useToast } from '@/hooks/use-toast';
import { confirmPackingAndShip, getArticlesByCodes } from './actions';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

interface PackingRow {
    articleCode: string;
    description: string;
    totalQty: number;
    unitWeightKg: number;
    packagingTareWeightKg: number;
    packagingType: string;
    packingInstructions: string;
    numberOfPackages: number;
    actualWeightKg: number;
    theoreticalWeightKg: number;
    jobIds: string[];
}

interface OrderGroup {
    numeroODL: string;
    articles: Record<string, PackingRow>;
}

interface ClienteGroup {
    cliente: string;
    orders: Record<string, OrderGroup>;
}

interface PackingClientPageProps {
    initialJobs: JobOrder[];
}

export default function PackingClientPage({ initialJobs }: PackingClientPageProps) {
    const { toast } = useToast();
    const [step, setStep] = useState<1 | 2 | 3>(1);
    const [selectedJobIds, setSelectedJobIds] = useState<string[]>([]);
    const [isProcessing, setIsProcessing] = useState(false);
    const [articles, setArticles] = useState<Record<string, Article>>({});
    const [packingData, setPackingData] = useState<Record<string, ClienteGroup>>({});
    
    // PDF Ref
    const pdfRef = useRef<HTMLDivElement>(null);

    // Step 1: Selection
    const toggleJob = (id: string) => {
        setSelectedJobIds(prev => 
            prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
        );
    };

    const handleNextToPacking = async () => {
        if (selectedJobIds.length === 0) {
            toast({ title: "Attenzione", description: "Seleziona almeno una commessa.", variant: "destructive" });
            return;
        }

        setIsProcessing(true);
        const selectedJobs = initialJobs.filter(j => selectedJobIds.includes(j.id));
        const articleCodes = selectedJobs.map(j => j.details);
        
        try {
            const fetchedArticles = await getArticlesByCodes(articleCodes);
            const articlesMap: Record<string, Article> = {};
            fetchedArticles.forEach(a => { articlesMap[a.code.toUpperCase()] = a; });
            setArticles(articlesMap);

            // Grouping Logic
            const groups: Record<string, ClienteGroup> = {};
            
            selectedJobs.forEach(job => {
                const cliente = job.cliente || "Cliente Sconosciuto";
                const orderNum = job.numeroODL || "Ordine N/D";
                const artCode = job.details;
                const article = articlesMap[artCode.toUpperCase()];

                if (!groups[cliente]) {
                    groups[cliente] = { cliente, orders: {} };
                }
                if (!groups[cliente].orders[orderNum]) {
                    groups[cliente].orders[orderNum] = { numeroODL: orderNum, articles: {} };
                }

                if (!groups[cliente].orders[orderNum].articles[artCode]) {
                    groups[cliente].orders[orderNum].articles[artCode] = {
                        articleCode: artCode,
                        description: artCode, // Placeholder
                        totalQty: 0,
                        unitWeightKg: article?.unitWeightKg || 0,
                        packagingTareWeightKg: article?.packagingTareWeightKg || 0,
                        packagingType: article?.packagingType || "N/D",
                        packingInstructions: article?.packingInstructions || "Nessuna istruzione",
                        numberOfPackages: 1,
                        actualWeightKg: 0,
                        theoreticalWeightKg: 0,
                        jobIds: []
                    };
                }

                const row = groups[cliente].orders[orderNum].articles[artCode];
                row.totalQty += job.qta;
                row.jobIds.push(job.id);
                row.theoreticalWeightKg = (row.totalQty * row.unitWeightKg) + (row.numberOfPackages * row.packagingTareWeightKg);
                row.actualWeightKg = Number(row.theoreticalWeightKg.toFixed(2)); // Default to theoretical
            });

            setPackingData(groups);
            setStep(2);
        } catch (error) {
            toast({ title: "Errore", description: "Impossibile caricare i dati degli articoli.", variant: "destructive" });
        } finally {
            setIsProcessing(false);
        }
    };

    // Update Weight Logic
    const updateRow = (cliente: string, order: string, artCode: string, fields: Partial<PackingRow>) => {
        setPackingData(prev => {
            const newGroups = { ...prev };
            const row = newGroups[cliente].orders[order].articles[artCode];
            Object.assign(row, fields);
            
            // Recalculate theoretical if colli or qty changed (qty shouldn't change here but for safety)
            row.theoreticalWeightKg = (row.totalQty * row.unitWeightKg) + (row.numberOfPackages * row.packagingTareWeightKg);
            
            return newGroups;
        });
    };

    const handleConfirmShipment = async () => {
        setIsProcessing(true);
        const flatData: { jobId: string, actualWeightKg: number, numberOfPackages: number }[] = [];
        
        Object.values(packingData).forEach(c => {
            Object.values(c.orders).forEach(o => {
                Object.values(o.articles).forEach(row => {
                    // Distribuiamo il peso reale proporzionalmente alle commesse (o semplicemente lo salviamo su tutte)
                    // Il requisito dice "salvare il peso reale confermato". 
                    // Se più commesse sono raggruppate, salviamo il peso totale e il numero colli su ciascuna?
                    // Probabilmente è meglio salvare il peso reale raggruppato.
                    row.jobIds.forEach(id => {
                        flatData.push({ 
                            jobId: id, 
                            actualWeightKg: row.actualWeightKg, 
                            numberOfPackages: row.numberOfPackages 
                        });
                    });
                });
            });
        });

        const result = await confirmPackingAndShip(flatData);
        if (result.success) {
            setStep(3);
            toast({ title: "Successo", description: result.message });
        } else {
            toast({ title: "Errore", description: result.message, variant: "destructive" });
        }
        setIsProcessing(false);
    };

    const downloadPDF = async () => {
        if (!pdfRef.current) return;
        setIsProcessing(true);
        try {
            const canvas = await html2canvas(pdfRef.current, { scale: 2 });
            const imgData = canvas.toDataURL('image/png');
            const pdf = new jsPDF('p', 'mm', 'a4');
            const pdfWidth = pdf.internal.pageSize.getWidth();
            const pdfHeight = (canvas.height * pdfWidth) / canvas.width;
            pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
            pdf.save(`PackingList_${new Date().toISOString().split('T')[0]}.pdf`);
        } catch (error) {
            toast({ title: "Errore", description: "Generazione PDF fallita.", variant: "destructive" });
        }
        setIsProcessing(false);
    };

    return (
        <div className="container mx-auto p-4 max-w-5xl space-y-6 pb-20">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-3xl font-bold tracking-tight">Packing List & Spedizioni</h1>
                    <p className="text-muted-foreground">Gestione "Ultimo Miglio" e spedizione materiali ai clienti.</p>
                </div>
                <div className="flex gap-2">
                    <Badge variant={step === 1 ? "default" : "outline"} className="px-3 py-1">1. Selezione</Badge>
                    <Badge variant={step === 2 ? "default" : "outline"} className="px-3 py-1">2. Imballo</Badge>
                    <Badge variant={step === 3 ? "default" : "outline"} className="px-3 py-1">3. Inviato</Badge>
                </div>
            </div>

            {step === 1 && (
                <Card>
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <Box className="h-5 w-5 text-primary" />
                            Commesse Pronte per Spedizione
                        </CardTitle>
                        <CardDescription>Seleziona le commesse completate che vuoi inserire nella Packing List.</CardDescription>
                    </CardHeader>
                    <CardContent>
                        <ScrollArea className="h-[500px] border rounded-md">
                            <div className="p-0">
                                {initialJobs.length === 0 ? (
                                    <div className="p-8 text-center text-muted-foreground">
                                        Nessuna commessa completata trovata.
                                    </div>
                                ) : (
                                    <table className="w-full text-sm">
                                        <thead className="bg-muted sticky top-0 z-10">
                                            <tr>
                                                <th className="p-3 text-left w-10"></th>
                                                <th className="p-3 text-left">Commessa</th>
                                                <th className="p-3 text-left">Cliente</th>
                                                <th className="p-3 text-left">Articolo</th>
                                                <th className="p-3 text-right">Q.tà</th>
                                                <th className="p-3 text-left">Data Fine</th>
                                            </tr>
                                        </thead>
                                        <tbody className="divide-y">
                                            {initialJobs.map(job => (
                                                <tr key={job.id} className="hover:bg-accent/50 cursor-pointer" onClick={() => toggleJob(job.id)}>
                                                    <td className="p-3 text-center" onClick={(e) => e.stopPropagation()}>
                                                        <Checkbox 
                                                            checked={selectedJobIds.includes(job.id)}
                                                            onCheckedChange={() => toggleJob(job.id)}
                                                        />
                                                    </td>
                                                    <td className="p-3 font-bold">{job.ordinePF}</td>
                                                    <td className="p-3">{job.cliente}</td>
                                                    <td className="p-3 font-mono">{job.details}</td>
                                                    <td className="p-3 text-right">{job.qta}</td>
                                                    <td className="p-3 text-muted-foreground text-xs">
                                                        {job.overallEndTime ? new Date(job.overallEndTime).toLocaleDateString() : 'N/D'}
                                                    </td>
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                )}
                            </div>
                        </ScrollArea>
                    </CardContent>
                    <CardFooter className="flex justify-between border-t p-4">
                        <p className="text-sm font-medium">{selectedJobIds.length} commesse selezionate</p>
                        <Button onClick={handleNextToPacking} disabled={selectedJobIds.length === 0 || isProcessing}>
                            {isProcessing ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <ChevronRight className="mr-2 h-4 w-4"/>}
                            Genera Packing List
                        </Button>
                    </CardFooter>
                </Card>
            )}

            {step === 2 && (
                <div className="space-y-6">
                    <div className="flex items-center gap-4">
                        <Button variant="outline" onClick={() => setStep(1)}><ChevronLeft className="mr-2 h-4 w-4"/> Indietro</Button>
                        <h2 className="text-xl font-bold">Raggruppamento e Verifica Pesi</h2>
                    </div>

                    {Object.values(packingData).map(clienteGroup => (
                        <Card key={clienteGroup.cliente} className="border-l-4 border-l-primary">
                            <CardHeader className="bg-muted/30">
                                <CardTitle className="text-lg flex items-center gap-2">
                                    <Building2 className="h-5 w-5 text-primary" />
                                    Cliente: {clienteGroup.cliente}
                                </CardTitle>
                            </CardHeader>
                            <CardContent className="p-0">
                                {Object.values(clienteGroup.orders).map(order => (
                                    <div key={order.numeroODL} className="border-b last:border-0">
                                        <div className="bg-accent/20 px-4 py-2 font-semibold text-sm flex items-center gap-2 border-b">
                                            <ListTodo className="h-4 w-4" /> Ordine Cliente: {order.numeroODL}
                                        </div>
                                        <div className="p-4 space-y-6">
                                            {Object.values(order.articles).map(row => (
                                                <div key={row.articleCode} className="grid grid-cols-1 md:grid-cols-12 gap-6 bg-background border p-4 rounded-xl shadow-sm relative overflow-hidden">
                                                    
                                                    {/* Badge Decorativo Tipo Imballo */}
                                                    <div className="absolute top-0 right-0">
                                                        <Badge variant="secondary" className="rounded-none rounded-bl-lg text-[10px] uppercase font-bold">
                                                            {row.packagingType}
                                                        </Badge>
                                                    </div>

                                                    {/* Info Articolo */}
                                                    <div className="md:col-span-4 space-y-2">
                                                        <div className="flex items-center gap-2">
                                                            <Package className="h-5 w-5 text-blue-500" />
                                                            <span className="text-lg font-bold font-mono">{row.articleCode}</span>
                                                        </div>
                                                        <div className="text-sm text-muted-foreground p-3 bg-muted rounded-lg border-2 border-dashed border-blue-200/50 italic">
                                                            <div className="font-bold text-blue-600 text-[10px] uppercase mb-1">📦 Istruzioni Imballo:</div>
                                                            {row.packingInstructions}
                                                        </div>
                                                        <div className="flex items-center gap-2 bg-blue-50 text-blue-700 p-2 rounded text-xs font-bold">
                                                            <Info className="h-3 w-3" />
                                                            {row.totalQty} pezzi totali
                                                            <Separator orientation="vertical" className="h-4 mx-1" />
                                                            {row.jobIds.length} Commesse
                                                        </div>
                                                    </div>

                                                    {/* Configurazione Colli e Pesi */}
                                                    <div className="md:col-span-8 grid grid-cols-1 sm:grid-cols-3 gap-4 items-center">
                                                        {/* Numero Colli */}
                                                        <div className="space-y-2">
                                                            <Label className="text-xs font-bold uppercase tracking-wider text-muted-foreground">Num. Colli</Label>
                                                            <div className="flex items-center gap-2">
                                                                <Boxes className="h-4 w-4 text-muted-foreground" />
                                                                <Input 
                                                                    type="number" 
                                                                    min={1} 
                                                                    value={row.numberOfPackages}
                                                                    onChange={(e) => updateRow(clienteGroup.cliente, order.numeroODL, row.articleCode, { numberOfPackages: parseInt(e.target.value) || 1 })}
                                                                    className="h-10 text-center font-bold"
                                                                />
                                                            </div>
                                                        </div>

                                                        {/* Peso Teorico */}
                                                        <div className="space-y-2">
                                                            <Label className="text-xs font-bold uppercase tracking-wider text-muted-foreground">Peso Teorico (Kg)</Label>
                                                            <div className="h-10 flex items-center gap-2 px-3 bg-muted rounded-md font-mono font-bold text-muted-foreground border">
                                                                <Scale className="h-4 w-4" />
                                                                {row.theoreticalWeightKg.toFixed(2)}
                                                            </div>
                                                            {row.unitWeightKg === 0 && (
                                                                <p className="text-[10px] text-destructive flex items-center gap-1">
                                                                    <AlertTriangle className="h-3 w-3" /> Dati peso mancanti!
                                                                </p>
                                                            )}
                                                        </div>

                                                        {/* Peso Reale */}
                                                        <div className="space-y-2">
                                                            <Label className="text-xs font-bold uppercase tracking-wider text-blue-600">Peso Reale Totale (Kg)</Label>
                                                            <div className="flex items-center gap-2">
                                                                <Scale className="h-4 w-4 text-blue-600" />
                                                                <Input 
                                                                    type="number" 
                                                                    step="0.01"
                                                                    value={row.actualWeightKg}
                                                                    onChange={(e) => updateRow(clienteGroup.cliente, order.numeroODL, row.articleCode, { actualWeightKg: parseFloat(e.target.value) || 0 })}
                                                                    className="h-10 border-blue-500 font-bold text-blue-700 bg-blue-50/50"
                                                                />
                                                            </div>
                                                        </div>
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                ))}
                            </CardContent>
                        </Card>
                    ))}

                    <div className="flex justify-end p-4 bg-muted/20 border rounded-lg sticky bottom-4 z-20 backdrop-blur-md">
                        <Button size="lg" onClick={handleConfirmShipment} disabled={isProcessing} className="bg-green-600 hover:bg-green-700 h-14 px-10 text-xl shadow-lg ring-2 ring-green-500/20">
                            {isProcessing ? <Loader2 className="mr-2 h-6 w-6 animate-spin"/> : <Ship className="mr-2 h-6 w-6"/>}
                            Conferma Spedizione e Chiudi
                        </Button>
                    </div>
                </div>
            )}

            {step === 3 && (
                <div className="flex flex-col items-center justify-center space-y-8 py-20">
                    <div className="h-32 w-32 rounded-full bg-green-100 flex items-center justify-center text-green-600 border-4 border-green-500 animate-bounce">
                        <CheckCircle2 className="h-20 w-20" />
                    </div>
                    <div className="text-center space-y-2">
                        <h2 className="text-4xl font-extrabold">Spedizione Confermata!</h2>
                        <p className="text-xl text-muted-foreground">Le commesse sono state rimosse dal WIP e segnate come spedite.</p>
                    </div>

                    <div className="flex gap-4">
                        <Button size="lg" variant="outline" onClick={() => window.location.reload()}>
                            Nuova Spedizione
                        </Button>
                        <Button size="lg" onClick={downloadPDF} disabled={isProcessing}>
                            {isProcessing ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <Printer className="mr-2 h-4 w-4"/>}
                            Scarica PDF Packing List
                        </Button>
                    </div>

                    {/* Hidden PDF Template */}
                    <div className="hidden">
                        <div ref={pdfRef} style={{ width: '210mm', padding: '15mm', backgroundColor: 'white', color: 'black', fontFamily: 'sans-serif' }}>
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderBottom: '2px solid black', paddingBottom: '5mm', marginBottom: '10mm' }}>
                                <div style={{ fontSize: '24pt', fontWeight: 'bold' }}>PACKING LIST</div>
                                <div style={{ textAlign: 'right' }}>
                                    <div style={{ fontWeight: 'bold' }}>DATA: {new Date().toLocaleDateString('it-IT')}</div>
                                    <div>PRODFAST XCAN MES</div>
                                </div>
                            </div>
                            
                            {Object.values(packingData).map(cliente => (
                                <div key={cliente.cliente} style={{ marginBottom: '8mm' }}>
                                    <div style={{ backgroundColor: '#f3f4f6', padding: '3mm', fontWeight: 'bold', fontSize: '14pt', border: '1px solid #ccc', marginBottom: '4mm' }}>
                                        CLIENTE: {cliente.cliente}
                                    </div>
                                    {Object.values(cliente.orders).map(order => (
                                        <div key={order.numeroODL} style={{ marginLeft: '5mm', marginBottom: '6mm' }}>
                                            <div style={{ fontWeight: 'bold', fontSize: '11pt', borderBottom: '1px solid #eee', marginBottom: '2mm', color: '#4b5563' }}>
                                                ORDINE CLIENTE: {order.numeroODL}
                                            </div>
                                            <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '10pt' }}>
                                                <thead>
                                                    <tr style={{ borderBottom: '2px solid #333', textAlign: 'left' }}>
                                                        <th style={{ padding: '2mm' }}>Articolo</th>
                                                        <th style={{ padding: '2mm' }}>Quantità</th>
                                                        <th style={{ padding: '2mm' }}>Imballo</th>
                                                        <th style={{ padding: '2mm' }}>Colli</th>
                                                        <th style={{ padding: '2mm', textAlign: 'right' }}>Peso Totale (Kg)</th>
                                                    </tr>
                                                </thead>
                                                <tbody>
                                                    {Object.values(order.articles).map(row => (
                                                        <tr key={row.articleCode} style={{ borderBottom: '1px solid #eee' }}>
                                                            <td style={{ padding: '2mm', fontWeight: 'bold' }}>{row.articleCode}</td>
                                                            <td style={{ padding: '2mm' }}>{row.totalQty} pezzi</td>
                                                            <td style={{ padding: '2mm' }}>{row.packagingType}</td>
                                                            <td style={{ padding: '2mm' }}>{row.numberOfPackages}</td>
                                                            <td style={{ padding: '2mm', textAlign: 'right', fontWeight: 'bold' }}>{row.actualWeightKg.toFixed(2)}</td>
                                                        </tr>
                                                    ))}
                                                </tbody>
                                            </table>
                                        </div>
                                    ))}
                                </div>
                            ))}

                            <div style={{ marginTop: '20mm', borderTop: '2px solid black', paddingTop: '5mm', textAlign: 'center', fontSize: '8pt', color: '#666' }}>
                                Documento generato automaticamente dal sistema MES. Controllo qualità ed integrità colli effettuato in fase di imballaggio.
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

"use client";

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { useToast } from "@/hooks/use-toast";
import { useAuth } from '@/components/auth/AuthProvider';
import { useCameraStream } from '@/hooks/use-camera-stream';

import type { JobOrder, JobPhase, RawMaterial, ActiveMaterialSessionData, RawMaterialType, Packaging, MaterialConsumption, IndependentMaterialSession } from '@/types';
import { findLastWeightForLotto, logTubiGuainaWithdrawal, getRawMaterialByCode, markPhaseMaterialReady } from './actions';
import { getPackagingItems } from '../inventory/actions';
import { getLotInfoForMaterial, type LotInfo } from '../admin/raw-material-management/actions';

import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "@/components/ui/dialog";
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Badge } from '@/components/ui/badge';
import { QrCode, Loader2, Weight, Archive, Send, Barcode, Play, Camera, AlertTriangle, Boxes, Info, X, Lock } from 'lucide-react';

import { cn } from '@/lib/utils';
import { Switch } from '@/components/ui/switch';
import { formatDisplayStock } from '@/lib/utils';
import { useBatchSelection } from '@/hooks/useBatchSelection';


const formSchema = z.object({
  material: z.custom<RawMaterial>().nullable(),
  lotto: z.string().optional(),
  ddt: z.string().optional(),
  openingWeightManual: z.coerce.number().min(0, "Il peso non può essere negativo.").optional(),
  quantityToWithdraw: z.coerce.number().optional(),
  packagingId: z.string().optional(),
});

type FormValues = z.infer<typeof formSchema>;
type ScanType = 'material' | 'lotto' | null;

interface MaterialAssociationDialogProps {
  isOpen: boolean;
  onOpenChange: (open: boolean) => void;
  phase: JobPhase;
  job: JobOrder | null;
  onSessionStart: (sessionData: Omit<IndependentMaterialSession, 'id' | 'startedAt' | 'status' | 'operatorId' | 'operatorName'>, type: RawMaterialType) => Promise<any>;
  onWithdrawalComplete: () => void;
}

export default function MaterialAssociationDialog({
  isOpen,
  onOpenChange,
  phase,
  job,
  onSessionStart,
  onWithdrawalComplete,
}: MaterialAssociationDialogProps) {
  const { toast } = useToast();
  const { operator } = useAuth();
  
  const [isProcessing, setIsProcessing] = useState(false);
  const [isCapturing, setIsCapturing] = useState(false);
  const [flash, setFlash] = useState(false);
  const [scanType, setScanType] = useState<ScanType>(null);
  const [inputUnit, setInputUnit] = useState<'primary' | 'kg'>('primary');
  const [packagingItems, setPackagingItems] = useState<Packaging[]>([]);
  const [availableBatches, setAvailableBatches] = useState<any[]>([]);

  const videoRef = React.useRef<HTMLVideoElement>(null);
  const { hasPermission } = useCameraStream(!!scanType, videoRef);

  const form = useForm<FormValues>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      material: null,
      lotto: "",
      ddt: "",
      openingWeightManual: undefined,
      quantityToWithdraw: undefined,
      packagingId: 'none'
    },
  });

  const selectedMaterial = form.watch('material');
  const lottoValue = form.watch('lotto');
  const isBobina = useMemo(() => (phase.name.toUpperCase().includes("TRECCIA") || phase.name.toUpperCase().includes("CORDA") || selectedMaterial?.type === 'BOB' || selectedMaterial?.type === 'PF3V0') && selectedMaterial?.unitOfMeasure !== 'n', [phase.name, selectedMaterial]);

  const {
      isLoading: isLoadingMetadata,
      lotAvailability,
      isFixedTare,
      calculatedNet,
      batchMetadata
  } = useBatchSelection({
      form,
      materialId: selectedMaterial?.id,
      quantityFieldName: isBobina ? 'openingWeightManual' : 'quantityToWithdraw',
      packagingFieldName: 'packagingId'
  });

  const isKgMode = selectedMaterial?.unitOfMeasure === 'kg' || inputUnit === 'kg';
  const effectiveNet = (calculatedNet > 0) ? calculatedNet : (lotAvailability?.available || 0);

  const handleScanTrigger = (type: ScanType) => {
    setScanType(type);
  };

  const triggerScan = async () => {
    if (!videoRef.current || videoRef.current.paused || videoRef.current.readyState < 2) {
      toast({ variant: 'destructive', title: 'Fotocamera non pronta.' });
      return;
    }
    if (!('BarcodeDetector' in window)) {
        toast({ variant: 'destructive', title: 'Funzionalità non supportata.' });
        return;
    }

    setIsCapturing(true);
    try {
        const barcodeDetector = new (window as any).BarcodeDetector({ formats: ['qr_code', 'code_128', 'ean_13', 'code_39'] });
        const barcodes = await barcodeDetector.detect(videoRef.current);
        if (barcodes.length > 0) {
            setFlash(true);
            setTimeout(() => setFlash(false), 500);
            await handleScan(barcodes[0].rawValue);
        } else {
            toast({ variant: 'destructive', title: 'Nessun codice trovato.', description: 'Inquadra meglio il QR.' });
        }
    } catch (error) {
        toast({ variant: 'destructive', title: 'Errore durante la scansione.' });
    } finally {
        setIsCapturing(false);
    }
  };

  const handleScan = useCallback(async (scannedValue: string) => {
    if (scanType === 'material') {
      const materialResult = await getRawMaterialByCode(scannedValue);
      if ('error' in materialResult) {
        toast({ variant: 'destructive', title: materialResult.title, description: materialResult.error });
      } else {
         form.setValue('material', materialResult);
      }
    } else if (scanType === 'lotto') {
        const lottoData = await findLastWeightForLotto(selectedMaterial?.id, scannedValue.trim());
        if (lottoData?.material) {
            form.setValue('material', lottoData.material);
            form.setValue('lotto', scannedValue.trim());
            toast({ title: "Lotto Riconosciuto", description: `Materiale: ${lottoData.material.code}, Lotto: ${scannedValue.trim()}` });
        } else {
            form.setValue('lotto', scannedValue.trim());
            toast({ title: 'Lotto Nuovo', description: 'Nessuno storico trovato per questo lotto.' });
        }
    }

    setScanType(null); 
  }, [scanType, form, toast]);


  const onAvviaSessione = async () => {
    const values = form.getValues();
    if (!selectedMaterial || !job || !operator) return;

    const openingWeight = values.openingWeightManual;
    if (openingWeight === undefined || openingWeight === null) {
        toast({ variant: 'destructive', title: 'Peso Mancante', description: 'Inserire il peso di apertura.' });
        return;
    }

    setIsProcessing(true);
    const selectedPackaging = packagingItems.find(p => p.id === values.packagingId);

    let linkedJobOrderIds: string[] = [];
    if (job.id.startsWith('group-') && job.jobOrderIds) {
        linkedJobOrderIds = job.jobOrderIds;
    } else {
        linkedJobOrderIds = [job.id];
    }

    const openingGross = openingWeight;
    const tare = selectedPackaging?.weightKg || 0;
    const openingNet = Math.max(0, openingGross - tare);

    const consumption: MaterialConsumption = {
        materialId: selectedMaterial.id,
        materialCode: selectedMaterial.code,
        grossOpeningWeight: openingGross,
        netOpeningWeight: openingNet,
        lottoBobina: values.lotto || '',
        packagingId: values.packagingId || 'none',
        tareWeight: tare,
    };

    const registerResult = await markPhaseMaterialReady(job.id, phase.id, { 
        materialCode: selectedMaterial.code, 
        lotto: values.lotto 
    });
    
    if (registerResult.success) {
    const openingGross = openingWeight;
    const tare = selectedPackaging?.weightKg || 0;
    const openingNet = Math.max(0, openingGross - tare);

    const sessionResult = await onSessionStart({
        materialId: selectedMaterial.id,
        materialCode: selectedMaterial.code,
        lotto: values.lotto || null,
        linkedJobOrderIds: linkedJobOrderIds,
        grossOpeningWeight: openingGross,
        netOpeningWeight: openingNet,
        packagingId: values.packagingId,
        tareWeight: tare,
    }, selectedMaterial.type);
        
        if (sessionResult.success) {
            toast({ title: "Sessione Indipendente Avviata", description: "La bobina è ora attiva e condivisa." });
            onOpenChange(false);
        } else {
            toast({ variant: 'destructive', title: 'Errore Sessione', description: sessionResult.message });
        }
    } else {
        toast({ variant: 'destructive', title: 'Errore', description: registerResult.message });
    }
    setIsProcessing(false);
  };
    const onPrelevaMateriale = async (values: FormValues, isFinished: boolean = false) => {
      if (!selectedMaterial || !job || !operator || (!values.quantityToWithdraw && !isFinished)) return;
      setIsProcessing(true);
      const formData = new FormData();
      formData.append('materialId', selectedMaterial.id);
      formData.append('operatorId', operator.id);
      formData.append('jobId', job.id);
      formData.append('jobOrderPF', job.ordinePF);
      formData.append('phaseId', phase.id);
      formData.append('quantity', String(isKgMode ? effectiveNet : (values.quantityToWithdraw || 0)));
      formData.append('unit', isKgMode ? 'kg' : selectedMaterial.unitOfMeasure);
      formData.append('lotto', values.lotto || '');
      
      const result = await logTubiGuainaWithdrawal(formData, isFinished);
      toast({
          title: result.success ? (isFinished ? 'Materiale Finito' : 'Prelievo Registrato') : 'Errore',
          description: result.message,
          variant: result.success ? 'default' : 'destructive',
      });
      if (result.success) {
          onWithdrawalComplete();
      }
      setIsProcessing(false);
  };
  
  const renderScanView = () => (
    <div className="animate-in fade-in zoom-in-95 duration-300">
        <div className="relative aspect-video bg-black rounded-2xl overflow-hidden my-4 border-4 border-slate-700 shadow-inner group">
            <video ref={videoRef} className="w-full h-full object-cover" autoPlay muted playsInline />
            
            {/* Flash Effect */}
            <div className={cn(
                "absolute inset-0 bg-green-500/40 transition-opacity duration-300 pointer-events-none",
                flash ? "opacity-100" : "opacity-0"
            )} />

            {hasPermission === false && (
                <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center text-center p-4">
                    <AlertTriangle className="h-12 w-12 text-destructive mb-4" />
                    <p className="text-white font-semibold">Accesso Fotocamera Negato</p>
                </div>
            )}

            {/* SPARA BUTTON Overlay */}
            <div className="absolute inset-x-0 bottom-4 flex justify-center">
                <Button 
                    onClick={triggerScan}
                    disabled={isCapturing || !hasPermission}
                    className="h-16 w-16 rounded-full bg-white/20 hover:bg-white/40 border-4 border-white shadow-2xl transition-all active:scale-90"
                >
                    <div className="h-10 w-10 rounded-full bg-red-600 group-hover:bg-red-500 shadow-inner" />
                </Button>
            </div>
            <div className="absolute bottom-2 w-full text-center">
                <span className="text-[10px] font-black uppercase text-white shadow-black drop-shadow-md">Tasto SPARA</span>
            </div>
        </div>
        <div className="flex flex-col gap-2">
             <Button variant="outline" onClick={() => setScanType(null)} className="w-full h-12 border-slate-700 text-slate-300 uppercase font-bold text-[10px] tracking-widest">
                 Indietro
             </Button>
        </div>
    </div>
  );

  const renderForm = () => {
    const selectedPackaging = packagingItems.find(p => p.id === form.watch('packagingId'));
    const tare = selectedPackaging?.weightKg || 0;
    const expectedGross = effectiveNet + tare;


    return (
     <Form {...form}>
        <form className="h-full flex flex-col overflow-hidden" onSubmit={(e) => e.preventDefault()}>
          <ScrollArea className="flex-1 px-6 py-2">
            <div className="space-y-4">
              {selectedMaterial ? (
                  <div className="space-y-3">
                      <div className="p-4 border rounded-xl bg-muted/50 border-primary/20 space-y-3">
                          <div className="text-center">
                            <p className="font-black text-xl tracking-tight leading-none mb-1">{selectedMaterial.code}</p>
                            <p className="text-[9px] text-muted-foreground uppercase font-bold tracking-widest">{selectedMaterial.description}</p>
                          </div>
                          
                          <div className="grid grid-cols-2 gap-2">
                            <div className="p-2 rounded-lg bg-background border flex flex-col items-center justify-center text-center shadow-sm">
                                <Label className="text-[8px] uppercase font-black text-muted-foreground mb-1">Totale Magazzino</Label>
                                <p className="text-sm font-black text-primary leading-tight">
                                    {formatDisplayStock(selectedMaterial.currentStockUnits, selectedMaterial.unitOfMeasure)} {selectedMaterial.unitOfMeasure.toUpperCase()}
                                </p>
                                <p className="text-[9px] font-bold text-muted-foreground">
                                    ({formatDisplayStock(selectedMaterial.currentWeightKg, 'kg')} KG)
                                </p>
                            </div>

                            <div className={cn(
                                "p-2 rounded-lg border flex flex-col items-center justify-center text-center transition-all shadow-sm",
                                lotAvailability ? "bg-primary/10 border-primary/40" : "bg-muted border-dashed opacity-50"
                            )}>
                                <Label className="text-[8px] uppercase font-black text-muted-foreground mb-1">In Uso (Lotto)</Label>
                                {lotAvailability ? (
                                    <>
                                        <p className="text-sm font-black text-primary leading-tight">
                                            {formatDisplayStock(lotAvailability.available, selectedMaterial.unitOfMeasure)} {selectedMaterial.unitOfMeasure.toUpperCase()}
                                        </p>
                                        <p className="text-[9px] font-bold text-primary/70">{lotAvailability.lotto}</p>
                                    </>
                                ) : (
                                    <p className="text-[10px] font-bold text-muted-foreground italic">Seleziona Lotto</p>
                                )}
                            </div>
                          </div>
                      </div>

                       {/* Ferrous Rule 1: Transparency Panel for KG */}
                      {isKgMode && lotAvailability && (
                          <div className="p-3 border-2 border-orange-500/20 bg-orange-500/5 rounded-xl space-y-2 animate-in slide-in-from-top-2">
                              <div className="flex justify-between items-center text-[10px] uppercase font-black text-orange-700/70 mb-1">
                                  <span>Trasparenza Peso (KG)</span>
                                  <Info className="h-3 w-3" />
                              </div>
                              <div className="grid grid-cols-3 gap-2 text-center">
                                  <div>
                                      <p className="text-[8px] font-bold text-muted-foreground uppercase leading-none mb-1">Netto</p>
                                      <p className="text-xs font-black">{effectiveNet.toFixed(3)}</p>
                                  </div>
                                  <div>
                                      <p className="text-[8px] font-bold text-muted-foreground uppercase leading-none mb-1">Tara</p>
                                      <p className={cn("text-xs font-black", isFixedTare ? "text-primary" : "text-orange-600")}>
                                          {isFixedTare && <Lock className="inline-block h-2 w-2 mr-0.5 mb-0.5" />}
                                          +{tare.toFixed(3)}
                                      </p>
                                  </div>
                                  <div className="bg-orange-500/10 rounded py-1">
                                      <p className="text-[8px] font-bold text-orange-700 uppercase leading-none mb-1">Lordo (Input)</p>
                                      <p className="text-xs font-black text-orange-700">{(Number(form.watch(isBobina ? 'openingWeightManual' : 'quantityToWithdraw')) || 0).toFixed(3)}</p>
                                  </div>
                              </div>
                          </div>
                      )}

                  </div>
              ) : <Alert className="border-primary/20 bg-primary/5 text-primary"><AlertDescription className="font-bold text-xs uppercase">Scansiona un materiale o un lotto per iniziare.</AlertDescription></Alert>}

              <div className="grid grid-cols-2 gap-2">
                  <Button type="button" onClick={() => handleScanTrigger('material')} className="h-10 text-[10px] uppercase font-black tracking-widest">
                      <QrCode className="mr-2 h-3 w-3" /> Materiale
                  </Button>
                   <Button type="button" onClick={() => handleScanTrigger('lotto')} className="h-10 text-[10px] uppercase font-black tracking-widest" variant="secondary">
                      <Barcode className="mr-2 h-3 w-3" /> Lotto
                  </Button>
              </div>
              
              {selectedMaterial && (
                <div className="space-y-4">
                    <FormField control={form.control} name="lotto" render={({field}) => (
                        <FormItem className="space-y-1">
                            <FormLabel className="font-black text-[10px] uppercase text-muted-foreground tracking-wider">Numero Lotto Attezzato</FormLabel>
                            <FormControl><Input {...field} value={field.value ?? ''} placeholder="Scansiona o digita..." className="font-mono font-bold text-sm h-9 border-primary/30" /></FormControl>
                        </FormItem>
                    )}/>

                    {availableBatches.length > 0 && (
                        <div className="space-y-2">
                            <Label className="font-black text-[9px] uppercase text-muted-foreground flex items-center gap-2">
                                <Boxes className="h-3 w-3" /> Lotti Disponibili ({availableBatches.length})
                            </Label>
                            <ScrollArea className="h-28 border-2 rounded-xl p-1 bg-muted/30 border-muted">
                                <div className="grid grid-cols-1 gap-1">
                                    {availableBatches.map((b, idx) => {
                                        const isOldest = idx === 0 && (b.netQuantity || 0) > 0;
                                        const isSelected = lottoValue === b.lotto;
                                        return (
                                            <Button 
                                                key={b.id || b.lotto || idx}
                                                type="button"
                                                variant={isSelected ? "default" : "ghost"}
                                                size="sm"
                                                className={cn(
                                                    "justify-between text-[11px] h-9 font-black px-3 rounded-lg border",
                                                    isSelected ? "border-primary" : "border-transparent hover:bg-primary/5",
                                                    isOldest && !isSelected && "border-green-500/20 bg-green-500/5 text-green-700"
                                                )}
                                                onClick={() => form.setValue('lotto', b.lotto || '')}

                                            >
                                                <div className="flex items-center gap-2">
                                                    <Barcode className="h-3 w-3 opacity-50" />
                                                    {b.lotto || 'Senza Lotto'}
                                                    {isOldest && <Badge className="text-[7px] h-3 px-1 bg-green-500 font-black">FIFO</Badge>}
                                                </div>
                                                <div className="text-[10px] font-mono opacity-80">
                                                    {formatDisplayStock(b.netQuantity, selectedMaterial.unitOfMeasure)}
                                                </div>
                                            </Button>
                                        );
                                    })}
                                </div>
                            </ScrollArea>
                        </div>
                    )}

                    <div className="grid grid-cols-2 gap-3 border-t pt-4">
                         <FormField control={form.control} name="packagingId" render={({field}) => (
                            <FormItem className="space-y-1">
                                <FormLabel className="text-[10px] font-black uppercase text-muted-foreground flex items-center justify-between">
                                    <span>Applica Tara Bobina</span>
                                    {isFixedTare && <Badge variant="outline" className="text-[7px] h-3 px-1 border-primary text-primary font-black"><Lock className="h-2 w-2 mr-0.5" /> CERTIFICATA</Badge>}
                                </FormLabel>
                                <Select onValueChange={(val) => field.onChange(val || 'none')} value={field.value || 'none'} disabled={isFixedTare}>
                                    <FormControl><SelectTrigger className={cn("text-xs h-9", isFixedTare && "bg-primary/5 border-primary/20")}><SelectValue placeholder="Seleziona..." /></SelectTrigger></FormControl>
                                    <SelectContent>
                                        <SelectItem value="none">Nessuna (0.0 kg)</SelectItem>
                                        {packagingItems.filter(p => !selectedMaterial || (p.associatedTypes && p.associatedTypes.includes(selectedMaterial.type))).map(item => (
                                            <SelectItem key={item.id} value={item.id} className="text-xs">{item.name} ({item.weightKg.toFixed(3)} kg)</SelectItem>
                                        ))}
                                    </SelectContent>
                                </Select>
                            </FormItem>
                        )} />


                        <FormField control={form.control} name="ddt" render={({field}) => (
                            <FormItem className="space-y-1">
                                <FormLabel className="text-[10px] font-black uppercase text-muted-foreground">Rif. DDT / Note</FormLabel>
                                <FormControl><Input {...field} value={field.value ?? ''} className="text-xs h-9" /></FormControl>
                            </FormItem>
                        )}/>
                    </div>

                    <div className="space-y-4 pt-2">
                        {isBobina ? (
                            <FormField control={form.control} name="openingWeightManual" render={({field}) => (
                                <FormItem className="space-y-1">
