"use client";

import React, { useState, useEffect } from 'react';
import { Button } from './ui/button';
import { Download, RefreshCw } from 'lucide-react';
import { Tooltip, TooltipProvider, TooltipContent, TooltipTrigger } from './ui/tooltip';
import { useToast } from '@/hooks/use-toast';
import { ToastAction } from './ui/toast';

// Add type for the install prompt event
interface BeforeInstallPromptEvent extends Event {
    readonly platforms: Array<string>;
    readonly userChoice: Promise<{
        outcome: 'accepted' | 'dismissed';
        platform: string;
    }>;
    prompt(): Promise<void>;
}

const PwaInstaller = () => {
    const [installPrompt, setInstallPrompt] = useState<BeforeInstallPromptEvent | null>(null);
    const { toast } = useToast();

    useEffect(() => {
        const handleBeforeInstallPrompt = (e: Event) => {
            e.preventDefault();
            setInstallPrompt(e as BeforeInstallPromptEvent);
        };

        const setupServiceWorker = async () => {
            if ('serviceWorker' in navigator) {
                try {
                    // Always try to register in development for easier testing if needed, 
                    // or keep it production-only if that's the intention.
                    // The user's original code had a check for Workbox on window.
                    // If we use workbox-sw.js in sw.js, we should still be able to register it manually.
                    
                    const registration = await navigator.serviceWorker.register('/sw.js');
                    console.log('Service Worker registered with scope:', registration.scope);

                    registration.addEventListener('updatefound', () => {
                        const newWorker = registration.installing;
                        if (newWorker) {
                            newWorker.addEventListener('statechange', () => {
                                if (newWorker.state === 'installed' && navigator.serviceWorker.controller) {
                                    toast({
                                        title: "Aggiornamento Disponibile",
                                        description: "È disponibile una nuova versione dell'app. Ricarica per aggiornare.",
                                        action: (
                                            <ToastAction altText="Aggiorna" onClick={() => window.location.reload()}>
                                                <RefreshCw className="mr-2 h-4 w-4" />
                                                Aggiorna
                                            </ToastAction>
                                        ),
                                    });
                                }
                            });
                        }
                    });
                } catch (error) {
                    console.error('Service Worker registration failed:', error);
                }
            }
        };

        window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
        window.addEventListener('load', setupServiceWorker);


        return () => {
            window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
            window.removeEventListener('load', setupServiceWorker);
        };
    }, [toast]);

    const handleInstallClick = async () => {
        if (!installPrompt) {
            toast({
                title: "Installazione non disponibile",
                description: "L'app potrebbe essere già installata o il tuo browser non supporta questa funzionalità.",
                variant: "default",
            });
            return;
        }
        await installPrompt.prompt();
        const { outcome } = await installPrompt.userChoice;
        if (outcome === 'accepted') {
            toast({ title: "Installazione Avviata", description: "L'app verrà aggiunta alla tua schermata principale." });
        }
        setInstallPrompt(null);
    };

    if (!installPrompt || window.location.pathname === '/') {
        return null; // Do not render if not applicable or if on the login page (handled there)
    }

    return (
        <div className="fixed bottom-16 right-4 z-50">
            <TooltipProvider>
                <Tooltip>
                    <TooltipTrigger asChild>
                        <Button
                            onClick={handleInstallClick}
                            variant="default"
                            size="icon"
                            className="h-12 w-12 rounded-full bg-green-600 hover:bg-green-700 text-white shadow-lg"
                        >
                            <Download className="h-6 w-6" />
                        </Button>
                    </TooltipTrigger>
                    <TooltipContent>
                        <p>Installa l'app sul tuo dispositivo</p>
                    </TooltipContent>
                </Tooltip>
            </TooltipProvider>
        </div>
    );
};

export default PwaInstaller;

"use client";

import React, { useState, useEffect } from 'react';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from '@/components/ui/button';
import { Switch } from '@/components/ui/switch';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Loader2, UserCheck, UserX, AlertCircle } from 'lucide-react';
import { Badge } from '@/components/ui/badge';

import { getOperators } from '@/app/admin/operator-management/actions';
import { bulkDeclareAttendance, getCalendarExceptions } from '@/app/admin/attendance-calendar/actions';
import type { Operator, CalendarException } from '@/types';
import { useToast } from '@/hooks/use-toast';
import { format, isWithinInterval, startOfDay, endOfDay, parseISO } from 'date-fns';


interface OperatorStatus {
  operatorId: string;
  operatorName: string;
  isPresent: boolean;
  reason?: string;
  exceptionInfo?: string; // e.g. "Permesso 4h"
}


interface DailyAttendanceModalProps {
  isOpen: boolean;
  onOpenChange: (open: boolean) => void;
  uid: string;
  onDeclared: () => void;
}

export function DailyAttendanceModal({ isOpen, onOpenChange, uid, onDeclared }: DailyAttendanceModalProps) {
  const [operators, setOperators] = useState<Operator[]>([]);
  const [statuses, setStatuses] = useState<OperatorStatus[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { toast } = useToast();
  const today = format(new Date(), 'yyyy-MM-dd');

  useEffect(() => {
    if (isOpen) {
      loadOperators();
    }
  }, [isOpen]);

  const loadOperators = async () => {
    setIsLoading(true);
    try {
      const [allOps, allExceptions] = await Promise.all([
          getOperators(),
          getCalendarExceptions()
      ]);

      const now = new Date();
      const todayInterval = { start: startOfDay(now), end: endOfDay(now) };

      // Only "real" operators and supervisors
      const realOps = allOps.filter(op => op.isReal !== false && (op.role === 'operator' || op.role === 'supervisor'));
      
      const initialStatuses = realOps.map(op => {
        // Check for exceptions today
        const opException = allExceptions.find(ex => 
           ex.targetId === op.id && 
           isWithinInterval(now, { 
               start: startOfDay(parseISO(ex.startDate)), 
               end: endOfDay(parseISO(ex.endDate)) 
           })
        );

        let isPresent = true;
        let reason = 'vacation';
        let exceptionInfo = undefined;

        if (opException) {
            // If hoursLost is full day (or undefined, meaning full absence), set to absent
            const isFullDay = !opException.hoursLost || opException.hoursLost >= 8;
            if (isFullDay) {
                isPresent = false;
                reason = opException.exceptionType || 'vacation';
            } else {
                // Partial absence (e.g. permission)
                isPresent = true;
                exceptionInfo = `${opException.exceptionType === 'permit' ? 'Permesso' : 'Ferie'} ${opException.hoursLost}h`;
            }

        }

        return {
          operatorId: op.id,
          operatorName: op.nome,
          isPresent,
          reason,
          exceptionInfo
        };
      });

      setOperators(realOps);
      setStatuses(initialStatuses);

    } catch (error) {
      toast({ variant: 'destructive', title: 'Errore', description: 'Impossibile caricare gli operatori.' });
    } finally {
      setIsLoading(false);
    }
  };

  const handleToggle = (id: string, present: boolean) => {
    setStatuses(prev => prev.map(s => s.operatorId === id ? { ...s, isPresent: present } : s));
  };

  const handleReasonChange = (id: string, reason: string) => {
    setStatuses(prev => prev.map(s => s.operatorId === id ? { ...s, reason } : s));
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    const res = await bulkDeclareAttendance(today, uid, statuses);
    if (res.success) {
      toast({ title: 'Successo', description: 'Presenze di oggi dichiarate correttamente.' });
      onDeclared();
      onOpenChange(false);
    } else {
      toast({ variant: 'destructive', title: 'Errore', description: res.message });
    }
    setIsSubmitting(false);
  };

  return (
    <Dialog open={isOpen} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-lg max-h-[90vh] flex flex-col">
        <DialogHeader>
          <DialogTitle>Dichiarazione Presenze Giornaliera</DialogTitle>
          <DialogDescription>
            Conferma chi è presente oggi ({format(new Date(), 'dd/MM/yyyy')}). Per gli assenti, indica il motivo.
          </DialogDescription>
        </DialogHeader>

        {isLoading ? (
          <div className="flex justify-center py-12">
            <Loader2 className="h-8 w-8 animate-spin text-primary" />
          </div>
        ) : (
          <div className="flex-1 overflow-y-auto py-4 space-y-4 pr-1">
            {statuses.length === 0 ? (
              <div className="text-center py-8 text-muted-foreground italic">
                Nessun operatore reale configurato.
              </div>
            ) : (
              statuses.map((status) => (
                <div key={status.operatorId} className="flex flex-col gap-2 p-3 border rounded-lg bg-muted/5">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3">
                      {status.isPresent ? (
                        <div className="h-8 w-8 rounded-full bg-green-100 flex items-center justify-center">
                          <UserCheck className="h-4 w-4 text-green-600" />
                        </div>
                      ) : (
                        <div className="h-8 w-8 rounded-full bg-destructive/10 flex items-center justify-center">
                          <UserX className="h-4 w-4 text-destructive" />
                        </div>
                      )}
                      <span className="font-semibold text-sm">{status.operatorName}</span>
                    </div>
                    <div className="flex items-center gap-2">
                        {status.exceptionInfo && (
                            <Badge variant="outline" className="text-[9px] font-bold bg-amber-50 text-amber-600 border-amber-200 animate-pulse">
                                <AlertCircle className="h-3 w-3 mr-1" /> {status.exceptionInfo}
                            </Badge>
                        )}
                        <span className="text-[10px] uppercase font-bold text-muted-foreground">
                            {status.isPresent ? "Presente" : "Assente"}
                        </span>
                        <Switch 
                            checked={status.isPresent} 
                            onCheckedChange={(val) => handleToggle(status.operatorId, val)}
                        />
                    </div>

                  </div>
                  
                  {!status.isPresent && (
                    <div className="flex items-center gap-2 mt-1 animate-in fade-in slide-in-from-top-1 px-1">
                        <span className="text-xs text-muted-foreground min-w-[50px]">Motivo:</span>
                        <Select value={status.reason} onValueChange={(val) => handleReasonChange(status.operatorId, val)}>
                            <SelectTrigger className="h-8 text-xs">
                                <SelectValue />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="vacation">Ferie / Permesso</SelectItem>
                                <SelectItem value="sick">Malattia / Mutua</SelectItem>
                                <SelectItem value="other">Altro / Chiusura</SelectItem>
                            </SelectContent>
                        </Select>
                    </div>
                  )}
                </div>
              ))
            )}
          </div>
        )}

        <DialogFooter className="border-t pt-4">
          <Button variant="outline" onClick={() => onOpenChange(false)} disabled={isSubmitting}>
            Annulla
          </Button>
          <Button onClick={handleSubmit} disabled={isLoading || isSubmitting || statuses.length === 0} className="bg-primary text-primary-foreground">
            {isSubmitting ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : null}
            Conferma Foglio Presenze
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

"use client";

