interface ActivePhaseInfo {
  phaseId: string;
  phaseName: string;
  operators: { id: string; name: string }[];
}

function getPhaseIcon(status: JobPhase['status']) {
  switch (status) {
    case 'pending': return <Circle className="h-4 w-4 text-muted-foreground" />;
    case 'in-progress': return <Hourglass className="h-4 w-4 text-blue-500 animate-spin" />;
    case 'paused': return <PauseCircle className="h-4 w-4 text-orange-500" />;
    case 'completed': return <CheckCircle2 className="h-4 w-4 text-primary" />;
    case 'skipped': return <EyeOff className="h-4 w-4 text-muted-foreground" />;
    default: return <Circle className="h-4 w-4 text-muted-foreground" />;
  }
}

function formatTime(seconds: number): string {
    if (seconds < 0) seconds = 0;
    const totalMinutes = Math.round(seconds / 60);
    const h = Math.floor(totalMinutes / 60);
    const m = totalMinutes % 60;
    return `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}`;
}

function PhaseLiveTimer({ phase }: { phase: JobPhase }) {
  const [elapsedTime, setElapsedTime] = useState('00:00');

  useEffect(() => {
    let interval: NodeJS.Timeout;

    const activeWorkPeriod = phase.workPeriods?.find(wp => wp.end === null);

    if (phase.status === 'in-progress' && activeWorkPeriod) {
      const startTime = new Date(activeWorkPeriod.start).getTime();
      
      const updateTimer = () => {
        const now = Date.now();
        const totalSeconds = Math.floor((now - startTime) / 1000);
        setElapsedTime(formatTime(totalSeconds));
      };

      updateTimer(); // Initial update
      interval = setInterval(updateTimer, 1000);
    } else {
        const totalSeconds = (phase.workPeriods || []).reduce((acc, wp) => {
            if(wp.end) {
                return acc + differenceInSeconds(new Date(wp.end), new Date(wp.start));
            }
            return acc;
        }, 0);
        setElapsedTime(formatTime(totalSeconds));
    }

    return () => clearInterval(interval);
  }, [phase]);

  return <p className="font-mono text-lg">{elapsedTime}</p>;
}


interface JobOrderCardProps {
    jobOrder: JobOrder;
    allOperators: Operator[];
    analysisData?: ProductionTimeData | null;
    onFetchAnalysis: () => void;
    isAnalysisLoading: boolean;
    groupPhases?: JobPhase[];
    onProblemClick: () => void;
    onForceFinishClick: (jobId: string) => void;
    onRevertForceFinishClick: (jobId: string) => void;
    onToggleGuainaClick: (jobId: string, phaseId: string, currentState: 'default' | 'postponed') => void;
    onRevertPhaseClick: (jobId: string, phaseId: string) => void;
    onForcePauseClick: (jobId: string, operatorIds: string[], reason?: string, notes?: string) => void;
    onForceCompleteClick: (jobId: string) => void;
    onResetJobOrderClick: (jobId: string) => void;
    onOpenPhaseManager: (item: JobOrder) => void;
    onOpenMaterialManager: (item: JobOrder) => void;
    onRevertCompletionClick: (jobId: string) => void;
    onUpdateDeliveryDate: (itemId: string, newDate: string) => void | Promise<void>;
    onUpdatePrepDate: (itemId: string, newDate: string) => void | Promise<void>;
    isSelected: boolean;
    onSelect: (jobId: string) => void;
    overallStatus: OverallStatus;
    onNavigateToAnalysis: (articleCode: string) => void;
    onCopyArticleCode: (articleCode: string) => void;
    forceAllowActions?: boolean;
}

export default function JobOrderCard({
    jobOrder,
    allOperators,
    analysisData,
    onFetchAnalysis,
    isAnalysisLoading,
    groupPhases,
    onProblemClick,
    onForceFinishClick,
    onRevertForceFinishClick,
    onToggleGuainaClick,
    onRevertPhaseClick,
    onForcePauseClick,
    onForceCompleteClick,
    onResetJobOrderClick,
    onOpenPhaseManager,
    onOpenMaterialManager,
    onRevertCompletionClick,
    onUpdateDeliveryDate,
    onUpdatePrepDate,
    isSelected,
    onSelect,
    overallStatus,
    onNavigateToAnalysis,
    onCopyArticleCode,
    forceAllowActions = false,
}: JobOrderCardProps) {
  const [isPauseDialogOpen, setIsPauseDialogOpen] = useState(false);
  const [isPauseReasonDialogOpen, setIsPauseReasonDialogOpen] = useState(false);
  const [isBOMDialogOpen, setIsBOMDialogOpen] = useState(false);
  const [isAttachmentsDialogOpen, setIsAttachmentsDialogOpen] = useState(false);
  const [selectedOperatorsToPause, setSelectedOperatorsToPause] = useState<string[]>([]);
  const hasMaterialMissing = jobOrder.phases.some(p => p.materialStatus === 'missing');
  const [remainingTime, setRemainingTime] = useState<string | null>(null);

   const updateRemainingTime = React.useCallback(() => {
    if (!analysisData || !analysisData.isTimeCalculationReliable) {
      setRemainingTime(null);
      return;
    }
    const completedPhasesTotalMinutes = jobOrder.phases
      .filter(p => p.status === 'completed' && analysisData.phases[p.name])
      .reduce((acc, p) => acc + (analysisData.phases[p.name].averageMinutesPerPiece * jobOrder.qta), 0);

    const totalEstimatedMinutes = analysisData.averageMinutesPerPiece * jobOrder.qta;
    const remainingMinutes = totalEstimatedMinutes - completedPhasesTotalMinutes;
    
    setRemainingTime(formatTime(remainingMinutes * 60));
  }, [analysisData, jobOrder]);
  
  useEffect(() => {
    if (analysisData) {
      updateRemainingTime();
    }
  }, [analysisData, updateRemainingTime]);


  const activePhasesWithOperators = useMemo((): ActivePhaseInfo[] => {
    const activePhasesMap = new Map<string, ActivePhaseInfo>();
    const phasesToInspect = groupPhases || jobOrder.phases || [];
    
    phasesToInspect.forEach(phase => {
        if (phase.status === 'in-progress') {
            const phaseOperators: ActivePhaseInfo['operators'] = [];
            (phase.workPeriods || []).forEach(wp => {
                if (wp.end === null) {
                    const operator = allOperators.find(op => op.id === wp.operatorId);
                    if (operator) {
                        phaseOperators.push({ id: operator.id, name: operator.nome });
                    }
                }
            });

            const uniqueOperators = Array.from(new Map(phaseOperators.map(op => [op.id, op])).values());

            if (uniqueOperators.length > 0) {
                if (!activePhasesMap.has(phase.id)) {
                    activePhasesMap.set(phase.id, {
                        phaseId: phase.id,
                        phaseName: phase.name,
                        operators: [],
                    });
                }
                activePhasesMap.get(phase.id)!.operators.push(...uniqueOperators);
            }
        }
    });

    return Array.from(activePhasesMap.values());
  }, [jobOrder, groupPhases, allOperators]);
  
  const handleOpenPauseDialog = () => {
    setSelectedOperatorsToPause([]);
    setIsPauseDialogOpen(true);
  };
  
  const handleConfirmPause = () => {
    if (selectedOperatorsToPause.length > 0) {
      setIsPauseDialogOpen(false);
      setIsPauseReasonDialogOpen(true);
    }
  };

  const handleReasonConfirm = (reason: string, notes?: string) => {
    onForcePauseClick(jobOrder.id, selectedOperatorsToPause, reason, notes);
    setIsPauseReasonDialogOpen(false);
    setSelectedOperatorsToPause([]);
  };

  const toggleOperatorSelection = (opId: string) => {
    setSelectedOperatorsToPause(prev =>
      prev.includes(opId) ? prev.filter(currentId => currentId !== opId) : [...prev, opId]
    );
  };

  const toggleSelectAll = () => {
    const allActiveOperatorIds = activePhasesWithOperators.flatMap(p => p.operators.map(op => op.id));
    if (selectedOperatorsToPause.length === allActiveOperatorIds.length) {
      setSelectedOperatorsToPause([]);
    } else {
      setSelectedOperatorsToPause(allActiveOperatorIds);
    }
  };
  
  const completedPhasesCount = jobOrder.phases.filter(p => p.status === 'completed' || p.status === 'skipped').length;
  const progressPercentage = jobOrder.phases.length > 0 ? (completedPhasesCount / jobOrder.phases.length) * 100 : 0;
  
  const deliveryDateString = jobOrder.dataConsegnaFinale;
  const deliveryDate = deliveryDateString && /^\d{4}-\d{2}-\d{2}$/.test(deliveryDateString)
    ? parseISO(deliveryDateString)
    : null;
    
  const isOverdue = deliveryDate && isPast(new Date(deliveryDate.toDateString())) && overallStatus !== 'Completata';
  
  const prepDateString = jobOrder.dataFinePreparazione;
  const prepDate = prepDateString && /^\d{4}-\d{2}-\d{2}$/.test(prepDateString)
    ? parseISO(prepDateString)
    : null;
  const isPrepOverdue = prepDate && isPast(new Date(prepDate.toDateString())) && overallStatus !== 'Completata';

  const isAnyPhaseInProgress = activePhasesWithOperators.length > 0;
  const canForceFinish = ['In Preparazione', 'Pronto per Produzione', 'In Lavorazione'].includes(overallStatus);
  const canForceComplete = !isAnyPhaseInProgress && overallStatus !== 'Completata';

  const isForcedToFinish = jobOrder.phases.some(p => p.forced);


  const guainaPhase = jobOrder.phases.find(p => p.name === "Taglio Guaina");
  
  const firstProductionPhase = jobOrder.phases
      .filter(p => p.type === 'production')
      .sort((a,b) => a.sequence - b.sequence)[0];
      
  const isGuainaPostponed = guainaPhase && firstProductionPhase && guainaPhase.sequence > firstProductionPhase.sequence;

  const isWorkInProgress = jobOrder.phases.some(p => p.status === 'in-progress' || p.status === 'paused');
  const canToggleGuaina = guainaPhase && (guainaPhase.status === 'pending' || guainaPhase.status === 'paused') && !isWorkInProgress;
  
  const isPartOfGroup = !!jobOrder.workGroupId;

  return (
    <>
      <Collapsible
        asChild
        className="w-full"
      >
        <Card
            className={cn(
            "relative flex flex-col h-full bg-card hover:bg-card/90 transition-all duration-300", 
            (jobOrder.isProblemReported || hasMaterialMissing) && "cursor-pointer border-destructive/50 hover:border-destructive",
            isSelected && "border-primary ring-2 ring-primary/50",
            isPartOfGroup && "shadow-none border-border/70",
            isOverdue && 'border-destructive/30'
            )}
            onClick={(jobOrder.isProblemReported || hasMaterialMissing) ? onProblemClick : undefined}
        >
          <div className="flex-grow">
            <CardHeader className="pb-4 space-y-2">
                <div className="flex justify-between items-center gap-4">
                    <div className="flex items-center gap-3">
                        {(!isPartOfGroup || forceAllowActions) && (
                          <Checkbox
                              checked={isSelected}
                              onCheckedChange={() => onSelect(jobOrder.id)}
                              aria-label={`Seleziona commessa ${jobOrder.id}`}
                              className="h-4 w-4"
                          />
                        )}
                        <CollapsibleTrigger asChild>
                          <div className="flex items-center gap-2 cursor-pointer group">
                              <CardTitle className="font-headline text-lg">{jobOrder.ordinePF}</CardTitle>
                               <ChevronDown className="h-5 w-5 text-muted-foreground transition-transform duration-200 group-data-[state=open]:-rotate-180" />
                          </div>
                        </CollapsibleTrigger>
                    </div>
                    <StatusBadge status={overallStatus} />
                </div>
                <div className="flex justify-between items-center gap-4">
                    <CardDescription className="flex items-center gap-2">
                        <Building className="h-4 w-4 text-muted-foreground" />
                        {jobOrder.cliente}
                    </CardDescription>
                    <div className="flex items-center gap-1">
                        <TooltipProvider>
                            <Tooltip>
                                <TooltipTrigger asChild>
                                    <Button variant="ghost" size="icon" className="h-8 w-8 text-muted-foreground" onClick={(e) => { e.stopPropagation(); setIsBOMDialogOpen(true); }}>
                                        <ClipboardList className="h-4 w-4" />
                                    </Button>
                                </TooltipTrigger>
                                <TooltipContent><p>Vedi Distinta Base</p></TooltipContent>
                            </Tooltip>
                            {!isPartOfGroup && (
                                <>
                                    <Tooltip>
                                        <TooltipTrigger asChild>
                                            <Button asChild variant="ghost" size="icon" className="h-8 w-8 text-muted-foreground">
                                                <Link href={`/admin/reports/${jobOrder.id}`}><CheckSquare className="h-4 w-4" /></Link>
                                            </Button>
                                        </TooltipTrigger>
                                        <TooltipContent><p>Vedi Dettagli Report</p></TooltipContent>
                                    </Tooltip>
                                    <Tooltip>
                                        <TooltipTrigger asChild>
                                            <Button asChild variant="ghost" size="icon" className="h-8 w-8 text-muted-foreground">
                                                <Link href={`/admin/data-management/print?jobId=${encodeURIComponent(jobOrder.id)}`} target="_blank"><Printer className="h-4 w-4" /></Link>
                                            </Button>
                                        </TooltipTrigger>
                                        <TooltipContent><p>Stampa Scheda</p></TooltipContent>
                                    </Tooltip>

                                    {jobOrder.attachments && jobOrder.attachments.length > 0 && (
                                        <Tooltip>
                                            <TooltipTrigger asChild>
                                                <Button 
                                                    variant="ghost" 
                                                    size="icon" 
                                                    className="h-8 w-8 text-blue-600 hover:text-blue-700 hover:bg-blue-50"
                                                    onClick={(e) => { e.stopPropagation(); setIsAttachmentsDialogOpen(true); }}
                                                >
                                                    <FileText className="h-4 w-4" />
                                                </Button>
                                            </TooltipTrigger>
                                            <TooltipContent><p>Disegni Tecnici ({jobOrder.attachments.length})</p></TooltipContent>
                                        </Tooltip>
                                    )}
                                </>
                            )}
                        </TooltipProvider>
                        {(!isPartOfGroup || forceAllowActions) && (
                          <DropdownMenu>
                              <DropdownMenuTrigger asChild>
                                  <Button variant="ghost" size="icon" className="h-8 w-8" onClick={e => e.stopPropagation()}>
                                      <MoreVertical className="h-4 w-4" />
                                  </Button>
                              </DropdownMenuTrigger>
                              <DropdownMenuContent align="end">
                                 <DropdownMenuItem onSelect={() => onOpenPhaseManager(jobOrder)} disabled={overallStatus === 'Completata'}>
                                      <ListOrdered className="mr-2 h-4 w-4" />
                                      <span>Gestisci Fasi</span>
                                  </DropdownMenuItem>
                                  <DropdownMenuItem onSelect={() => onOpenMaterialManager(jobOrder)} disabled={overallStatus === 'Completata'}>
                                      <Boxes className="mr-2 h-4 w-4" />
                                      <span>Gestisci Materiali</span>
                                  </DropdownMenuItem>
                                  {canToggleGuaina && guainaPhase && (
                                      <AlertDialog>
                                          <AlertDialogTrigger asChild>
                                              <DropdownMenuItem onSelect={(e) => e.preventDefault()}>
                                              {isGuainaPostponed ? <CornerUpLeft className="mr-2 h-4 w-4" /> : <CornerDownRight className="mr-2 h-4 w-4" />}
                                              <span>{isGuainaPostponed ? 'Ripristina Guaina' : 'Posticipa Guaina'}</span>
                                              </DropdownMenuItem>
                                          </AlertDialogTrigger>
                                          <AlertDialogContent>
                                              <AlertDialogHeader>
                                                  <AlertDialogTitle>Conferma Spostamento Fase</AlertDialogTitle>
                                                  <AlertDialogDescription>
                                                  Stai per {isGuainaPostponed ? 'riportare la fase "Taglio Guaina" alla sua posizione originale.' : 'posticipare la fase "Taglio Guaina" a dopo la produzione.'} Vuoi continuare?
                                                  </AlertDialogDescription>
                                              </AlertDialogHeader>
                                              <AlertDialogFooter>
                                                  <AlertDialogCancel>Annulla</AlertDialogCancel>
                                                  <AlertDialogAction onClick={() => onToggleGuainaClick(jobOrder.id, guainaPhase.id, isGuainaPostponed ? 'postponed' : 'default')}>Conferma</AlertDialogAction>
                                              </AlertDialogFooter>
                                          </AlertDialogContent>
                                      </AlertDialog>
                                  )}
                                   <DropdownMenuSeparator />
                                   <DropdownMenuItem onSelect={handleOpenPauseDialog} disabled={!isAnyPhaseInProgress}>
                                      <Users className="mr-2 h-4 w-4" />
                                      <span>Forza Pausa Operatori</span>
                                  </DropdownMenuItem>
                                   {canForceFinish && (
                                      <AlertDialog>
                                          <AlertDialogTrigger asChild><DropdownMenuItem onSelect={(e) => e.preventDefault()}><FastForward className="mr-2 h-4 w-4" />Forza a Finitura</DropdownMenuItem></AlertDialogTrigger>
                                          <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Conferma Azione</AlertDialogTitle><AlertDialogDescription>Forzare tutte le fasi di produzione a 'completata'?</AlertDialogDescription></AlertDialogHeader>
                                          <AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={() => onForceFinishClick(jobOrder.id)}>Conferma</AlertDialogAction></AlertDialogFooter></AlertDialogContent>
                                      </AlertDialog>
                                  )}
                                   {isForcedToFinish && (
                                      <AlertDialog>
                                          <AlertDialogTrigger asChild><DropdownMenuItem onSelect={(e) => e.preventDefault()} className="text-amber-600 focus:text-amber-700"><Undo2 className="mr-2 h-4 w-4" />Annulla Forzatura</DropdownMenuItem></AlertDialogTrigger>
                                          <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Annullare la Forzatura?</AlertDialogTitle><AlertDialogDescription>Le fasi completate forzatamente verranno resettate allo stato 'in attesa'.</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={() => onRevertForceFinishClick(jobOrder.id)}>Sì, annulla</AlertDialogAction></AlertDialogFooter></AlertDialogContent>
                                      </AlertDialog>
                                  )}
                                  {canForceComplete && (
                                      <AlertDialog>
                                          <AlertDialogTrigger asChild><DropdownMenuItem onSelect={(e) => e.preventDefault()}><PowerOff className="mr-2 h-4 w-4" />Forza Chiusura Commessa</DropdownMenuItem></AlertDialogTrigger>
                                          <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Conferma Azione</AlertDialogTitle><AlertDialogDescription>Stai per impostare manualmente questa commessa come 'Completata'.</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={() => onForceCompleteClick(jobOrder.id)}>Conferma</AlertDialogAction></AlertDialogFooter></AlertDialogContent>
                                      </AlertDialog>
                                  )}
                                   {jobOrder.forcedCompletion && (
                                     <AlertDialog>
                                       <AlertDialogTrigger asChild>
                                         <DropdownMenuItem onSelect={(e) => e.preventDefault()} className="text-amber-600 focus:text-amber-700">
                                           <ArchiveRestore className="mr-2 h-4 w-4" />
                                           <span>Riapri Commessa</span>
                                         </DropdownMenuItem>
                                       </AlertDialogTrigger>
                                       <AlertDialogContent>
                                         <AlertDialogHeader>
                                           <AlertDialogTitle>Sei sicuro di voler riaprire?</AlertDialogTitle>
                                           <AlertDialogDescription>
                                             Questa azione riporterà la commessa al suo ultimo stato di avanzamento, annullando la chiusura forzata.
                                           </AlertDialogDescription>
                                         </AlertDialogHeader>
                                         <AlertDialogFooter>
                                           <AlertDialogCancel>Annulla</AlertDialogCancel>
                                           <AlertDialogAction onClick={() => onRevertCompletionClick(jobOrder.id)}>Sì, riapri</AlertDialogAction>
                                         </AlertDialogFooter>
                                       </AlertDialogContent>
                                     </AlertDialog>
                                   )}
                                   <DropdownMenuSeparator />
                                   <AlertDialog>
                                       <AlertDialogTrigger asChild>
                                       <DropdownMenuItem onSelect={(e) => e.preventDefault()} className="text-destructive focus:text-destructive">
                                           <RefreshCcw className="mr-2 h-4 w-4" />
                                           <span>Annulla e Resetta</span>
                                       </DropdownMenuItem>
                                       </AlertDialogTrigger>
                                       <AlertDialogContent>
                                       <AlertDialogHeader>
                                           <AlertDialogTitle>Sei assolutamente sicuro?</AlertDialogTitle>
                                           <AlertDialogDescription>
                                           Questa azione è irreversibile. La commessa <span className="font-bold">{jobOrder.ordinePF}</span> verrà riportata allo stato "pianificata", le lavorazioni azzerate e lo stock dei materiali consumati verrà ripristinato.
                                           </AlertDialogDescription>
                                       </AlertDialogHeader>
                                       <AlertDialogFooter>
                                           <AlertDialogCancel>Annulla</AlertDialogCancel>
                                           <AlertDialogAction onClick={() => onResetJobOrderClick(jobOrder.id)} className="bg-destructive hover:bg-destructive/90">Sì, annulla e resetta</AlertDialogAction>
                                       </AlertDialogFooter>
                                       </AlertDialogContent>
                                   </AlertDialog>
                               </DropdownMenuContent>
                           </DropdownMenu>
                         )}
                     </div>
                 </div>

                 {(jobOrder.isProblemReported || hasMaterialMissing) && (
                     <p className="text-sm text-destructive font-semibold mt-2 flex items-center">
                         <ShieldAlert className="mr-2 h-4 w-4" /> 
                         {jobOrder.isProblemReported ? "Problema segnalato!" : "Materiale mancante!"}
                     </p>
                 )}
             </CardHeader>
             <CardContent className="pt-0 pb-4 px-6 space-y-4">
                 <div className="flex justify-between items-start gap-4">
                     <div className="space-y-3 text-sm">
                         <p className="flex items-center gap-2 text-muted-foreground">
                             <ClipboardList className="h-4 w-4" />
                             <span className="font-semibold text-foreground">{jobOrder.numeroODLInterno || 'N/D'}</span>
                         </p>
                         <p className="flex items-center gap-2 text-muted-foreground">
                             <Factory className="h-4 w-4" />
                             {jobOrder.department}
                         </p>
                         <ContextMenu>
                           <ContextMenuTrigger>
                             <p className="flex items-center gap-2 text-muted-foreground hover:text-primary cursor-pointer">
                                 <Package className="h-4 w-4" />
                                 <span className="hover:underline">{jobOrder.details}</span>
                             </p>
                           </ContextMenuTrigger>
                            <ContextMenuContent>
                               <ContextMenuItem onSelect={() => onNavigateToAnalysis(jobOrder.details)}>
                                   <BarChart3 className="mr-2 h-4 w-4"/>
                                   Analisi Tempi Articolo
                               </ContextMenuItem>
                               <ContextMenuItem onSelect={() => onCopyArticleCode(jobOrder.details)}>
                                   <Copy className="mr-2 h-4 w-4"/>
                                   Copia Codice Articolo
                               </ContextMenuItem>
                           </ContextMenuContent>
                         </ContextMenu>
                         
                         <div className="space-y-2 pt-1">
                            {/* FINE PREP */}
                            <Popover>
                                <PopoverTrigger asChild>
                                    <button 
                                        className="flex items-center gap-2 w-full group text-left"
                                        onClick={(e) => e.stopPropagation()}
                                    >
                                        <Calendar className={cn("h-3.5 w-3.5", isPrepOverdue ? "text-destructive" : "text-muted-foreground")} />
                                        <Badge 
                                          variant="outline" 
                                          className={cn(
                                            "bg-amber-500/10 text-amber-700 border-amber-500/20 hover:bg-amber-500/20 transition-colors px-2 py-0.5 text-[10px] uppercase font-bold",
                                            isPrepOverdue && "bg-destructive/10 text-destructive border-destructive/20"
                                          )}
                                        >
                                            Fine Prep: {prepDate ? format(prepDate, 'dd MMM yyyy', { locale: it }) : 'N/D'}
                                        </Badge>
                                    </button>
                                </PopoverTrigger>
                                <PopoverContent className="w-auto p-0" align="start">
                                    <CalendarPicker
                                        mode="single"
                                        selected={prepDate || undefined}
                                        onSelect={(date) => {
                                            if (date) {
                                                onUpdatePrepDate(jobOrder.id, format(date, 'yyyy-MM-dd'));
                                            }
                                        }}
                                        initialFocus
                                    />
                                </PopoverContent>
                            </Popover>

                            {/* CONSEGNA FINALE */}
                            <Popover>
                                <PopoverTrigger asChild>
                                    <button 
                                        className={cn(
                                            "flex items-center gap-2 text-xs font-medium hover:text-primary transition-colors pl-0.5", 
                                            isOverdue ? "text-destructive" : "text-muted-foreground"
                                        )}
                                        onClick={(e) => e.stopPropagation()}
                                    >
                                        <Clock className="h-3.5 w-3.5" />
                                        <span>Consegna: {deliveryDate ? format(deliveryDate, 'dd MMM yyyy', { locale: it }) : 'N/D'}</span>
                                    </button>
                                </PopoverTrigger>
                                <PopoverContent className="w-auto p-0" align="start">
                                    <CalendarPicker
                                        mode="single"
                                        selected={deliveryDate || undefined}
                                        onSelect={(date) => {
                                            if (date) {
                                                onUpdateDeliveryDate(jobOrder.id, format(date, 'yyyy-MM-dd'));
                                            }
                                        }}
                                        initialFocus
                                    />
                                </PopoverContent>
                            </Popover>
                          </div>
                     </div>
                     <div className="text-right flex-shrink-0">
                         <div className="flex items-center gap-1 justify-end">
                           <Package className="h-4 w-4 text-muted-foreground" />
                           <span className="font-bold">{jobOrder.qta}</span>
                           <span className="text-muted-foreground text-xs">pz</span>
                         </div>
                     </div>
                 </div>

                 {isAnyPhaseInProgress && (
                   <div className="rounded-lg border-2 border-cyan-400/50 bg-cyan-900/20 p-3 space-y-3 animate-pulse">
                       <h4 className="text-sm font-semibold text-foreground/90 flex items-center gap-2">
                           <Hourglass className="h-4 w-4 text-cyan-500"/>
                           Operatori Attivi
                       </h4>
                       {activePhasesWithOperators.map(info => (
                           <div key={info.phaseId} className="pl-2">
                             <p className="font-semibold text-primary">{info.phaseName}:</p>
                             <div className="flex flex-wrap gap-2 pt-1">
                                 {info.operators.map(op => (
                                     <Badge key={op.id} variant="outline" className="flex items-center gap-1.5 py-1 bg-background">
                                         <User className="h-3 w-3" />
                                         {op.name}
                                     </Badge>
                                 ))}
                             </div>
                           </div>
                       ))}
                   </div>
                 )}
                 
                 <div className="p-3 rounded-lg border bg-background/50 space-y-2">
                     {remainingTime ? (
                         <>
                             <div className="flex justify-between items-center">
                                 <div className="flex items-center gap-2 text-sm font-semibold">
                                     <Timer className="h-4 w-4 text-primary"/>
                                     Ore Rimanenti Stimate
                                 </div>
                                 <TooltipProvider>
                                     <Tooltip>
                                         <TooltipTrigger asChild>
                                             <Button variant="ghost" size="icon" className="h-6 w-6" onClick={(e) => { e.stopPropagation(); updateRemainingTime(); }}>
                                                 <RefreshCcw className="h-4 w-4" />
                                             </Button>
                                         </TooltipTrigger>
                                         <TooltipContent><p>Aggiorna stima</p></TooltipContent>
                                     </Tooltip>
                                 </TooltipProvider>
                             </div>
                             <p className="font-mono text-xl font-bold text-primary text-center">{remainingTime}</p>
                         </>
                     ) : (
                         <Button onClick={onFetchAnalysis} disabled={isAnalysisLoading} className="w-full">
                             {isAnalysisLoading ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Timer className="mr-2 h-4 w-4" />}
                             Calcola Stima Tempi
                         </Button>
                     )}
                 </div>
                 
                 <div className="w-full pt-2">
                     <div className="flex justify-between text-xs text-muted-foreground mb-1">
                         <span>Progresso</span>
                         <span>{Math.round(progressPercentage)}%</span>
                     </div>
                     <Progress value={progressPercentage} className="h-2" />
                 </div>
             </CardContent>
           </div>
           
           <CollapsibleContent>
             <CardContent className="flex-grow space-y-4 pt-4 px-6">
               <Separator />
               <div className="space-y-2">
                 <h4 className="text-sm font-semibold text-foreground/80">Avanzamento Fasi</h4>
                 {jobOrder.phases && jobOrder.phases.length > 0 ? (
                     jobOrder.phases.sort((a,b) => a.sequence - b.sequence).map(phase => (
                         <div key={phase.id} className="p-2 rounded-lg border bg-background/50 space-y-2">
                             <div className="flex items-center justify-between gap-2">
                                 <div className="flex items-center gap-2">
                                     {getPhaseIcon(phase.status)}
                                     <span className={cn("text-xs font-semibold uppercase tracking-wider", phase.status === 'skipped' && 'line-through text-muted-foreground')}>{phase.name}</span>
                                 </div>
                                 {phase.status === 'completed' && overallStatus !== 'Completata' && !isPartOfGroup && (
                                     <AlertDialog>
                                         <AlertDialogTrigger asChild>
                                             <Button variant="ghost" size="icon" className="h-6 w-6 text-muted-foreground hover:text-destructive">
                                                 <Undo2 className="h-4 w-4" />
                                             </Button>
                                         </AlertDialogTrigger>
                                         <AlertDialogContent>
                                             <AlertDialogHeader><AlertDialogTitle>Ripristinare la fase?</AlertDialogTitle><AlertDialogDescription>Questa azione riporterà la fase "{phase.name}" allo stato di pausa, conservando il tempo di lavoro già registrato. Sei sicuro?</AlertDialogDescription></AlertDialogHeader>
                                             <AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={() => onRevertPhaseClick(jobOrder.id, phase.id)}>Sì, ripristina</AlertDialogAction></AlertDialogFooter>
                                         </AlertDialogContent>
                                     </AlertDialog>
                                 )}
                             </div>
                             <div className="grid grid-cols-2 gap-2 text-center">
                                  <div className="p-1 rounded-md bg-muted/50">
                                      <Label className="text-xs text-muted-foreground">Tempo eff.</Label>
                                      <PhaseLiveTimer phase={phase} />
                                  </div>
                                  <div className="p-1 rounded-md bg-muted/50 flex flex-col justify-center items-center relative">
                                      <Label className="text-xs text-muted-foreground">Tempo Stimato</Label>
                                      <div className="flex items-center gap-2">
                                          <p className="font-mono text-lg">
                                              {(analysisData?.phases[phase.name] && analysisData?.phases[phase.name].averageMinutesPerPiece > 0)
                                                  ? formatTime(analysisData.phases[phase.name].averageMinutesPerPiece * jobOrder.qta * 60)
                                                  : 'N/D'
                                              }
                                          </p>
                                          {analysisData?.phases[phase.name]?.confidenceWarning && (
                                              <TooltipProvider>
                                                  <Tooltip>
                                                      <TooltipTrigger asChild>
                                                          <ShieldAlert className="h-4 w-4 text-amber-500 animate-pulse" />
                                                      </TooltipTrigger>
                                                      <TooltipContent>
                                                          <p>{analysisData.phases[phase.name].confidenceWarning}</p>
                                                      </TooltipContent>
                                                  </Tooltip>
                                              </TooltipProvider>
                                          )}
                                      </div>
                                  </div>
                             </div>
                         </div>
                     ))
                 ) : (
                     <p className="text-sm text-muted-foreground">Nessuna fase definita per questa commessa.</p>
                 )}
               </div>
             </CardContent>
           </CollapsibleContent>
         </Card>
      </Collapsible>

      {isBOMDialogOpen && (
        <BOMDialog
            isOpen={isBOMDialogOpen}
            onOpenChange={setIsBOMDialogOpen}
            job={jobOrder}
        />
      )}

      <Dialog open={isPauseDialogOpen} onOpenChange={setIsPauseDialogOpen}>
          <DialogContent>
              <DialogHeader>
                  <DialogTitle>Seleziona Operatori da Mettere in Pausa</DialogTitle>
                  <DialogDescription>
                      Scegli quali operatori attivi sulla commessa <span className="font-bold">{jobOrder.ordinePF}</span> vuoi mettere in pausa.
                  </DialogDescription>
              </DialogHeader>
              <div className="py-4 space-y-3">
                   <div className="flex items-center space-x-2">
                      <Checkbox
                          id="select-all"
                          checked={selectedOperatorsToPause.length === activePhasesWithOperators.flatMap(p => p.operators).length && activePhasesWithOperators.length > 0}
                          onCheckedChange={toggleSelectAll}
                      />
                      <Label htmlFor="select-all">Seleziona Tutti</Label>
                  </div>
                  {activePhasesWithOperators.flatMap(p => p.operators).map(op => (
                      <div key={op.id} className="flex items-center space-x-2 p-2 rounded-md border">
                           <Checkbox
                               id={op.id}
                               checked={selectedOperatorsToPause.includes(op.id)}
                               onCheckedChange={() => toggleOperatorSelection(op.id)}
                           />
                           <Label htmlFor={op.id} className="flex-1">
                               <span className="font-semibold">{op.name}</span>
                           </Label>
                      </div>
                  ))}
                  {activePhasesWithOperators.length === 0 && <p className="text-sm text-muted-foreground text-center py-4">Nessun operatore attivo su questa commessa.</p>}
              </div>
              <DialogFooter>
                  <Button variant="outline" onClick={() => setIsPauseDialogOpen(false)}>Annulla</Button>
                  <Button onClick={handleConfirmPause} disabled={selectedOperatorsToPause.length === 0}>
                      Metti in Pausa Selezionati ({selectedOperatorsToPause.length})
                  </Button>
              </DialogFooter>
          </DialogContent>
      </Dialog>

      <PauseReasonDialog 
        isOpen={isPauseReasonDialogOpen} 
        onOpenChange={setIsPauseReasonDialogOpen} 
        onConfirm={handleReasonConfirm as any}
      />

      <AttachmentViewerDialog 
        isOpen={isAttachmentsDialogOpen} 
        onOpenChange={setIsAttachmentsDialogOpen} 
        attachments={jobOrder.attachments || []} 
      />
    </>
  );
}

import React from 'react';
import QRCode from 'react-qr-code';
import { format, isValid, parseISO } from 'date-fns';
import type { JobOrder, RawMaterial, Article } from '@/types';
import { ODLConfig, DEFAULT_ODL_CONFIG } from '@/lib/odl-config';
import { calculateBOMRequirement } from '@/lib/inventory-utils';
import { GlobalSettings } from '@/lib/settings-types';

interface ODLPrintTemplateProps {
  job: JobOrder;
  article: Article | null;
  materials: RawMaterial[];
  printDate?: Date;
  config?: ODLConfig;
  qrRule?: string;
  globalSettings?: GlobalSettings | null;
}

export default function ODLPrintTemplate({ 
  job, 
  article, 
  materials, 
  printDate, 
  config = DEFAULT_ODL_CONFIG,
  qrRule = "{ordinePF}@{details}@{qta}",
  globalSettings
}: ODLPrintTemplateProps) {
  const materialsMap = new Map(materials.map(m => [m.code.toUpperCase(), m]));

  const allItems = (job.billOfMaterials || []).map(item => {
    const mat = materialsMap.get(item.component.toUpperCase());
    const type = mat?.type?.toUpperCase() || 'TRECCIA';
    return { ...item, type, mat };
  });

  const trecciaItems = allItems.filter(i => ['BOB', 'PF3V0', 'BARRA', 'TRECCIA'].includes(i.type));
  const tubiItems = allItems.filter(i => i.type === 'TUBI');
  const guainaItems = allItems.filter(i => i.type === 'GUAINA');

  const getDeptSigla = (name: string) => {
    const n = (name || '').toUpperCase();
    if (n.includes('CONN') || n.includes('PICCOLE') || n.includes('CP')) return 'CP';
    if (n.includes('QUALITÀ') || n.includes('CG')) return 'CG';
    if (n.includes('BURATTATURA') || n.includes('FINITURA') || n.includes('BF')) return 'BF';
    if (n.includes('MAGAZZINO') || n.includes('MAG')) return 'MAG';
    if (n.includes('COLLAUDO') || n.includes('TEST') || n.includes('QLTY')) return 'QLTY';
    if (n.includes('OFFICINA') || n.includes('OFF')) return 'OFF';
    return n;
  };

  const formatDateSafe = (dateInput: any) => {
    if (!dateInput) return '---';
    try {
      const d = typeof dateInput === 'string' ? parseISO(dateInput) : (dateInput.toDate ? dateInput.toDate() : new Date(dateInput));
      return isValid(d) ? format(d, 'dd/MM/yyyy') : '---';
    } catch (e) { return '---'; }
  };

  const getEstimatedTimeForSection = (phaseId: string) => {
    const timeData = article?.phaseTimes?.[phaseId];
    if (!timeData || (!timeData.expectedMinutesPerPiece && !timeData.detectedMinutesPerPiece)) return 'N/D';
    const mins = timeData.expectedMinutesPerPiece || timeData.detectedMinutesPerPiece || 0;
    const totalMins = Math.round(mins * job.qta);
    const h = Math.floor(totalMins / 60);
    const m = totalMins % 60;
    return `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}`;
  };

  const styles = {
    page: {
      width: "297mm",
      height: "210mm",
      padding: "5mm",
      backgroundColor: "white",
      color: "black",
      fontFamily: "'PT Sans', 'Calibri', sans-serif",
      boxSizing: "border-box" as const,
      display: "flex",
      flexDirection: "column" as const,
      overflow: "hidden",
      pageBreakAfter: "always" as const,
    },
    masterTable: {
      width: "100%",
      borderCollapse: "collapse" as const,
      tableLayout: "fixed" as const,
      border: `1.5px solid ${config.colors.border}`,
    },
    cell: {
      border: `1px solid ${config.colors.border}`,
      padding: "0",
      fontSize: `${config.typography.baseFontSize}pt`,
      height: "8.5mm",
      verticalAlign: (config.layout.verticalAlign || "middle") as any,
      textAlign: (config.layout.textAlign || "center") as any,
      lineHeight: "1",
      position: "relative" as const,
    },
    label: {
        fontSize: `${config.typography.headerFontSize}pt`,
        fontWeight: "bold" as const,
        color: config.colors.headerText || "#555",
        textAlign: "center" as const,
        marginBottom: "1px",
    },
    title: {
      backgroundColor: config.colors.primary,
      color: "white",
      fontWeight: "bold" as const,
      fontSize: `${config.typography.titleFontSize}pt`,
      textAlign: "center" as const,
      height: config.header.titleHeight || "12mm",
      position: "relative" as const,
    },
    qrWrapper: {
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        height: '100%',
        width: '100%',
        padding: '2mm',
        boxSizing: 'border-box' as const,
    },
    qrInner: {
        backgroundColor: 'white',
        padding: '1mm',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
    },
    verificaGrid: {
        display: "flex",
        width: "100%",
        height: "100%",
        alignItems: "stretch",
    },
    verificaSlot: {
        flex: 1,
        borderRight: `1px solid ${config.colors.border}`,
    },
    valueLarge: {
        fontSize: "12pt", // Slightly smaller but bold
        fontWeight: "bold" as const,
    },
    spacingRow: {
        height: "3mm",
        width: "100%",
        backgroundColor: "white",
    }
  };

  const getCellFlexStyles = (colConfig?: any) => {
    const vAlign = colConfig?.verticalAlign || config.layout.verticalAlign || 'middle';
    const hAlign = colConfig?.textAlign || config.layout.textAlign || 'center';
    
    return {
      display: "flex",
      alignItems: vAlign === 'top' ? 'flex-start' : vAlign === 'bottom' ? 'flex-end' : 'center',
      justifyContent: hAlign === 'left' ? 'flex-start' : hAlign === 'right' ? 'flex-end' : 'center',
      height: "100%",
      width: "100%",
      padding: `${config.layout.cellPadding || 0}px`,
      boxSizing: "border-box" as const,
    };
  };

  // NORMALIZED GRID: 10 Columns
  const GRID_COLS = 10;
  const colWidth = 100 / GRID_COLS;

  const activeHeaderCols = config.header.columns?.filter(c => c.visible) || [];

  const renderHeader = () => {
    const logoSrc = config.header.logoBase64 || config.header.logoUrl;

    return (
      <div style={{ marginBottom: '3mm', position: 'relative' }}>
        {/* Revision Info - Independent Top Right */}
        {config.header.showRevInfo && (
            <div style={{ 
                position: 'absolute', 
                top: '-2mm', 
                right: '0', 
                fontSize: '6pt', 
                color: '#666',
                fontStyle: 'italic'
            }}>
                {config.header.revText}
            </div>
        )}

        <table style={{ ...styles.masterTable }}>
            <colgroup>
                <col width={`calc(100% - ${config.header.qrColumnWidth || '15%'})`} />
                <col width={config.header.qrColumnWidth || '15%'} />
            </colgroup>
            <tbody>
                <tr>
                    <td style={{ padding: 0, verticalAlign: 'top', borderRight: `1.5px solid ${config.colors.border}` }}>
                        <table style={{ width: '100%', borderCollapse: 'collapse', tableLayout: 'fixed' }}>
                            <colgroup>
                                <col width={config.header.logoColumnWidth || '23.5%'} />
                                <col width={`calc(100% - ${config.header.logoColumnWidth || '23.5%'})`} />
                            </colgroup>
                            <tbody>
                                <tr>
                                    <td style={{ ...styles.cell, borderLeft: 0, borderTop: 0, borderBottom: 0, backgroundColor: config.header.logoBg || 'white' }}>
                                        <div style={styles.qrWrapper}>
                                            {logoSrc && <img src={logoSrc} alt="Logo" style={{ height: `${config.header.logoHeight}px`, maxWidth: '95%', objectFit: 'contain' }} />}
                                        </div>
                                    </td>
                                    <td style={{ ...styles.title, border: 0, borderLeft: `1px solid ${config.colors.border}`, backgroundColor: config.header.titleBg || config.colors.primary, height: config.header.titleHeight || '12mm' }}>
                                        <div style={getCellFlexStyles()}>{config.header.title}</div>
                                    </td>
                                </tr>
                            </tbody>
                        </table>
                        <table style={{ width: '100%', borderCollapse: 'collapse', tableLayout: 'fixed', borderTop: `1px solid ${config.colors.border}` }}>
                          <colgroup>
                            {activeHeaderCols.map((col) => (
                              <col key={col.id} width={col.width || `${100 / activeHeaderCols.length}%`} />
                            ))}
                          </colgroup>
                          <tbody>
                            {/* HEADER LABELS */}
                            <tr style={{ backgroundColor: config.colors.headerBg }}>
                              {activeHeaderCols.map((col, idx) => (
                                <td key={col.id} style={{ ...styles.cell, borderTop: 0, borderBottom: 0, borderLeft: idx === 0 ? 0 : `1px solid ${config.colors.border}`, borderRight: idx === activeHeaderCols.length - 1 ? 0 : `1px solid ${config.colors.border}`, fontSize: `${col.fontSize || config.typography.headerFontSize}pt` }}>
                                  <div style={styles.label}>{col.label}</div>
                                </td>
                              ))}
                            </tr>
                            {/* HEADER VALUES */}
                            <tr style={{ fontWeight: 'bold', fontSize: '11pt' }}>
                              {activeHeaderCols.map((col, idx) => {
                                let val = '---';
                                if (col.field === 'reparto') val = getDeptSigla(job.department);
                                if (col.field === 'dataOdl') val = format(printDate || new Date(), 'dd/MM/yyyy');
                                if (col.field === 'ordinePf') val = job.ordinePF;
                                if (col.field === 'numeroOdl') val = job.numeroODLInterno || '---';

                                return (
                                  <td key={col.id} style={{ ...styles.cell, borderLeft: idx === 0 ? 0 : `1px solid ${config.colors.border}`, borderRight: idx === activeHeaderCols.length - 1 ? 0 : `1px solid ${config.colors.border}`, borderBottom: 0, fontSize: `${col.fontSize || 11}pt`, backgroundColor: col.field === 'reparto' || col.field === 'ordinePf' || col.field === 'numeroOdl' ? config.colors.bgValueGreen : 'white' }}>
                                    <div style={getCellFlexStyles(col)}>{val}</div>
                                  </td>
                                );
                              })}
                            </tr>
                          </tbody>
                        </table>
                    </td>
                    <td style={{ padding: 0, verticalAlign: 'top', backgroundColor: 'white' }}>
                        <div style={{ display: 'flex', flexDirection: 'column', height: '100%' }}>
                            <div style={{ backgroundColor: config.header.qrTitleBg || config.colors.primary, color: 'white', fontSize: '6.5pt', fontWeight: 'bold', textAlign: 'center', padding: '1mm', borderBottom: `1px solid ${config.colors.border}`, flex: '0 0 auto', height: config.header.qrTitleHeight || '6mm', boxSizing: 'border-box', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                CODICE COMMESSA
                            </div>
                            <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '1mm' }}>
                                <QRCode value={
                                  (qrRule || "{ordinePF}@{details}@{qta}")
                                  .replace('{ordinePF}', job.ordinePF || '')
                                  .replace('{details}', job.details || '')
                                  .replace('{qta}', String(job.qta || ''))
                                  .replace('{numeroODLInterno}', job.numeroODLInterno || '')
                                } size={config.header.qrSize || 65} />
                            </div>
                        </div>
                    </td>
                </tr>
            </tbody>
        </table>
      </div>
    );
  };

  const renderJobDetails = () => {
    const activeInfoCols = config.info.columns.filter(c => c.visible);
    const rowCount = activeInfoCols.length || 1;
    
    // Label and Value widths from config. The rest for Drawing.
    const labelW = config.info.labelWidth || '15%';
    const valueW = config.info.valueWidth || '25%';
    
    // Convert percentages to numbers to calculate remaining
    const lVal = parseFloat(labelW);
    const vVal = parseFloat(valueW);
    const drawW = 100 - lVal - vVal; // Full remaining width 

    return (
      <div style={{ marginBottom: '3mm' }}>
        <table style={styles.masterTable}>
          <colgroup>
              <col width={labelW} />
              <col width={valueW} />
              <col width={`${drawW}%`} />
          </colgroup>
          <tbody>
            {(activeInfoCols.length > 0 ? activeInfoCols : [{ id: 'empty', label: '-', field: '', visible: true }]).map((col, idx) => {
              let val = '---';
              if (col.field === 'cliente') val = job.cliente;
              if (col.field === 'details') val = job.details;
              if (col.field === 'qta') val = `${job.qta}`;
              if (col.field === 'dataFinePreparazione') val = formatDateSafe(job.dataFinePreparazione || job.dataConsegnaFinale);
              if (col.field === 'dataConsegnaFinale') val = formatDateSafe(job.dataConsegnaFinale);

              return (
                <tr key={col.id} style={{ height: '8.5mm' }}>
                  {/* LABEL */}
                  <td style={{ ...styles.cell, backgroundColor: config.colors.headerBg, fontWeight: 'bold', fontSize: `${config.info.fontSize}pt` }}>
                      <div style={getCellFlexStyles()}>{col.label}</div>
                  </td>
                  {/* VALUE */}
                  <td style={{ ...styles.cell, backgroundColor: col.colorKey ? (config.colors as any)[col.colorKey] : 'white', fontWeight: 'bold', fontSize: `${config.info.fontSize + 2}pt` }}>
                    <div style={getCellFlexStyles()}>{val}</div>
                  </td>

                  {/* DRAWING / NOTES AREA */}
                  {idx === 0 && (
                    <td style={{ ...styles.cell, color: config.colors.drawingAreaText, fontWeight: 'bold', fontSize: '18pt', backgroundColor: config.colors.drawingAreaBg, textAlign: 'center', verticalAlign: 'middle', borderLeft: `1.5px solid ${config.colors.border}`, height: config.layout.drawingAreaHeight || '40mm' }} rowSpan={rowCount}>
                      <div style={{ ...getCellFlexStyles(), flexDirection: 'column', gap: '2mm' }}>
                        <div>{config.layout.showDrawingArea ? config.layout.drawingAreaText : ''}</div>
                        {job.attachments && job.attachments.length > 0 && (
                          <div style={{ fontSize: '8pt', color: '#555', textAlign: 'left', width: '90%', marginTop: 'auto', borderTop: '1px dashed #ccc', paddingTop: '2mm' }}>
                            <div style={{ textTransform: 'uppercase', marginBottom: '1mm', color: '#000' }}>📄 Documentazione MES:</div>
                            {job.attachments.map((att, i) => (
                              <div key={i} style={{ whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                                • {att.name}
                              </div>
                            ))}
                          </div>
                        )}
                      </div>
                    </td>
                  )}
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    );
  };

  const renderSectionHeader = () => (
    <table style={{ ...styles.masterTable, marginBottom: '0' }}>
      <tbody>
        <tr>
          <td style={{ ...styles.cell, backgroundColor: config.colors.tableHeaderBg, color: config.colors.tableHeaderText, height: "6mm", border: `1.5px solid ${config.colors.border}` }}>
            <div style={getCellFlexStyles()}>PREPARAZIONE COMPONENTI {config.layout.splitByCategoryThreshold < allItems.length ? "(CONTINUA)" : ""}</div>
          </td>
        </tr>
      </tbody>
    </table>
  );

  const renderTableRows = (items: any[], columnConfigs: any[], sectionType: 'treccia' | 'tubi' | 'guaina') => {
    if (items.length === 0) return null;

    // Check if any item in this section has notes
    const hasAnyNote = items.some(item => item.note && item.note.trim() !== '');
    
    // Dynamic column balancing
    let visibleCols = columnConfigs.filter(c => c.visible);
    
    // If NO notes in entire section, and 'note' column is selected, we hide it and expand others
    const noteColIndex = visibleCols.findIndex(c => c.field === 'note');
    if (!hasAnyNote && noteColIndex !== -1) {
        const removedWidthStr = visibleCols[noteColIndex].width;
        const removedWidth = parseFloat(removedWidthStr) || 0;
        
        visibleCols = visibleCols.filter(c => c.field !== 'note');
        
        // Redistribute width (pro-rata expansion)
        if (visibleCols.length > 0 && removedWidth > 0 && removedWidthStr.includes('%')) {
            const extra = removedWidth / visibleCols.length;
            visibleCols = visibleCols.map(c => ({
                ...c,
                width: `${(parseFloat(c.width) || 0) + extra}%`
            }));
        }
    }

    return (
      <table style={{ ...styles.masterTable, borderTop: '0' }}>
        <colgroup>
          {visibleCols.map((col) => (
            <col key={col.id} width={col.width} />
          ))}
        </colgroup>
        <thead>
          <tr style={{ backgroundColor: config.colors.tableHeaderBg, color: config.colors.tableHeaderText, fontWeight: 'bold', fontSize: '7pt' }}>
            {visibleCols.map((col) => (
              <td key={col.id} style={styles.cell}>
                <div style={getCellFlexStyles(col)}>{col.label}</div>
              </td>
            ))}
          </tr>
        </thead>
        <tbody>
          {items.map((item, i) => {
            const configMat = globalSettings?.rawMaterialTypes.find(t => t.id === item.mat?.type) || { defaultUnit: item.mat?.unitOfMeasure };
            const req = calculateBOMRequirement(job.qta, item, item.mat as any, configMat as any);
            
            const data: any = {
              codice: item.component,
              lunghezzaTaglio: item.lunghezzaTaglioMm || 0,
              quantita: req.totalPieces, // Use total pieces as requested
              pesoTotale: req.weightKg.toFixed(1),
              metriTotali: req.totalMeters?.toFixed(2) || '0.00',
              placeholder: '',
              checkbox: '□',
              tempoPrevisto: '',
              note: item.note || ''
            };

            return (
              <tr key={`${sectionType}-${i}`} style={{ height: '9mm', backgroundColor: sectionType === 'treccia' ? config.colors.bgTreccia : sectionType === 'tubi' ? config.colors.bgTubi : config.colors.bgGuaina }}>
                {visibleCols.map((col) => {
                  const isTempoPrevisto = col.field === 'tempoPrevisto';
                  const cellFontSize = col.fontSize || config.typography.baseFontSize;
                  
                  if (isTempoPrevisto) {
                    if (i === 0) {
                      return (
                        <td key={col.id} rowSpan={items.length} style={{ ...styles.cell, fontWeight: 'bold', fontSize: `${cellFontSize}pt`, backgroundColor: 'white' }}>
                          <div style={getCellFlexStyles(col)}>
                              {config.layout.showEstimatedTimes ? getEstimatedTimeForSection(
                                  sectionType === 'treccia' ? 'phase-template-1' : 
                                  sectionType === 'tubi' ? 'phase-template-7' : 'phase-template-6'
                              ) : '---'}
                          </div>
                        </td>
                      );
                    }
                    return null;
                  }

                  // Conditional rendering for notes: only show if present
                  const displayValue = col.field === 'note' ? (data.note || '') : (data[col.field] ?? '---');

                  return (
                    <td key={col.id} style={{ ...styles.cell, fontSize: `${cellFontSize}pt` }}>
                      <div style={getCellFlexStyles(col)}>
                        {col.field === 'placeholder' ? (
                          <div style={styles.verificaGrid}><div style={styles.verificaSlot}></div><div style={styles.verificaSlot}></div><div style={{ flex: 1 }}></div></div>
                        ) : displayValue}
                      </div>
                    </td>
                  );
                })}
              </tr>
            );
          })}
        </tbody>
      </table>
    );
  };

  const renderFooter = () => (
    <table style={{ ...styles.masterTable, marginTop: '3mm' }}>
      <tbody>
        <tr style={{ height: '10mm' }}>
          <td style={{ ...styles.cell, backgroundColor: config.colors.footerBg, color: config.colors.footerText, fontWeight: 'bold', padding: '2mm' }} colSpan={6}>
              <div style={getCellFlexStyles({ textAlign: 'left', verticalAlign: 'top' })}>NOTE / NON CONFORMITÀ (NC)</div>
          </td>
          <td style={{ ...styles.cell, backgroundColor: config.colors.headerBg, color: config.colors.headerText || "#555", fontWeight: 'bold', padding: '2mm' }} colSpan={4}>
              <div style={getCellFlexStyles({ textAlign: 'left', verticalAlign: 'top' })}>DATA E FIRMA OPERATORE</div>
          </td>
        </tr>
        <tr style={{ height: '10mm', backgroundColor: 'white' }}>
          <td style={styles.cell} colSpan={6}></td>
          <td style={{ ...styles.cell, padding: '4mm' }} colSpan={4}>
            <div style={{ display: 'flex', justifyContent: 'space-between', width: '100%', alignItems: 'flex-end', height: '100%', paddingBottom: '1mm', fontSize: '7.5pt' }}>
                <span style={{ fontWeight: 'bold' }}>DATA: ___/___/______</span>
                <span style={{ fontWeight: 'bold' }}>FIRMA: ___________________________________</span>
            </div>
          </td>
        </tr>
      </tbody>
    </table>
  );

  const totalItemsRows = trecciaItems.length + tubiItems.length + guainaItems.length;
  const shouldSplit = totalItemsRows > config.layout.splitByCategoryThreshold && (
      (trecciaItems.length > 0 && tubiItems.length > 0) || 
      (trecciaItems.length > 0 && guainaItems.length > 0) || 
      (tubiItems.length > 0 && guainaItems.length > 0)
  );

  if (shouldSplit) {
    return (
      <div id="odl-pdf-pages" style={{ width: '297mm' }}>
        {trecciaItems.length > 0 && (
          <div className="odl-page" style={styles.page}>
              {renderHeader()}
              {renderJobDetails()}
              {renderSectionHeader()}
              {renderTableRows(trecciaItems, config.columns.treccia, 'treccia')}
              {renderFooter()}
          </div>
        )}
        {tubiItems.length > 0 && (
          <div className="odl-page" style={styles.page}>
              {renderHeader()}
              {renderJobDetails()}
              {renderSectionHeader()}
              {renderTableRows(tubiItems, config.columns.tubi, 'tubi')}
              {renderFooter()}
          </div>
        )}
        {guainaItems.length > 0 && (
          <div className="odl-page" style={styles.page}>
              {renderHeader()}
              {renderJobDetails()}
              {renderSectionHeader()}
              {renderTableRows(guainaItems, config.columns.guaina, 'guaina')}
              {renderFooter()}
          </div>
        )}
      </div>
    );
  }

  return (
    <div id="odl-pdf-pages" style={{ width: '297mm' }}>
      <div className="odl-page" style={styles.page}>
          {renderHeader()}
          {renderJobDetails()}
          {renderSectionHeader()}
          {renderTableRows(trecciaItems, config.columns.treccia, 'treccia')}
          {trecciaItems.length > 0 && (tubiItems.length > 0 || guainaItems.length > 0) && <div style={styles.spacingRow}></div>}
          {renderTableRows(tubiItems, config.columns.tubi, 'tubi')}
          {tubiItems.length > 0 && guainaItems.length > 0 && <div style={styles.spacingRow}></div>}
          {renderTableRows(guainaItems, config.columns.guaina, 'guaina')}
          {renderFooter()}
      </div>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { DragDropContext, Droppable, Draggable, DropResult } from '@hello-pangea/dnd';
import { useRouter } from 'next/navigation';
import { format, addWeeks, subWeeks, addDays, parseISO, isBefore, startOfDay, getWeek, isPast, isSameWeek, isSameDay } from 'date-fns';
import { it } from 'date-fns/locale';
import { JobOrder, Article, RawMaterial } from '@/types';
import { Badge } from '@/components/ui/badge';
import { Card, CardContent } from '@/components/ui/card';
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from '@/components/ui/tooltip';
import { AlertTriangle, Boxes, Timer, Star, TrendingUp, FileText, MonitorPlay, Calendar as CalendarIcon, Clock, Search, X, Filter } from 'lucide-react';
import { cn } from '@/lib/utils';
import { Progress } from '@/components/ui/progress';
import { Input } from '@/components/ui/input';
import { Switch } from '@/components/ui/switch';
import { Label } from '@/components/ui/label';
import { toggleJobPriority, bulkUpdateJobSortOrder } from '@/app/admin/resource-planning/actions';
import { useToast } from '@/hooks/use-toast';
import AttachmentViewerDialog from './AttachmentViewerDialog';

export interface WeekKanbanBoardProps {
  jobOrders: JobOrder[];
  mrpTimelines: Map<string, any[]>;
  rawMaterials: RawMaterial[];
  articles: Article[];
  currentWeekStart: Date; // Monday
  snapshot: any; // Contains capacity data
  activeTab: string;
  activeSubTab: string | null;
  onJobDrop: (jobId: string, assignedDate: string | null) => void;
  selectedJobIds: string[];
  onToggleSelection: (jobId: string) => void;
  onBatchSelection: (ids: string[], selected: boolean) => void;
}

interface MrpStatus {
  alert: boolean;
  dateArrival: string | null;
  text: string;
}

// Helper per calcolare lo stato MRP a livello di board (per i filtri)
const getMrpStatus = (job: JobOrder, rawMaterials: RawMaterial[], mrpTimelines: Map<string, any[]>): MrpStatus => {
    if (!job.billOfMaterials || job.billOfMaterials.length === 0) return { alert: false, dateArrival: null, text: 'Nessuna BOM' };
    let earliestCoverDate: string | null = null;
    let hasMissing = false;
    job.billOfMaterials.forEach((item: any) => {
       const matCode = item.component.toUpperCase();
       const mat = rawMaterials.find((m: RawMaterial) => m.code.toUpperCase() === matCode);
       if (!mat) { hasMissing = true; return; }
       const timeline = mrpTimelines.get(matCode) || [];
       const jobEntry = timeline.find((e: any) => e.jobId === job.id);
       if (jobEntry && jobEntry.date !== 'IMMEDIATA') {
           hasMissing = true;
           if (jobEntry.date !== 'MAI' && (!earliestCoverDate || isBefore(parseISO(jobEntry.date), parseISO(earliestCoverDate)))) {
               earliestCoverDate = jobEntry.date;
           }
       }
    });
    if (hasMissing) {
        if (earliestCoverDate) return { alert: true, dateArrival: earliestCoverDate, text: `Arrivo mat: ${format(parseISO(earliestCoverDate), 'dd/MM')}` };
        return { alert: true, dateArrival: null, text: 'Materiale Mancante (No ordini)' };
    }
    return { alert: false, dateArrival: null, text: 'Mat. OK' };
};

export default function WeekKanbanBoard({
  jobOrders,
  mrpTimelines,
  rawMaterials,
  articles,
  currentWeekStart,
  snapshot,
  activeTab,
  activeSubTab,
  onJobDrop,
  selectedJobIds,
  onToggleSelection,
  onBatchSelection
}: WeekKanbanBoardProps) {
  const { toast } = useToast();
  const [mounted, setMounted] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [showMissingOnly, setShowMissingOnly] = useState(false);
  const [showPriorityOnly, setShowPriorityOnly] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);
  
  // GENERATE 5 WEEKS + 1 BEYOND
  const workWeeks = useMemo(() => {
    return Array.from({ length: 5 }).map((_, i) => {
        const d = addWeeks(currentWeekStart, i);
        return {
            date: format(d, 'yyyy-MM-dd'),
            weekNum: getWeek(d, { weekStartsOn: 1 }),
            label: `SETTIMANA ${getWeek(d, { weekStartsOn: 1 })}`,
            range: `${format(d, 'dd MMM')} - ${format(addDays(d, 6), 'dd MMM')}`
        };
    });
  }, [currentWeekStart]);

  const [columns, setColumns] = useState<Record<string, JobOrder[]>>({ unassigned: [], beyond: [] });

  useEffect(() => {
    const cols: Record<string, JobOrder[]> = { unassigned: [], beyond: [] };
    workWeeks.forEach(w => { cols[w.date] = []; });

    // 1. LOCAL FILTERING
    const filteredJobs = jobOrders.filter(job => {
        const matchesSearch = !searchTerm || 
            job.ordinePF.toLowerCase().includes(searchTerm.toLowerCase()) || 
            job.details.toLowerCase().includes(searchTerm.toLowerCase()) ||
            job.cliente.toLowerCase().includes(searchTerm.toLowerCase());
        
        const matchesPriority = !showPriorityOnly || job.isPriority;
        
        let matchesMissing = true;
        if (showMissingOnly) {
            const status = getMrpStatus(job, rawMaterials, mrpTimelines);
            matchesMissing = status.alert;
        }

        return matchesSearch && matchesPriority && matchesMissing;
    });

    // 2. DISTRIBUTION INTO COLUMNS
    filteredJobs.forEach(job => {
      if (!job.assignedDate) {
        cols.unassigned.push(job);
        return;
      }

      const assignedDate = job.assignedDate;
      const firstWeekStart = workWeeks[0].date;
      const lastWeekEnd = format(addDays(parseISO(workWeeks[workWeeks.length - 1].date), 6), 'yyyy-MM-dd');

      if (assignedDate < firstWeekStart) {
        // Still show it in the first week but marked as carryover
        const carryoverJob = { ...job, isCarryover: true } as any;
        cols[firstWeekStart].push(carryoverJob);
      } else if (assignedDate > lastWeekEnd) {
        cols.beyond.push(job);
      } else {
        // Find which week it falls into
        const targetWeek = workWeeks.find(w => {
            const wStart = w.date;
            const wEnd = format(addDays(parseISO(wStart), 6), 'yyyy-MM-dd');
            return assignedDate >= wStart && assignedDate <= wEnd;
        });

        if (targetWeek && cols[targetWeek.date]) {
            cols[targetWeek.date].push(job);
        } else {
            cols.unassigned.push(job);
        }
      }
    });

    // SORTING LOGIC: 1. sortIndex, 2. dataConsegnaFinale
    Object.keys(cols).forEach(key => {
        cols[key].sort((a: any, b: any) => {
            if (a.sortIndex !== undefined && b.sortIndex !== undefined) return a.sortIndex - b.sortIndex;
            if (a.sortIndex !== undefined) return -1;
            if (b.sortIndex !== undefined) return 1;
            
            if (!a.dataConsegnaFinale) return 1;
            if (!b.dataConsegnaFinale) return -1;
            return a.dataConsegnaFinale.localeCompare(b.dataConsegnaFinale);
        });
    });

    setColumns(cols);
  }, [jobOrders, workWeeks]);

  const onDragEnd = async (result: DropResult) => {
    const { source, destination } = result;
    if (!destination) return;
    if (source.droppableId === destination.droppableId && source.index === destination.index) return;

    // Source and Destination columns
    const sourceCol = [...(columns[source.droppableId] || [])];
    const destCol = source.droppableId === destination.droppableId ? sourceCol : [...(columns[destination.droppableId] || [])];
    
    // Check if it's a multi-select move
    const movedItem = sourceCol[source.index];
    const isMultiMove = selectedJobIds.includes(movedItem.id);
    const movingJobIds = isMultiMove ? selectedJobIds : [movedItem.id];
    
    // Extract items to move
    const movingJobs = sourceCol.filter(j => movingJobIds.includes(j.id));
    const remainingSource = sourceCol.filter(j => !movingJobIds.includes(j.id));
    
    // We update local state first for instant feedback (Optimistic)
    let newColumns = { ...columns };
    
    if (source.droppableId === destination.droppableId) {
        // Reordering in same column
        const finalDest = [...remainingSource];
        finalDest.splice(destination.index, 0, ...movingJobs);
        newColumns[source.droppableId] = finalDest;
    } else {
        // Moving to different column
        const finalDest = [...destCol];
        finalDest.splice(destination.index, 0, ...movingJobs);
        newColumns[source.droppableId] = remainingSource;
        newColumns[destination.droppableId] = finalDest;
    }

    setColumns(newColumns);

    const isSpecialCol = destination.droppableId === 'unassigned' || destination.droppableId === 'beyond';
    const newDate = isSpecialCol ? null : destination.droppableId;
    
    // 1. Update assignment date (Monday of the week)
    onJobDrop(movedItem.id, newDate);

    // 2. Persist sort order for ALL items in the destination column
    const targetCol = newColumns[destination.droppableId];
    const updates = targetCol.map((item, index) => ({
        id: item.id,
        sortIndex: index
    }));
    await bulkUpdateJobSortOrder(updates);
  };

  const handleTogglePriority = async (jobId: string, currentPriority: boolean) => {
      const newValue = !currentPriority;
      const updatedCols = { ...columns };
      Object.keys(updatedCols).forEach(key => {
          updatedCols[key] = updatedCols[key].map(j => j.id === jobId ? { ...j, isPriority: newValue } : j);
      });
      setColumns(updatedCols);

      const res = await toggleJobPriority(jobId, newValue);
      if (!res.success) {
          toast({ variant: 'destructive', title: 'Errore', description: res.message });
      }
  };

  const getCapacityForWeek = (monday: string) => {
      if (!snapshot || !activeTab) return { supply: 0, demand: 0 };
      const weekDays = Array.from({ length: 7 }).map((_, i) => format(addDays(parseISO(monday), i), 'yyyy-MM-dd'));
      let supply = 0;
      let demand = 0;

      weekDays.forEach(day => {
          if (activeTab === 'PRODUZIONE' && activeSubTab) {
              const dept = snapshot.macroAreas['PRODUZIONE']?.find((d: any) => d.code === activeSubTab);
              const dayData = dept?.data?.find((d: any) => d.date === day);
              if (dayData) { supply += dayData.supplyHours || 0; demand += dayData.areaSpecificDemand || 0; }
          } else {
              const areaDepts = snapshot.macroAreas[activeTab] || [];
              areaDepts.forEach((dept: any) => {
                  const dayData = dept?.data?.find((d: any) => d.date === day);
                  if (dayData) {
                      supply += (dayData.supplyHours || 0);
                      demand += (dayData.areaSpecificDemand || dayData.demandHours || 0);
                  }
              });
          }
      });
      return { supply, demand };
  };

  const commonProps = {
    activeTab,
    activeSubTab,
    articles,
    mrpTimelines,
    rawMaterials,
    onTogglePriority: handleTogglePriority,
    selectedJobIds,
    onToggleSelection,
    onBatchSelection,
    mounted
  };

  return (
    <div className="flex flex-col h-full gap-4">
      {/* FILTER BAR - PREMIUM DESIGN */}
      <div className="flex flex-wrap items-center gap-4 bg-white/80 backdrop-blur-md p-3 rounded-2xl border-2 border-slate-100 shadow-sm transition-all hover:shadow-md sticky top-0 z-10 mx-2">
        <div className="relative flex-1 min-w-[300px] group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400 group-focus-within:text-blue-600 transition-colors" />
            <Input 
                placeholder="Cerca Commessa, Articolo o Cliente..." 
                className="pl-9 h-10 bg-slate-50 border-none focus-visible:ring-2 focus-visible:ring-blue-500 font-bold text-sm rounded-xl"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
            />
            {searchTerm && (
                <button onClick={() => setSearchTerm('')} className="absolute right-3 top-1/2 -translate-y-1/2 p-1 hover:bg-slate-200 rounded-full transition-colors">
                    <X className="h-3.5 w-3.5 text-slate-500" />
                </button>
            )}
        </div>

        <div className="flex items-center gap-6 px-4 py-1.5 bg-slate-50 rounded-xl border border-slate-200">
            <div className="flex items-center space-x-2">
                <Switch id="missing-mat" checked={showMissingOnly} onCheckedChange={setShowMissingOnly} />
                <Label htmlFor="missing-mat" className="text-[10px] font-black uppercase tracking-tight cursor-pointer flex items-center gap-1.5">
                    <AlertTriangle className={cn("h-3 w-3", showMissingOnly ? "text-red-500 animate-pulse" : "text-slate-400")} />
                    Manca Materiale
                </Label>
            </div>
            <div className="w-px h-6 bg-slate-200" />
            <div className="flex items-center space-x-2">
                <Switch id="priority-only" checked={showPriorityOnly} onCheckedChange={setShowPriorityOnly} />
                <Label htmlFor="priority-only" className="text-[10px] font-black uppercase tracking-tight cursor-pointer flex items-center gap-1.5">
                    <Star className={cn("h-3 w-3", showPriorityOnly ? "text-amber-500 fill-amber-500" : "text-slate-400")} />
                    Alta Priorità
                </Label>
            </div>
        </div>

        {selectedJobIds.length > 0 && (
            <div className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-xl shadow-lg animate-in fade-in zoom-in duration-300">
                <Filter className="h-4 w-4" />
                <span className="text-xs font-black uppercase tracking-tighter">Selezionate: {selectedJobIds.length}</span>
                <button onClick={() => onBatchSelection([], false)} className="ml-2 hover:bg-white/20 p-0.5 rounded transition-colors">
                    <X className="h-4 w-4" />
                </button>
            </div>
        )}
      </div>

    <DragDropContext onDragEnd={onDragEnd}>
      <div className="flex h-full w-full overflow-x-auto overflow-y-hidden gap-6 pb-4 px-2 scrollbar-thin scrollbar-thumb-slate-300">
        <Column 
          id="unassigned" 
          title="DA PIANIFICARE" 
          jobs={columns.unassigned || []} 
          isUnassigned 
          {...commonProps} 
        />

        {workWeeks.map((week, idx) => {
          const cap = getCapacityForWeek(week.date);
          return (
            <Column 
              key={week.date} 
              id={week.date} 
              title={week.label}
              subtitle={week.range}
              jobs={columns[week.date] || []} 
              capacity={cap.supply}
              demand={cap.demand}
              isCurrentWeek={idx === 0}
              {...commonProps}
            />
          );
        })}

        <Column 
          id="beyond" 
          title="OLTRE"
          subtitle="Commisse a lungo termine"
          jobs={columns.beyond || []} 
          isFuture
          {...commonProps} 
        />
      </div>
    </DragDropContext>
    </div>
  );
}

function Column({ id, title, subtitle, jobs, isUnassigned, isFuture, capacity, demand, articles, activeTab, activeSubTab, mrpTimelines, rawMaterials, onTogglePriority, selectedJobIds, onToggleSelection, onBatchSelection, isCurrentWeek, mounted }: any) {
  const isOverloaded = !isUnassigned && !isFuture && demand > capacity;
  const allJobsInColIds = jobs.map((j: any) => j.id);
  const isAllSelected = allJobsInColIds.length > 0 && allJobsInColIds.every((id: string) => selectedJobIds.includes(id));
  const isSomeSelected = !isAllSelected && allJobsInColIds.some((id: string) => selectedJobIds.includes(id));

  return (
    <div className={cn(
        "flex flex-col w-[350px] shrink-0 h-full rounded-2xl border-2 transition-all shadow-sm",
        isCurrentWeek ? "bg-blue-50/40 border-blue-200/50 ring-2 ring-blue-100/20" : "bg-slate-50/50 border-slate-200",
        isUnassigned && "bg-slate-100/30 border-dashed"
    )}>
      <div className={cn(
        "p-4 border-b rounded-t-2xl shrink-0 flex flex-col gap-2",
        isOverloaded ? "bg-red-50/80 border-red-200" : "bg-white/80 backdrop-blur-sm"
      )}>
        <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
                <input 
                    type="checkbox" 
                    checked={isAllSelected}
                    ref={(el) => { if (el) el.indeterminate = isSomeSelected; }}
                    onChange={(e) => onBatchSelection(allJobsInColIds, e.target.checked)}
                    className="h-4 w-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500 cursor-pointer transition-transform hover:scale-110"
                />
                <div className="flex flex-col">
                    <h3 className="font-black text-sm uppercase text-slate-800 tracking-tight leading-none">{title}</h3>
                    {subtitle && <p className="text-[10px] font-bold text-slate-400 mt-1 uppercase tracking-tighter italic">{subtitle}</p>}
                </div>
            </div>
            <Badge variant="secondary" className="bg-slate-800 text-white border-none font-black px-2 py-0.5 text-xs">{jobs.length}</Badge>
        </div>

        {!isUnassigned && !isFuture && capacity > 0 && (
          <div className="space-y-1.5 mt-1">
             <div className="flex justify-between items-end text-[10px] font-black uppercase tracking-tighter">
                <span className="text-slate-500">Allocazione Week</span>
                <span className={isOverloaded ? "text-red-600 animate-pulse" : "text-emerald-600"}>
                    {demand.toFixed(1)}h / {capacity.toFixed(0)}h
                </span>
             </div>
             <Progress 
                value={Math.min(100, (demand / capacity) * 100)} 
                className={cn("h-2 bg-slate-100", isOverloaded && "[&>div]:bg-red-500")} 
             />
          </div>
        )}
      </div>

      <Droppable droppableId={id}>
        {(provided, snapshot) => (
          <div 
            {...provided.droppableProps} 
            ref={provided.innerRef}
            className={cn(
              "flex-1 p-3 overflow-y-auto space-y-3 scrollbar-thin scrollbar-thumb-slate-300 transition-colors",
              snapshot.isDraggingOver ? "bg-blue-50/30" : ""
            )}
          >
            {jobs.map((job: any, index: number) => (
               <Draggable key={job.id} draggableId={job.id} index={index}>
                 {(provided, dSnapshot) => (
                   <div
                     ref={provided.innerRef}
                     {...provided.draggableProps}
                     {...provided.dragHandleProps}
                     style={{ ...provided.draggableProps.style }}
                   >
                      <JobKanbanCard 
                        job={job} 
                        articles={articles} 
                        activeTab={activeTab} 
                        activeSubTab={activeSubTab} 
                        mrpTimelines={mrpTimelines}
                        rawMaterials={rawMaterials}
                        isDragging={dSnapshot.isDragging}
                        columnId={id}
                        isCarryover={job.isCarryover}
                        onTogglePriority={onTogglePriority}
                      isSelected={selectedJobIds.includes(job.id)}
                      onToggleSelection={onToggleSelection}
                      selectionCount={selectedJobIds.includes(job.id) ? selectedJobIds.length : 0}
                      isMounted={mounted}
                    />
                   </div>
                 )}
               </Draggable>
            ))}
            {provided.placeholder}
          </div>
        )}
      </Droppable>
    </div>
  );
}

const JobKanbanCard = React.memo(({ job, articles, activeTab, activeSubTab, mrpTimelines, rawMaterials, isDragging, columnId, isCarryover, onTogglePriority, isSelected, onToggleSelection, selectionCount, isMounted }: any): JSX.Element => {
  const router = useRouter();
  const [isAttachmentsDialogOpen, setIsAttachmentsDialogOpen] = useState(false);
  const article = useMemo(() => articles.find((a: Article) => a.code.toUpperCase() === job.details?.toUpperCase()), [articles, job.details]);
  const attachments = job.attachments || article?.attachments || [];
  const progress = useMemo(() => {
    if (!job.phases || job.phases.length === 0) return 0;
    const completed = job.phases.filter((p: any) => p.status === 'completed').length;
    return (completed / job.phases.length) * 100;
  }, [job.phases]);

  const { hours, isIpothesis } = useMemo(() => {
    if (!job.details) return { hours: 0, isIpothesis: false };
    const article = articles.find((a: Article) => a.code.toUpperCase() === job.details.toUpperCase());
    let hasUsedFallback = false;
    const relevantPhases = (job.phases || []).filter((phase: any) => {
        if (activeTab === 'PREPARAZIONE') return phase.type === 'preparation';
        if (activeTab === 'QLTY_PACK') return phase.type === 'quality' || phase.type === 'packaging';
        if (activeTab === 'PRODUZIONE') {
            if (!activeSubTab) return phase.type === 'production';
            return phase.type === 'production' && job.department === activeSubTab;
        }
        return false;
    });
    const totalMinutes = relevantPhases.reduce((acc: number, phase: any) => {
        const time = article?.phaseTimes?.[phase.name]?.expectedMinutesPerPiece || 10;
        if (!article?.phaseTimes?.[phase.name]) hasUsedFallback = true;
        return acc + (time * job.qta);
    }, 0);
    return { hours: totalMinutes / 60, isIpothesis: hasUsedFallback };
  }, [job, articles, activeTab, activeSubTab]);

  const mrpStatus: MrpStatus = useMemo(() => getMrpStatus(job, rawMaterials, mrpTimelines), [job, rawMaterials, mrpTimelines]);

  const isMrpConflict = columnId !== 'unassigned' && columnId !== 'beyond' && mrpStatus.alert && mrpStatus.dateArrival && isBefore(parseISO(columnId), startOfDay(parseISO(mrpStatus.dateArrival)));
  const isMrpCritical = columnId !== 'unassigned' && columnId !== 'beyond' && mrpStatus.alert && !mrpStatus.dateArrival;
  const isMultiDay = hours > 8;

  return (
    <Card className={cn(
      "transition-all cursor-grab active:cursor-grabbing border-l-4 group bg-white shadow-sm hover:shadow-md",
      isDragging && "shadow-xl ring-2 ring-primary/50 rotate-2 opacity-90",
      job.isPriority && "ring-2 ring-red-500 animate-pulse border-l-red-600",
      !job.isPriority && (job.status === 'production' ? "border-l-blue-500" : "border-l-slate-300"),
      (isMrpConflict || isMrpCritical) ? "bg-red-50/80 border-l-red-500" : "",
      isSelected && "ring-2 ring-blue-400"
    )}>
      <CardContent className="p-3 space-y-2">
         <div className="flex justify-between items-start">
            <div className="flex items-start gap-2 max-w-[80%]">
               <input 
                 type="checkbox" 
                 checked={isSelected}
                 onChange={(e) => { e.stopPropagation(); onToggleSelection(job.id); }}
                 className="mt-0.5 h-3 w-3 rounded border-gray-300 text-blue-600 focus:ring-blue-500 cursor-pointer shrink-0"
               />
               <div className="space-y-0.5 overflow-hidden">
                   <div className="flex items-center gap-1">
                       <span className={cn("text-xs font-black truncate", isMrpConflict ? "text-red-900" : "text-slate-800")}>{job.ordinePF}</span>
                       {job.numeroODLInterno && <span className="text-[8px] bg-slate-100 text-slate-500 px-1 rounded truncate">{job.numeroODLInterno}</span>}
                   </div>
                   <div className="flex flex-wrap gap-1 mt-0.5">
                      <p className={cn("text-[9px] font-bold uppercase truncate", isMrpConflict ? "text-red-700/80" : "text-muted-foreground")}>{job.details}</p>
                      {isCarryover && (
                        <Badge variant="outline" className="h-3.5 px-1 bg-blue-50 text-blue-600 border-blue-200 text-[7px] font-black animate-pulse uppercase">
                          🔄 CONT.
                        </Badge>
                      )}
                   </div>
               </div>
            </div>
            
            <div className="flex items-center gap-1.5 shrink-0">
                <button 
                  onClick={(e) => { e.stopPropagation(); onTogglePriority(job.id, !!job.isPriority); }}
                  className={cn("p-1 rounded-full transition-colors", job.isPriority ? "text-red-600 bg-red-100" : "text-slate-300 hover:text-slate-500 hover:bg-slate-100")}
                >
                    <Star className={cn("h-3.5 w-3.5", job.isPriority && "fill-current")} />
                </button>
                {attachments.length > 0 && (
                  <button 
                    onClick={(e) => { e.stopPropagation(); setIsAttachmentsDialogOpen(true); }}
                    className="p-1 rounded-full text-blue-500 bg-blue-50 hover:bg-blue-100 transition-colors"
                  >
                      <FileText className="h-3.5 w-3.5" />
                  </button>
                )}

                <button 
                  onClick={(e) => { 
                    e.stopPropagation(); 
                    const param = job.workGroupId || job.ordinePF;
                    const type = job.workGroupId ? 'groupId' : 'search';
                    router.push(`/admin/production-console?${type}=${param}`); 
                  }}
                  className="p-1 rounded-full text-emerald-600 bg-emerald-50 hover:bg-emerald-100 transition-colors"
                  title="Vai alla Console Produzione"
                >
                    <MonitorPlay className="h-3.5 w-3.5" />
                </button>
                {mrpStatus.alert ? (
                    <TooltipProvider>
                        <Tooltip>
                            <TooltipTrigger asChild>
                                <AlertTriangle className={cn("h-4 w-4 shrink-0", isMrpConflict || isMrpCritical ? "text-red-600 animate-pulse" : "text-amber-500")} />
                            </TooltipTrigger>
                            <TooltipContent className="bg-white border text-black shadow-xl">
                                <p className="font-bold text-xs">{mrpStatus.text}</p>
                            </TooltipContent>
                        </Tooltip>
                    </TooltipProvider>
                ) : (
                    <div className="h-2 w-2 rounded-full bg-emerald-500 mt-1 shrink-0" />
                )}
            </div>
         </div>

         {isDragging && selectionCount > 1 && (
             <div className="absolute -top-3 -right-3 bg-blue-600 text-white text-[10px] font-black h-6 w-6 rounded-full flex items-center justify-center shadow-lg border-2 border-white animate-bounce z-50">
                {selectionCount}
             </div>
         )}

         <div className="space-y-2">
             <div className="space-y-1">
                 <div className="flex justify-between items-center text-[7px] font-bold text-slate-400 uppercase">
                     <span>Progresso</span>
                     <span>{Math.round(progress)}%</span>
                 </div>
                 <Progress value={progress} className="h-1 bg-slate-100" />
             </div>

             {/* DUE DATE DISPLAY */}
             {isMounted && job.dataConsegnaFinale && (
                 <div className={cn(
                     "flex items-center justify-between p-1.5 rounded-lg border-2 transition-all",
                     (isPast(parseISO(job.dataConsegnaFinale)) || isSameWeek(parseISO(job.dataConsegnaFinale), new Date(), { weekStartsOn: 1 })) 
                        ? "bg-red-50 border-red-200 text-red-600 animate-[pulse_2s_infinite]" 
                        : "bg-slate-50 border-slate-100 text-slate-600"
                 )}>
                    <div className="flex items-center gap-1.5">
                        <Clock className="h-3 w-3" />
                        <span className="text-[10px] font-black uppercase tracking-tighter">
